-- Poems batch 3
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('09837acc-5db1-4202-9c19-541451797944','琴曲歌辭 山人勸酒','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u4ed5\u9014", "\u611f\u4f24", "\u4e50\u5e9c"]','蒼蒼雲松，落落綺皓。',130,'全唐诗/poet.tang.1000.json','["蒼蒼雲松，落落綺皓。", "春風爾來爲阿誰，胡蝶忽然滿芳草。", "秀眉霜雪顏桃花，骨青髓綠長美好。", "稱是秦時避世人，勸酒相歡不知老。", "各守兔鹿志，恥隨龍虎爭。", "歘起佐太子，漢王乃復驚。", "顧謂戚夫人，彼翁羽翼成。", "歸來南山下，泛若雲無情。", "舉觴酹巢由，洗耳何獨清？", "浩歌望嵩嶽，意氣還相傾。"]'),
('540059fa-03ad-4e23-8ca7-7a7b6dfcfb63','琴曲歌辭 幽澗泉','李白','唐','唐诗','tang','','["\u7434\u66f2\u6b4c\u8f9e", "\u97f3\u4e50", "\u611f\u4f24", "\u4e50\u5e9c"]','拂彼白石，彈吾素琴。',113,'全唐诗/poet.tang.1000.json','["拂彼白石，彈吾素琴。", "幽澗愀兮流泉深，善手明徽高張清。", "心寂歷似千古，松颼飀兮萬尋。", "中見愁猨弔影而危處兮，呌秋木而長吟。", "客有哀時失志而聽者，淚淋浪以霑襟。", "乃緝商綴羽，潺湲成音。", "吾但寫聲發情於妙指，殊不知此曲之古今。", "幽澗泉，鳴深林。"]'),
('5bc23215-91c6-48d6-8d9d-5995b37c244d','琴曲歌辭 龍宮操','顧況','唐','唐诗','tang','','[]','龍宮月明光參差，精衛銜石東飛時。',48,'全唐诗/poet.tang.1000.json','["龍宮月明光參差，精衛銜石東飛時。", "鮫人織綃采藕絲，翻江倒海傾吳蜀。", "漢女江妃杳相續，龍王宮中水不足。"]'),
('c4b42026-8bea-4d0d-a0b3-f6ecc59a420a','琴曲歌辭 飛鳶操','劉禹錫','唐','唐诗','tang','','[]','鳶飛杳杳青雲裏，鳶鳴蕭蕭風四起。',192,'全唐诗/poet.tang.1000.json','["鳶飛杳杳青雲裏，鳶鳴蕭蕭風四起。", "旗尾飄揚勢漸高，箭頭砉劃聲相似。", "長空悠悠霽日懸，六翮不動凝飛煙。", "遊鶤翔鴈出其下，慶雲清景相迴旋。", "忽聞飢烏一噪聚，瞥下雲中爭腐鼠。", "騰音礪吻相喧呼，仰天大嚇疑鴛雛。", "畏人避犬投高處，俛啄無聲猶屢顧。", "青鳥自愛玉山禾，仙禽徒貴華亭露。", "樸𣙙危巢向暮時，毰毸飽腹蹲枯枝。", "遊童挾彈一麾肘，臆碎羽分人不悲。", "天生衆禽各有類，威鳳文章在仁義。", "鷹隼儀形螻蟻心，雖能戾天何足貴。"]'),
('2558ab95-ea7f-4124-96e5-a498f843198c','琴曲歌辭 昇仙操','李羣玉','唐','唐诗','tang','','[]','嬴女去秦宮，瓊簫生碧空。',72,'全唐诗/poet.tang.1000.json','["嬴女去秦宮，瓊簫生碧空。", "鳳臺閉煙霧，鸞吹飄天風。", "復聞周太子，亦遇浮丘公。", "叢簧發仙弄，輕舉紫霞中。", "濁世不久住，清都路何窮。", "一去霄漢上，世人那得逢。"]'),
('6b7a1754-680e-4488-be9b-d530ede678b6','琴曲歌辭 司馬相如琴歌','張祜','唐','唐诗','tang','','[]','鳳兮鳳兮非無凰，山重水闊不可量。',32,'全唐诗/poet.tang.1000.json','["鳳兮鳳兮非無凰，山重水闊不可量。", "梧桐結陰在朝陽，濯羽弱水鳴高翔。"]'),
('271c14ff-6628-4ab5-862c-ee0a524358f8','琴曲歌辭 霍將軍','崔顥','唐','唐诗','tang','','[]','長安甲第高入雲，誰家居住霍將軍。',80,'全唐诗/poet.tang.1000.json','["長安甲第高入雲，誰家居住霍將軍。", "日晚朝回擁賓從，路傍揖拜何紛紛。", "莫言炙手手可熱，須臾火盡灰亦滅。", "莫言貧賤即可欺，人生富貴自有時。", "一朝天子賜顏色，世上悠悠應自知。"]'),
('dfc0cb68-548a-41aa-a47f-492d7e264183','琴曲歌辭 琴歌','顧況','唐','唐诗','tang','','[]','琴調秋些，胡風遶雪。',20,'全唐诗/poet.tang.1000.json','["琴調秋些，胡風遶雪。", "峽泉生咽，佳人愁些。"]'),
('0ee76ac8-3321-4568-9217-ae3267ce875f','雜曲歌辭 秦女休行','李白','唐','唐诗','tang','','["\u6b4c\u9882", "\u590d\u4ec7", "\u5987\u5973", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','西門秦氏女，秀色如瓊花。',108,'全唐诗/poet.tang.1000.json','["西門秦氏女，秀色如瓊花。", "手揮白楊刀，清晝殺讐家。", "羅袖灑赤血，英聲凌紫霞。", "直上西山去，關吏相邀遮。", "壻爲燕國王，身被詔獄加。", "犯刑若履虎，不畏落爪牙。", "素頸未及斷，摧眉伏泥沙。", "金雞忽放赦，大辟得寬賒。", "何慙聶政姊，萬古共驚嗟。"]'),
('0b9e0802-9e1e-44f0-893a-8f34e4be5394','雜曲歌辭 出門行二首 一','孟郊','唐','唐诗','tang','','[]','長河悠悠去無極，百齡同此可歎息。',80,'全唐诗/poet.tang.1000.json','["長河悠悠去無極，百齡同此可歎息。", "秋風白露霑人衣，壯心凋落奪顏色。", "少年出門將訴誰，川無梁兮路無岐。", "一聞陌上苦寒奏，使我佇立驚且悲。", "君今得意厭粱肉，豈復念我貧賤時。"]'),
('215dbf70-fc96-41e5-80ae-edf233df30e1','雜曲歌辭 出門行二首 二','孟郊','唐','唐诗','tang','','[]','海風蕭蕭天雨霜，窮愁獨坐夜何長？',96,'全唐诗/poet.tang.1000.json','["海風蕭蕭天雨霜，窮愁獨坐夜何長？", "驅車舊憶太行險，始知遊子悲故鄉。", "美人相思隔天闕，長望雲端不可越。", "手持琅玕欲有贈，愛而不見心斷絕。", "南山峨峨白石爛，碧海之波浩漫漫。", "參辰出沒不相待，我欲橫天無羽翰。"]'),
('8fd9bf41-ae6c-4def-aa3e-e6c92abc811f','雜曲歌辭 出門行','元稹','唐','唐诗','tang','','[]','兄弟同出門，同行不同志。',288,'全唐诗/poet.tang.1000.json','["兄弟同出門，同行不同志。", "悽悽分岐路，各各營所爲。", "兄上荆山巔，翻石辨虹氣。", "弟沈滄海底，偷珠待龍睡。", "出門不數年，同歸亦同遂。", "俱用私所珍，升沈自茲異。", "獻珠龍王宮，值龍覓珠次。", "但喜復得珠，不求珠所自。", "酬客雙龍女，授客六龍轡。", "遣充行雨神，雨澤隨客意。", "雩夏鐘鼓繁，禜秋玉帛積。", "彩色畫廊廟，奴僮被珠翠。", "驥騄千萬雙，鴛鴦七十二。", "言者禾稼枯，無人敢輕議。", "其兄因獻璞，再刖不履地。", "門戶親戚疎，匡牀妻妾棄。", "銘心有所待，視足無所愧。", "持璞自枕頭，淚痕雙血漬。", "一朝龍醒寤，本問偷珠事。", "因知行雨偏，妻子五刑備。", "仁兄捧屍哭，勢友掉頭諱。", "喪車黔首葬，弔客青蠅至。", "楚有望氣人，王前忽長跪。", "賀王得貴寶，不遠王所莅。"]'),
('9f49d949-dffa-43ef-a250-75f80a49f914','雜曲歌辭 出自薊北門行','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u6218\u4e89", "\u751f\u6d3b", "\u4e50\u5e9c"]','虜陣橫北荒，胡星曜精芒。',146,'全唐诗/poet.tang.1000.json','["虜陣橫北荒，胡星曜精芒。", "羽書速驚電，烽火晝連光。", "虎竹救邊急，戎車森已行。", "明主不安席，按劒心飛揚。", "推轂出猛將，連旗登戰場。", "兵威衝絕漠，殺氣凌穹蒼。", "列卒赤山下，開營紫塞傍。", "途冬沙風緊，旌旗颯凋傷。", "[畫]角悲海月，征衣卷天霜。", "揮刃斬樓蘭，彎弓射賢王。", "單于一平蕩，種落自奔亡。", "收功報天子，行歌歸咸陽。"]'),
('79bf2cc4-024c-4e4c-bb59-62e5c8f333d7','雜曲歌辭 薊門行五首 一','高適','唐','唐诗','tang','','[]','邊城十一月，雨雪亂霏霏。',36,'全唐诗/poet.tang.1000.json','["邊城十一月，雨雪亂霏霏。", "元戎號令嚴，人馬亦輕肥。", "羌胡無盡日，征戰幾人歸。"]'),
('697c1c85-a50d-494b-8319-013009006006','雜曲歌辭 薊門行五首 二','高適','唐','唐诗','tang','','[]','幽州多騎射，結髮重橫行。',36,'全唐诗/poet.tang.1000.json','["幽州多騎射，結髮重橫行。", "一朝事將軍，出入有聲名。", "紛紛獵秋草，相向角弓鳴。"]'),
('dfc7bc0d-8f02-4987-a99c-b18d95073829','雜曲歌辭 薊門行五首 三','高適','唐','唐诗','tang','','[]','薊門逢古老，獨立思氛氳。',36,'全唐诗/poet.tang.1000.json','["薊門逢古老，獨立思氛氳。", "一身既零丁，頭鬢白紛紛。", "勳庸今已矣，不識霍將軍。"]'),
('571e88d5-df2d-4c4a-bedf-5faea8b44382','雜曲歌辭 薊門行五首 四','高適','唐','唐诗','tang','','[]','茫茫長城外，日沒更煙塵。',36,'全唐诗/poet.tang.1000.json','["茫茫長城外，日沒更煙塵。", "胡騎雖憑陵，漢兵不顧身。", "古樹滿空塞，黃雲愁殺人。"]'),
('182de17f-2ad0-4afb-be82-3891ea7b55b1','雜曲歌辭 薊門行五首 五','高適','唐','唐诗','tang','','[]','漢家能用武，開拓窮異域。',36,'全唐诗/poet.tang.1000.json','["漢家能用武，開拓窮異域。", "戍卒厭糠覈，降胡飽衣食。", "開亭試一望，吾欲涕霑臆。"]'),
('888e21ea-f3bc-4453-83b8-2048410e3b91','雜曲歌辭 薊門行','李希仲','唐','唐诗','tang','','[]','旄頭有精芒，胡騎獵秋草。',96,'全唐诗/poet.tang.1000.json','["旄頭有精芒，胡騎獵秋草。", "羽檄南渡河，邊庭用兵早。", "漢家愛征戰，宿將今已老。", "辛苦羽林兒，從戎榆關道。", "一身救邊速，烽火連薊門。", "前軍鳥飛斷，格鬬塵沙昏。", "寒日鼓聲急，單于夜火奔。", "當須徇忠義，身死報國恩。"]'),
('9aab1a47-7626-4ca7-af13-80ec5bc8e741','雜曲歌辭 君子有所思行','李白','唐','唐诗','tang','','["\u65e0\u5948", "\u4e50\u5e9c", "\u6742\u66f2\u6b4c\u8f9e", "\u6124\u6168"]','紫閣連終南，青冥天倪色。',132,'全唐诗/poet.tang.1000.json','["紫閣連終南，青冥天倪色。", "憑崖望咸陽，宮闕羅北極。", "萬井驚畫出，九衢如弦直。", "渭水清銀河，橫天流不息。", "朝野盛文物，衣冠何翕赩。", "廐馬散連山，軍容威絕域。", "伊皐運元化，衛霍輸筋力。", "歌鐘樂未休，榮去老還逼。", "圓光過滿缺，太陽移中昃。", "不散東海金，何爭西輝匿。", "無作牛山悲，惻愴淚霑臆。"]'),
('664ccc00-6def-413f-94ac-733c4ec9b6c1','雜曲歌辭 君子有所思行 一','僧貫休','唐','唐诗','tang','','[]','我愛正考甫，思賢作商頌。',103,'全唐诗/poet.tang.1000.json','["我愛正考甫，思賢作商頌。", "我愛揚子雲，理亂皆如鳳。", "振衣中夜起，露花香旖旎。", "撲碎驪龍明月珠，敲出鳳凰五色髓。", "陋卷蕭蕭風淅淅，緬想斯人勝珪璧。", "寂寥千載不相逢，無限區區盡虛擲。", "君不見沈約道，佳人不在茲，春光爲誰惜。"]'),
('36ccc570-092d-4e94-932d-43f019f20802','雜曲歌辭 君子有所思行 二','僧貫休','唐','唐诗','tang','','[]','安得龍猛筆，點石爲黃金。',52,'全唐诗/poet.tang.1000.json','["安得龍猛筆，點石爲黃金。", "散問酷吏家，使無貪殘心。", "甘棠密葉成翠幄，潁鳳不來天地塞。", "所以傾城人，如今不可得。"]'),
('82166154-7317-4617-a50c-a9a5a2896da3','雜曲歌辭 傷歌行','張籍','唐','唐诗','tang','','[]','黃門詔下促收捕，京兆君繫御史府。',112,'全唐诗/poet.tang.1000.json','["黃門詔下促收捕，京兆君繫御史府。", "出門無復部曲隨，親戚相逢不容語。", "辭成謫尉南海州，受命不得須臾留。", "身著青衫騎惡馬，東門之東無送者。", "郵夫防吏急喧驅，往往驚墮馬蹏下。", "長安里中荒大宅，朱門已除十二戟。", "高堂舞榭鎖管弦，美人遙望西南天。"]'),
('0ba3b183-531e-48da-aa22-cacc3936e6aa','雜曲歌辭 傷歌行','孟郊','唐','唐诗','tang','','[]','衆毒蔓貞松，一枝難久榮。',72,'全唐诗/poet.tang.1000.json','["衆毒蔓貞松，一枝難久榮。", "豈知黃庭客，仙骨生不成。", "春色舍芳蕙，秋風遶枯莖。", "彈琴不成曲，始覺知音傾。", "館月改舊照，弔賓寫餘情。", "還舟空江上，波浪送銘旌。"]'),
('217032c7-c751-4c94-8b3b-b1b3417dcac7','雜曲歌辭 傷歌行','莊南傑','唐','唐诗','tang','','[]','兔走鳥飛不相見，人事依稀速如電。',96,'全唐诗/poet.tang.1000.json','["兔走鳥飛不相見，人事依稀速如電。", "王母夭桃一度開，玉樓紅粉千回變。", "車馳馬走咸陽道，石家舊宅空荒草。", "秋雨無情不惜花，芙蓉一一驚香倒。", "勸君莫謾栽荆棘，秦皇虛費驅山力。", "英風一去更無言，白骨沈埋暮山碧。"]'),
('2c9fcb36-9e32-4ad9-8e44-eafc1df1b2a3','雜曲歌辭 悲歌','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u5b64\u72ec", "\u7406\u60f3", "\u6000\u624d\u4e0d\u9047"]','悲來乎，悲來乎！主人有酒且莫斟，聽我一曲悲來吟。',248,'全唐诗/poet.tang.1000.json','["悲來乎，悲來乎！主人有酒且莫斟，聽我一曲悲來吟。", "悲來不吟還不笑，天下無人知我心。", "君有數斗酒，我有三尺琴。", "琴鳴酒樂兩相得，一杯不啻千鈞金。", "悲來乎，悲來乎！天雖長，地雖久，金玉滿堂應不守。", "富貴百年能幾何？死生一度人皆有。", "孤猨坐啼墳上月，且須一盡杯中酒。", "悲來乎，悲來乎！鳳鳥不至河無圖，微子去之箕子奴。", "漢帝不憶李將軍，楚王放却屈大夫。", "悲來乎，悲來乎！秦家李斯早追悔，虛名撥向身之外。", "范子何曾愛五湖，功成名遂身自退。", "劒是一夫用，書能知姓名。", "惠施不肯干萬乘，卜式未必窮一經。", "還須黑頭取方伯，莫謾白首爲儒生。"]'),
('8c257f77-fbd5-4f89-a01d-f069cc2189b2','雜曲歌辭 悲哉行','孟雲卿','唐','唐诗','tang','','[]','孤兒去慈親，遠客喪主人。',84,'全唐诗/poet.tang.1000.json','["孤兒去慈親，遠客喪主人。", "莫吟苦辛曲，誰忍聞可聞。", "可聞不可說，去去無期別。", "行人念前程，不待參辰沒。", "朝亦常苦飢，暮亦常苦飢。", "飄飄萬餘里，貧賤多是非。", "少年莫遠遊，遠遊多不歸。"]'),
('21781aca-5d96-4c9e-9bc1-ed8140e1107b','雜曲歌辭 悲哉行','白居易','唐','唐诗','tang','','[]','悲哉爲儒者，力學不能疲。',192,'全唐诗/poet.tang.1000.json','["悲哉爲儒者，力學不能疲。", "讀書眼欲暗，秉筆手生胝。", "十上方一第，成名常苦遲。", "縱有宦達者，兩鬢已成絲。", "可憐少壯日，適在窮賤時。", "丈夫老且病，焉用富貴爲。", "沈沈朱門宅，中有乳臭兒。", "狀貌如婦人，光明膏粱肌。", "手不把書卷，身不擐戎衣。", "二十襲封爵，門承勳戚資。", "春來日日出，服御何輕肥。", "朝從博徒飲，暮有倡樓期。", "評封還酒債，堆金選蛾眉。", "聲色狗馬外，其餘一無知。", "山苗與澗松，地勢隨高卑。", "古來無奈何，非君獨傷悲。"]'),
('cd8c3590-e097-4289-bcda-ad852ed095ab','雜曲歌辭 悲哉行','鮑溶','唐','唐诗','tang','','[]','促促晨復昏，死生同一源。',108,'全唐诗/poet.tang.1000.json','["促促晨復昏，死生同一源。", "貴年不懼老，賤老傷久存。", "朗朗哭前歌，絳旌引幽魂。", "來爲千金子，去臥百草根。", "黃土塞生路，悲風送回轅。", "金鞍舊良馬，四顧不出門。", "生結千歲念，榮及百代孫。", "黃金買性命，白刃讐一言。", "寧知北山上，松柏侵田園。"]'),
('ad84f24a-7552-4e1d-ac0e-8e74b824f807','雜曲歌辭 妾薄命','崔國輔','唐','唐诗','tang','','[]','雖入秦帝宮，不上秦帝牀。',24,'全唐诗/poet.tang.1000.json','["雖入秦帝宮，不上秦帝牀。", "夜夜玉窗裏，與他卷羅裳。"]'),
('7ba1642b-a69c-4d3a-87ac-fd019f934922','雜曲歌辭 妾薄命','武平一','唐','唐诗','tang','','[]','有女妖且麗，裴回湘水湄。',144,'全唐诗/poet.tang.1000.json','["有女妖且麗，裴回湘水湄。", "水湄蘭杜芳，采之將寄誰。", "瓠犀發皓齒，雙蛾嚬翠眉。", "紅臉如開蓮，素膚若凝脂。", "綽約多逸態，輕盈不自持。", "常矜絕代色，復恃傾城姿。", "子夫前入侍，飛燕復當時。", "正悅掌中舞，寧哀團扇詩。", "洛川昔云遇，高唐今尚違。", "幽閤禽雀噪，閑階草露滋。", "流景一何速，年華不可追。", "解佩安何贈，怨咽空自悲。"]'),
('37b7744a-916c-481e-9420-6703ead41481','雜曲歌辭 妾薄命','李百藥','唐','唐诗','tang','','[]','團扇秋風起，長門夜月明。',48,'全唐诗/poet.tang.1000.json','["團扇秋風起，長門夜月明。", "羞聞拊背人，恨說舞腰輕。", "太常應已醉，劉君恆帶酲。", "橫陳每虛設，吉夢竟何成。"]'),
('83fb9c9b-7cdf-48cd-b03a-0c1102bf7728','雜曲歌辭 妾薄命','杜審言','唐','唐诗','tang','','[]','草綠長門閉，苔青永巷幽。',48,'全唐诗/poet.tang.1000.json','["草綠長門閉，苔青永巷幽。", "寵移新愛奪，泣下故情留。", "啼鳥驚殘夢，飛花攪獨愁。", "自憐春色罷，團扇復迎秋。"]'),
('362e9ec3-e452-4f59-b5f4-10757da34b28','雜曲歌辭 妾薄命','劉元淑','唐','唐诗','tang','','[]','自從離別守空閨，遙聞征戰起雲梯。',192,'全唐诗/poet.tang.1000.json','["自從離別守空閨，遙聞征戰起雲梯。", "夜夜愁君遼海外，年年棄妾渭橋西。", "陽春白日照空暖，紫燕銜花向庭滿。", "綵鸞琴裏怨聲多，飛鵲鏡前妝梳斷。", "誰家夫壻不從征，應是漁陽別有情。", "莫道紅顏燕地少，家家還似洛陽城。", "且逐新人殊未歸，還令秋至夜霜飛。", "北斗星前橫度鴈，南樓月下擣寒衣。", "夜深聞鴈腸欲絕，獨坐縫衣燈又滅。", "暗啼羅帳空自憐，夢度陽關向誰說。", "每憐容貌宛如神，如何薄命不勝人。", "願君朝夕燕山至，好作明年楊柳春。"]'),
('11470667-67f3-4142-b415-e82d74b30252','雜曲歌辭 妾薄命','李白','唐','唐诗','tang','','["\u54f2\u7406", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','漢帝重阿嬌，貯之黃金屋。',96,'全唐诗/poet.tang.1000.json','["漢帝重阿嬌，貯之黃金屋。", "咳唾落九天，隨風生珠玉。", "寵極愛還歇，妒深情却疎。", "長門一步地，不肯暫回車。", "雨落不上天，水覆難再收。", "君情與妾意，各自東西流。", "昔日芙蓉花，今成斷根草。", "以色事他人，能得幾時好。"]'),
('973d6b4b-6a53-4d6c-a900-b187c8eb569a','雜曲歌辭 妾薄命','孟郊','唐','唐诗','tang','','[]','不惜十指弦，爲君千萬彈。',72,'全唐诗/poet.tang.1000.json','["不惜十指弦，爲君千萬彈。", "常恐新聲至，坐使故聲殘。", "棄置今日悲，即是昨日歡。", "將新變故易，持故爲新難。", "青山有蘼蕪，淚葉長不乾。", "空令後代人，采掇幽思攢。"]'),
('f9d02cdb-7dc0-436a-a758-e29b65bb461b','雜曲歌辭 妾薄命','張籍','唐','唐诗','tang','','[]','薄命婦，良家子，無事從軍去萬里。',96,'全唐诗/poet.tang.1000.json','["薄命婦，良家子，無事從軍去萬里。", "漢家天子平四夷，護羌都尉裹屍歸。", "念君此行爲死別，對君裁縫泉下衣。", "與君一日爲夫婦，千年萬歲亦相守。", "君愛龍城征戰功，妾願青樓歡樂同。", "人生各各有所欲，詎得將心入君腹。"]'),
('f8eb9a73-6985-4572-806d-733ed9452ff8','雜曲歌辭 妾薄命三首 一','李端','唐','唐诗','tang','','["\u95fa\u6028"]','憶妾初嫁君，花鬟如綠雲。',100,'全唐诗/poet.tang.1000.json','["憶妾初嫁君，花鬟如綠雲。", "回燈入綺帳，對面脫羅裙。", "折步教人學，偷香與客熏。", "容顏南國重，名字北方聞。", "一從失恩意，轉覺身憔悴。", "對鏡不梳頭，倚窗空落淚。", "新人莫恃新，秋至會無春。", "從來閉在長門者，必是宮中第一人。"]'),
('fde07a47-7e59-407b-b7c9-f5d65ff73ecc','雜曲歌辭 妾薄命三首 二','李端','唐','唐诗','tang','','[]','玉壘城邊爭走馬，銅蹏市裏共乘舟。',64,'全唐诗/poet.tang.1000.json','["玉壘城邊爭走馬，銅蹏市裏共乘舟。", "鳴環動佩思無盡，掩袖低巾淚不流。", "疇昔將歌邀客醉，如今欲舞對君羞。", "忍懷賤妾平生曲，獨上襄陽舊酒樓。"]'),
('b80850c4-91b8-47bc-b9a7-7c51345c051e','雜曲歌辭 妾薄命三首 三','李端','唐','唐诗','tang','','[]','自從君棄妾，憔悴不羞人。',24,'全唐诗/poet.tang.1000.json','["自從君棄妾，憔悴不羞人。", "惟餘壞粉淚，未免映衫勻。"]'),
('b8789639-b0e2-407b-bc97-844def8f9dc4','雜曲歌辭 妾薄命','盧綸','唐','唐诗','tang','','[]','妾年初二八，兩度嫁狂夫。',24,'全唐诗/poet.tang.1000.json','["妾年初二八，兩度嫁狂夫。", "薄命今猶在，堅貞掃地無。"]'),
('26d7090e-d22c-439c-9b47-5c3e2f2608e3','雜曲歌辭 妾薄命','盧弼','唐','唐诗','tang','','[]','君恩已斷盡成空，追想嬌歡恨莫窮。',64,'全唐诗/poet.tang.1000.json','["君恩已斷盡成空，追想嬌歡恨莫窮。", "長爲蕣華光曉日，誰知團扇送秋風。", "黃金買賦心徒切，清路飛塵信莫通。", "閑凭玉欄思舊事，幾回春暮泣殘紅。"]'),
('da83e659-b95a-4cd4-b9ba-40f581921a90','雜曲歌辭 妾薄命','胡曾','唐','唐诗','tang','','[]','阿嬌初失漢皇恩，舊賜羅衣亦罷熏。',64,'全唐诗/poet.tang.1000.json','["阿嬌初失漢皇恩，舊賜羅衣亦罷熏。", "欹枕夜悲金屋雨，卷簾朝泣玉樓雲。", "宮前葉落鴛鴦瓦，架上塵生翡翠裙。", "龍騎不巡時漸久，長門長掩綠苔文。"]'),
('d7c33d59-df0b-464e-b700-aec62a9a2795','雜曲歌辭 妾薄命','王貞白','唐','唐诗','tang','','[]','薄命頭欲白，頻年嫁不成。',48,'全唐诗/poet.tang.1000.json','["薄命頭欲白，頻年嫁不成。", "秦娥未十五，昨夜事公卿。", "豈有機杼力，空傳歌舞名。", "妾專修婦德，媒氏却相輕。"]'),
('3683533a-058c-4b40-affa-2c1a9ca032d2','雜曲歌辭 羽林行','王建','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5199\u4eba", "\u8bbd\u523a"]','長安惡少出名字，樓下劫商樓上醉。',80,'全唐诗/poet.tang.1000.json','["長安惡少出名字，樓下劫商樓上醉。", "天明下直明光宮，散入五陵松柏中。", "百回殺人身合死，赦書尚有收城功。", "九衢一日消息定，鄉吏籍中重改姓。", "出來依舊屬羽林，立在殿前射飛禽。"]'),
('c5c4e4d0-682a-4c8f-9756-c181dc9a52dc','雜曲歌辭 羽林行','孟郊','唐','唐诗','tang','','["\u9ec4\u6cb3"]','朔雪寒斷指，朔風勁裂冰。',48,'全唐诗/poet.tang.1000.json','["朔雪寒斷指，朔風勁裂冰。", "胡中射鵰者，此日猶不能。", "翩翩羽林兒，錦臂飛蒼鷹。", "揮鞭決白馬，走出黃河凌。"]'),
('230aaaca-a890-41d0-a4b4-4dfc73f7a14a','雜曲歌辭 羽林行','鮑溶','唐','唐诗','tang','','[]','朝出羽林宮，入參雲臺議。',108,'全唐诗/poet.tang.1000.json','["朝出羽林宮，入參雲臺議。", "獨請萬里行，不奏和親事。", "君王重年少，深納開邊利。", "寶馬雕玉鞍，一朝從萬騎。", "煌煌都門外，祖帳光七貴。", "歌鐘樂行軍，雲物慘別地。", "簫笳整部曲，幢蓋動郊次。", "臨風親戚懷，滿袖兒女淚。", "行行復何贈，長劒報恩字。"]'),
('402c5cc0-8255-4a01-8e5e-2641417bf8a2','雜曲歌辭 白馬篇','李白','唐','唐诗','tang','','["\u6cf0\u5c71", "\u4fa0\u5ba2", "\u7231\u56fd", "\u5199\u9a6c", "\u9a6c", "\u58ee\u5fd7"]','龍馬花雪毛，金鞍五陵豪。',120,'全唐诗/poet.tang.1000.json','["龍馬花雪毛，金鞍五陵豪。", "秋霜切玉劒，落日明珠袍。", "鬬雞事萬乘，軒蓋一何高。", "弓摧宜山虎，手接泰山猱。", "酒後競風彩，三杯弄寶刀。", "殺人如翦草，劇孟同遊遨。", "發憤去函谷，從軍向臨洮。", "叱咤萬戰場，匈奴盡波濤。", "歸來使酒氣，未肯拜蕭曹。", "羞入原憲室，荒徑隱蓬蒿。"]'),
('4365fdc6-9e89-489c-abe1-4eda95a85062','雜曲歌辭 升天行','僧齊己','唐','唐诗','tang','','[]','身不沈，骨不重，驅青鸞，駕白鳳。',80,'全唐诗/poet.tang.1000.json','["身不沈，骨不重，驅青鸞，駕白鳳。", "幢蓋飄飄入冷空，天風瑟瑟星河動。", "瑤闕參差阿母家，樓臺戲閉凝彤霞。", "五三仙子乘龍車，堂前碾爛蟠桃花。", "回頭却顧蓬山頂，一點濃嵐在深井。"]'),
('1d19a6b1-ec7b-4bfc-b393-0c4d431d82e2','雜曲歌辭 神仙曲','李賀','唐','唐诗','tang','','[]','碧峰海面藏靈書，上帝揀作神仙居。',80,'全唐诗/poet.tang.1000.json','["碧峰海面藏靈書，上帝揀作神仙居。", "晴時笑語聞空虛，鬬乘巨浪騎鯨魚。", "春羅翦字邀王母，共宴紅樓最深處。", "鶴羽衝風過海遲，不如卻使青龍去。", "猶疑王母不相許，垂露娃鬟更傳語。"]'),
('cd66d8b3-abe6-4316-ab34-b88a4bb8bb83','雜曲歌辭 北風行','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u601d\u5ff5", "\u5199\u96ea", "\u51ac\u5929", "\u5199\u98ce", "\u6292\u60c5"]','燭龍棲寒門，光曜猶旦開。',151,'全唐诗/poet.tang.1000.json','["燭龍棲寒門，光曜猶旦開。", "日月照之何不及此，惟有北風怒號天上來。", "燕山雪花大如席，片片吹落軒轅臺。", "幽州思婦十二月，停歌罷笑雙蛾摧。", "倚門望行人，念君長城苦寒良可哀。", "別時提劒救邊去，遺此虎文金髀釵。", "中有一雙白羽箭，蜘蛛結網生塵埃。", "箭空在，人今戰死不復迴。", "不忍見此物，焚之已成灰。", "黃河捧土尚可塞，北風雨雪恨難裁。"]'),
('f3a972d4-cd1c-4b14-b1a5-77ddcf3f02f8','雜曲歌辭 苦熱行','王維','唐','唐诗','tang','','[]','赤日滿天地，火雲成山嶽。',96,'全唐诗/poet.tang.1000.json','["赤日滿天地，火雲成山嶽。", "草木盡焦卷，川澤皆竭涸。", "輕紈覺衣重，密樹苦陰薄。", "莞簟不可近，絺綌再三濯。", "思出宇宙外，曠然在寥廓。", "長風萬里來，江海蕩煩濁。", "却顧身爲患，始知心未覺。", "忽入甘露門，宛然清涼樂。"]'),
('736e1080-b7ce-4a2f-9e8c-8ba28fd28de9','雜曲歌辭 苦熱行','王轂','唐','唐诗','tang','','[]','祝融南來鞭火龍，火旗焰焰燒天紅。',64,'全唐诗/poet.tang.1000.json','["祝融南來鞭火龍，火旗焰焰燒天紅。", "日輪當午凝不去，萬國如在洪爐中。", "五嶽翠乾雲彩滅，陽侯海底愁波竭。", "何當一夕金風發？爲我掃却天下熱。"]'),
('7e3ea889-0643-4291-90bb-41e29b0151c5','雜曲歌辭 苦熱行','僧皎然','唐','唐诗','tang','','[]','六月金數伏，茲辰日在庚。',120,'全唐诗/poet.tang.1000.json','["六月金數伏，茲辰日在庚。", "炎曦曝肌膚，毒霧昏檐楹。", "安得奮翅翮，超遙出雲征。", "不知天地心，如何匠生成。", "火德燒百卉，瑤草不及榮。", "省客當此時，忽貽懷中瓊。", "捧翫煩袂滌，嘯歌美風生。", "遲君佐元氣，調使四序平。", "中令霜不祅，火餘氣常貞。", "江南詩騷客，休吟苦熱行。"]'),
('13b0c8fc-cd4b-43c1-aed7-6d7224438823','雜曲歌辭 苦熱行','僧齊己','唐','唐诗','tang','','[]','離宮劃開赤帝怒，喝起六龍奔日馭。',64,'全唐诗/poet.tang.1000.json','["離宮劃開赤帝怒，喝起六龍奔日馭。", "下土熬熬若煎煮，蒼生惶惶無處處。", "火雲崢嶸焚泬寥，東皐老農腸欲焦。", "何當一雨蘇我苗？爲君擊壞歌帝堯。"]'),
('4b5df95c-2080-4a03-9c87-7a53cad39113','雜曲歌辭 太行苦熱行','劉長卿','唐','唐诗','tang','','[]','迢迢太行路，自古稱險惡。',192,'全唐诗/poet.tang.1000.json','["迢迢太行路，自古稱險惡。", "千騎儼欲前，羣峯望如削。", "火雲從中起，仰視飛鳥落。", "汗馬臥高原，危旌倚長薄。", "清風何不至？赤日方煎爍。", "石露山木焦，鱗窮水泉涸。", "九重今旰食，萬里傳明略。", "諸將候軒車，元兇愁鼎鑊。", "何勞短兵接，自有長纓縛。", "通越事豈難，渡瀘功未博。", "朝辭羊腸坂，夕望貝丘郭。", "漳水斜遶營，常山遙入幕。", "永懷姑蘇下，因寄建安作。", "白雪和誠難，滄波意空託。", "陳琳書記好，王粲從軍樂。", "早晚歸漢庭，隨君上麟閣。"]'),
('5bf64938-ec5a-4d0e-bcbc-2e6a0f024489','雜曲歌辭 太行苦熱行','獨孤及','唐','唐诗','tang','','[]','駟馬上太行，修途亙遼碣。',192,'全唐诗/poet.tang.1000.json','["駟馬上太行，修途亙遼碣。", "王程無留駕，日昃未遑歇。", "請問此何時，恢台朱明月。", "長蛇稽天討，上將方北伐。", "明主命使臣，皇華得時傑。", "已忘羊腸險，豈憚溫風入。", "搖策汗滂沲，登崖思紆結。", "炎雲如煙火，溪谷將恐竭。", "晝景赩可畏，涼飆何由發？", "山長飛鳥墮，目極行車絕。", "趙魏方俶擾，安危俟明哲。", "歸路豈不懷，飲冰有苦節。", "會同傳檄至，疑議立談決。", "況有阮元瑜，翩翩秉書札。", "起予歌赤坂，永好踰白雪。", "維念剖竹人，無因執羈紲。"]'),
('cb55e33f-ee4d-4b88-a23f-280fd0cfd271','雜曲歌辭 春日行','李白','唐','唐诗','tang','','["\u6625\u5929", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','深宮高樓入紫清，金作蛟龍盤繡楹。',148,'全唐诗/poet.tang.1000.json','["深宮高樓入紫清，金作蛟龍盤繡楹。", "佳人當窗弄白日，弦將手語彈鳴箏。", "春風吹落君王耳，此曲乃是升天行。", "因出天池汎蓬瀛，樓船蹙沓波浪驚。", "三千雙蛾獻歌笑，撾鐘考鼓宮殿傾。", "萬姓聚舞歌太平，我無爲，人自寧。", "三十六帝欲相迎，仙人飄翩下雲軿。", "帝不去，留鎬京。", "安能爲軒轅，獨往入窅冥。", "小臣拜獻南山壽，陛下萬古垂鴻名。"]'),
('5180277d-a3b2-4644-9f1f-2d5a4af7c604','雜曲歌辭 春日行','張籍','唐','唐诗','tang','','[]','春日融融池上暖，竹牙出土蘭心短。',96,'全唐诗/poet.tang.1000.json','["春日融融池上暖，竹牙出土蘭心短。", "草堂晨起酒半醒，家僮報我園花滿。", "頭上皮冠未曾整，直入花間不尋徑。", "樹樹殷勤盡遶行，舉枝未徧春日暝。", "不用積金著青天，不用服藥求神仙。", "但願園裏花長好，一生飲酒花前老。"]'),
('c35c203f-69aa-42f9-ba07-77e7ea2975f5','雜曲歌辭 朗月行','李白','唐','唐诗','tang','','["\u6292\u60c5", "\u6708\u4eae", "\u4e50\u5e9c", "\u6742\u66f2\u6b4c\u8f9e", "\u4e2d\u79cb"]','小時不識月，呼作白玉盤。',96,'全唐诗/poet.tang.1000.json','["小時不識月，呼作白玉盤。", "又疑瑤臺鏡，飛在青雲端。", "仙人垂兩足，桂樹作團團。", "白兔擣藥成，問言與誰餐。", "蟾蜍蝕圜影，天明夜已殘。", "羿昔落九烏，天人清且安。", "陰精此淪惑，去去不足觀。", "憂來其如何？惻愴摧心肝。"]'),
('152344f5-238d-42e9-9b7e-3476310e1b35','雜曲歌辭 前有一尊酒行二首 一','李白','唐','唐诗','tang','','[]','春風東來忽相過，金尊綠酒生微波。',72,'全唐诗/poet.tang.1000.json','["春風東來忽相過，金尊綠酒生微波。", "落花紛紛稍覺多，美人欲醉朱顏酡。", "青軒桃李能幾何？流光欺人忽蹉跎。", "君起舞，日西夕，當年意氣不肯傾，白髮如絲歎何益。"]'),
('0882a5d4-0b22-4bfa-80c3-2a39bd5a841d','雜曲歌辭 前有一尊酒行二首 二','李白','唐','唐诗','tang','','[]','琴奏龍門之綠桐，玉壺美酒清若空。',60,'全唐诗/poet.tang.1000.json','["琴奏龍門之綠桐，玉壺美酒清若空。", "催弦拂柱與君飲，看朱成碧顏始紅。", "胡姬貌如花，當鑪笑春風。", "笑春風，舞羅衣，君今不醉欲安歸。"]'),
('f40cb6c3-66e9-4a83-a497-124d085ed298','雜曲歌辭 緩歌行','李頎','唐','唐诗','tang','','[]','小來託身攀貴遊，傾財破產無所憂。',160,'全唐诗/poet.tang.1000.json','["小來託身攀貴遊，傾財破產無所憂。", "暮擬經過石渠署，朝將出入銅龍樓。", "結交杜陵輕薄子，謂言可生復可死。", "一沈一浮會有時，棄我翻然如脫屣。", "男兒立身須自彊，十五閉戶潁水陽。", "業就功成見明主，擊鐘鼎食坐華堂。", "二八蛾眉梳墮馬，美酒清歌曲房下。", "文昌宮中賜錦衣，長安陌上退朝歸。", "五侯賓從莫敢視，三省官僚揖者稀。", "早知今日讀書是，悔作從來任俠非。"]'),
('8eeb3273-d271-4674-900b-2057c3f59957','雜曲歌辭 結客少年場行','虞世南','唐','唐诗','tang','','[]','韓魏多奇節，倜儻遺名利。',132,'全唐诗/poet.tang.1000.json','["韓魏多奇節，倜儻遺名利。", "共矜然諾心，各負縱橫志。", "結友一言重，相思千里至。", "綠沈明月弦，金絡浮雲轡。", "吹簫入吳市，擊筑游燕肆。", "尋源博望侯，結客遠相求。", "少年重一顧，長驅背隴頭。", "燄燄霜戈動，耿耿劒虹浮。", "天山冬夏雪，交河南北流。", "雲起龍沙暗，木落鴈行秋。", "輕生徇知己，非是爲身謀。"]'),
('79462191-3bcb-4599-b51b-40bcf4d3065d','雜曲歌辭 結客少年場行','虞羽客','唐','唐诗','tang','','[]','幽幷俠少年，金絡控連錢。',120,'全唐诗/poet.tang.1000.json','["幽幷俠少年，金絡控連錢。", "竊符方救趙，擊筑正懷燕。", "輕生辭鳳闕，揮袂上祁連。", "陸離橫寶劒，出沒驚徂旃。", "蒙輪恆顧敵，超乘忽爭先。", "摧枯逾百戰，拓地遠三千。", "骨都魂已散，樓蘭首復傳。", "龍城含曉霧，瀚海隔遙天。", "歌吹金微返，振旅玉門旋。", "烽火今已息，非復照甘泉。"]'),
('f3e3dab9-6df9-4bc1-b428-ace90e3a922c','雜曲歌辭 結客少年場行','盧照鄰','唐','唐诗','tang','','[]','長安重遊俠，洛陽富才雄。',132,'全唐诗/poet.tang.1000.json','["長安重遊俠，洛陽富才雄。", "玉劒浮雲騎，金鞍明月弓。", "鬬雞過渭北，走馬向關東。", "孫賓遙見待，郭解暗相通。", "不受千金爵，誰論萬里功。", "將軍下天上，虜騎入雲中。", "烽火夜似月，兵氣曉成虹。", "橫行徇知己，負羽遠從戎。", "龍旌昏朔霧，鳥陣卷寒風。", "追奔瀚海咽，戰罷陰山空。", "歸來謝天子，何如馬上翁。"]'),
('818ab313-009a-4bca-829a-30768146e907','雜曲歌辭 結客少年場行','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u8c6a\u8fc8", "\u4e50\u5e9c"]','紫燕黃金瞳，啾啾搖綠鬉。',120,'全唐诗/poet.tang.1000.json','["紫燕黃金瞳，啾啾搖綠鬉。", "平明相馳逐，結客洛門東。", "少年學劒術，凌轢白猨公。", "珠袍曳錦帶，七首插吳鴻。", "由來萬夫勇，挾此生雄風。", "託交從劇孟，買醉入新豐。", "笑盡一杯酒，殺人都市中。", "羞道易水寒，從令日貫虹。", "燕丹事不立，虛沒秦帝宮。", "舞陽死灰人，安可與成功。"]'),
('2d7dac40-92dc-450e-a834-3050521eb709','雜曲歌辭 結客少年場行','沈彬','唐','唐诗','tang','','[]','重義輕生一劒知，白虹貫日報讐歸。',32,'全唐诗/poet.tang.1000.json','["重義輕生一劒知，白虹貫日報讐歸。", "片心惆悵清平世，酒市無人問布衣。"]'),
('51e663b3-6f76-41f4-8e75-c03772e5f8e1','雜曲歌辭 少年子','李百藥','唐','唐诗','tang','','[]','少年飛翠蓋，上路動金鑣。',72,'全唐诗/poet.tang.1000.json','["少年飛翠蓋，上路動金鑣。", "始酌文君酒，新吹弄玉簫。", "少年不歡樂，何以盡芳朝。", "千金笑裏面，一搦抱中腰。", "挂冠豈憚宿，迎拜不勝嬌。", "寄語少年子，無辭歸路遙。"]'),
('e475a182-9775-4dcb-9087-4abb71fc6476','雜曲歌辭 少年子','李白','唐','唐诗','tang','','[]','青雲少年子，挾彈章臺左。',48,'全唐诗/poet.tang.1000.json','["青雲少年子，挾彈章臺左。", "鞍馬四邊開，突如流星過。", "金丸落飛鳥，夜入瓊樓臥。", "夷齊是何人？獨守西山餓。"]'),
('232b2330-be81-492f-ab96-52be310cd64d','雜曲歌辭 少年樂','李賀','唐','唐诗','tang','','[]','芳草落花如錦地，二十長遊醉鄉裏。',64,'全唐诗/poet.tang.1000.json','["芳草落花如錦地，二十長遊醉鄉裏。", "紅纓不重白馬驕，垂柳金絲香拂水。", "吳娥未笑花不開，綠鬢聳墮蘭雲起。", "陸郎倚醉牽羅袂，奪得寶釵金翡翠。"]'),
('4d9c03ce-ae52-44ae-8100-f43432da8432','雜曲歌辭 少年樂','張祜','唐','唐诗','tang','','[]','二十便封侯，名居第一流。',72,'全唐诗/poet.tang.1000.json','["二十便封侯，名居第一流。", "綠鬟深小院，清管下高樓。", "醉把金船擲，閑敲玉鐙遊。", "帶盤紅鼹鼠，袍砑紫犀牛。", "錦袋歸調箭，羅鞋起撥毬。", "眼前長貴盛，那信世間愁。"]'),
('6cc5782f-97e4-4f04-970a-d56618e8edf9','雜曲歌辭 少年行三首 一','李白','唐','唐诗','tang','','[]','擊筑飲美酒，劒歌易水湄。',48,'全唐诗/poet.tang.1000.json','["擊筑飲美酒，劒歌易水湄。", "經過燕太子，結託幷州兒。", "少年負壯氣，奮烈自有時。", "因聲魯句踐，爭情勿相欺。"]'),
('21bf8b8a-d5c1-4146-b572-31d2372a6474','雜曲歌辭 少年行三首 二','李白','唐','唐诗','tang','','[]','五陵年少金市東，銀鞍白馬度春風。',32,'全唐诗/poet.tang.1000.json','["五陵年少金市東，銀鞍白馬度春風。", "落花踏盡遊何處？笑入胡姬酒肆中。"]'),
('d1c29cbc-5e59-4332-8a20-033c7524e3d0','雜曲歌辭 少年行三首 三','李白','唐','唐诗','tang','','[]','君不見淮南少年遊俠客，白日毬獵夜擁擲。',243,'全唐诗/poet.tang.1000.json','["君不見淮南少年遊俠客，白日毬獵夜擁擲。", "呼盧百萬終不惜，報讐千里如咫尺。", "少年遊俠好經過，渾身裝束皆綺羅。", "蘭蕙相隨喧妓女，風光去處滿笙歌。", "驕矜自言不可有，俠士堂中養來久。", "好鞍好馬乞與人，十千五千旋沽酒。", "赤心用盡爲知己，黃金不惜栽桃李。", "桃李栽來幾度春，一回花落一回新。", "府縣盡爲門下客，王侯皆是平交人。", "男兒百年且樂命，何須徇書受貧病。", "男兒百年且榮身，何須徇節甘風塵。", "衣冠半是征戰士，窮儒浪作林泉民。", "遮莫枝根長百丈，不如當代多還往。", "遮莫姻親連帝城，不如當身自簪纓。", "看取富貴眼前者，何用悠悠身後名。"]'),
('e16cb386-9a1c-463f-a43f-2110e2a36e33','雜曲歌辭 少年行四首 一','王維','唐','唐诗','tang','','[]','新豐美酒斗十千，咸陽遊俠多少年。',32,'全唐诗/poet.tang.1000.json','["新豐美酒斗十千，咸陽遊俠多少年。", "相逢意氣爲君飲，繫馬高樓垂柳邊。"]'),
('428cbfda-43a6-4cb3-9418-d65f2ea45d54','雜曲歌辭 少年行四首 二','王維','唐','唐诗','tang','','[]','漢家君臣歡宴終，高議雲臺論戰功。',32,'全唐诗/poet.tang.1000.json','["漢家君臣歡宴終，高議雲臺論戰功。", "天子臨軒賜侯印，將軍佩出明光宮。"]'),
('6acd85a2-fea8-4875-83c5-6ef888f875bc','雜曲歌辭 少年行四首 三','王維','唐','唐诗','tang','','[]','出身仕漢羽林郎，初隨驃騎戰漁陽。',32,'全唐诗/poet.tang.1000.json','["出身仕漢羽林郎，初隨驃騎戰漁陽。", "孰知不向邊庭苦，縱死猶聞俠骨香。"]'),
('66f48ee1-6f1b-4a05-89ae-c904f70ac9b7','雜曲歌辭 少年行四首 四','王維','唐','唐诗','tang','','[]','一身能臂兩雕弧，虜騎千羣只似無。',32,'全唐诗/poet.tang.1000.json','["一身能臂兩雕弧，虜騎千羣只似無。", "偏坐金鞍調白羽，紛紛射殺五單于。"]'),
('77659827-473d-4602-9888-f305d9c70273','雜曲歌辭 少年行二首 一','王昌齡','唐','唐诗','tang','','[]','西陵俠年少，送客過長亭。',48,'全唐诗/poet.tang.1000.json','["西陵俠年少，送客過長亭。", "青槐夾兩路，白馬如流星。", "聞道羽書急，單于寇井陘。", "氣高輕赴難，誰顧燕山銘。"]'),
('21943b5d-11e5-44f2-9714-ad996dade3ae','雜曲歌辭 少年行二首 二','王昌齡','唐','唐诗','tang','','[]','走馬還相尋，西樓下夕陰。',48,'全唐诗/poet.tang.1000.json','["走馬還相尋，西樓下夕陰。", "結交期一劒，留意贈千金。", "高閣歌聲遠，重關柳色深。", "夜閑須盡醉，莫負百年心。"]'),
('70adc79e-eace-4cd8-a20e-1e8b609ab8eb','雜曲歌辭 少年行','張籍','唐','唐诗','tang','','[]','少年從出獵長楊，禁中新拜羽林郎。',112,'全唐诗/poet.tang.1000.json','["少年從出獵長楊，禁中新拜羽林郎。", "獨到輦前射雙虎，君王手賜黃金鐺。", "日日鬬雞都市裏，贏得寶刀重刻字。", "百里報讐夜出城，平明還在倡樓醉。", "遙聞虜到平陵下，不待詔書行上馬。", "斬得名王獻桂宮，封侯起第一日中。", "不爲六郡良家子，百戰始取邊城功。"]'),
('b0049020-3b5e-4a46-9b66-71f6de65501d','雜曲歌辭 少年行三首 一','李嶷','唐','唐诗','tang','','[]','十八羽林郎，戎衣事漢王。',36,'全唐诗/poet.tang.1000.json','["十八羽林郎，戎衣事漢王。", "臂鷹金殿側，挾彈玉輿旁。", "馳道春風起，陪遊出建章。"]'),
('0cf6265f-c453-4bc5-9f3f-55a6ab43a83a','雜曲歌辭 少年行三首 二','李嶷','唐','唐诗','tang','','[]','侍獵長楊下，承恩更射飛。',36,'全唐诗/poet.tang.1000.json','["侍獵長楊下，承恩更射飛。", "塵生馬影滅，箭落鴈行稀。", "薄暮歸隨仗，聯翩入瑣闈。"]'),
('8baf651c-c608-4795-9260-c572c4af580b','雜曲歌辭 少年行三首 三','李嶷','唐','唐诗','tang','','[]','玉劒膝邊橫，金杯馬上傾。',36,'全唐诗/poet.tang.1000.json','["玉劒膝邊橫，金杯馬上傾。", "朝遊茂陵道，暮宿鳳凰城。", "豪吏多猜忌，無勞問姓名。"]'),
('60de5a95-c758-49be-ad0a-380712d15cb3','雜曲歌辭 少年行','劉長卿','唐','唐诗','tang','','[]','射飛誇侍獵，行樂愛聯鑣。',48,'全唐诗/poet.tang.1000.json','["射飛誇侍獵，行樂愛聯鑣。", "薦枕青娥豔，鳴鞭白馬驕。", "曲房珠翠合，深巷管弦調。", "日晚春風裏，衣香滿路飄。"]'),
('5a194d8f-5981-4036-9da1-dc6e3cedf4f9','雜曲歌辭 少年行四首 一','令狐楚','唐','唐诗','tang','','[]','少小邊州慣放狂，驏騎蕃馬射黃羊。',32,'全唐诗/poet.tang.1000.json','["少小邊州慣放狂，驏騎蕃馬射黃羊。", "如今年事無筋力，猶倚營門數鴈行。"]'),
('a9c061a4-c957-4d74-a0f3-86001d8b2a7f','雜曲歌辭 少年行四首 二','令狐楚','唐','唐诗','tang','','[]','家本清河住五城，須憑弓箭得功名。',32,'全唐诗/poet.tang.1000.json','["家本清河住五城，須憑弓箭得功名。", "等閑飛鞚秋原上，獨向寒雲試射聲。"]'),
('133359e4-c7c2-4a43-9adc-e5e8ea4e2e41','雜曲歌辭 少年行四首 三','令狐楚','唐','唐诗','tang','','["\u7231\u56fd", "\u51fa\u5f81", "\u58ee\u5fd7"]','弓背霞明劒照霜，秋風走馬出咸陽。',32,'全唐诗/poet.tang.1000.json','["弓背霞明劒照霜，秋風走馬出咸陽。", "未收天子河湟地，不擬回頭望故鄉。"]'),
('5f5d9f3e-a3d3-446a-ba9c-3066f4b6eff9','雜曲歌辭 少年行四首 四','令狐楚','唐','唐诗','tang','','[]','霜滿中庭月過樓，金尊玉柱對清秋。',32,'全唐诗/poet.tang.1000.json','["霜滿中庭月過樓，金尊玉柱對清秋。", "當年稱意須爲樂，不到天明未肯休。"]'),
('195ac36f-552e-4cc2-9e99-6d8c0cc93b72','雜曲歌辭 少年行二首 一','杜牧','唐','唐诗','tang','','[]','官爲駿馬監，職帥羽林兒。',72,'全唐诗/poet.tang.1000.json','["官爲駿馬監，職帥羽林兒。", "兩綬藏不見，落花何處期？", "獵敲白玉鐙，怒袖紫金鎚。", "田竇長留醉，蘇辛曲護岐。", "豪持出塞節，笑別遠山眉。", "捷報雲臺賀，公卿拜壽巵。"]'),
('de67de33-4490-4be1-accf-46965ae26d38','雜曲歌辭 少年行二首 二','杜牧','唐','唐诗','tang','','[]','連環羈玉聲光碎，綠錦蔽泥虬卷高。',32,'全唐诗/poet.tang.1000.json','["連環羈玉聲光碎，綠錦蔽泥虬卷高。", "春風細雨走馬去，珠落璀璀白𦋺袍。"]'),
('94fe7344-b244-4341-8887-e717c373c9a2','雜曲歌辭 少年行三首 一','杜甫','唐','唐诗','tang','','[]','莫笑田家老瓦盆，自從盛酒長兒孫。',32,'全唐诗/poet.tang.1000.json','["莫笑田家老瓦盆，自從盛酒長兒孫。", "傾銀注瓦驚人眼，共醉終同臥竹根。"]'),
('2f609657-375a-4d97-b35e-880dbca040b2','雜曲歌辭 少年行三首 二','杜甫','唐','唐诗','tang','','[]','巢燕養雛渾去盡，紅花結子已無多。',32,'全唐诗/poet.tang.1000.json','["巢燕養雛渾去盡，紅花結子已無多。", "黃衫年少來宜數，不見堂前東逝波。"]'),
('7a97a451-d5e0-4de9-8762-7ccdf64773dd','雜曲歌辭 少年行三首 三','杜甫','唐','唐诗','tang','','[]','馬上誰家白面郎，臨階下馬坐人牀。',32,'全唐诗/poet.tang.1000.json','["馬上誰家白面郎，臨階下馬坐人牀。", "不通姓字麄豪甚，指點銀瓶索酒嘗。"]'),
('0145b0c7-8703-4e0d-b2a0-16a069723bd0','雜曲歌辭 少年行','張祜','唐','唐诗','tang','','[]','少年足風情，垂鞭賣眼行。',50,'全唐诗/poet.tang.1000.json','["少年足風情，垂鞭賣眼行。", "帶金師子小，裘錦騏驎獰。", "選匠裝金鐙，推錢買[鈿]箏。", "李陵雖效死，時論得虛名。"]'),
('26f3fc34-fc1c-41ef-8c59-9b6d1806020e','雜曲歌辭 少年行','韓翃','唐','唐诗','tang','','[]','千點斕斒噴玉驄，青絲結尾繡纏騣。',32,'全唐诗/poet.tang.1000.json','["千點斕斒噴玉驄，青絲結尾繡纏騣。", "鳴鞭晚出章臺路，葉葉春依楊柳風。"]'),
('e3e7c18c-7987-4926-ae60-8e2ef9e2d7dd','雜曲歌辭 少年行','施肩吾','唐','唐诗','tang','','[]','醉騎白馬走空衢，惡少皆稱電不如。',32,'全唐诗/poet.tang.1000.json','["醉騎白馬走空衢，惡少皆稱電不如。", "五鳳街頭閑勒轡，半垂衫袖揖金吾。"]'),
('924c524c-67cb-4e2a-9d9b-e16243269c66','雜曲歌辭 少年行三首 一','僧貫休','唐','唐诗','tang','','[]','錦衣鮮華手擎鶻，閑行氣貌多輕忽。',32,'全唐诗/poet.tang.1000.json','["錦衣鮮華手擎鶻，閑行氣貌多輕忽。", "稼穡艱難總不知，五帝三王是何物。"]'),
('c3702d36-4293-4d70-a4e9-3b752445769f','雜曲歌辭 少年行三首 二','僧貫休','唐','唐诗','tang','','[]','自拳五色毬，迸入他人宅。',24,'全唐诗/poet.tang.1000.json','["自拳五色毬，迸入他人宅。", "卻捉蒼頭奴，玉鞭打一百。"]'),
('de165d68-2bc6-4a4f-8b86-d746d9f82a7d','雜曲歌辭 少年行三首 三','僧貫休','唐','唐诗','tang','','[]','面白如削玉，猖狂曲江曲。',24,'全唐诗/poet.tang.1000.json','["面白如削玉，猖狂曲江曲。", "馬上黃金鞍，適來新賭得。"]'),
('de37c5eb-9420-4c1d-a0a8-e9d9a5a118ca','雜曲歌辭 少年行','韋莊','唐','唐诗','tang','','[]','五陵豪客多，買酒黃金賤。',48,'全唐诗/poet.tang.1000.json','["五陵豪客多，買酒黃金賤。", "醉下酒家樓，美人雙翠幰。", "揮劒邯鄲市，走馬梁王苑。", "樂事殊未央，年華已云晚。"]'),
('151b748b-c973-46df-9c3a-6ce7a9ab53e0','雜曲歌辭 漢宮少年行','李益','唐','唐诗','tang','','[]','君不見上宮警夜營八屯，鼕鼕街鼓朝朱軒。',243,'全唐诗/poet.tang.1000.json','["君不見上宮警夜營八屯，鼕鼕街鼓朝朱軒。", "玉階霜仗擁未合，少年排入銅龍門。", "暗聞弦管九天上，宮漏沈沈清吹繁。", "纔明走馬絕馳道，呼鷹挾彈通繚垣。", "玉籠金瑣養黃口，探雛取卵伴王孫。", "分曹六博快一擲，迎歡先意笑語喧。", "巧爲柔媚學優孟，儒衣嬉戲冠沐猨。", "晚來香街經柳市，行過倡市宿桃根。", "相逢杯酒一言失，回朱點白聞至尊。", "金張許史伺顏色，王侯將相莫敢論。", "豈知人事無定勢，朝歡暮戚如掌翻。", "椒房寵移子愛奪，一夕秋風生戾園。", "徒用黃金將買賦，寧知白玉暗成痕。", "持杯收水水已覆，徙薪避火火更燔。", "欲求四老張丞相，南山如天不可上。"]'),
('9d98b9ab-f80b-40ee-9b22-370fd62cac82','雜曲歌辭 長樂少年行','崔國輔','唐','唐诗','tang','','[]','遺卻珊瑚鞭，白馬驕不行。',24,'全唐诗/poet.tang.1000.json','["遺卻珊瑚鞭，白馬驕不行。", "章臺折楊柳，春草路旁情。"]'),
('3ab356ea-69fc-43ff-b74c-4ece4a0b8277','雜曲歌辭 長安少年行十首 一','李廓','唐','唐诗','tang','','[]','金紫少年郎，繞街鞍馬光。',48,'全唐诗/poet.tang.1000.json','["金紫少年郎，繞街鞍馬光。", "身從左中尉，官屬右春坊。", "剗戴揚州帽，重熏異國香。", "垂鞭踏青草，來去杏園芳。"]'),
('1d2c74e3-c2b7-490c-9acf-50569e84ac7f','雜曲歌辭 長安少年行十首 二','李廓','唐','唐诗','tang','','[]','追逐輕薄伴，閑遊不著緋。',48,'全唐诗/poet.tang.1000.json','["追逐輕薄伴，閑遊不著緋。", "長攏出獵馬，數換打毬衣。", "曉日尋花去，春風帶酒歸。", "青樓無晝夜，歌舞歇時稀。"]'),
('b5fe37ca-edcb-443c-ad33-7031aeb811fe','雜曲歌辭 長安少年行十首 三','李廓','唐','唐诗','tang','','[]','日高春睡足，帖馬賞年華。',48,'全唐诗/poet.tang.1000.json','["日高春睡足，帖馬賞年華。", "倒插銀魚袋，行隨金犢車。", "還攜新市酒，遠醉曲江花。", "幾度歸侵黑，金吾送到家。"]'),
('30de6830-2b0e-4719-b3df-cf10cd1ff31e','雜曲歌辭 長安少年行十首 四','李廓','唐','唐诗','tang','','[]','好勝耽長行，天明燭滿樓。',48,'全唐诗/poet.tang.1000.json','["好勝耽長行，天明燭滿樓。", "留人看獨脚，賭馬換偏頭。", "樂奏曾無歇，杯巡不暫休。", "時時遙冷笑，怪客有春愁。"]'),
('b4dce1fe-1d34-467d-bd5c-4c4700dbfc30','雜曲歌辭 長安少年行十首 五','李廓','唐','唐诗','tang','','[]','遨遊攜豔妓，裝束似男兒。',48,'全唐诗/poet.tang.1000.json','["遨遊攜豔妓，裝束似男兒。", "杯酒逢花住，笙歌簇馬吹。", "鸎聲催曲急，春色訝歸遲。", "不以聞銜鼓，華筵待月移。"]'),
('20fddc31-f54f-42b1-94ab-982db8af120a','雜曲歌辭 長安少年行十首 六','李廓','唐','唐诗','tang','','[]','賞春惟逐勝，大宅可曾歸。',48,'全唐诗/poet.tang.1000.json','["賞春惟逐勝，大宅可曾歸。", "不樂還逃席，多狂慣衩衣。", "歌人踏月起，語燕卷簾飛。", "好婦惟相妒，倡樓不醉稀。"]'),
('53d87055-9847-4740-b963-b9ed763b27dc','雜曲歌辭 長安少年行十首 七','李廓','唐','唐诗','tang','','[]','戟門連日閉，苦飲惜殘春。',48,'全唐诗/poet.tang.1000.json','["戟門連日閉，苦飲惜殘春。", "開瑣通新客，教姬屈醉人。", "請歌牽白馬，自舞踏紅茵。", "時輩皆相許，平生不負身。"]'),
('ead3046a-4747-487f-a645-2695cd744c3d','雜曲歌辭 長安少年行十首 八','李廓','唐','唐诗','tang','','[]','新年高殿上，始見有光輝。',48,'全唐诗/poet.tang.1000.json','["新年高殿上，始見有光輝。", "玉鴈排方帶，金鵝立仗衣。", "酒深和椀賜，馬疾打珂飛。", "朝下人爭看，香街意氣歸。"]'),
('12371483-23f7-473a-a7fa-b466029e7023','雜曲歌辭 長安少年行十首 九','李廓','唐','唐诗','tang','','[]','遊市慵騎馬，隨姬入坐車。',48,'全唐诗/poet.tang.1000.json','["遊市慵騎馬，隨姬入坐車。", "樓邊聽歌吹，簾外市釵花。", "樂眼從人鬧，歸心畏日斜。", "蒼頭來去報，飲伴到倡家。"]'),
('e8f002c5-afdb-457a-975a-78cc51739426','雜曲歌辭 長安少年行十首 十','李廓','唐','唐诗','tang','','[]','小婦教鸚鵡，頭邊喚醉醒。',48,'全唐诗/poet.tang.1000.json','["小婦教鸚鵡，頭邊喚醉醒。", "犬嬌眠玉簟，鷹掣撼金鈴。", "碧地攢花障，紅泥待客亭。", "雖然長按曲，不飲不曾聽。"]'),
('88223ac4-d3bd-4452-a514-35b58bf8f219','雜曲歌辭 長安少年行','僧皎然','唐','唐诗','tang','','[]','翠樓春酒蝦蟆陵，長安少年皆共矜。',32,'全唐诗/poet.tang.1000.json','["翠樓春酒蝦蟆陵，長安少年皆共矜。", "紛紛半醉綠槐道，蹀躞花驄驕不勝。"]'),
('5f5d6ee5-b0eb-4fe8-b26f-26f4bd9fe093','雜曲歌辭 渭城少年行','崔顥','唐','唐诗','tang','','[]','洛陽二月梨花飛，秦地行人春憶歸。',240,'全唐诗/poet.tang.1000.json','["洛陽二月梨花飛，秦地行人春憶歸。", "揚鞭走馬城南陌，朝逢驛使秦川客。", "驛使前日發章臺，傳道長安春早來。", "棠梨宮中燕初至，葡萄館裏花正開。", "念此使人歸更早，三月便達長安道。", "長安道上春可憐，搖風蕩日曲河邊。", "萬戶樓臺臨渭水，五陵花柳滿秦川。", "秦川寒食盛繁華，遊子春來喜見花。", "鬬雞下杜塵初合，走馬章臺日半斜。", "章臺帝城稱貴里，青樓日晚歌鐘起。", "貴里豪家白馬驕，五陵年少不相饒。", "雙雙挾彈來金市，兩兩鳴鞭上渭橋。", "渭城橋頭酒新熟，金鞍白馬誰家宿。", "可憐錦瑟箏琵琶，玉臺清酒就君家。", "小婦春來不解羞，嬌歌一曲楊柳花。"]'),
('48156f67-5e1a-4a77-8b33-207ee517a763','雜曲歌辭 邯鄲少年行','高適','唐','唐诗','tang','','[]','邯鄲城南遊俠子，自矜生長邯鄲裏。',113,'全唐诗/poet.tang.1000.json','["邯鄲城南遊俠子，自矜生長邯鄲裏。", "千場縱博家仍富，幾度報讐身不死。", "宅中歌笑日紛紛，門外車馬如雲屯。", "未知肝膽向誰是，令人却憶平原君。", "君不見今人交態薄，黃金用盡還疎索。", "以茲感激辭舊遊，更於時事無所求。", "且與少年飲美酒，往來射獵西山頭。"]'),
('45052a4c-136c-4b68-9ac8-839e3fb430ad','雜曲歌辭 長安少年行','鄭錫','唐','唐诗','tang','','[]','霞鞍金口騮，豹袖紫貂裘。',48,'全唐诗/poet.tang.1000.json','["霞鞍金口騮，豹袖紫貂裘。", "家住叢臺下，門前漳水流。", "喚人呈楚舞，借客試吳鉤。", "見說秦兵至，甘心赴國讐。"]'),
('e5b07d20-8ae2-43eb-a1a2-9559f9434b11','雜曲歌辭 輕薄篇','李益','唐','唐诗','tang','','[]','豪不必馳千騎，雄不在垂雙鞬。',142,'全唐诗/poet.tang.1000.json','["豪不必馳千騎，雄不在垂雙鞬。", "天生俊氣自相逐，出與鵰鶚同飛翻。", "朝行九衢不得意，下鞭走馬城西原。", "忽聞燕雁一聲去，迴鞭挾彈平陵園。", "歸來青樓曲未半，美人玉色當金尊。", "淮陰少年不相下，酒酣半笑倚市門。", "安知我有不平色，白日欲顧紅塵昏。", "死生容易如反掌，得意失意由一言。", "少年但飲莫相問，此中報讐亦報恩。"]'),
('6a46720e-68dc-4499-a81c-531d77dcc20f','雜曲歌辭 輕薄篇二首 一','僧貫休','唐','唐诗','tang','','[]','繡林錦野，春態相壓。',52,'全唐诗/poet.tang.1000.json','["繡林錦野，春態相壓。", "誰家少年，馬蹏蹋蹋。", "鬬雞走狗夜不歸，一擲賭却如花妾。", "惟云不顛不狂，其名不彰。", "悲夫！。"]'),
('a7d10684-3aca-47d4-9e9e-bbe65fc2be41','雜曲歌辭 輕薄篇二首 二','僧貫休','唐','唐诗','tang','','[]','木落蕭蕭，蛩鳴唧唧。',46,'全唐诗/poet.tang.1000.json','["木落蕭蕭，蛩鳴唧唧。", "不覺朱蔫臉紅，霜劫鬢漆。", "世途多事，泣向秋日。", "方吟少壯不努力，老大徒傷悲。"]'),
('3d4e85e1-0bed-4e7b-8bb6-81677d9f448d','雜曲歌辭 輕薄行','僧齊己','唐','唐诗','tang','','[]','玉鞭金鐙驊騮蹏，橫眉吐氣如虹霓。',64,'全唐诗/poet.tang.1000.json','["玉鞭金鐙驊騮蹏，橫眉吐氣如虹霓。", "五陵春暖芳草齊，笙歌到處花成泥。", "日沈月上且鬬雞，醉來莫問天高低。", "伯陽道德何涕唾，仲尼禮樂徒卑棲。"]'),
('8406ffdc-03fd-479f-9231-a716d93ab242','雜曲歌辭 灞上輕薄行','孟郊','唐','唐诗','tang','','[]','長安無緩步，況值天景暮。',60,'全唐诗/poet.tang.1000.json','["長安無緩步，況值天景暮。", "相逢灞滻間，親戚不相顧。", "自歎方拙身，忽隨輕薄倫。", "常恐失所避，化爲車轍塵。", "此中生白髮，疾走亦未歇。"]'),
('1af491fc-3298-4059-8f3e-533889aa466b','雜曲歌辭 遊俠篇','崔顥','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','少年負膽氣，好勇復知機。',84,'全唐诗/poet.tang.1000.json','["少年負膽氣，好勇復知機。", "仗劒出門去，孤城逢合圍。", "殺人遼水上，走馬漁陽歸。", "錯落金瑣甲，蒙茸貂鼠衣。", "還家行且獵，弓矢速如飛。", "地迥鷹犬疾，草深狐兔肥。", "腰間懸兩綬，轉眄生光輝。"]'),
('fdf5c629-aac9-4b27-a025-acdb82f02349','雜曲歌辭 遊俠行','孟郊','唐','唐诗','tang','','[]','壯士性剛決，火中見石裂。',48,'全唐诗/poet.tang.1000.json','["壯士性剛決，火中見石裂。", "殺人不迴頭，輕生如暫別。", "豈知眼有淚，肯白頭上髮。", "平生無恩酬，劒閑一百月。"]'),
('016daf19-f22d-4933-9582-3d91c4f9aeab','雜曲歌辭 俠客行','李白','唐','唐诗','tang','','["\u8d5e\u9882", "\u5199\u4eba", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','趙客縵胡纓，吳鉤霜雪明。',144,'全唐诗/poet.tang.1000.json','["趙客縵胡纓，吳鉤霜雪明。", "銀鞍照白馬，颯沓如流星。", "十步殺一人，千里不留行。", "事了拂衣去，深藏身與名。", "閑過信陵飲，脫劒膝前橫。", "將炙啖朱亥，持觴勸侯嬴。", "三杯吐然諾，五嶽倒爲輕。", "眼花耳熱後，意氣素霓生。", "救趙揮金槌，邯鄲先震驚。", "千秋二壯士，烜赫大梁城。", "縱死俠骨香，不慙世上英。", "誰能書閣下，白首太玄經。"]'),
('86a4715d-5148-469e-95e1-a3c4db3a9b19','雜曲歌辭 俠客行','元稹','唐','唐诗','tang','','[]','俠客不怕死，怕在事不成。',92,'全唐诗/poet.tang.1000.json','["俠客不怕死，怕在事不成。", "事成不肯藏姓名，我非竊賊誰夜行。", "白日堂堂殺袁盎，九衢草草人面青。", "此客此心師海鯨，海鯨露背橫滄溟。", "海濱分作兩處生，海鯨分海減海力。", "俠客有謀人不測，三尺鐵蛇延二國。"]'),
('42357d0c-52e0-4fb4-88a3-6b09333932a0','雜曲歌辭 俠客行','溫庭筠','唐','唐诗','tang','','["\u5199\u4eba", "\u8c6a\u8fc8", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','欲出鴻都門，陰雲蔽城闕。',36,'全唐诗/poet.tang.1000.json','["欲出鴻都門，陰雲蔽城闕。", "寶劒黯如水，微紅溼餘血。", "白馬夜頻嘶，三更霸陵雪。"]'),
('741c3eef-8892-4a08-9a13-3723b288c0ba','雜曲歌辭 行行遊且獵篇','李白','唐','唐诗','tang','','["\u6e38\u730e", "\u8fb9\u585e"]','邊城兒，生年不讀一字書，但知遊獵誇輕趫。',84,'全唐诗/poet.tang.1000.json','["邊城兒，生年不讀一字書，但知遊獵誇輕趫。", "胡馬秋肥宜白草，騎來躡影何矜驕。", "金鞭拂雲揮鳴鞘，半酣呼鷹出遠郊。", "弓彎滿月不虛發，雙鶬迸落連飛𩩉。", "海邊觀者皆辟易，猛氣英風振沙磧。"]'),
('22923091-18da-429d-9ef1-6b367fd74b1a','雜曲歌辭 遊子吟','孟郊','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c", "\u6bcd\u7231", "\u4e09\u5e74\u7ea7\u4e0b\u518c", "\u8d5e\u9882"]','慈母手中線，遊子身上衣。',36,'全唐诗/poet.tang.1000.json','["慈母手中線，遊子身上衣。", "臨行密密縫，意恐遲遲歸。", "誰言寸草心，報得三春暉。"]'),
('afa0d6db-b93a-4e96-aae9-59ec920eb6de','雜曲歌辭 遊子吟','顧況','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u6292\u6000", "\u601d\u4e61", "\u5199\u666f", "\u58ee\u5fd7\u672a\u916c"]','故櫪思疲馬，故巢思迷禽。',288,'全唐诗/poet.tang.1000.json','["故櫪思疲馬，故巢思迷禽。", "浮雲蔽我鄉，躑躅遊子吟。", "遊子悲久滯，浮雲鬱東岑。", "客堂無絲桐，落葉如秋霖。", "艱哉遠遊子，所以悲滯淫。", "一爲浮雲詞，憤塞誰能禁。", "馳暉百年內，惟願展所欽。", "胡爲不歸歟，坐使年病侵。", "未老霜遶鬢，非狂火燒心。", "太行何艱哉？北斗不可斟。", "夜晴星河出，耿耿辰與參。", "佳人敻青天，尺素重於金。", "泬寥羣動異，眇默諸境森。", "苔衣上閑階，蜻蛚催寒砧。", "立身計幾誤，道險無容針。", "三年不還家，萬里遺錦衾。", "夢魂無重阻，離憂因古今。", "胡爲不歸歟，孤負丘中琴。", "腰下是何物？牽纏曠登尋。", "朝與名山期，夕宿楚水陰。", "楚水殊演漾，名山杳嶇嶔。", "客從洞庭來，婉孌瀟湘深。", "橘柚在南國，鴻雁遺秋音。", "下有碧草洲，上有青橘林。"]'),
('33097bd6-4e80-4ed3-97fe-4444ff7468cb','雜曲歌辭 遊子吟','李益','唐','唐诗','tang','','[]','女羞夫壻蕩，客恥主人賤。',72,'全唐诗/poet.tang.1000.json','["女羞夫壻蕩，客恥主人賤。", "遭遇同衆流，低回愧相見。", "君非青銅鏡，何事空照面？", "莫以衣上塵，不謂心如練。", "人生當榮盛，待士勿言倦。", "君看白日馳，何異弦上箭。"]'),
('199cb91d-b884-4cee-bb45-d85c40d9ef16','雜曲歌辭 壯士吟','賈島','唐','唐诗','tang','','[]','壯士不曾悲，悲即無回期。',24,'全唐诗/poet.tang.1000.json','["壯士不曾悲，悲即無回期。", "如何易水上，未歌先淚垂。"]'),
('0afe4eae-ded2-4a70-ae06-6144d4e77cf0','雜曲歌辭 壯士行','劉禹錫','唐','唐诗','tang','','[]','陰風振寒郊，猛虎正咆哮。',96,'全唐诗/poet.tang.1000.json','["陰風振寒郊，猛虎正咆哮。", "徐行出燒地，連吼入黃茆。", "壯士走馬去，鐙前彎玉弰。", "叱之使人立，一發如鈹交。", "悍睛忽星墜，飛血濺林梢。", "彪炳爲我席，羶腥充我庖。", "里中欣害除，賀酒紛號呶。", "明日長橋上，傾城看斬蛟。"]'),
('60e6c4fc-0583-4d86-898f-9bab22c5846a','雜曲歌辭 壯士行','鮑溶','唐','唐诗','tang','','[]','西方太白高，壯士羞病死。',60,'全唐诗/poet.tang.1000.json','["西方太白高，壯士羞病死。", "心知報恩處，對酒歌易水。", "砂鴻嗥天末，橫劒別妻子。", "蘇武執節歸，班超束書起。", "山河不足重，重在遇知己。"]'),
('23e1a814-7dfd-4148-8318-3f3b7cccafb2','雜曲歌辭 壯士行','施肩吾','唐','唐诗','tang','','[]','一斗之膽撐臟腑，如磥之筋礙臂骨。',64,'全唐诗/poet.tang.1000.json','["一斗之膽撐臟腑，如磥之筋礙臂骨。", "有時誤入千人叢，自覺一身橫突兀。", "當今四海無煙塵，胸襟被壓不得伸。", "凍梟殘蠆我不取，汙我匣黑青蛇鱗。"]'),
('29e4fffb-ebb1-4bd5-96f0-fab28f4e18de','雜曲歌辭 浩歌','李賀','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u6000", "\u5199\u666f"]','南風吹山作平地，帝遣天吳移海水。',128,'全唐诗/poet.tang.1000.json','["南風吹山作平地，帝遣天吳移海水。", "王母桃花千遍紅，彭祖巫咸幾回死。", "青毛驄馬參差錢，嬌春楊柳含細煙。", "箏人勸我金屈巵，神血未凝身問誰。", "不須浪飲丁督護，世上英雄本無主。", "買絲繡作平原君，有酒惟澆趙州土。", "漏催水咽玉蟾蜍，衛娘髮薄不勝梳。", "看見秋眉換深綠，二十男兒那刺促。"]'),
('bab8a287-f853-4c81-ab99-2795a5484ae1','雜曲歌辭 浩歌行','白居易','唐','唐诗','tang','','[]','天長地久無終畢，昨夜今朝又明日。',160,'全唐诗/poet.tang.1000.json','["天長地久無終畢，昨夜今朝又明日。", "鬢髮蒼浪牙齒疎，不覺身年四十七。", "前去五十有幾年，把鏡照面心茫然。", "既無長繩繫白日，又無大藥駐朱顏。", "朱顏日漸不如故，青史功名在何處？", "欲留年少待富貴，富貴不來年少去。", "去復去兮如長河，東流赴海無迴波。", "賢愚貴賤同歸盡，北邙冢墓高嵯峨。", "古來如此非獨我，未死有酒且酣歌。", "顏回短命伯夷餓，我今所得亦已多。"]'),
('37484eba-f71b-4797-aaa9-d8a43d3219cd','雜曲歌辭 歸去來引','張熾','唐','唐诗','tang','','[]','歸去來，歸期不可違。',22,'全唐诗/poet.tang.1000.json','["歸去來，歸期不可違。", "相見故明月，浮雲共我歸。"]'),
('12fa4755-e5e9-40fe-91bf-590aafb4ddf9','雜曲歌辭 麗人曲','崔國輔','唐','唐诗','tang','','[]','紅顏稱絕代，欲並真無侶。',24,'全唐诗/poet.tang.1000.json','["紅顏稱絕代，欲並真無侶。", "獨有鏡中人，由來自相許。"]'),
('aaae5882-9b74-4b45-9bb5-9f773a721119','雜曲歌辭 麗人行','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c", "\u8bbd\u523a", "\u548f\u53f9"]','三月三日天氣新，長安水邊多麗人。',204,'全唐诗/poet.tang.1000.json','["三月三日天氣新，長安水邊多麗人。", "態濃意遠淑且真，肌理細膩骨肉勻。", "繡羅衣裳照暮春，蹙金孔雀銀麒麟。", "頭上何所有？翠微㔩葉垂鬢脣。", "背後何所見？珠壓腰衱穩稱身。", "就中雲幕椒房親，賜名大國虢與秦。", "紫駞之峯出翠釜，水晶之盤行素鱗。", "犀筯厭飫久未下，鸞刀縷切空紛綸。", "黃門飛鞚不動塵，御廚絲絡送八珍。", "簫鼓哀吟感鬼神，賓從雜遝實要津。", "後來鞍馬何逡巡，當軒下馬入錦茵。", "楊花雪落覆白蘋，青鳥飛去銜紅巾。", "炙手可熱勢絕倫，慎莫近前丞相嗔。"]'),
('a35c63d8-b7e1-4da5-9780-47b1c8736b0c','雜曲歌辭 東飛伯勞歌','張柬之','唐','唐诗','tang','','[]','青田白鶴丹山鳳，婺女姮娥兩相送。',80,'全唐诗/poet.tang.1000.json','["青田白鶴丹山鳳，婺女姮娥兩相送。", "誰家絕世綺帳前，豔粉芳脂映寶鈿。", "窈窕玉堂褰翠幕，參差繡戶懸珠箔。", "絕世三五愛紅妝，冶袖長裾蘭麝香。", "春去花枝俄易改，可歎年光不相待。"]'),
('006d90dd-df34-4d79-af85-99e7e7d497bf','雜曲歌辭 東飛伯勞歌','李嶠','唐','唐诗','tang','','[]','傳書青鳥迎簫鳳，巫嶺荆臺數通夢。',80,'全唐诗/poet.tang.1000.json','["傳書青鳥迎簫鳳，巫嶺荆臺數通夢。", "誰家窈窕住園樓，五馬千金照陌頭。", "羅裙玉佩當軒出，點翠施紅競春日。", "佳人二八盛舞歌，羞將百萬呈雙娥。", "庭前芳樹朝夕改，空駐妍華欲誰待。"]'),
('6b2b0b80-871c-4b5f-ac4d-1d266fc0df36','雜曲歌辭 東飛伯勞歌','李暇','唐','唐诗','tang','','[]','秦王龍劒燕后琴，珊瑚寶匣鏤雙心。',80,'全唐诗/poet.tang.1000.json','["秦王龍劒燕后琴，珊瑚寶匣鏤雙心。", "誰家女兒抱香枕，開衾滅燭願侍寢。", "瓊窗半上金縷幬，輕羅隱面不障羞。", "青綺幃中坐相憶，紅羅鏡裏見愁色。", "簷花照月鶯對棲，空將可憐暗中啼。"]'),
('2076be94-1be6-4df6-b8a4-4bd7a755d247','雜曲歌辭 鳴雁行','李白','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u4eba\u751f", "\u548f\u7269\u8bd7", "\u574e\u5777"]','胡雁鳴，辭燕山，昨發委羽朝度關。',62,'全唐诗/poet.tang.1000.json','["胡雁鳴，辭燕山，昨發委羽朝度關。", "一一銜蘆枝，南飛散落天地間。", "連行接翼往復還，客居煙波寄湘吳。", "凌霜觸雪毛體枯，畏逢矰繳驚相呼。"]'),
('aaa3d713-8c7f-4f46-a0d5-39ed552d9511','雜曲歌辭 鳴雁行','韓愈','唐','唐诗','tang','','[]','嗷嗷鳴雁鳴且飛，窮秋南去春北歸。',80,'全唐诗/poet.tang.1000.json','["嗷嗷鳴雁鳴且飛，窮秋南去春北歸。", "去寒就暖識所處，天長地闊棲息稀。", "風霜酸苦稻粱微，羽毛摧落身不肥。", "徘徊反顧羣侶違，哀鳴欲下洲渚非。", "江南水闊朝雲多，草長沙輭無網羅。"]'),
('0ef99715-15ba-4586-98d0-bb90aece4b71','雜曲歌辭 鳴雁行','鮑溶','唐','唐诗','tang','','[]','七月朔方雁心苦，聯影翻空落南土。',112,'全唐诗/poet.tang.1000.json','["七月朔方雁心苦，聯影翻空落南土。", "八月江南陰復晴，浮雲繞天難夜行。", "羽翼勞痛心虛驚，一聲相呼百處鳴。", "楚童夜宿煙波側，沙上布羅連草色。", "月闇風悲欲下天，不知何處容棲息？", "楚童胡爲傷我神，爾不曾作遠行人。", "江南羽族本不少，寧得網羅此客鳥。"]'),
('31bc78e4-ece6-4a4f-b5bb-a8c00df6c620','雜曲歌辭 鳴雁行','陸龜蒙','唐','唐诗','tang','','[]','朔風動地來，吹起沙上聲。',36,'全唐诗/poet.tang.1000.json','["朔風動地來，吹起沙上聲。", "閨中有邊思，玉筯此時橫。", "莫怕兒女恨，主人烹不鳴。"]'),
('51234d8c-4147-4404-a709-797f87f6931f','雜曲歌辭 空城雀','李白','唐','唐诗','tang','','["\u5fd7\u5411", "\u65e0\u5948", "\u4e50\u5e9c", "\u5199\u9e1f", "\u6742\u66f2\u6b4c\u8f9e", "\u9e1f"]','嗷嗷空城雀，身計何戚促。',72,'全唐诗/poet.tang.1000.json','["嗷嗷空城雀，身計何戚促。", "本與鷦鷯羣，不隨鳳凰族。", "提攜四黃口，飲乳未嘗足。", "食君糠粃餘，常恐烏鳶逐。", "恥涉太行險，羞營覆車粟。", "天命有定端，守分絕所欲。"]'),
('bdd79ce6-205b-4c91-bf73-532087f5acfe','雜曲歌辭 空城雀','王建','唐','唐诗','tang','','[]','空城雀，何不飛來人家住？',100,'全唐诗/poet.tang.1000.json','["空城雀，何不飛來人家住？", "空城無人種禾黍。", "土間生子草間長，滿地蓬蒿幸無主。", "近村雖有高樹枝，雨中無食長苦飢。", "八月小兒夾弓箭，家家畏我田頭飛。", "但能不出空城裏，秋時百草皆有子。", "黃口黃口莫啾啾，長爾得成無橫死。"]'),
('b48917db-dd2c-48ff-b521-5a655dd0734a','雜曲歌辭 空城雀','聶夷中','唐','唐诗','tang','','[]','一雀入官倉，所食能損幾。',36,'全唐诗/poet.tang.1000.json','["一雀入官倉，所食能損幾。", "所慮往損頻，官倉乃害爾。", "魚網不在天，鳥網不在水。"]'),
('fe167a9d-6e8f-423b-90e5-9ba015de0358','雜曲歌辭 空城雀','劉駕','唐','唐诗','tang','','[]','飢啄空城土，莫近太倉粟。',48,'全唐诗/poet.tang.1000.json','["飢啄空城土，莫近太倉粟。", "一粒未充腸，却入公子腹。", "且弔城上骨，幾曾害爾族。", "不聞莊辛語，今日寒蕪綠。"]'),
('32d70177-1afe-411b-9a36-684d2e840b72','雜曲歌辭 車遙遙','孟郊','唐','唐诗','tang','','[]','路喜到江盡，江上又通舟。',96,'全唐诗/poet.tang.1000.json','["路喜到江盡，江上又通舟。", "舟車兩無阻，何處不得遊？", "丈夫四方志，女子安可留？", "郎自別日言，無令生遠愁。", "旅鴈忽叫月，斷猨寒啼秋。", "此夕夢君夢，君在百城樓。", "寄淚無因波，寄恨無因輈。", "願爲馭者手，與郎迴馬頭。"]'),
('b3cadd66-3071-4a7d-976c-4b2ec9ab2e23','雜曲歌辭 車遙遙','張籍','唐','唐诗','tang','','[]','征人遙遙出古城，雙輪齊動駟馬鳴。',112,'全唐诗/poet.tang.1000.json','["征人遙遙出古城，雙輪齊動駟馬鳴。", "山川無處無歸路，念君長作萬里行。", "野田人稀秋草綠，日暮放馬車中宿。", "驚麏遊兔在我傍，獨唱鄉歌對僮僕。", "君家大宅鳳城隅，年年道上隨行車。", "願爲玉鑾繫華軾，終日有聲在君側。", "門前舊轍久已平，無由復得君消息。"]'),
('9db361d6-8924-443c-bd96-2b01b1a8c95d','雜曲歌辭 車遙遙','張祜','唐','唐诗','tang','','[]','東方曨曨車軋軋，地色不分新去轍。',80,'全唐诗/poet.tang.1000.json','["東方曨曨車軋軋，地色不分新去轍。", "閨門半掩牀半空，斑斑枕花殘淚紅。", "君心若車千萬轉，妾身如轍遺漸遠。", "碧川迢迢山宛宛，馬蹏在耳輪在眼。", "桑間女兒情不淺，莫道野蠶能作繭。"]'),
('0c5018e5-d3da-49b5-965b-ac5c58fac0e5','雜曲歌辭 車遙遙','胡曾','唐','唐诗','tang','','[]','自從車馬出門朝，便入空房守寂寥。',64,'全唐诗/poet.tang.1000.json','["自從車馬出門朝，便入空房守寂寥。", "玉枕夜殘魚信絕，金鈿秋盡雁書遙。", "臉邊楚雨臨風落，頭上春雲向日銷。", "芳草又衰還不至，碧天霜冷轉無憀。"]'),
('198f15ab-e3b2-404d-b6c5-7f53d7a0f0e8','雜曲歌辭 自君之出矣','辛弘智','唐','唐诗','tang','','["\u95fa\u6028", "\u76f8\u601d", "\u5987\u5973", "\u4e50\u5e9c"]','自君之出矣，梁塵靜不飛。',24,'全唐诗/poet.tang.1000.json','["自君之出矣，梁塵靜不飛。", "思君如滿月，夜夜減容暉。"]'),
('eeab8129-4858-4ec3-beaf-8f176f357b7e','雜曲歌辭 自君之出矣','李康成','唐','唐诗','tang','','[]','自君之出矣，弦吹絕無聲。',24,'全唐诗/poet.tang.1000.json','["自君之出矣，弦吹絕無聲。", "思君如百草，撩亂逐春生。"]'),
('01bd3441-2699-41e1-96f4-b59e1d42c3a3','雜曲歌辭 自君之出矣','盧仝','唐','唐诗','tang','','[]','自君之出矣，壁上蜘蛛織。',96,'全唐诗/poet.tang.1000.json','["自君之出矣，壁上蜘蛛織。", "近取見妾心，夜夜無休息。", "妾有雙玉環，寄君表相憶。", "環是妾之心，玉是君之德。", "馳情增悴容，蓄思損精力。", "玉簟寒悽悽，延想心惻惻。", "風含霜月明，水泛碧天色。", "此水有盡時，此情無終極。"]'),
('145211da-6f92-4a02-aecb-b260130e310d','雜曲歌辭 自君之出矣','雍裕之','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e50\u5e9c"]','自君之出矣，寶鏡爲誰明。',24,'全唐诗/poet.tang.1000.json','["自君之出矣，寶鏡爲誰明。", "思君如隴水，長聞嗚咽聲。"]'),
('fe76e09a-ec1d-4ca8-b10f-cba85c1598d6','雜曲歌辭 自君之出矣','張祜','唐','唐诗','tang','','[]','自君之出矣，萬物看成古。',24,'全唐诗/poet.tang.1000.json','["自君之出矣，萬物看成古。", "千尋葶藶枝，爭奈長長苦。"]'),
('feed970e-6f9d-451c-ba5c-ba6a629f924f','雜曲歌辭 長相思','郎大家宋氏','唐','唐诗','tang','','[]','長相思，久離別。',40,'全唐诗/poet.tang.1000.json','["長相思，久離別。", "關山阻，風煙絕。", "臺上鏡文銷，袖中書字滅。", "不見君形影，何曾有懽悅。"]'),
('99314a0f-cce0-4006-aaaf-1e0cb2569f89','雜曲歌辭 長相思','蘇頲','唐','唐诗','tang','','[]','君不見天津橋下東流水，東望龍門北朝市。',51,'全唐诗/poet.tang.1000.json','["君不見天津橋下東流水，東望龍門北朝市。", "楊柳青青宛地垂，桃紅李白花參差。", "花參差，柳堪結，此時憶君心斷絕。"]'),
('d4baf2d1-ea61-4fb3-a284-e889275bdca2','雜曲歌辭 長相思三首 一','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6742\u66f2\u6b4c\u8f9e", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u4f24\u6000"]','長相思，在長安，絡緯秋啼金井欄。',88,'全唐诗/poet.tang.1000.json','["長相思，在長安，絡緯秋啼金井欄。", "微霜淒淒簟色寒，孤燈不明思欲絕。", "卷帷望月空長歎，美人如花隔雲端。", "上有青冥之長天，下有綠水之波瀾。", "天長路遠魂飛苦，夢魂不到關山難。", "長相思，摧心肝。"]'),
('caa023cf-9f55-450c-9638-1cf5c0223cc1','雜曲歌辭 長相思三首 二','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e50\u5e9c"]','日色已盡花含煙，月明欲素愁不眠。',82,'全唐诗/poet.tang.1000.json','["日色已盡花含煙，月明欲素愁不眠。", "趙瑟初停鳳凰柱，蜀琴欲奏鴛鴦弦。", "此曲有意無人傳，願隨春風寄燕然，憶君迢迢隔青天。", "昔日橫波目，今成流淚泉。", "不信妾腸斷，歸來看取明鏡前。"]'),
('f0dc1b19-1846-4837-937f-8c2ff37fcd18','雜曲歌辭 長相思三首 三','李白','唐','唐诗','tang','','[]','美人在時花滿堂，美人去後花餘牀。',56,'全唐诗/poet.tang.1000.json','["美人在時花滿堂，美人去後花餘牀。", "牀中繡被卷不寢，至今三載猶聞香。", "香亦竟不滅，人亦竟不來。", "相思黃葉落，白露點青苔。"]'),
('2b87015d-2a4a-4fa7-af5e-fe7cebc4a99f','雜曲歌辭 長相思','張繼','唐','唐诗','tang','','[]','遼陽望河縣，白首無由見。',24,'全唐诗/poet.tang.1000.json','["遼陽望河縣，白首無由見。", "海上珊瑚枝，年年寄春燕。"]'),
('4345418b-e039-46ad-b17a-e26a7bebed93','雜曲歌辭 長相思二首 一','令狐楚','唐','唐诗','tang','','[]','君行登隴上，妾夢在閨中。',24,'全唐诗/poet.tang.1000.json','["君行登隴上，妾夢在閨中。", "玉筯千行落，銀牀一半空。"]'),
('158d4260-8f5c-4c8e-9ffd-872651a996ad','雜曲歌辭 長相思二首 二','令狐楚','唐','唐诗','tang','','[]','綺席春眠覺，紗窗曉望迷。',24,'全唐诗/poet.tang.1000.json','["綺席春眠覺，紗窗曉望迷。", "朦朧殘夢裏，猶自在遼西。"]'),
('7e26f9c9-ef6f-4b26-bf34-c683d1e41786','雜曲歌辭 長相思','白居易','唐','唐诗','tang','','[]','九月西風興，月冷霜華凝。',132,'全唐诗/poet.tang.1000.json','["九月西風興，月冷霜華凝。", "思君秋夜長，一夜魂九升。", "二月東風來，草坼花心開。", "思君春日遲，一日腸九迴。", "妾住洛橋北，君住洛橋南。", "十五即相識，今年二十三。", "有如女蘿草，生在松之側。", "蔓短枝苦高，縈迴上不得。", "人言人有願，願至天必成。", "願作遠方獸，步步比肩行。", "願作深山木，枝枝連理生。"]'),
('7e6ddfac-90eb-4c9f-839d-062601924763','雜曲歌辭 千里思','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u540c\u60c5", "\u4e50\u5e9c"]','李陵沒胡沙，蘇武還漢家。',48,'全唐诗/poet.tang.1000.json','["李陵沒胡沙，蘇武還漢家。", "迢迢五原關，朔雪亂邊花。", "一去隔絕域，思歸但長嗟。", "鴻雁向西北，飛書報天涯。"]'),
('09480502-2a86-458b-93be-fc0aca0f9b04','雜曲歌辭 千里思','李端','唐','唐诗','tang','','[]','涼州風月美，遙望居延路。',48,'全唐诗/poet.tang.1000.json','["涼州風月美，遙望居延路。", "泛泛下天雲，青青緣塞樹。", "燕山蘇武上，海島田橫住。", "更是草生時，行人出門去。"]'),
('6393b72d-7d61-4201-9072-e5589b1637ab','雜曲歌辭 行路難','盧照鄰','唐','唐诗','tang','','["\u54f2\u7406"]','君不見長安城北渭橋邊，枯木橫槎臥古田。',323,'全唐诗/poet.tang.1000.json','["君不見長安城北渭橋邊，枯木橫槎臥古田。", "昔日含紅復含紫，常時留霧亦留煙。", "春景春風花似雪，香車玉轝恆闐咽。", "若箇遊人不競攀，若箇倡家不來折。", "倡家寶袜蛟龍帔，公子銀鞍千萬騎。", "黃鶯一向花嬌春，兩兩三三將子戲。", "千尺長條百尺枝，丹桂青榆相蔽虧。", "珊瑚葉上鴛鴦鳥，鳳凰巢裏雛鵷兒。", "巢傾枝折鳳歸去，條枯葉落狂風吹。", "一朝零落無人問，萬古摧殘君詎知。", "人生貴賤無終始，倏忽須臾難久恃。", "誰家能駐西山日，誰家能堰東流水。", "漢家陵樹滿秦川，行來行去盡哀憐。", "自昔公卿二千石，咸擬榮華一萬年。", "不見朱脣將白貌，惟聞素棘與黃泉。", "金貂有時須換酒，玉麈但搖莫計錢。", "寄言坐客神仙署，一生一死交情處。", "蒼龍闕下君不來，白鶴山前我應去。", "雲間海上邈難期，赤心會合在何時？", "但願堯年一百萬，長作巢由也不辭。"]'),
('8285c2b9-3ad8-4ea6-9b16-3b739380036e','雜曲歌辭 行路難','張紘','唐','唐诗','tang','','[]','君不見溫家玉鏡臺，提攜抱握九重來。',146,'全唐诗/poet.tang.1000.json','["君不見溫家玉鏡臺，提攜抱握九重來。", "君不見相如綠綺琴，一撫一拍鳳凰音。", "人生意氣須及早，莫負當年行樂心。", "荆王奏曲楚妃歎，曲盡歡終夜將半。", "朱樓銀閣正平生，碧草青苔坐蕪漫。", "當春對酒不須疑，視目相看能幾時。", "春風吹盡燕初至，此時自謂稱君意。", "秋露萎草鴻始歸，此時衰暮與君違。", "人生翻覆何常足，誰保容顏無是非。"]'),
('7c4fcc83-5d62-47d2-b232-9f0143ecf61f','雜曲歌辭 行路難五首 一','賀蘭進明','唐','唐诗','tang','','[]','君不見嵒下井，百尺不及泉。',74,'全唐诗/poet.tang.1000.json','["君不見嵒下井，百尺不及泉。", "君不見山上蒿，數寸凌雲煙。", "人生相命亦如此，何苦太息自憂煎。", "但願親友長含笑，相逢莫吝杖頭錢。", "寒夜邀歡須秉燭，豈得空思花柳年。"]'),
('a455576e-eadf-4a75-a283-80266e1054fb','雜曲歌辭 行路難五首 二','賀蘭進明','唐','唐诗','tang','','[]','君不見門前柳，榮曜暫時蕭索久。',62,'全唐诗/poet.tang.1000.json','["君不見門前柳，榮曜暫時蕭索久。", "君不見陌上花，狂風吹去落誰家。", "誰家思婦見之歎，蓬首不梳心歷亂。", "盛年夫壻長別離，歲暮相逢色凋換。"]'),
('05ca1eef-d549-4f8e-b853-1340fbb486b8','雜曲歌辭 行路難五首 三','賀蘭進明','唐','唐诗','tang','','[]','君不見荒樹枝，春花落盡蜂不窺。',62,'全唐诗/poet.tang.1000.json','["君不見荒樹枝，春花落盡蜂不窺。", "君不見梁上泥，秋風始高燕不棲。", "蕩子從軍事征戰，蛾眉嬋娟空守閨。", "獨宿自然堪下淚，況復時聞烏夜啼。"]'),
('caddd8da-5834-41d5-a136-9e1a56c7cef2','雜曲歌辭 行路難五首 四','賀蘭進明','唐','唐诗','tang','','[]','君不見雲間月，暫盈還復缺。',58,'全唐诗/poet.tang.1000.json','["君不見雲間月，暫盈還復缺。", "君不見林下風，聲遠意難窮。", "親故平生欲聚散，歡娛未盡尊酒空。", "自歎青青陵上柏，歲寒能與幾人同。"]'),
('10f85086-3dcd-46d9-8522-d850af4e9975','雜曲歌辭 行路難五首 五','賀蘭進明','唐','唐诗','tang','','[]','君不見東流水，一去無窮已。',58,'全唐诗/poet.tang.1000.json','["君不見東流水，一去無窮已。", "君不見西郊雲，日夕空氛氳。", "羣雁裴回不能去，一雁悲鳴復失羣。", "人生結交在終始，莫爲升沈中路分。"]'),
('bf1d7c98-80bb-4886-93a1-ffbd1365dd20','雜曲歌辭 行路難','崔顥','唐','唐诗','tang','','[]','君不見建章宮中金明枝，萬萬長條拂地垂。',163,'全唐诗/poet.tang.1000.json','["君不見建章宮中金明枝，萬萬長條拂地垂。", "二月三月花如霰，九重幽深君不見。", "豔彩朝含四寶宮，香風吹入朝雲殿。", "漢家宮女春未闌，愛此芳香朝暮看。", "看去看來心不忘，攀折將安鏡臺上。", "雙雙素手剪不成，兩兩紅妝笑相向。", "建章昨夜起春風，一花飛落長信宮。", "長信麗人見花泣，憶此珍樹何嗟及。", "我昔初在昭陽時，朝折暮折登玉墀。", "祗言歲歲長相對，不寤今朝遙相思。"]'),
('527eba4b-b35c-4d29-99e7-8f40c6f3d5b7','雜曲歌辭 行路難三首 一','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u52b1\u5fd7", "\u53cb\u60c5", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5185)", "\u521d\u4e2d\u53e4\u8bd7", "\u4e50\u5e9c"]','金尊清酒斗十千，玉盤珍羞直萬錢。',96,'全唐诗/poet.tang.1000.json','["金尊清酒斗十千，玉盤珍羞直萬錢。", "停杯投筯不能食，拔劒四顧心茫然。", "欲渡黃河冰塞川，將登太行雪暗天。", "閑來垂釣坐溪上，忽復乘舟夢日邊。", "行路難，行路難，多岐路，今安在？", "長風破浪會有時，直挂雲帆濟滄海。"]'),
('e12edd83-36cd-4e8a-a630-91874631c51f','雜曲歌辭 行路難三首 二','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u5931\u610f", "\u53f9\u606f"]','大道如青天，我獨不得出。',119,'全唐诗/poet.tang.1000.json','["大道如青天，我獨不得出。", "羞逐長安社中兒，赤雞白狗賭梨栗。", "彈劒作歌奏苦聲，曳裾王門不稱情。", "淮陰市井笑韓信，漢朝公卿忌賈生。", "君不見昔時燕家重郭隗，擁篲折腰無嫌猜。", "劇辛樂毅感恩分，輸肝剖膽效英才。", "昭王白骨縈蔓草，誰人更掃黃金臺。", "行路難，歸去來。"]'),
('b4f9c5b3-0108-4127-bf3e-73fd207176f3','雜曲歌辭 行路難三首 三','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4eba\u751f", "\u4e50\u5e9c", "\u6001\u5ea6"]','有耳莫洗潁川水，有口莫食首陽蕨。',131,'全唐诗/poet.tang.1000.json','["有耳莫洗潁川水，有口莫食首陽蕨。", "含光混世貴無名，何用孤高比雲月。", "吾觀自古賢達人，功成不退皆殞身。", "子胥既棄吳江上，屈原終投湘水濱。", "陸機才多豈自保，李斯稅駕苦不早。", "華亭鶴唳詎可聞，上蔡蒼鷹何足道？", "君不見吳中張翰稱達士，秋風忽憶江東行。", "且樂生前一杯酒，何須身後千載名。"]'),
('a5388739-d560-444f-b24b-537db93e7519','雜曲歌辭 行路難三首 一','顧況','唐','唐诗','tang','','[]','君不見古來燒水銀，變作北邙山上塵。',95,'全唐诗/poet.tang.1000.json','["君不見古來燒水銀，變作北邙山上塵。", "藕絲挂身在虛空，欲落不落愁殺人。", "睢水英雄多血刃，建章宮闕成灰燼。", "淮王身死桂枝折，徐氏一去音書絕。", "行路難，行路難，生死皆由天。", "秦皇漢武遭下脫，汝獨何人學神仙。"]'),
('7ee919e0-cdff-4594-bc72-3d5d88503cee','雜曲歌辭 行路難三首 二','顧況','唐','唐诗','tang','','[]','君不見擔雪塞井徒用力，炊砂作飯豈堪喫。',99,'全唐诗/poet.tang.1000.json','["君不見擔雪塞井徒用力，炊砂作飯豈堪喫。", "一生肝膽向人盡，相識不如不相識。", "冬青樹上挂凌宵，歲[晏]花凋樹不凋。", "凡物各自有根本，種禾終不生豆苗。", "行路難，行路難，何處是平道？", "中心無事當富貴，今日覺君顏色好。"]'),
('160c5168-d55c-4a4c-ba73-ae1596f4b900','雜曲歌辭 行路難三首 三','顧況','唐','唐诗','tang','','[]','君不見少年頭上如雲髮，少壯如雲老如雪。',99,'全唐诗/poet.tang.1000.json','["君不見少年頭上如雲髮，少壯如雲老如雪。", "豈知灌頂有醍醐，能使清涼頭不熱。", "呂梁之水挂飛流，黿鼉蛟蜃不敢游。", "少年恃險若平地，獨倚長劒凌清秋。", "行路難，行路難，昔少年，今已老。", "前朝竹帛事皆空，日暮牛羊古城草。"]'),
('028b5cb7-2c3b-4023-ae17-90d2128c5b75','雜曲歌辭 行路難','李頎','唐','唐诗','tang','','[]','漢家名臣楊德祖，四代五公享茅土。',160,'全唐诗/poet.tang.1000.json','["漢家名臣楊德祖，四代五公享茅土。", "父兄子弟綰銀黃，躍馬鳴珂朝建章。", "火浣單衣繡方領，茱萸錦帶玉盤囊。", "賓客填街復滿坐，片言出口生輝光。", "世人逐勢爭奔走，瀝膽隳肝惟恐後。", "當時一顧生青雲，自謂生死長隨君。", "一朝謝病還鄉里，窮巷蒼茫絕知己。", "秋風落葉閉重門，昨日論交竟誰是。", "薄俗嗟嗟難重陳，深山麋鹿下爲鄰。", "魯連所以蹈滄海，古往今來稱達人。"]'),
('5fc49eb5-7f24-4b67-8f25-30348868291d','雜曲歌辭 行路難二首 一','高適','唐','唐诗','tang','','[]','君不見富家翁，昔時貧賤誰比數。',79,'全唐诗/poet.tang.1000.json','["君不見富家翁，昔時貧賤誰比數。", "一朝金多結豪貴，萬事勝人健如虎。", "子孫成長滿眼前，妻能管弦妾能舞。", "自矜一朝忽如此，却笑傍人獨悲苦。", "東鄰少年安所如，席門窮巷出無車。"]'),
('ba2f4924-7ab8-48f2-9e23-d656dea0117b','雜曲歌辭 行路難二首 二','高適','唐','唐诗','tang','','[]','長安少年不少錢，能騎駿馬鳴金鞭。',64,'全唐诗/poet.tang.1000.json','["長安少年不少錢，能騎駿馬鳴金鞭。", "五侯相逢大道邊，美人弦管爭留連。", "黃金如斗不敢惜，片言如山莫棄捐。", "安知顦顇讀書者，暮宿虛臺私自憐。"]'),
('1f401d0c-fe7d-4cd2-be76-5e30bfe28f2d','雜曲歌辭 行路難','張籍','唐','唐诗','tang','','[]','湘東行人長歎息，十年離家歸未得。',63,'全唐诗/poet.tang.1000.json','["湘東行人長歎息，十年離家歸未得。", "弊裘羸馬苦難行，童僕飢寒少筋力。", "君不見牀頭黃金盡，壯士無顏色。", "龍蟠泥中未有雲，不能生彼升天翼。"]'),
('7111877e-28e4-47cd-bba0-fa2372beccb5','雜曲歌辭 行路難','聶夷中','唐','唐诗','tang','','[]','莫言行路難，夷狄如中國。',48,'全唐诗/poet.tang.1000.json','["莫言行路難，夷狄如中國。", "謂言骨肉親，中門如異域。", "出處全在人，路亦無通塞。", "門前兩條轍，何處去不得。"]'),
('013bf750-098b-4b37-93d9-82c2efea2634','雜曲歌辭 行路難','韋應物','唐','唐诗','tang','','[]','荆山之白玉兮。',99,'全唐诗/poet.tang.1000.json','["荆山之白玉兮。", "良工雕琢雙環連，月蝕中央鏡心穿。", "故人贈妾初相結，恩在環中尋不絕。", "人情厚薄苦須臾，昔似連環今似玦。", "連環可碎不可離，如何物在人自移。", "上客勿遽歡，聽妾歌路難。", "傍人見環環可憐，不知中有長恨端。"]'),
('07cfcd66-7c89-4b1c-b2c9-82e9ce69fcf3','雜曲歌辭 行路難三首 一','柳宗元','唐','唐诗','tang','','[]','君不見夸父逐日窺虞淵，跳踉北海超崑崙。',99,'全唐诗/poet.tang.1000.json','["君不見夸父逐日窺虞淵，跳踉北海超崑崙。", "披霄決漢出沆漭，瞥裂左右遺星辰。", "須臾力盡道渴死，狐鼠蜂蟻爭噬吞。", "北方竫人長九寸，開口抵掌更笑喧。", "啾啾飲食滴與粒，生死亦足終天年。", "睢盱大志少成遂，坐使兒女相悲憐。"]'),
('c4812c8a-c01e-4340-aa75-13d0a6e5d3ef','雜曲歌辭 行路難三首 二','柳宗元','唐','唐诗','tang','','[]','虞衡斤斧羅千山，工命采斫杙與椽。',115,'全唐诗/poet.tang.1000.json','["虞衡斤斧羅千山，工命采斫杙與椽。", "深林土翦十取一，百牛連鞅摧雙轅。", "萬圍千尋妨道路，東西蹶倒山火焚。", "遺餘毫末不見保，躝礫磵壑何當存。", "羣材未成質已夭，突兀𡷸豁空巖巒。", "柏梁天災武庫火，匠石狼顧相愁冤。", "君不見南山棟梁益稀少，愛材養育誰復論。"]'),
('a8e39b30-119d-4b4f-b557-da792950a2a3','雜曲歌辭 行路難三首 三','柳宗元','唐','唐诗','tang','','[]','飛雪斷道冰成梁，侯家熾炭雕玉房。',112,'全唐诗/poet.tang.1000.json','["飛雪斷道冰成梁，侯家熾炭雕玉房。", "蟠龍吐耀虎喙張，熊蹲豹擲爭低昂。", "攢巒叢崿射朱光，丹霞翠霧飄奇香。", "美人四向迴明璫，雪山冰谷晞太陽。", "星躔奔走不得止，奄忽雙燕棲虹梁。", "風臺露榭生光飾，死灰棄置參與商。", "盛時一去貴反賤，桃笙葵扇安可常。"]'),
('fc57bcad-f98d-4152-ac21-3a633ab7426f','雜曲歌辭 行路難','鮑溶','唐','唐诗','tang','','[]','玉堂向夕如無人，絲竹儼然宮商死。',80,'全唐诗/poet.tang.1000.json','["玉堂向夕如無人，絲竹儼然宮商死。", "細人何言入君耳？塵生金尊酒如水。", "君今不念歲蹉跎，雁天明明涼露多。", "華燈青凝久照夜，綵童窈窕虛垂羅。", "入宮見妬君不察，莫入此地出風波。"]'),
('955d967d-4df1-48ac-a81f-4965efe8dc37','雜曲歌辭 行路難五首 一','僧貫休','唐','唐诗','tang','','[]','不會當時作天地，剛有多般愚與智。',99,'全唐诗/poet.tang.1000.json','["不會當時作天地，剛有多般愚與智。", "到頭還用真宰心，何如上下皆清氣。", "大道冥冥不知處，那堪頓得羲和轡。", "義不義兮仁不仁，擬學長生更容易。", "負心爲爐復爲火，緣木求魚應且止。", "君不見燒金煉石古帝王，鬼火熒熒白楊裏。"]'),
('efd95247-1ecf-4032-ad4f-4e2b3e875f85','雜曲歌辭 行路難五首 二','僧貫休','唐','唐诗','tang','','[]','君不見道傍廢井生古木，本是驕奢貴人屋。',113,'全唐诗/poet.tang.1000.json','["君不見道傍廢井生古木，本是驕奢貴人屋。", "幾度美人照影來，素綆銀缾濯纖玉。", "雲飛雨散今如此，繡闥雕甍作荒谷。", "沸渭笙歌君莫誇，不應長是西家哭。", "休說遺編行者幾，至竟終須合天理。", "敗他成此亦何功，蘇張終作多言鬼。", "行路難，行路難，不在羊腸裏。"]'),
('13b62101-428b-4ace-adab-6491df65e655','雜曲歌辭 行路難五首 三','僧貫休','唐','唐诗','tang','','[]','九有茫茫共堯日，浪死虛生亦非一。',88,'全唐诗/poet.tang.1000.json','["九有茫茫共堯日，浪死虛生亦非一。", "清淨玄音竟不聞，花眼酒腸暗如漆。", "或偶因片言隻字登第光二親，又不能獻可替不航要津。", "口談羲軒與周孔，履行不及屠沽人。", "行路難，行路難，日暮途遠空悲歎。"]'),
('b79db72a-d0ca-42d1-846e-43cb64cea188','雜曲歌辭 行路難五首 四','僧貫休','唐','唐诗','tang','','[]','君不見道傍樹有寄生枝，青青鬱鬱同榮衰。',115,'全唐诗/poet.tang.1000.json','["君不見道傍樹有寄生枝，青青鬱鬱同榮衰。", "無情之物尚如此，爲人不及還堪悲。", "父歸墳兮未朝夕，已分黃金爭田宅。", "高堂老母頭似霜，心作數支淚常滴。", "我聞忽如負芒刺，不獨爲君空歎息。", "古人尺布猶可縫，潯陽義犬令人憶。", "寄言世上爲人子，孝義團圓莫如此。"]'),
('18d97728-ded9-4a2d-beb2-d4e66945fcc1','雜曲歌辭 行路難五首 五','僧貫休','唐','唐诗','tang','','[]','君不見山高海深人不測，古往今來轉青碧。',63,'全唐诗/poet.tang.1000.json','["君不見山高海深人不測，古往今來轉青碧。", "淺近輕浮莫與交，池卑只解生荆棘。", "誰道黃金如糞土，張耳陳餘斷消息。", "行路難，行路難，君自看。"]'),
('0216919e-398c-4028-ac06-ca7b2d4852ba','雜曲歌辭 行路難二首 一','僧齊己','唐','唐诗','tang','','[]','行路難，君好看。',86,'全唐诗/poet.tang.1000.json','["行路難，君好看。", "驚波不在黤黮間，小人心裏藏奔湍。", "七盤九折寒崷崪，翻車倒蓋猶堪出。", "未似是非脣舌危，闇中潛毀平人骨。", "君不見楚靈均，千古沈冤湘水濱。", "又不見李太白，一朝却作江南客。"]'),
('d5935b82-f49f-4547-ac41-fd71911825d8','雜曲歌辭 行路難二首 二','僧齊己','唐','唐诗','tang','','[]','下浸與高盤，不爲行路難。',48,'全唐诗/poet.tang.1000.json','["下浸與高盤，不爲行路難。", "是非真險惡，翻覆作峰巒。", "漆媿同時黑，朱慙巧處丹。", "令人畏相識，欲畫白雲看。"]'),
('832147f1-7dcc-4626-b3fc-0d197f29ad77','雜曲歌辭 行路難','翁綬','唐','唐诗','tang','','[]','行路艱難不復歌，故人榮達我蹉跎。',64,'全唐诗/poet.tang.1000.json','["行路艱難不復歌，故人榮達我蹉跎。", "雙輪晚上銅梁雪，一葉春浮瘴海波。", "自古要津皆若此，方今失路欲如何？", "君看西漢翟丞相，鳳沼朝辭暮雀羅。"]'),
('debe2ac4-0b95-48c8-b3b1-33f5600b04c0','雜曲歌辭 行路難','薛能','唐','唐诗','tang','','[]','何處力堪殫？人心險萬端。',72,'全唐诗/poet.tang.1000.json','["何處力堪殫？人心險萬端。", "藏山難測度，暗水自波瀾。", "對面如千里，迴腸似七盤。", "已經吳坂困，欲向鴈門難。", "南北誠須泣，高深不可干。", "無因善行止，車轍得平安。"]'),
('a50fdaca-5397-4000-8c2c-bfcb9ab8e681','雜曲歌辭 從軍中行路難二首 一','駱賓王','唐','唐诗','tang','','[]','君不見封狐雄虺自成羣，馮深負固結妖氛。',343,'全唐诗/poet.tang.1000.json','["君不見封狐雄虺自成羣，馮深負固結妖氛。", "玉璽分兵徵惡少，金壇受律動將軍。", "將軍擁旄宣廟略，戰士橫行靜夷落。", "長驅一息背銅梁，直指三巴逾劒閣。", "閣道岧嶤上戍樓，劒門遙裔俯靈丘。", "邛關九折無平路，江水雙源有急流。", "征役無期返，他鄉歲華晚。", "杳杳丘陵出，蒼蒼林薄遠。", "途危紫蓋峰，路澀青泥坂。", "去去指哀牢，行行入不毛。", "絕壁千里險，連山四望高。", "中外分區宇，夷夏殊風土。", "交趾枕南荒，昆彌臨北戶。", "川源饒毒霧，溪谷多淫雨。", "行潦四時流，崩查千歲古。", "漂梗飛蓬不自安，捫藤引葛度危巒。", "昔時聞道從軍樂，今日方知行路難。", "蒼江綠水東流駛，炎洲丹徼南中地。", "南中南斗映星河，秦川秦塞阻煙波。", "三春邊地風光少，五月瀘中瘴癘多。", "朝驅疲斥候，夕息倦誰何。", "向月彎繁弱，連星轉太阿。", "重義輕生懷一顧，東伐西征凡幾度。", "夜夜朝朝斑鬢新，年年歲歲戎衣故。"]'),
('ede162c2-2d52-4ead-a96f-5e14e96369ac','雜曲歌辭 從軍中行路難二首 二','駱賓王','唐','唐诗','tang','','[]','君不見玉關塵色暗邊亭，銅鞮雜虜寇長城。',207,'全唐诗/poet.tang.1000.json','["君不見玉關塵色暗邊亭，銅鞮雜虜寇長城。", "天子按劒徵餘勇，將軍受脤事橫行。", "七德龍韜開玉帳，千里鼉鼓疊金鉦。", "陰山苦霧埋高壘，交河孤月照連營。", "連營去去無窮極，擁斾遙遙過絕國。", "陣雲朝結晦天山，寒沙夕漲迷疎勒。", "龍鱗水上開魚貫，馬首山前振鵰翼。", "長驅萬里讋祁連，分麾三命武功宣。", "百發烏號遙碎柳，七尺龍文迥照蓮。", "春來秋去移灰琯，蘭閨柳市芳塵斷。", "鴈門迢遰尺書稀，鴛被相思雙帶緩。", "行路難，誓令氛祲靜皐蘭。", "但使封侯龍額貴，詎隨中婦鳳樓寒。"]'),
('447e1bf3-306c-4dc3-86db-6a279f2a8257','雜曲歌辭 變行路難','王昌齡','唐','唐诗','tang','','[]','向晚橫吹悲，風動馬嘶合。',48,'全唐诗/poet.tang.1000.json','["向晚橫吹悲，風動馬嘶合。", "前驅引旗節，千重陣雲帀。", "單于下陰山，砂礫空颯颯。", "封侯取一戰，豈復念閨閤。"]'),
('6b939a56-7ec3-4f83-a887-48db856ae272','雜曲歌辭 古別離','沈佺期','唐','唐诗','tang','','[]','白水東悠悠，中有西行舟。',96,'全唐诗/poet.tang.1000.json','["白水東悠悠，中有西行舟。", "舟行有返棹，水去無還流。", "奈何生別者，戚戚懷遠遊。", "遠遊誰當惜，所悲會難收。", "自君間芳躧，青陽四五遒。", "皓月掩蘭室，光風虛蕙樓。", "相思無明晦，長歎累冬秋。", "離居分遲暮，駕高何淹留。"]'),
('d85a6f55-150a-4e1e-8382-c9ba95c38f39','雜曲歌辭 古別離','孟雲卿','唐','唐诗','tang','','[]','朝日上高臺，離人怨秋草。',108,'全唐诗/poet.tang.1000.json','["朝日上高臺，離人怨秋草。", "但見萬里天，不見萬里道。", "君行本遙遠，苦樂良難保。", "宿昔夢同衾，憂心夢顛倒。", "含酸欲誰訴，轉轉傷懷抱。", "結髮年已遲，征行去何早。", "寒暄有時謝，顦顇難再好。", "人皆算年壽，死者何曾老。", "少壯無見期，水深風浩浩。"]'),
('b8ca61a8-148b-4046-8829-7165fc6cb503','雜曲歌辭 古別離','李益','唐','唐诗','tang','','[]','雙劒欲別風悽然，雌沈水底雄上天。',48,'全唐诗/poet.tang.1000.json','["雙劒欲別風悽然，雌沈水底雄上天。", "江迴漢轉兩不見，雲交雨合知何年。", "古來萬事皆由命，何用臨岐苦涕漣。"]'),
('1d47d568-f9fa-4e5f-8dcb-9ae5ac6c2cac','雜曲歌辭 古別離二首 一','于濆','唐','唐诗','tang','','[]','入室少情意，出門多路岐。',72,'全唐诗/poet.tang.1000.json','["入室少情意，出門多路岐。", "黃鶴有歸日，蕩子無還時。", "人誰無分命，妾身何太奇。", "君爲東南風，妾作西北枝。", "青樓鄰里婦，終年畫長眉。", "自倚對良匹，笑妾空羅幃。"]'),
('24d00fc4-4043-4ce6-bb89-efcb1f3b3d7c','雜曲歌辭 古別離二首 二','于濆','唐','唐诗','tang','','[]','郎本東家兒，妾本西家女。',48,'全唐诗/poet.tang.1000.json','["郎本東家兒，妾本西家女。", "對門中道間，終謂無離阻。", "豈知中道間，遣作空閨主。", "自是愛封侯，非關備胡虜。"]'),
('6fcf9b47-d7b1-4d40-9121-99c57c4747e3','雜曲歌辭 古別離二首 一','李端','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','水國葉黃時，洞庭霜落夜。',96,'全唐诗/poet.tang.1000.json','["水國葉黃時，洞庭霜落夜。", "行舟聞商估，宿在楓林下。", "此地送君還，茫茫似夢間。", "後期知幾日，前路轉多山。", "巫峽通湘浦，迢迢隔雲雨。", "天晴見海檣，月落聞津鼓。", "人老自多愁，水深難急流。", "清宵歌一曲，白首對汀洲。"]'),
('04f7819f-2ca3-43bf-afbc-26cb4f5cd0f1','雜曲歌辭 古別離二首 二','李端','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','與君桂陽別，令君岳陽待。',132,'全唐诗/poet.tang.1000.json','["與君桂陽別，令君岳陽待。", "後事忽差池，前期日空在。", "木落鴈嗷嗷，洞庭波浪高。", "遠山雲似蓋，極浦樹如毫。", "朝發能幾里，暮來風又起。", "如何兩處愁，皆在孤舟裏。", "昨夜天月明，長川寒且清。", "菊花開欲盡，薺菜拍來生。", "下江帆勢速，五兩遙相逐。", "欲問去時人，知投何處宿。", "空令猨嘯時，泣對湘潭竹。"]'),
('d842953e-6c4b-46bf-8eed-3315ad11c7fc','雜曲歌辭 古別離','王縉','唐','唐诗','tang','','[]','下階欲離別，相對映蘭叢。',48,'全唐诗/poet.tang.1000.json','["下階欲離別，相對映蘭叢。", "含辭未及吐，淚落蘭叢中。", "高堂靜秋日，羅衣飄暮風。", "誰能待明月，迴首見牀空。"]'),
('0457d34c-f28a-47a0-aa77-ab3b3a3b14e7','雜曲歌辭 古別離','僧皎然','唐','唐诗','tang','','["\u592a\u6e56"]','太湖三山口，吳王在時道。',104,'全唐诗/poet.tang.1000.json','["太湖三山口，吳王在時道。", "寂寞千載心，無人見春草。", "誰堪緘怨者，持此傷懷抱。", "孤舟畏狂風，一點宿煙島。", "望所思兮若何，月蕩漾兮空波。", "雲離離兮北斷，鴈眇眇兮南多。", "身去兮天畔，心折兮湖岸。", "春山胡爲兮塞路，使我歸夢兮撩亂。"]'),
('dae495a8-d198-4fe8-86d6-a56da79ac7b6','雜曲歌辭 古別離','聶夷中','唐','唐诗','tang','','["\u9001\u522b", "\u5973\u5b50", "\u60c5\u90ce"]','欲別牽郎衣，問郎遊何處？不恨歸日遲，莫向臨邛去。',24,'全唐诗/poet.tang.1000.json','["欲別牽郎衣，問郎遊何處？不恨歸日遲，莫向臨邛去。"]'),
('83383a17-2f32-4c5e-a25b-1b1d9c7873a1','雜曲歌辭 古別離二首 一','施肩吾','唐','唐诗','tang','','[]','古人謾歌西飛燕，十年不見狂夫面。',48,'全唐诗/poet.tang.1000.json','["古人謾歌西飛燕，十年不見狂夫面。", "三更風作切夢刀，萬轉愁成繫腸線。", "所嗟不及牛女星，一年一度得相見。"]'),
('b693eaa3-5152-47da-bb89-56ac4b2d11cd','雜曲歌辭 古別離二首 二','施肩吾','唐','唐诗','tang','','[]','老母別愛子，少妻送征郎。',52,'全唐诗/poet.tang.1000.json','["老母別愛子，少妻送征郎。", "血流既四面，乃亦斷二腸。", "不愁寒無衣，不怕飢無糧。", "惟恐征戰不還鄉，母化爲鬼妻爲孀。"]'),
('53ba7bdc-7c71-435f-b93c-7d7479e6f239','雜曲歌辭 古別離','吳融','唐','唐诗','tang','','[]','紫燕黃鵠雖別離，一舉千里何難追。',96,'全唐诗/poet.tang.1000.json','["紫燕黃鵠雖別離，一舉千里何難追。", "猶聞啼風與叫月，流連斷續令人悲。", "賦情更有深繾綣，碧甃千尋尚爲淺。", "蟾蜍正向清夜流，蛺蝶須教墮絲罥。", "莫道斷絲不可續，丹穴鳳皇膠不遠。", "草草通流水不迴，海上兩潮長不返。"]'),
('567a2bed-87c9-40d6-9a49-6a6fcf776f9d','雜曲歌辭 古離別','王適','唐','唐诗','tang','','[]','昔歲驚楊柳，高樓悲獨守。',112,'全唐诗/poet.tang.1000.json','["昔歲驚楊柳，高樓悲獨守。", "今年芳樹枝，孤棲怨別離。", "珠簾晝不卷，羅幔曉長垂。", "苦調琴先覺，愁容鏡獨知。", "頻來鴈度無消息，罷去鴛文何用織。", "夜還羅帳空有情，春著帬腰自無力。", "青軒桃李落紛紛，紫庭蘭蕙日氛氳。", "已能顦顇今如此，更復含情一待君。"]'),
('f8373bfa-2eab-4e53-9f5c-aa41d9b065d6','雜曲歌辭 古離別','常理','唐','唐诗','tang','','[]','君御狐白裘，妾居緗綺幬。',72,'全唐诗/poet.tang.1000.json','["君御狐白裘，妾居緗綺幬。", "粟鈿金夾膝，花錯玉搔頭。", "離別生庭草，征行斷戍樓。", "蠨蛸網清曙，菡萏落紅秋。", "小膽空房怯，長眉滿鏡愁。", "爲傳兒女意，不用遠封侯。"]'),
('65fb6fba-0ddb-449d-aea5-06cc005fba45','雜曲歌辭 古離別','姚係','唐','唐诗','tang','','[]','涼風已嫋嫋，露重木蘭枝。',48,'全唐诗/poet.tang.1000.json','["涼風已嫋嫋，露重木蘭枝。", "獨上高樓望，行人遠不知。", "輕寒入洞戶，明月滿秋池。", "燕去鴻方至，年年是別離。"]'),
('cdeb9b53-185c-4b96-a83e-adbf55f4e59e','雜曲歌辭 古離別','張彪','唐','唐诗','tang','','[]','離別無遠近，事歡情亦悲。',48,'全唐诗/poet.tang.1000.json','["離別無遠近，事歡情亦悲。", "不聞車輪聲，後會將何時。", "去日忘寄書，來日乖前期。", "縱知明當還，一夕千萬思。"]'),
('dc78a304-0ac7-4e42-b904-6fabc0de0149','雜曲歌辭 古離別','趙微明','唐','唐诗','tang','','[]','違別未幾日，一日如三秋。',48,'全唐诗/poet.tang.1000.json','["違別未幾日，一日如三秋。", "猶疑望可見，日日上高樓。", "惟見分手處，白蘋滿芳洲。", "寸心寧死別，不忍生離愁。"]'),
('e6aad1c8-38bc-44bd-a516-d9a87a0aea99','雜曲歌辭 古離別二首 一','孟郊','唐','唐诗','tang','','[]','松山雲繚繞，萍路水分離。',48,'全唐诗/poet.tang.1000.json','["松山雲繚繞，萍路水分離。", "雲去有歸日，水分無合時。", "春芳役雙眼，春色柔四支。", "楊柳織別愁，千條萬條絲。"]'),
('08b42e3e-75d5-46ef-abe7-bc5cd02668d8','雜曲歌辭 古離別二首 二','孟郊','唐','唐诗','tang','','[]','山川古今路，縱橫無斷絕。',96,'全唐诗/poet.tang.1000.json','["山川古今路，縱橫無斷絕。", "來往天地間，人皆有離別。", "行衣未束帶，中腸已先結。", "不用看鏡中，自知生白髮。", "欲陳去留意，聲向言前咽。", "愁結填心胸，茫茫若爲說。", "荒郊煙莽蒼，曠野風淒切。", "處處得相隨，人那不如月。"]'),
('00b4d14e-5b09-485b-a9f7-5d6e9b9629b4','雜曲歌辭 古離別','顧況','唐','唐诗','tang','','[]','西江上，風動麻姑嫁時浪。',28,'全唐诗/poet.tang.1000.json','["西江上，風動麻姑嫁時浪。", "西山爲水水爲塵，不是人間離別人。"]'),
('9185b303-813a-493d-ae09-5d4979cd90ef','雜曲歌辭 古離別','僧貫休','唐','唐诗','tang','','["\u957f\u6c5f", "\u522b\u79bb", "\u8b66\u793a", "\u7231\u60c5"]','離恨如旨酒，古今飲皆醉。',48,'全唐诗/poet.tang.1000.json','["離恨如旨酒，古今飲皆醉。", "只恐長江水，盡是兒女淚。", "伊余非此輩，送人空把臂。", "他日再相逢，清風動天地。"]'),
('f71778d1-64c3-4270-a9ce-4a94f16c9462','雜曲歌辭 古離別','韋莊','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u666f"]','晴煙漠漠柳毿毿，不那離情酒半酣。',32,'全唐诗/poet.tang.1000.json','["晴煙漠漠柳毿毿，不那離情酒半酣。", "更把馬鞭雲外指，斷腸春色在江南。"]'),
('9a2bdab8-9e68-4478-ade8-11d5fbb822c6','雜曲歌辭 生別離','孟雲卿','唐','唐诗','tang','','[]','結髮生別離，相思復相保。',96,'全唐诗/poet.tang.1000.json','["結髮生別離，相思復相保。", "何知日已久，五變庭中草。", "眇眇天海途，悠悠吳江島。", "但恐不出門，出門無遠道。", "遠道行既難，家貧衣服單。", "嚴風吹積雪，晨起鼻何酸。", "人生各有戀，豈不懷所安。", "分明天上日，生死誓同歡。"]'),
('bdb32446-6efc-402e-93f0-901b8eefe57e','雜曲歌辭 生別離','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','食蘗不易食梅難，蘗能苦兮梅能酸。',128,'全唐诗/poet.tang.1000.json','["食蘗不易食梅難，蘗能苦兮梅能酸。", "未如生別之爲難，苦在心兮酸在肝。", "晨雞載鳴殘月沒，征馬重嘶行人出。", "迴看骨肉哭一聲，梅酸蘗苦甘如蜜。", "黃河水白黃雲秋，行人河邊相對愁。", "天寒野曠何處宿？棠梨葉戰風颼颼。", "生離別，生離別，憂從中來無斷絕。", "憂積心勞血氣衰，未年三十生白髮。"]'),
('495e6bc4-42a4-463e-ac80-b4fa4a6ea878','雜曲歌辭 遠別離','李白','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u79bb\u522b", "\u5199\u4eba", "\u6545\u4e8b", "\u5fe7\u56fd\u5fe7\u6c11", "\u6742\u66f2\u6b4c\u8f9e"]','遠別離，古有皇英之二女，乃在洞庭之南，瀟湘之浦。',179,'全唐诗/poet.tang.1000.json','["遠別離，古有皇英之二女，乃在洞庭之南，瀟湘之浦。", "海水直下萬里深，誰人不言此離苦。", "日慘慘兮雲冥冥，猩猩啼煙兮鬼嘯雨。", "我縱言之將何補，皇穹竊恐不照余之忠誠。", "雷馮馮兮欲吼怒，堯舜當之亦禪禹。", "君失臣兮龍爲魚，權歸臣兮鼠變虎。", "或云堯幽囚，舜野死，九疑聯緜皆相似，重瞳孤墳竟何是。", "帝子泣兮綠雲間，隨風波兮去無還。", "慟哭兮遠望，見蒼梧之深山。", "蒼梧山崩湘水絕，竹上之淚乃可滅。"]'),
('4f866479-db88-497f-b2b6-29dcb0ec2a63','雜曲歌辭 遠別離','張籍','唐','唐诗','tang','','["\u957f\u6c5f"]','蓮葉團團杏花拆，長江鯉魚鰭鬣赤。',64,'全唐诗/poet.tang.1000.json','["蓮葉團團杏花拆，長江鯉魚鰭鬣赤。", "念君少年棄親戚，千里萬里獨爲客。", "誰言遠別心不易，天星墜地能爲石。", "幾時斷得城南陌，勿使居人有行役。"]'),
('7c76bd40-ab40-4b1d-97ed-c3a3dd2d8310','雜曲歌辭 遠別離二首 一','令狐楚','唐','唐诗','tang','','[]','楊柳黃金穗，梧桐碧玉枝。',24,'全唐诗/poet.tang.1000.json','["楊柳黃金穗，梧桐碧玉枝。", "春來消息斷，早晚是歸時。"]'),
('66793505-27a2-4119-beb5-fc018b062fbc','雜曲歌辭 遠別離二首 二','令狐楚','唐','唐诗','tang','','[]','玳織鴛鴦履，金裝翡翠簪。',24,'全唐诗/poet.tang.1000.json','["玳織鴛鴦履，金裝翡翠簪。", "畏人相問著，不擬到城南。"]'),
('0a57cefe-4ed5-4655-ace2-08edb17cdba1','雜曲歌辭 久別離','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6742\u66f2\u6b4c\u8f9e", "\u5973\u5b50", "\u4e50\u5e9c"]','別來幾春未還家，玉窗五見櫻桃花。',96,'全唐诗/poet.tang.1000.json','["別來幾春未還家，玉窗五見櫻桃花。", "況有錦字書，開緘使人嗟。", "至此腸斷彼心絕，雲鬟綠鬢罷攬結。", "愁如迴飆亂白雪，去年寄書報陽臺。", "今年寄書重相催，胡爲東風爲我吹行雲。", "使西來，待來竟不來，落花寂寂委青苔。"]'),
('2f1de501-ff4c-4292-8b4c-5141753afc5d','雜曲歌辭 新別離','戴叔倫','唐','唐诗','tang','','[]','手把杏花枝，未曾經別離。',24,'全唐诗/poet.tang.1000.json','["手把杏花枝，未曾經別離。", "黃昏掩閨後，寂寞自心知。"]'),
('ae14b4a7-e09b-4151-ab64-307800f6d5a7','雜曲歌辭 今別離','崔國輔','唐','唐诗','tang','','[]','送別未能旋，相望連水口。',24,'全唐诗/poet.tang.1000.json','["送別未能旋，相望連水口。", "船行欲映洲，幾度急搖手。"]'),
('0e6f2405-6495-4b50-a112-addbd8054f84','雜曲歌辭 暗別離','劉氏瑤','唐','唐诗','tang','','[]','槐花結子桐葉焦，單飛越鳥嗁青霄。',80,'全唐诗/poet.tang.1000.json','["槐花結子桐葉焦，單飛越鳥嗁青霄。", "翠軒輾雲輕遙遙，燕脂淚迸紅線條。", "瑤草歇芳心耿耿，玉佩無聲畫屏冷。", "朱弦暗斷不見人，風動花枝月中影。", "青鸞脈脈西飛去，海闊天高不知處。"]'),
('a33b0c7a-27af-4daf-9d0d-2d64f8db478b','雜曲歌辭 潛別離','白居易','唐','唐诗','tang','','["\u7231\u60c5"]','不得哭，潛別離，不得語，暗相思，兩心之外無人知。',76,'全唐诗/poet.tang.1000.json','["不得哭，潛別離，不得語，暗相思，兩心之外無人知。", "深籠夜[鎖]獨棲鳥，利劒[春]斷連理枝。", "河水雖濁有清日，烏頭雖黑有白時。", "惟有潛離與暗別，彼此甘心無後期。"]'),
('ab88405a-eab9-4b19-8179-7471d5d865ce','雜曲歌辭 別離曲','張籍','唐','唐诗','tang','','[]','行人結束出門去，馬蹏幾時踏門路。',80,'全唐诗/poet.tang.1000.json','["行人結束出門去，馬蹏幾時踏門路。", "憶昔君初納綵時，不言身屬遼陽戍。", "早知今日當別離，成君家計良爲誰。", "男兒生身自有役，那得悞我少年時。", "不如逐君征戰死，誰能獨老空閨裏。"]'),
('97bebaf8-2310-4683-b9a3-2281f414c53a','雜曲歌辭 別離曲','陸龜蒙','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u4eba", "\u8bae\u8bba"]','丈夫非無淚，不灑離別間。',48,'全唐诗/poet.tang.1000.json','["丈夫非無淚，不灑離別間。", "仗劒對尊酒，恥爲游子顏。", "蝮蛇一螫手，壯士疾解腕。", "所思在功名，離別何足歎。"]'),
('3072c03d-8411-490c-b2f4-ead8056a3bfa','雜曲歌辭 西洲曲','溫庭筠','唐','唐诗','tang','','[]','悠悠復悠悠，昨日下西洲。',168,'全唐诗/poet.tang.1000.json','["悠悠復悠悠，昨日下西洲。", "西洲風色好，遙見武昌樓。", "武昌何鬱鬱，儂家定無匹。", "小婦被流黃，登樓撫瑤瑟。", "朱弦繁復輕，素手直淒清。", "一彈三四解，掩抑似含情。", "南樓登且望，西江廣復平。", "艇子搖兩槳，催過石頭城。", "門前烏臼樹，慘澹天將曙。", "鵾鵊飛復還，郎隨早帆去。", "迴頭語同伴，定復負情儂。", "去帆不安幅，作抵使西風。", "他日相尋索，莫作西洲客。", "西洲人不歸，春草年年碧。"]'),
('02512a3b-3a1c-4a91-809a-7586791afb51','雜曲歌辭 荆州樂','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6742\u66f2\u6b4c\u8f9e", "\u5987\u5973", "\u4e50\u5e9c"]','白帝城邊足風波，瞿塘五月誰敢過。',40,'全唐诗/poet.tang.1000.json','["白帝城邊足風波，瞿塘五月誰敢過。", "荆州麥熟繭成蛾，繅絲憶君頭緒多，撥穀飛鳴奈妾何。"]'),
('c7466a70-7646-42f2-b7cb-e31e3734e8b1','雜曲歌辭 荆州樂二首 一','劉禹錫','唐','唐诗','tang','','[]','渚宮楊柳暗，麥城朝雉飛。',24,'全唐诗/poet.tang.1000.json','["渚宮楊柳暗，麥城朝雉飛。", "可憐踏青伴，乘暖著輕衣。"]'),
('48f8c45d-f720-4d52-ad85-5a7339ea14fd','雜曲歌辭 荆州樂二首 二','劉禹錫','唐','唐诗','tang','','[]','今日好南風，商旅相催發。',24,'全唐诗/poet.tang.1000.json','["今日好南風，商旅相催發。", "沙頭檣竿上，始見春江闊。"]'),
('84817a87-9ee4-4fc1-8207-68ba2ef51bc0','雜曲歌辭 荆州泊','李端','唐','唐诗','tang','','[]','南樓西下時，月裏聞來棹。',48,'全唐诗/poet.tang.1000.json','["南樓西下時，月裏聞來棹。", "桂水舳艫回，荆州津濟鬧。", "移帷望星漢，引帶思容貌。", "今夜一江人，惟應妾身覺。"]'),
('ee2f7142-ec63-4efb-ad6b-b26db2c7255c','雜曲歌辭 紀南歌','劉禹錫','唐','唐诗','tang','','[]','風煙紀南城，塵土荆門路。',24,'全唐诗/poet.tang.1000.json','["風煙紀南城，塵土荆門路。", "天寒獵獸者，走上樊姬墓。"]'),
('b4b28471-1a3e-47f0-a72b-8893ea3115a5','雜曲歌辭 宜城歌','劉禹錫','唐','唐诗','tang','','[]','野水遶空城，行塵起孤驛。',36,'全唐诗/poet.tang.1000.json','["野水遶空城，行塵起孤驛。", "花臺側生樹，石碣陽鐫頭。", "靡靡度行人，溫風吹宿麥。"]'),
('4bef9a5e-f4a1-44bd-a78c-cb0fe38ccdff','雜曲歌辭 長干曲四首 一','崔顥','唐','唐诗','tang','','["\u5b64\u72ec", "\u5973\u5b50", "\u601d\u4e61", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','君家定何處？妾住在橫塘。',24,'全唐诗/poet.tang.1000.json','["君家定何處？妾住在橫塘。", "停舟暫借問，或恐是同鄉。"]'),
('8d480633-1876-4082-aaca-a7b3a26c04d7','雜曲歌辭 長干曲四首 二','崔顥','唐','唐诗','tang','','["\u5bb6\u4e61", "\u5973\u5b50", "\u70ed\u7231", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','家臨九江水，去來九江側。',24,'全唐诗/poet.tang.1000.json','["家臨九江水，去來九江側。", "同是長干人，生小不相識。"]'),
('de3624ff-f06e-4552-8e8c-22e75c3e6303','雜曲歌辭 長干曲四首 三','崔顥','唐','唐诗','tang','','[]','下渚多風浪，蓮舟漸覺稀。',24,'全唐诗/poet.tang.1000.json','["下渚多風浪，蓮舟漸覺稀。", "那能不相待，獨自逆潮歸。"]'),
('4e1d3e0d-b5d7-4d30-bce9-9fd69e694a80','雜曲歌辭 長干曲四首 四','崔顥','唐','唐诗','tang','','[]','三江潮水急，五湖風浪湧。',24,'全唐诗/poet.tang.1000.json','["三江潮水急，五湖風浪湧。", "由來花性輕，莫畏蓮舟重。"]'),
('1352fbf1-2c3d-459c-b4ac-061e0c6befb8','雜曲歌辭 長干行二首 一','李白','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','妾髮初覆額，折花門前劇。',180,'全唐诗/poet.tang.1000.json','["妾髮初覆額，折花門前劇。", "郎騎竹馬來，遶牀弄青梅。", "同居長干里，兩小無嫌猜。", "十四爲君婦，羞顏尚不開。", "低頭向暗壁，千喚不一迴。", "十五始展眉，願同塵與灰。", "常存抱柱信，豈上望夫臺。", "十六君遠行，瞿塘灩預堆。", "五月不可觸，猨鳴天上哀。", "門前遲行跡，一一生綠苔。", "苔深不能掃，落葉秋風早。", "八月蝴蝶來，雙飛西園草。", "感此傷妾心，坐愁紅顏老。", "早晚下三巴，預將書報家。", "相迎不道遠，直至長風沙。"]'),
('529cf938-bb80-4453-b73f-7425d18396e4','雜曲歌辭 長干行二首 二','李白','唐','唐诗','tang','','[]','憶妾深閨裏，煙塵不曾識。',168,'全唐诗/poet.tang.1000.json','["憶妾深閨裏，煙塵不曾識。", "嫁與長干人，沙頭候風色。", "五月南風興，思君在巴陵。", "八月西風起，想君發揚子。", "去來悲如何，見少別離多。", "湘潭幾日到，妾夢越風波。", "昨夜狂風度，吹折江頭樹。", "淼淼暗無邊，行人在何處？", "北客真王公，朱衣滿江中。", "日暮來投宿，數朝不肎東。", "好乘浮雲驄，佳期蘭渚東。", "鴛鴦綠浦上，翡翠錦屏中。", "自憐十五餘，顏色桃李紅。", "那作商人婦，愁水復愁風。"]'),
('157a14f5-9ce9-41a4-ad4d-05e4b7ba595e','雜曲歌辭 長干行','張潮','唐','唐诗','tang','','[]','壻貧如珠玉，壻富如埃塵。',144,'全唐诗/poet.tang.1000.json','["壻貧如珠玉，壻富如埃塵。", "貧時不忘舊，富貴多寵新。", "妾本富家女，與君爲偶匹。", "惠好一何深，中門不曾出。", "妾有繡衣裳，葳蕤金縷光。", "念君貧且賤，易此從遠方。", "遠方三千里，發去悔不已。", "日暮情更來，空望去時水。", "孟夏麥始秀，江上多南風。", "商賈歸欲盡，君今尚巴東。", "巴東有巫山，窈窕神女顏。", "常恐遊此山，果然不知還。"]'),
('cf218c4b-ebb6-4ae0-8aaa-7ad0da70c949','雜曲歌辭 小長干曲','崔國輔','唐','唐诗','tang','','[]','月暗送湖風，相尋路不通。',24,'全唐诗/poet.tang.1000.json','["月暗送湖風，相尋路不通。", "菱歌唱不輟，知在此塘中。"]'),
('eee43be4-f6fe-4f0a-976e-a7a3279c26ee','雜曲歌辭 杞梁妻','僧貫休','唐','唐诗','tang','','[]','秦之無道兮四海枯，築長城兮遮北胡。',81,'全唐诗/poet.tang.1000.json','["秦之無道兮四海枯，築長城兮遮北胡。", "築人築土一萬里，杞梁貞婦嗁嗚嗚。", "上無父兮中無夫，下無子兮孤復孤。", "一號城崩塞色苦，再號杞梁骨出土。", "疲魂飢魄相逐歸，陌上少年莫相非。"]'),
('9ad6cb9c-3c3a-4140-9197-03bed14ca119','雜曲歌辭 盧女曲','崔顥','唐','唐诗','tang','','[]','二月春來半，宮中日漸長。',48,'全唐诗/poet.tang.1000.json','["二月春來半，宮中日漸長。", "柳垂金屋暖，花覆玉樓香。", "拂匣先臨鏡，調笙更炙簧。", "還將盧女曲，夜夜奉君王。"]'),
('ec0707a9-2298-40f6-bd03-100847a86e97','雜曲歌辭 盧姬篇','崔顥','唐','唐诗','tang','','[]','盧姬小小魏王家，綠鬢紅脣桃李花。',112,'全唐诗/poet.tang.1000.json','["盧姬小小魏王家，綠鬢紅脣桃李花。", "魏王綺樓十二重，水精簾箔繡芙蓉。", "白玉闌干金作柱，樓上朝朝學歌舞。", "前堂後堂羅袖人，南窗北窗花發春。", "翠幌珠簾鬬弦管，一奏一彈雲欲斷。", "君王日晚下朝歸，鳴環佩玉生光輝。", "人生今日得驕貴，誰道盧姬身細微。"]'),
('1927aaaf-c323-4b29-88cb-95f77886d5bd','雜曲歌辭 邯鄲才人嫁爲廝養卒婦','李白','唐','唐诗','tang','','["\u5199\u4eba", "\u5973\u5b50", "\u5199\u4eba\u8bd7"]','妾本叢臺女，揚蛾入丹闕。',60,'全唐诗/poet.tang.1000.json','["妾本叢臺女，揚蛾入丹闕。", "自倚顏如花，寧知有凋歇。", "一辭玉階下，去若朝雲沒。", "每憶邯鄲城，深宮夢秋月。", "君王不可見，惆悵至明發。"]'),
('5d26ae92-8701-4cba-ac21-43755964f77c','雜曲歌辭 楊白花','柳宗元','唐','唐诗','tang','','[]','楊白花，風吹度江水。',42,'全唐诗/poet.tang.1000.json','["楊白花，風吹度江水。", "坐令宮樹無顏色，搖蕩春光千萬里。", "茫茫曉日下長秋，哀歌未斷城鵶起。"]'),
('dc988aaa-b1e6-4a0f-b0e5-798d42652c8c','雜曲歌辭 茱萸女','萬楚','唐','唐诗','tang','','[]','山陰柳家女，九日采茱萸。',84,'全唐诗/poet.tang.1000.json','["山陰柳家女，九日采茱萸。", "復得東鄰伴，雙爲陌上姝。", "插花向高髻，結子置長裾。", "作性恆遲緩，非關詫丈夫。", "平明折林樹，日入反城隅。", "俠客邀羅袖，行人挑短書。", "蛾眉自有主，年少莫踟躕。"]'),
('21aab035-72a4-49cb-b3a3-0be7e553f2d8','雜曲歌辭 于闐采花','李白','唐','唐诗','tang','','["\u7528\u4eba", "\u6742\u66f2\u6b4c\u8f9e", "\u611f\u4f24", "\u4e50\u5e9c"]','于闐采花人，自言花相似。',72,'全唐诗/poet.tang.1000.json','["于闐采花人，自言花相似。", "明妃一朝西入胡，胡中美女多羞死。", "乃知漢地多名姝，胡中無花可方比。", "丹青能令醜者妍，無鹽翻在深宮裏。", "自古妬蛾眉，胡沙埋皓齒。"]'),
('af16773b-0873-4690-b802-9f3825d1efef','雜曲歌辭 秦女卷衣','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u7231\u60c5", "\u4e50\u5e9c"]','天子居未央，妾侍卷衣裳。',60,'全唐诗/poet.tang.1000.json','["天子居未央，妾侍卷衣裳。", "顧無紫宮寵，敢拂黃金牀。", "水至亦不去，熊來尚可當。", "微身奉日月，飄若螢火光。", "願君采葑菲，無以下體妨。"]'),
('42bc232f-00c5-4e92-8c55-8f38280a9dbe','雜曲歌辭 愛妾換馬 一','張祜','唐','唐诗','tang','','[]','一面妖桃千里蹏，嬌姿駿背價應齊。',64,'全唐诗/poet.tang.1000.json','["一面妖桃千里蹏，嬌姿駿背價應齊。", "乍牽玉勒辭金棧，催整花鈿出繡閨。", "去日豈無霑袂泣，歸時還有頓銜嘶。", "嬋娟躞蹀春風裏，揮手搖鞭楊柳堤。"]'),
('a46125e8-7617-40ac-90f6-35d2f9af010c','雜曲歌辭 愛妾換馬 二','張祜','唐','唐诗','tang','','[]','綺閣香銷華厩空，忍將行雨換追風。',64,'全唐诗/poet.tang.1000.json','["綺閣香銷華厩空，忍將行雨換追風。", "休憐柳葉雙眉翠，卻愛桃花兩耳紅。", "侍宴永辭春色裏，趁朝休立漏聲中。", "恩勞未盡情先盡，暗泣嘶風兩意同。"]'),
('dc3453b2-0268-4064-90a5-1a3d17192724','雜曲歌辭 枯魚過河泣','李白','唐','唐诗','tang','','[]','白龍改常服，偶被豫且制。',60,'全唐诗/poet.tang.1000.json','["白龍改常服，偶被豫且制。", "誰使爾爲魚，徒勞訴天帝。", "作書報鯨鯢，勿恃風濤勢。", "濤落歸泥沙，翻遭螻蟻噬。", "萬乘慎出入，柏人以爲誡。"]'),
('ead76427-5fa0-475e-bc09-3feb81b89a6a','雜曲歌辭 飲酒樂','聶夷中','唐','唐诗','tang','','[]','日月似有事，一夜行一周。',72,'全唐诗/poet.tang.1000.json','["日月似有事，一夜行一周。", "草木猶須老，人生得無愁。", "一飲解百結，再飲破百憂。", "白髮欺貧賤，不入醉人頭。", "我願東海水，盡向杯中流。", "安得阮步兵，同入醉鄉遊。"]'),
('5b7a301f-f717-4fd1-a39f-f0db207a0887','雜曲歌辭 王孫遊','崔國輔','唐','唐诗','tang','','[]','自與王孫別，頻看黃鳥飛。',24,'全唐诗/poet.tang.1000.json','["自與王孫別，頻看黃鳥飛。", "應由春草誤，著處不成歸。"]'),
('9bb05363-395d-48f6-b28a-55d3e414d6cf','雜曲歌辭 發白馬','李白','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u6218\u4e89", "\u5199\u9a6c", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c", "\u9a6c"]','將軍發白馬，旌節渡黃河。',96,'全唐诗/poet.tang.1000.json','["將軍發白馬，旌節渡黃河。", "簫鼓聒川嶽，滄溟湧洪波。", "武安有振瓦，易水無寒歌。", "鐵騎若雪山，飲流涸滹沱。", "揚兵獵月窟，轉戰畧朝那。", "倚劍登燕然，邊峰列嵯峨。", "蕭條萬里外，耕作五原多。", "一掃清大漠，包虎戢金戈。"]'),
('b422712d-ef98-46d3-b967-0a2c5c000fc7','雜曲歌辭 結韈子','李白','唐','唐诗','tang','','["\u6cf0\u5c71", "\u5199\u4eba", "\u548f\u53f2\u6000\u53e4", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','燕南壯士吳門豪，筑中置鉛魚隱刀。',32,'全唐诗/poet.tang.1000.json','["燕南壯士吳門豪，筑中置鉛魚隱刀。", "感君恩重許君命，泰山一擲輕鴻毛。"]'),
('3bbd4504-0c3d-4ab5-a537-3da6eab3eb29','雜曲歌辭 沐浴子','李白','唐','唐诗','tang','','[]','沐芳莫彈冠，浴蘭莫振衣。',36,'全唐诗/poet.tang.1000.json','["沐芳莫彈冠，浴蘭莫振衣。", "處世忌太潔，志人貴藏輝。", "滄浪有釣叟，吾與爾同歸。"]'),
('d201d25e-b274-479a-96b0-2465250dc564','雜曲歌辭 三臺二首 一','韋應物','唐','唐诗','tang','','[]','一年一年老去，明日後日花開。',28,'全唐诗/poet.tang.1000.json','["一年一年老去，明日後日花開。", "未報長安平定，萬國豈得銜杯。"]'),
('283d3d6b-8182-488d-8d04-9b3bc3a4da26','雜曲歌辭 三臺二首 二','韋應物','唐','唐诗','tang','','[]','冰泮寒塘始綠，雨餘百草皆生。',28,'全唐诗/poet.tang.1000.json','["冰泮寒塘始綠，雨餘百草皆生。", "朝來門閤無事，晚下高齋有情。"]'),
('ed42eaf6-78fd-493d-acf6-612c30c704fc','雜曲歌辭 上皇三臺','韋應物','唐','唐诗','tang','','[]','不寐倦長更，披衣出戶行。',24,'全唐诗/poet.tang.1000.json','["不寐倦長更，披衣出戶行。", "月寒秋竹冷，風切夜窗聲。"]'),
('7474cb5a-0ad3-485b-b8f9-90af07d6f51a','雜曲歌辭 突厥三臺','韋應物','唐','唐诗','tang','','[]','鴈門山上鴈初飛，馬邑闌中馬正肥。',32,'全唐诗/poet.tang.1000.json','["鴈門山上鴈初飛，馬邑闌中馬正肥。", "日旰山西逢驛使，殷勤南北送征衣。"]'),
('40501915-700c-4cbe-8232-c5905a115f97','雜曲歌辭 宮中三臺二首 一','王建','唐','唐诗','tang','','[]','魚藻池邊射鴨，芙蓉園裏看花。',28,'全唐诗/poet.tang.1000.json','["魚藻池邊射鴨，芙蓉園裏看花。", "日色柘袍相似，不著紅鸞扇遮。"]'),
('49fb819b-564d-47ec-b0c1-fabe5924176a','雜曲歌辭 宮中三臺二首 二','王建','唐','唐诗','tang','','[]','池北池南草綠，殿前殿後花紅。',28,'全唐诗/poet.tang.1000.json','["池北池南草綠，殿前殿後花紅。", "天子千年萬歲，未央明月清風。"]'),
('14a9ef0e-ad64-4dba-83ad-91719b1499da','雜曲歌辭 江南三臺四首 一','王建','唐','唐诗','tang','','[]','揚州橋邊小婦，長干市裏商人。',28,'全唐诗/poet.tang.1000.json','["揚州橋邊小婦，長干市裏商人。", "三年不得消息，各自拜鬼求神。"]'),
('d7bbc9ec-1800-4da3-9ed2-b06b5ea19684','雜曲歌辭 江南三臺四首 二','王建','唐','唐诗','tang','','[]','青草湖邊草色，飛猨嶺上猨聲。',28,'全唐诗/poet.tang.1000.json','["青草湖邊草色，飛猨嶺上猨聲。", "萬里三湘客到，有風有雨人行。"]'),
('38aaa671-b84f-4419-a483-f2f4613d0bf5','雜曲歌辭 江南三臺四首 三','王建','唐','唐诗','tang','','[]','樹頭花落花開，道上人去人來。',28,'全唐诗/poet.tang.1000.json','["樹頭花落花開，道上人去人來。", "朝愁暮愁即老，百年幾度三臺。"]'),
('f26fae5d-2f45-409d-8401-bc28cddda693','雜曲歌辭 江南三臺四首 四','王建','唐','唐诗','tang','','[]','聞身彊健且爲，頭白齒落難追。',28,'全唐诗/poet.tang.1000.json','["聞身彊健且爲，頭白齒落難追。", "准擬百年千歲，能得幾許多時。"]'),
('434c8a6e-2cd4-4195-bf8c-08d9a32b3095','雜曲歌辭 築城曲','張籍','唐','唐诗','tang','','[]','築城去，千人萬人齊抱杵。',76,'全唐诗/poet.tang.1000.json','["築城去，千人萬人齊抱杵。", "重重土堅試行錐，軍吏執鞭催作遲。", "來時一年深磧裏，著盡短衣渴無水。", "力盡不得拋杵聲，杵聲未定人皆死。", "家家養男當門戶，今日作君城下土。"]'),
('81023b90-e4af-4540-bcc2-5d99bd77ab28','雜曲歌辭 築城曲五解','元稹','唐','唐诗','tang','','[]','年年塞下丁，長作出塞兵。',120,'全唐诗/poet.tang.1000.json','["年年塞下丁，長作出塞兵。", "自從冒頓彊，官築遮虜城。", "築城須努力，城高遮得賊。", "但恐賊路多，有城遮不得。", "丁口傳父口，莫問城堅不。", "平城被虜圍，漢斸城牆走。", "因茲虜請和，虜往騎來多。", "半疑兼半信，築城猶嵯峨。", "築城安敢煩，願聽丁一言。", "請築鴻臚寺，兼愁虜出關。"]'),
('499f57c6-97bf-4fd3-8010-d76a4f3ebc0b','雜曲歌辭 築城曲','陸龜蒙','唐','唐诗','tang','','[]','城上一掊土，手中千萬杵。',48,'全唐诗/poet.tang.1000.json','["城上一掊土，手中千萬杵。", "築城畏不堅，堅城在何處？", "莫歎築城勞，將軍要却敵。", "城高功亦高，爾命何處惜。"]'),
('26b7a177-210b-4d15-8e26-e17db2d1ca13','雜曲歌辭 湖陰曲','溫庭筠','唐','唐诗','tang','','[]','祖龍黃須珊瑚鞭，鐵驄金面青連錢。',128,'全唐诗/poet.tang.1000.json','["祖龍黃須珊瑚鞭，鐵驄金面青連錢。", "虎髯拔劒欲成夢，日壓賊營如血鮮。", "海旗風急驚眠起，甲重光搖照湖水。", "蒼黃追騎塵外歸，森索妖星陣前死。", "五陵愁碧春萋萋，灞川玉馬空中嘶。", "羽書如電入青瑣，雪腕如搥催畫鞞。", "白虬天子金煌鋩，高臨帝座迴龍章。", "吳波不動楚山晚，花壓闌干春晝長。"]'),
('5aca9b73-4673-4dbf-a5dc-65add8136e76','雜曲歌辭 無愁果有愁曲','李商隱','唐','唐诗','tang','','[]','東有青龍西白虎，中含福皇包世度。',112,'全唐诗/poet.tang.1000.json','["東有青龍西白虎，中含福皇包世度。", "玉壺渭水笑清潭，鑿天不到牽牛處。", "騏驎踏雲天馬獰，牛山撼碎珊瑚聲。", "秋娥點滴不成淚，十二玉樓無故釘。", "推煙唾月拋千里，十番紅桐一行死。", "白楊別屋鬼迷人，空留暗記如蠶紙。", "日暮向風牽短絲，血凝血散今誰是。"]'),
('27ce9f4a-b246-472d-b3c5-6f20fcdf2cc4','雜曲歌辭 起夜來','施肩吾','唐','唐诗','tang','','[]','香銷連理帶，塵覆合歡杯。',24,'全唐诗/poet.tang.1000.json','["香銷連理帶，塵覆合歡杯。", "嬾臥相思枕，愁吟起夜來。"]'),
('ec880efb-495d-48aa-9764-a827c4bd8864','雜曲歌辭 起夜半','聶夷中','唐','唐诗','tang','','[]','念遠心如燒，不覺中夜起。',24,'全唐诗/poet.tang.1000.json','["念遠心如燒，不覺中夜起。", "桃花帶露泛，立在月明裏。"]'),
('15079155-e95e-4abc-b36e-f6b605848f37','雜曲歌辭 獨不見','沈佺期','唐','唐诗','tang','','["\u601d\u5ff5", "\u95fa\u6028", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','盧家小婦鬱金堂，海燕雙栖玳瑁梁。',64,'全唐诗/poet.tang.1000.json','["盧家小婦鬱金堂，海燕雙栖玳瑁梁。", "九月寒砧催下葉，十年征戍憶遼陽。", "白狼河北音書斷，丹鳳城南秋夜長。", "誰知含愁獨不見，使妾明月照流黃。"]'),
('7684cf1b-97f8-4697-bb08-6990dc5f72e0','雜曲歌辭 獨不見','王訓','唐','唐诗','tang','','[]','日晚宜春暮，風輭上林朝。',48,'全唐诗/poet.tang.1000.json','["日晚宜春暮，風輭上林朝。", "對酒近初節，開樓蕩夜嬌。", "石橋通小澗，竹路上青霄。", "持底誰見許，長愁成細腰。"]'),
('7ffd2c22-09b3-46cf-a0b6-62d503e26cf2','雜曲歌辭 獨不見','楊巨源','唐','唐诗','tang','','[]','東風豔陽色，柳綠花如霰。',48,'全唐诗/poet.tang.1000.json','["東風豔陽色，柳綠花如霰。", "競理同心鬟，爭持合歡扇。", "香傳賈娘手，粉離何郎面。", "最恨卷簾時，含情獨不見。"]'),
('f406635d-5044-4232-bd70-e34b542803b6','雜曲歌辭 獨不見','李白','唐','唐诗','tang','','["\u601d\u5ff5", "\u6742\u66f2\u6b4c\u8f9e", "\u5973\u5b50", "\u4e50\u5e9c"]','白馬誰家子，黃龍邊塞兒。',84,'全唐诗/poet.tang.1000.json','["白馬誰家子，黃龍邊塞兒。", "天山三丈雪，豈是遠行時。", "春蕙忽秋草，莎雞鳴曲池。", "風催寒椶響，月入霜閨悲。", "憶與君別年，種桃齊蛾眉。", "桃今百餘尺，花落成枯枝。", "終然獨不見，流淚空自知。"]'),
('fc1c3862-676c-4eb6-822d-4c5fe33df317','雜曲歌辭 獨不見','戴叔倫','唐','唐诗','tang','','[]','前宮路非遠，舊苑春將遍。',60,'全唐诗/poet.tang.1000.json','["前宮路非遠，舊苑春將遍。", "玉戶看早梅，雕梁數歸燕。", "身輕逐舞袖，香暖傳歌扇。", "自知秋風詞，長侍昭陽殿。", "誰信後庭人，年年獨不見。"]'),
('3d3e36fd-515d-43e3-9336-c3e827a93bdc','雜曲歌辭 獨不見','胡曾','唐','唐诗','tang','','[]','玉關一自有氛埃，年少從軍竟未回。',64,'全唐诗/poet.tang.1000.json','["玉關一自有氛埃，年少從軍竟未回。", "門外塵凝張樂榭，水邊香滅按歌臺。", "窗殘夜月人何處？簾卷春風燕復來。", "萬里寂寥音信絕，寸心爭忍不成灰。"]'),
('23e08615-433c-48b1-a1e8-9d3ceb31e899','雜曲歌辭 攜手曲','田娥','唐','唐诗','tang','','[]','攜手共惜芳菲節，鶯啼錦花滿城闕。',48,'全唐诗/poet.tang.1000.json','["攜手共惜芳菲節，鶯啼錦花滿城闕。", "行樂逶迤念容色，色衰祗恐君恩歇。", "鳳笙龍管白日陰，盈虧自感青天月。"]'),
('b89f5c6f-e3b2-4503-9d26-8b67db0ae707','雜曲歌辭 大垂手','聶夷中','唐','唐诗','tang','','[]','金刀翦輕雲，盤用黃金縷。',36,'全唐诗/poet.tang.1000.json','["金刀翦輕雲，盤用黃金縷。", "裝束趙飛燕，教來掌上舞。", "舞罷飛燕死，片片隨風去。"]'),
('e14cbebf-e7fd-4eb3-af52-d8d5587ae78b','雜曲歌辭 夜夜曲','不詳','唐','唐诗','tang','','[]','愁人夜獨傷，滅燭臥蘭房。',24,'全唐诗/poet.tang.1000.json','["愁人夜獨傷，滅燭臥蘭房。", "祗恐多情月，旋來照妾牀。"]'),
('68a3e39c-58e3-4b5b-890a-22f1e3f1c185','雜曲歌辭 夜夜曲','王偃','唐','唐诗','tang','','[]','北斗星移銀漢低，班姬愁思鳳城西。',32,'全唐诗/poet.tang.1000.json','["北斗星移銀漢低，班姬愁思鳳城西。", "青槐陌上人行絕，明月樓前烏夜啼。"]'),
('2abccdd1-975e-460b-a0a4-a9e523cab8e4','雜曲歌辭 夜夜曲','僧貫休','唐','唐诗','tang','','[]','蟪蛄切切風騷騷，芙蓉噴香蟾蜍高。',32,'全唐诗/poet.tang.1000.json','["蟪蛄切切風騷騷，芙蓉噴香蟾蜍高。", "孤燈耿耿征婦勞，更深撲落金錯刀。"]'),
('08df45bf-0fcf-4ada-aaf9-844b6e18490e','雜曲歌辭 秋夜長','王勃','唐','唐诗','tang','','[]','秋夜長，殊未央。',120,'全唐诗/poet.tang.1000.json','["秋夜長，殊未央。", "月明白露澄清光，層城綺閣遙相望。", "遙相望，川無梁。", "北風受節鴈南翔，崇蘭委質時菊芳。", "鳴環曳履出長廊，爲君秋夜擣衣裳。", "纖羅對鳳皇，丹綺雙鴛鴦。", "調砧亂杵思自傷，思自傷，征夫萬里戍他鄉。", "鶴關音信斷，龍門道路長。", "所在天一方，寒衣徒自香。"]'),
('9ff8ecff-2578-40c6-87b9-7ca546c25fac','雜曲歌辭 秋夜長','張籍','唐','唐诗','tang','','[]','秋天如水夜未央，天漢東西月色光。',64,'全唐诗/poet.tang.1000.json','["秋天如水夜未央，天漢東西月色光。", "愁人不寐畏枕席，暗蟲唧唧遶我傍。", "荒城爲村無更聲，起看北斗天未明。", "白露滿田風褭褭，千聲萬聲鶡鳥鳴。"]'),
('9fa92cdf-24cf-4a6a-af33-db5809652091','雜曲歌辭 秋夜曲二首 一','王建','唐','唐诗','tang','','[]','天清漏長霜泊泊，蘭綠收榮桂膏涸。',80,'全唐诗/poet.tang.1000.json','["天清漏長霜泊泊，蘭綠收榮桂膏涸。", "高樓雲鬟弄嬋娟，古瑟暗斷秋風弦。", "玉關遙隔萬里道，金刀不翦雙淚泉。", "香囊火死香氣少，向帷合眼何時曉？", "城烏作營嗁野月，秦川少婦生離別。"]'),
('53cf061b-f9b7-4a39-bccc-241449bef36f','雜曲歌辭 秋夜曲二首 二','王建','唐','唐诗','tang','','[]','秋燈向壁掩洞房，良人此夜直明光。',32,'全唐诗/poet.tang.1000.json','["秋燈向壁掩洞房，良人此夜直明光。", "天河悠悠漏水長，南樓北斗兩相當。"]'),
('acd009f5-60ec-4569-878f-28fb51b0ef0f','雜曲歌辭 秋夜曲','張仲素','唐','唐诗','tang','','["\u601d\u5ff5", "\u79cb\u5929", "\u95fa\u6028"]','丁丁漏水夜何長，漫漫輕雲露月光。',32,'全唐诗/poet.tang.1000.json','["丁丁漏水夜何長，漫漫輕雲露月光。", "秋壁闇蟲通夕響，寒衣未寄莫飛霜。"]'),
('1f66d2ec-8418-485e-a434-e21a0d439dda','雜曲歌辭 秋夜曲','王涯','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u79cb\u5929", "\u5973\u5b50", "\u4e50\u5e9c"]','桂魄初生秋露微，輕羅已薄未更衣。',32,'全唐诗/poet.tang.1000.json','["桂魄初生秋露微，輕羅已薄未更衣。", "銀箏夜久殷勤弄，心怯空房不忍歸。"]'),
('2b8a54fd-f08a-4f0d-a6ab-96774ef6b15b','雜曲歌辭 夜坐吟','李白','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u97f3\u4e50", "\u4e50\u5e9c", "\u5973\u5b50"]','冬夜夜寒覺夜長，沈吟久坐坐北堂。',78,'全唐诗/poet.tang.1000.json','["冬夜夜寒覺夜長，沈吟久坐坐北堂。", "冰合井泉月入閨，青缸凝明照悲嗁。", "青缸滅，嗁轉多，掩妾淚，聽君歌。", "歌有聲，妾有情，情聲合，兩無違。", "一語不入意，從君萬曲梁塵飛。"]'),
('c89fcc8b-70df-4b67-84c8-6c855555eb41','雜曲歌辭 夜坐吟','李白','唐','唐诗','tang','','[]','踏踏馬頭誰見過，眼看北斗直天河。',72,'全唐诗/poet.tang.1000.json','["踏踏馬頭誰見過，眼看北斗直天河。", "西風羅幕生翠波，鉛華笑妾顰青蛾。", "爲君起唱長相思，簾外嚴霜皆倒飛。", "明星爛爛東方陲，紅霞稍出東南涯，陸郎去矣乘斑騅。"]'),
('6feba2ad-2a6e-40d1-ace1-6ecc16819a82','雜曲歌辭 夜寒吟','鮑溶','唐','唐诗','tang','','[]','九衢金吾夜行行，上宮玉漏遙分明。',96,'全唐诗/poet.tang.1000.json','["九衢金吾夜行行，上宮玉漏遙分明。", "霜飆乘陰掃地起，旅鴻迷雪繞枕聲。", "遠人歸夢既不成，留家惜夜歡心發。", "羅幕畫堂深皎潔，蘭煙對酒客幾人。", "獸火揚光二三月，細腰楚姬絲竹間。", "白紵長袖歌閑閑，豈識苦寒損朱顏。"]'),
('dce26031-6d6a-4cb4-abe6-95f50c149af0','雜曲歌辭 定情篇','喬知之','唐','唐诗','tang','','[]','共君結新婚，歲寒心未卜。',292,'全唐诗/poet.tang.1000.json','["共君結新婚，歲寒心未卜。", "相與遊春園，各隨情所逐。", "君念菖蒲花，妾感苦寒竹。", "菖花多豔姿，寒竹有貞葉。", "此時妾比君，君心不如妾。", "簪玉步河堤，妖韶援綠{𥫗/戢}。", "鳧鴈將子遊，鶯燕從雙栖。", "君念春光好，妾向春光嗁。", "君時不得意，妾棄還金閨。", "結言本同心，悲懽何未齊。", "怨咽前致辭，願得中所悲。", "人間丈夫易，世路婦難爲。", "始經天月照，終若流星馳。", "長信佳麗人，失意非蛾眉。", "廬江小吏婦，非關織作遲。", "本願長相對，今已長相思。", "復有遊宦子，結援從梁陳。", "燕居崇三朝，去來歷九春。", "誓心妾終始，蠶桑奉所親。", "歸願未克從，黃金贈路人。", "潔婦懷明義，從汎河之津。", "於今千萬年，誰當問水濱。", "更憶倡家樓，夫壻事封侯。", "去時思灼灼，去罷心悠悠。"]'),
('b1c23df5-e9ea-4ab7-bf23-ed6fd7036b62','雜曲歌辭 定情樂','施肩吾','唐','唐诗','tang','','[]','敢嗟君不憐，自是命不諧。',24,'全唐诗/poet.tang.1000.json','["敢嗟君不憐，自是命不諧。", "著破三條裾，卻還雙股釵。"]'),
('b3b95e77-5985-49ef-b603-cce95a5c6ae2','雜曲歌辭 春江曲','郭元振','唐','唐诗','tang','','["\u7231\u60c5"]','江水春沈沈，上有雙竹林。',24,'全唐诗/poet.tang.1000.json','["江水春沈沈，上有雙竹林。", "竹葉壞水色，郎亦壞人心。"]'),
('306c2503-eff5-418b-873e-c72596a676bd','雜曲歌辭 春江曲','張籍','唐','唐诗','tang','','[]','春江無雲潮水平，蒲心出水鳧雛鳴。',80,'全唐诗/poet.tang.1000.json','["春江無雲潮水平，蒲心出水鳧雛鳴。", "長干夫壻愛遠行，自染春衣縫已成。", "妾身生長金陵側，去年隨夫住江北。", "春來未到父母家，舟小風多渡不得。", "欲辭舅姑先問人，私向江頭祭水神。"]'),
('22df0b35-cf47-4dd2-844b-1984891d5db0','雜曲歌辭 春江曲','王涯','唐','唐诗','tang','','[]','搖漾越江春，相將看白蘋。',24,'全唐诗/poet.tang.1000.json','["搖漾越江春，相將看白蘋。", "歸時不覺夜，出浦月隨人。"]'),
('6c3450f9-3313-4b37-a250-3a2a65ffc6ea','雜曲歌辭 春江曲二首 一','張仲素','唐','唐诗','tang','','[]','家寄征江岸，征人幾歲遊。',24,'全唐诗/poet.tang.1000.json','["家寄征江岸，征人幾歲遊。", "不知潮水信，每日到沙頭。"]'),
('7c801e3f-7e0e-427e-bdc6-20a221935c19','雜曲歌辭 春江曲二首 二','張仲素','唐','唐诗','tang','','[]','乘曉南湖去，參差疊浪橫。',24,'全唐诗/poet.tang.1000.json','["乘曉南湖去，參差疊浪橫。", "前洲在何處？霧裏鴈嚶嚶。"]'),
('132c7276-e108-4501-b619-ae997cf31e4b','雜曲歌辭 江上曲','李嘉祐','唐','唐诗','tang','','[]','江上澹澹芙蓉花，江口蛾眉獨浣紗。',80,'全唐诗/poet.tang.1000.json','["江上澹澹芙蓉花，江口蛾眉獨浣紗。", "可憐應是陽臺女，坐對鸕鷀嬌不語。", "掩面羞看北地人，回首忽作空山雨。", "蒼梧秋色不堪論，千載依依帝子魂。", "君看峯上斑斑竹，盡是湘妃泣淚痕。"]'),
('09fea87e-c0a8-44bc-a18f-307b9f7ee92b','雜曲歌辭 桃花曲','顧況','唐','唐诗','tang','','[]','魏帝宮人舞鳳樓，隋家天子泛龍舟。',34,'全唐诗/poet.tang.1000.json','["魏帝宮人舞鳳樓，隋家天子泛龍舟。", "君王夜醉春眠[晏]，不覺桃花逐水流。"]'),
('ed9367a7-fa9f-42b7-a45a-b9bd34a1c531','雜曲歌辭 樹中草','李白','唐','唐诗','tang','','["\u547d\u8fd0", "\u6292\u60c5", "\u6742\u66f2\u6b4c\u8f9e", "\u4e50\u5e9c"]','鳥銜野田草，誤入枯桑裏。',48,'全唐诗/poet.tang.1000.json','["鳥銜野田草，誤入枯桑裏。", "客土植危根，逢春猶不死。", "草木雖無情，因依尚可生。", "如何同枝葉，各自有枯榮。"]'),
('5f0805f2-27d7-4ca4-b338-22722d62e69e','雜曲歌辭 樹中草','張祜','唐','唐诗','tang','','[]','青青樹中草，託根非不危。',24,'全唐诗/poet.tang.1000.json','["青青樹中草，託根非不危。", "草生樹卻死，榮枯君可知。"]'),
('c98aa957-7dec-4900-81c9-2cf976568176','雜曲歌辭 春遊吟','李章','唐','唐诗','tang','','[]','初春遍芳甸，千里靄盈矚。',52,'全唐诗/poet.tang.1000.json','["初春遍芳甸，千里靄盈矚。", "美人摘新英，步步玩春綠。", "所思杳何處，宛在吳江曲。", "可憐不得共芳菲，日暮歸來淚滿衣。"]'),
('352f00c4-1ac3-4ab0-a0a0-7a2bb4ca86fe','雜曲歌辭 春遊樂','施肩吾','唐','唐诗','tang','','[]','一年三百六十日，賞心那似春中物。',32,'全唐诗/poet.tang.1000.json','["一年三百六十日，賞心那似春中物。", "草迷曲塢花滿園，東家少年西家出。"]'),
('65dfff04-3602-4d69-b326-82b5a3da2c6a','雜曲歌辭 春遊樂二首 一','李端','唐','唐诗','tang','','[]','遊童蘇合帶，倡女蒲葵扇。',48,'全唐诗/poet.tang.1000.json','["遊童蘇合帶，倡女蒲葵扇。", "初日映城時，相思忽相見。", "褰裳踏露草，理鬢回花面。", "薄暮不同歸，留情此芳甸。"]'),
('f0321b79-1e81-4776-8ef4-2f171d71e842','雜曲歌辭 春遊樂二首 二','李端','唐','唐诗','tang','','[]','柘彈連錢馬，銀鉤妥墮鬟。',48,'全唐诗/poet.tang.1000.json','["柘彈連錢馬，銀鉤妥墮鬟。", "采桑春陌上，踏草夕陽間。", "意合辭先露，心誠貌卻閑。", "明朝若相憶，雲雨出巫山。"]'),
('5a8f5fae-de21-42ba-b458-893eeffa3c54','雜曲歌辭 春遊曲三首 一','張仲素','唐','唐诗','tang','','[]','煙柳飛輕絮，風榆落小錢。',24,'全唐诗/poet.tang.1000.json','["煙柳飛輕絮，風榆落小錢。", "濛濛百花裏，羅綺競鞦韆。"]'),
('30a09ffc-27bf-4fec-b22b-6e91f4dd8a0a','雜曲歌辭 春遊曲三首 二','張仲素','唐','唐诗','tang','','[]','騁望登香閣，爭高下砌臺。',24,'全唐诗/poet.tang.1000.json','["騁望登香閣，爭高下砌臺。", "林間踏青去，席上意錢來。"]'),
('47fc9ebc-0070-4a86-bf6c-63fe970ae534','雜曲歌辭 春遊曲三首 三','張仲素','唐','唐诗','tang','','[]','行樂三春節，林花百和香。',24,'全唐诗/poet.tang.1000.json','["行樂三春節，林花百和香。", "當年重意氣，先占鬬雞場。"]'),
('b8bc16df-4b48-40e4-b666-dbed47d9047c','雜曲歌辭 樂府二首 一','劉言史','唐','唐诗','tang','','[]','花頷紅騣一向偏，綠槐香陌欲朝天。',32,'全唐诗/poet.tang.1000.json','["花頷紅騣一向偏，綠槐香陌欲朝天。", "仍嫌衆裏嬌行疾，傍鐙深藏白玉鞭。"]'),
('ac87576e-bb93-4ad0-86eb-b21f1cf7429b','雜曲歌辭 樂府二首 二','劉言史','唐','唐诗','tang','','[]','噴珠團香小桂條，玉鞭兼賜霍嫖姚。',32,'全唐诗/poet.tang.1000.json','["噴珠團香小桂條，玉鞭兼賜霍嫖姚。", "弄影便從天禁出，碧蹏聲碎五門橋。"]'),
('7307d6c8-62c3-4487-97d2-86e55dc12ebc','雜曲歌辭 樂府','顧況','唐','唐诗','tang','','[]','暖谷春光至，宸遊近甸榮。',144,'全唐诗/poet.tang.1000.json','["暖谷春光至，宸遊近甸榮。", "雲隨天仗轉，風入御簾輕。", "翠蓋浮佳氣，朱樓倚太清。", "朝臣冠劒退，宮女管弦迎。", "細草承雕輦，繁花入幔城。", "文房開聖藻，武衛宿天營。", "玉醴隨觴至，銅壺逐漏行。", "五星含土德，萬姓徹中聲。", "親祀先崇典，躬推示勸耕。", "國風新正樂，農器近消兵。", "道德關河固，刑章日月明。", "野人同鳥獸，率舞感升平。"]'),
('36efd4bc-6d4f-489a-9c9a-e333e18739af','雜曲歌辭 樂府','權德輿','唐','唐诗','tang','','[]','光風澹蕩百花吐，樓上朝朝學歌舞。',64,'全唐诗/poet.tang.1000.json','["光風澹蕩百花吐，樓上朝朝學歌舞。", "身年二八壻侍中，幼妹承恩兄尚主。", "綠窗珠箔繡鴛鴦，侍婢先焚百和香。", "鶯嗁日出不知曙，寂寂羅幃春夢長。"]'),
('bf9e7e4a-227e-441a-865f-873ad8e957c5','雜曲歌辭 樂府三首 一','孟郊','唐','唐诗','tang','','[]','蓮子不可得，荷花生水中。',24,'全唐诗/poet.tang.1000.json','["蓮子不可得，荷花生水中。", "猶勝道傍柳，無事蕩春風。"]'),
('0b0061ae-a45e-43f3-9c20-aa221f18852f','雜曲歌辭 樂府三首 二','孟郊','唐','唐诗','tang','','[]','淥萍與荷葉，同時一水中。',24,'全唐诗/poet.tang.1000.json','["淥萍與荷葉，同時一水中。", "風吹荷葉在，淥萍西復東。"]'),
('a01640c4-01fc-44c4-bf10-f2a4b79a31e0','雜曲歌辭 樂府三首 三','孟郊','唐','唐诗','tang','','[]','蓮花未開時，苦心終日卷。',24,'全唐诗/poet.tang.1000.json','["蓮花未開時，苦心終日卷。", "春水徒蕩漾，荷花未開展。"]'),
('e23c4038-0674-4bc3-b6f6-051d116a6191','雜曲歌辭 樂府','陸長源','唐','唐诗','tang','','[]','芙蓉初出水，菡萏露中花。',24,'全唐诗/poet.tang.1000.json','["芙蓉初出水，菡萏露中花。", "風吹著枯木，無奈值空槎。"]'),
('854b6573-38fc-4cfa-95a9-8f0f2b731d19','雜曲歌辭 雜曲','王勃','唐','唐诗','tang','','[]','智瓊神女，來訪文君。',44,'全唐诗/poet.tang.1000.json','["智瓊神女，來訪文君。", "蛾眉始約，羅袖初薰。", "歌齊曲韻，舞亂行分。", "若向陽臺薦枕，何啻得勝朝雲。"]'),
('9dbfbde5-aa79-40ba-8a91-b22ee077a8e9','雜曲歌辭 古曲五首 一','施肩吾','唐','唐诗','tang','','[]','可憐江北女，慣唱江南曲。',24,'全唐诗/poet.tang.1000.json','["可憐江北女，慣唱江南曲。", "搖蕩木蘭舟，雙鳧不成浴。"]'),
('6b77cfb9-d9f3-40ab-b94d-6d8f6d0d59f0','雜曲歌辭 古曲五首 二','施肩吾','唐','唐诗','tang','','[]','郎爲匕上香，妾爲籠上灰。',24,'全唐诗/poet.tang.1000.json','["郎爲匕上香，妾爲籠上灰。", "歸時雖暖熱，去罷生塵埃。"]'),
('7aae9190-ddaa-4148-a93e-f1a7d7b3bb7b','雜曲歌辭 古曲五首 三','施肩吾','唐','唐诗','tang','','[]','夜裁鴛鴦綺，朝織蒲桃綾。',24,'全唐诗/poet.tang.1000.json','["夜裁鴛鴦綺，朝織蒲桃綾。", "欲試一寸心，待縫三尺冰。"]'),
('b94c5a1b-2074-41fd-8545-1527160fe131','雜曲歌辭 古曲五首 四','施肩吾','唐','唐诗','tang','','[]','憐時魚得水，怨罷商與參。',24,'全唐诗/poet.tang.1000.json','["憐時魚得水，怨罷商與參。", "不如山支子，卻解結同心。"]'),
('3f566f5b-d74e-4b91-b7f6-31b49deff655','雜曲歌辭 古曲五首 五','施肩吾','唐','唐诗','tang','','[]','紅顏感暮花，白日同流水。',24,'全唐诗/poet.tang.1000.json','["紅顏感暮花，白日同流水。", "思君如孤燈，一夜一心死。"]'),
('b05b8916-14f3-4727-9074-7a5191560361','雜曲歌辭 高句麗','李白','唐','唐诗','tang','','[]','金花折風帽，白馬小遲回。',24,'全唐诗/poet.tang.1000.json','["金花折風帽，白馬小遲回。", "翩翩舞廣袖，似鳥海東來。"]'),
('47f20f9b-0dcc-4282-b429-c13d22f32f26','雜曲歌辭 摩多樓子','李賀','唐','唐诗','tang','','[]','玉塞去金人，二萬四千里。',72,'全唐诗/poet.tang.1000.json','["玉塞去金人，二萬四千里。", "風吹沙作雲，一時渡遼水。", "天白水如練，甲絲雙串斷。", "行行莫苦辛，城月猶殘半。", "曉氣朔煙上，趢趗胡馬蹏。", "行人聽水別，隔隴長東西。"]'),
('c9af7e0b-49ef-4661-bbd5-50358eb88ed7','雜曲歌辭 遼東行','王建','唐','唐诗','tang','','["\u6218\u4e89", "\u51ac\u5929", "\u4e50\u5e9c", "\u8fd1\u4ee3\u66f2\u8f9e"]','遼東萬里遼水曲，古戍無城復無屋。',80,'全唐诗/poet.tang.1000.json','["遼東萬里遼水曲，古戍無城復無屋。", "黃雲蓋地雪作山，不惜黃金買衣服。", "戰回各自收弓箭，正西回面家鄉遠。", "年年郡縣送征人，將與遼東作丘坂。", "寧爲草木鄉中生，有身不向遼東行。"]'),
('ebd43cac-8ec6-413b-a17a-120e02cebafa','雜曲歌辭 渡遼水','王建','唐','唐诗','tang','','["\u6218\u4e89", "\u8fd1\u4ee3\u66f2\u8f9e", "\u4e50\u5e9c"]','渡遼水，此去咸陽五千里。',60,'全唐诗/poet.tang.1000.json','["渡遼水，此去咸陽五千里。", "來時父母知隔生，重著衣裳如送死。", "亦有白骨歸咸陽，營家各與題本鄉。", "身在應無回渡日，駐馬相看遼水傍。"]'),
('238e54b0-be71-449d-8184-a084c2769f0a','雜曲歌辭 昔昔鹽 垂柳覆金堤','趙嘏','唐','唐诗','tang','','[]','新年垂柳色，嫋嫋對空閨。',48,'全唐诗/poet.tang.1000.json','["新年垂柳色，嫋嫋對空閨。", "不畏芳菲好，自緣離別嗁。", "因風飄玉戶，向日映金堤。", "驛使何時度？還將贈隴西。"]'),
('50fa86ae-4358-4dac-bc7d-26a60929034f','雜曲歌辭 昔昔鹽 蘼蕪葉復齊','趙嘏','唐','唐诗','tang','','[]','提筐紅葉下，度日采蘼蕪。',48,'全唐诗/poet.tang.1000.json','["提筐紅葉下，度日采蘼蕪。", "掬翠香盈袖，看花憶故夫。", "葉齊誰復見，風暖恨偏孤。", "一被春光累，容顏與昔殊。"]'),
('18575058-f526-4248-a273-164a84618218','雜曲歌辭 昔昔鹽 水溢芙蓉沼','趙嘏','唐','唐诗','tang','','[]','淥沼春光後，青青草色濃。',48,'全唐诗/poet.tang.1000.json','["淥沼春光後，青青草色濃。", "綺羅驚翡翠，暗粉妒芙蓉。", "雲遍窗前見，荷翻鏡裏逢。", "將心託流水，終日渺無從。"]'),
('bc8adf47-d6ff-46f9-99a3-ee2833e075b7','雜曲歌辭 昔昔鹽 花飛桃李蹊','趙嘏','唐','唐诗','tang','','[]','遠期難可託，桃李自依依。',48,'全唐诗/poet.tang.1000.json','["遠期難可託，桃李自依依。", "花徑無容跡，戎裘未下機。", "隨風開又落，度日掃還飛。", "欲折枝枝贈，那知歸不歸。"]'),
('30f0ddbd-2f19-4dba-8a7a-79433098b5b6','雜曲歌辭 昔昔鹽 采桑秦氏女','趙嘏','唐','唐诗','tang','','[]','南陌采桑出，誰知妾姓秦。',48,'全唐诗/poet.tang.1000.json','["南陌采桑出，誰知妾姓秦。", "獨憐傾國貌，不負早鶯春。", "珠履盪花溼，龍鉤折桂新。", "使君那駐馬，自有侍中人。"]'),
('c24b1f64-0a19-417f-95a9-225b99c242db','雜曲歌辭 昔昔鹽 織錦竇家妻','趙嘏','唐','唐诗','tang','','[]','當年誰不羨，分作竇家妻。',48,'全唐诗/poet.tang.1000.json','["當年誰不羨，分作竇家妻。", "錦字行行苦，羅帷日日嗁。", "豈知登隴遠，祗恨下機迷。", "直候陽關使，殷勤寄海西。"]'),
('f8766a6c-a017-4b39-8765-0d5b57c668bf','雜曲歌辭 昔昔鹽 關山別蕩子','趙嘏','唐','唐诗','tang','','[]','那堪聞蕩子，迢遰涉關山。',48,'全唐诗/poet.tang.1000.json','["那堪聞蕩子，迢遰涉關山。", "腸爲馬嘶斷，衣從淚滴斑。", "愁看塞上路，詎惜鏡中顏。", "儻見征西鴈，應傳一字還。"]'),
('e43db4ab-925d-4cb0-b14a-d105ef6cd63c','雜曲歌辭 昔昔鹽 風月守空閨','趙嘏','唐','唐诗','tang','','[]','良人猶遠戍，耿耿夜閨空。',48,'全唐诗/poet.tang.1000.json','["良人猶遠戍，耿耿夜閨空。", "繡戶流宵月，羅帷坐曉風。", "魂飛沙帳北，腸斷玉關中。", "尚自無消息，錦衾那得同。"]'),
('988b8d28-4cf1-4f52-818d-78eae6fa546e','雜曲歌辭 昔昔鹽 恆斂千金笑','趙嘏','唐','唐诗','tang','','[]','玉顏恆自斂，羞出鏡臺前。',48,'全唐诗/poet.tang.1000.json','["玉顏恆自斂，羞出鏡臺前。", "早惑陽城客，今悲華錦筵。", "從軍人更遠，投喜鵲空傳。", "夫壻交河北，迢迢路幾千。"]'),
('c1fc2fbc-1dee-4646-a0f7-108ec7d40161','雜曲歌辭 昔昔鹽 長垂雙玉嗁','趙嘏','唐','唐诗','tang','','[]','雙雙紅淚墮，度日暗中嗁。',48,'全唐诗/poet.tang.1000.json','["雙雙紅淚墮，度日暗中嗁。", "鴈出居延北，人猶遼海西。", "向燈垂玉枕，對月灑金閨。", "不惜羅衣溼，惟愁歸意迷。"]'),
('09651746-3fe6-4d53-a888-d3b865951982','雜曲歌辭 昔昔鹽 蟠龍隨鏡隱','趙嘏','唐','唐诗','tang','','[]','鸞鏡無由照，蛾眉豈忍看。',48,'全唐诗/poet.tang.1000.json','["鸞鏡無由照，蛾眉豈忍看。", "不知愁髮換，空見隱龍蟠。", "那愜紅顏改，偏傷白日殘。", "今朝窺玉匣，雙淚落闌干。"]'),
('dea46cae-439c-45e6-ba22-06519ba0793f','雜曲歌辭 昔昔鹽 綵鳳逐帷低','趙嘏','唐','唐诗','tang','','[]','巧繡雙飛鳳，朝朝伴下帷。',48,'全唐诗/poet.tang.1000.json','["巧繡雙飛鳳，朝朝伴下帷。", "春花那見照，暮色已頻欺。", "欲卷思君處，將嗁裛淚時。", "何年征戍客？傳語報佳期。"]'),
('eebcac54-df54-47a7-9045-aaa691f418ab','雜曲歌辭 昔昔鹽 驚魂同夜鵲','趙嘏','唐','唐诗','tang','','[]','萬里無人見，衆情難與論。',48,'全唐诗/poet.tang.1000.json','["萬里無人見，衆情難與論。", "思君常入夢，同鵲屢驚魂。", "孤寢紅羅帳，雙嗁玉筯痕。", "妾心甘自保，豈復暫忘恩。"]'),
('49459ec1-5948-4b67-950c-339b4e058684','雜曲歌辭 昔昔鹽 倦寢聽晨雞','趙嘏','唐','唐诗','tang','','[]','去去邊城騎，愁眠掩夜閨。',48,'全唐诗/poet.tang.1000.json','["去去邊城騎，愁眠掩夜閨。", "披衣窺落月，拭淚待鳴雞。", "不憤連年別，那堪長夜嗁。", "功成應自恨，早晚發遼西。"]'),
('dadfdd07-52de-4eb0-b72a-e9f06a09e652','雜曲歌辭 昔昔鹽 暗牖懸蛛網','趙嘏','唐','唐诗','tang','','[]','暗中蛛網織，歷亂綺窗前。',48,'全唐诗/poet.tang.1000.json','["暗中蛛網織，歷亂綺窗前。", "萬里終無信，一條徒自懸。", "分從珠露滴，愁見隙風牽。", "妾意何聊賴，看看劇斷弦。"]'),
('a06cb556-2b4d-4b1c-a52a-fcff10b7f87e','雜曲歌辭 昔昔鹽 空梁落燕泥','趙嘏','唐','唐诗','tang','','[]','春至今朝燕，花時伴獨嗁。',48,'全唐诗/poet.tang.1000.json','["春至今朝燕，花時伴獨嗁。", "飛斜珠箔隔，語近畫梁低。", "帷卷閑窺戶，牀空暗落泥。", "誰能長對此，雙去復雙棲。"]'),
('d1de2239-e272-4be0-b710-ae16ece61789','雜曲歌辭 昔昔鹽 前年過代北','趙嘏','唐','唐诗','tang','','[]','代北幾千里，前年又復經。',48,'全唐诗/poet.tang.1000.json','["代北幾千里，前年又復經。", "燕山雲自合，胡塞草應青。", "鐵馬喧鼙鼓，蛾眉怨錦屏。", "不知羌笛曲，掩淚若爲聽。"]'),
('a9a7c49b-cf3c-4469-936c-a23449959978','雜曲歌辭 昔昔鹽 今歲往遼西','趙嘏','唐','唐诗','tang','','[]','萬里飛書至，聞君已渡遼。',48,'全唐诗/poet.tang.1000.json','["萬里飛書至，聞君已渡遼。", "祗諳新別苦，忘卻舊時嬌。", "烽戍年將老，紅顏日向彫。", "胡沙兼漢苑，相望幾迢迢。"]'),
('f619ba03-5e1d-497e-af90-2367f48e9c01','雜曲歌辭 昔昔鹽 一去無還意','趙嘏','唐','唐诗','tang','','[]','良人征絕域，一去不言還。',48,'全唐诗/poet.tang.1000.json','["良人征絕域，一去不言還。", "百戰攻胡虜，三冬阻玉關。", "蕭蕭邊馬思，獵獵戍旗閑。", "獨把千重恨，連年未解顏。"]'),
('4c9c3d75-272f-4529-bf21-8aafbe5b276e','雜曲歌辭 昔昔鹽 那能惜馬蹏','趙嘏','唐','唐诗','tang','','[]','雲中路杳杳，江畔草萋萋。',48,'全唐诗/poet.tang.1000.json','["雲中路杳杳，江畔草萋萋。", "妾久垂珠淚，君何惜馬蹏。", "邊風悲曉角，營月怨春鼙。", "未道休征戰，愁眉又復低。"]'),
('321a1b75-4cdf-48c7-8f57-047300fa7f50','雜曲歌辭 水調 歌第一','不詳','唐','唐诗','tang','','[]','平沙落日大荒西，隴上明星高復低。',32,'全唐诗/poet.tang.1000.json','["平沙落日大荒西，隴上明星高復低。", "孤山幾處看烽火，壯士連營候鼓鼙。"]'),
('148561e3-75bd-49f3-a2ad-0f0a65e4ab18','雜曲歌辭 水調 歌第二','不詳','唐','唐诗','tang','','[]','猛將關西意氣多，能騎駿馬弄琱戈。',32,'全唐诗/poet.tang.1000.json','["猛將關西意氣多，能騎駿馬弄琱戈。", "金鞍寶鉸精神出，笛倚新翻水調歌。"]'),
('d7f44dab-e6ec-46dc-8967-6c20743ca4f9','雜曲歌辭 水調 歌第三','不詳','唐','唐诗','tang','','[]','王孫別上綠珠輪，不羨名公樂此身。',32,'全唐诗/poet.tang.1000.json','["王孫別上綠珠輪，不羨名公樂此身。", "戶外碧潭春洗馬，樓前紅燭夜迎人。"]'),
('0634a2b4-170c-4f89-8bc3-84cbe50dd49f','雜曲歌辭 水調 歌第四','不詳','唐','唐诗','tang','','[]','隴頭一叚氣長秋，舉目蕭條總是愁。',32,'全唐诗/poet.tang.1000.json','["隴頭一叚氣長秋，舉目蕭條總是愁。", "秖爲征人多下淚，年年添作斷腸流。"]'),
('99774e06-b675-4e90-812d-8687d5dec0cc','雜曲歌辭 水調 歌第五','不詳','唐','唐诗','tang','','[]','雙帶仍分影，同心巧結香。',24,'全唐诗/poet.tang.1000.json','["雙帶仍分影，同心巧結香。", "不應須換彩，意欲媚濃妝。"]'),
('5c078e52-4245-4e6c-bdb6-f2ee4ea18b72','雜曲歌辭 水調 入破第一','不詳','唐','唐诗','tang','','[]','細草河邊一鴈飛，黃龍關裏挂戎衣。',32,'全唐诗/poet.tang.1000.json','["細草河邊一鴈飛，黃龍關裏挂戎衣。", "爲受明王恩寵甚，從事經年不復歸。"]'),
('3a1b9edf-ca5a-4cd5-ae29-759a67fbaced','雜曲歌辭 水調 入破第二','不詳','唐','唐诗','tang','','[]','錦城絲管日紛紛，半入江風半入雲。',32,'全唐诗/poet.tang.1000.json','["錦城絲管日紛紛，半入江風半入雲。", "此曲只應天上去，人間能得幾回聞。"]'),
('bfaf022d-6290-4edf-8d26-e6bb69a2e5e2','雜曲歌辭 水調 入破第三','不詳','唐','唐诗','tang','','[]','昨夜遙歡出建章，今朝綴賞度昭陽。',32,'全唐诗/poet.tang.1000.json','["昨夜遙歡出建章，今朝綴賞度昭陽。", "傳聲莫閉黃金屋，爲報先開白玉堂。"]'),
('283d91c5-d4a9-4d74-8cde-151d413e4257','雜曲歌辭 水調 入破第四','不詳','唐','唐诗','tang','','[]','日晚笳聲咽戍樓，隴雲漫漫水東流。',32,'全唐诗/poet.tang.1000.json','["日晚笳聲咽戍樓，隴雲漫漫水東流。", "行人萬里向西去，滿目關山空恨愁。"]'),
('c7ce62e6-0839-4be5-bb5a-2afa195d7b23','雜曲歌辭 水調 入破第五','不詳','唐','唐诗','tang','','[]','千年一遇聖明朝，願對君王舞細腰。',32,'全唐诗/poet.tang.1000.json','["千年一遇聖明朝，願對君王舞細腰。", "乍可當熊任生死，誰能伴鳳上雲霄。"]'),
('0fef5012-ce3c-4d1c-b10e-763f536f4d1f','雜曲歌辭 水調 入破第六徹','不詳','唐','唐诗','tang','','[]','閨燭無人影，羅屏有夢魂。',24,'全唐诗/poet.tang.1000.json','["閨燭無人影，羅屏有夢魂。", "近來音耗絕，終日望君門。"]'),
('da9d2ede-c1ae-4d70-ad8a-86a1c1cbaeab','雜曲歌辭 水調','吳融','唐','唐诗','tang','','[]','鑿河千里走黃沙，浮殿西來動日華。',32,'全唐诗/poet.tang.1000.json','["鑿河千里走黃沙，浮殿西來動日華。", "可道新聲是亡國，且貪惆悵後庭花。"]'),
('ee4f90a7-2e12-4406-9160-0ce744364e98','雜曲歌辭 堂堂 一','李義府','唐','唐诗','tang','','[]','鏤月成歌扇，裁雲作舞衣。',24,'全唐诗/poet.tang.1000.json','["鏤月成歌扇，裁雲作舞衣。", "自憐回雪影，好取洛川歸。"]'),
('4443735c-8ed2-4f28-a04d-7b4e4b3f1005','雜曲歌辭 堂堂 二','李義府','唐','唐诗','tang','','[]','嬾正鴛鴦被，羞褰玳瑁牀。',24,'全唐诗/poet.tang.1000.json','["嬾正鴛鴦被，羞褰玳瑁牀。", "春風別有意，密處也尋香。"]'),
('c72218f8-026a-4393-9a75-141f2aa28294','雜曲歌辭 堂堂','李賀','唐','唐诗','tang','','[]','堂堂復堂堂，紅脫梅灰香。',60,'全唐诗/poet.tang.1000.json','["堂堂復堂堂，紅脫梅灰香。", "十年粉蠹生畫梁，飢蟲不食推碎黃。", "蕙花已老桃葉長，禁院懸簾隔御光。", "華清源中礜石湯，裴回百鳳隨君王。"]'),
('e3517279-6e20-4847-a7a7-518aa6eb9eb3','雜曲歌辭 涼州 歌第一','不詳','唐','唐诗','tang','','[]','漢家宮裏柳如絲，上苑桃花連碧池。',32,'全唐诗/poet.tang.1000.json','["漢家宮裏柳如絲，上苑桃花連碧池。", "聖壽已傳千歲酒，天文更賞百僚詩。"]'),
('45c8fb06-8bc7-4f39-8874-9d6748c12fb9','雜曲歌辭 涼州 歌第二','不詳','唐','唐诗','tang','','[]','朔風吹葉鴈門秋，萬里煙塵昏戍樓。',32,'全唐诗/poet.tang.1000.json','["朔風吹葉鴈門秋，萬里煙塵昏戍樓。", "征馬長思青海北，胡笳夜聽隴山頭。"]'),
('aa89c7ac-8d34-4f99-9572-205ac0ed78b2','雜曲歌辭 涼州 歌第三','不詳','唐','唐诗','tang','','[]','開篋淚霑襦，見君前日書。',24,'全唐诗/poet.tang.1000.json','["開篋淚霑襦，見君前日書。", "夜臺空寂寞，猶見紫雲車。"]'),
('03c22f95-a8cd-4b3b-81ad-48c2e94469dd','雜曲歌辭 涼州 排遍第一','不詳','唐','唐诗','tang','','[]','三秋陌上早霜飛，羽獵平田淺草齊。',32,'全唐诗/poet.tang.1000.json','["三秋陌上早霜飛，羽獵平田淺草齊。", "錦背蒼鷹初出按，五花驄馬餵來肥。"]'),
('1f7a578f-f6da-4dee-a195-938e2aeddb99','雜曲歌辭 涼州 排遍第二','不詳','唐','唐诗','tang','','[]','鴛鴦殿裏笙歌起，翡翠樓前出舞人。',32,'全唐诗/poet.tang.1000.json','["鴛鴦殿裏笙歌起，翡翠樓前出舞人。", "喚上紫微三五夕，聖明方壽一千春。"]'),
('13d01f32-e7b8-4ba4-a834-5cbd2174970f','雜曲歌辭 涼州詞','耿[湋]','唐','唐诗','tang','','[]','國使翩翩隨斾旌，隴西岐路足荒城。',32,'全唐诗/poet.tang.1000.json','["國使翩翩隨斾旌，隴西岐路足荒城。", "氈裘牧馬胡雛小，日暮蕃歌三兩聲。"]'),
('ea4f6277-8e73-4d23-b500-dd995005322a','雜曲歌辭 涼州詞 一','張籍','唐','唐诗','tang','','[]','邊城暮雨鴈飛低，蘆筍初生漸欲齊。',32,'全唐诗/poet.tang.1000.json','["邊城暮雨鴈飛低，蘆筍初生漸欲齊。", "無數鈴聲遙過磧，應馱白練到安西。"]'),
('e8284624-2472-47b7-ab3f-0bc99f42df81','雜曲歌辭 涼州詞 二','張籍','唐','唐诗','tang','','[]','古鎮城門白磧開，胡兵往往傍沙堆。',32,'全唐诗/poet.tang.1000.json','["古鎮城門白磧開，胡兵往往傍沙堆。", "巡邊使客行應早，每待平安火到來。"]'),
('d93b8fa9-665b-4e61-a353-a15d869d8c92','雜曲歌辭 涼州詞 三','張籍','唐','唐诗','tang','','["\u8fb9\u5c06", "\u6c34", "\u5199\u666f", "\u8c34\u8d23"]','鳳林關裏水東流，白草黃榆六十秋。',32,'全唐诗/poet.tang.1000.json','["鳳林關裏水東流，白草黃榆六十秋。", "邊將皆承主恩澤，無人解道取涼州。"]'),
('3f44618a-ec8e-40e0-bbfd-7cefa27e61d2','雜曲歌辭 涼州詞','薛逢','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u7231\u56fd"]','昨夜蕃兵報國讐，沙州都護破涼州。',32,'全唐诗/poet.tang.1000.json','["昨夜蕃兵報國讐，沙州都護破涼州。", "黃河九曲今歸漢，塞外縱橫戰血流。"]'),
('198b8237-295c-41ac-a4b0-49d3761a85b7','雜曲歌辭 太和 第一','不詳','唐','唐诗','tang','','[]','國門卿相舊山莊，聖主移來宴綠芳。',32,'全唐诗/poet.tang.1000.json','["國門卿相舊山莊，聖主移來宴綠芳。", "簾外輾爲車馬路，花間踏出舞人場。"]'),
('0a16801c-b035-4c76-b485-2e02c736e508','雜曲歌辭 太和 第二','不詳','唐','唐诗','tang','','[]','國鳥尚含天樂轉，寒風猶帶御衣香。',32,'全唐诗/poet.tang.1000.json','["國鳥尚含天樂轉，寒風猶帶御衣香。", "爲報碧潭明月夜，會須留賞待君王。"]'),
('c5a61d09-e847-43a2-8ff4-45b37ca64d90','雜曲歌辭 太和 第三','不詳','唐','唐诗','tang','','[]','庭前鵲遶相思樹，井上鶯歌爭刺桐。',32,'全唐诗/poet.tang.1000.json','["庭前鵲遶相思樹，井上鶯歌爭刺桐。", "含情少婦悲春草，多是良人學轉蓬。"]'),
('51b62ef0-7fba-42f9-9560-945a0d15e2b8','雜曲歌辭 太和 第四','不詳','唐','唐诗','tang','','[]','塞北江南共一家，何須淚落怨黃沙。',32,'全唐诗/poet.tang.1000.json','["塞北江南共一家，何須淚落怨黃沙。", "春酒半酣千日醉，庭前還有落梅花。"]'),
('53e0450d-1e04-4909-a384-c6c9b6f17e5a','雜曲歌辭 太和 第五徹','不詳','唐','唐诗','tang','','[]','我皇膺運太平年，四海朝宗會百川。',32,'全唐诗/poet.tang.1000.json','["我皇膺運太平年，四海朝宗會百川。", "自古幾多明聖主，不如今帝勝堯天。"]'),
('14473112-f820-431f-b353-a013af09dede','雜曲歌辭 伊州 歌第一','蓋嘉運','唐','唐诗','tang','','[]','秋風明月獨離居，蕩子從戎十載餘。',32,'全唐诗/poet.tang.1000.json','["秋風明月獨離居，蕩子從戎十載餘。", "征人去日殷勤屬，歸鴈來時數寄書。"]'),
('d12a1587-2ddf-4162-86a9-f8f208371f9e','雜曲歌辭 伊州 歌第二','蓋嘉運','唐','唐诗','tang','','[]','彤闈曉闢萬鞍迴，玉輅春遊薄晚開。',32,'全唐诗/poet.tang.1000.json','["彤闈曉闢萬鞍迴，玉輅春遊薄晚開。", "渭北清光搖草樹，州南嘉景入樓臺。"]'),
('3a5a5f7f-3f3d-4471-b883-9f8ab80cd1a7','鄭國夫人挽歌詞','趙良器','唐','唐诗','tang','','[]','淑德延公胄，宜家接帝姻。',48,'全唐诗/poet.tang.10000.json','["淑德延公胄，宜家接帝姻。", "桂宮男掌僕，蘭殿女昇嬪。", "恩澤昭前命，盈虛變此辰。", "萬年今已矣，彤管列何人。"]'),
('0ae441bd-4ec8-460e-853f-f367e2e2fa05','郡中客舍','黃麟','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蟲響亂啾啾，更人正數籌。',48,'全唐诗/poet.tang.10000.json','["蟲響亂啾啾，更人正數籌。", "魂歸洞庭夜，霜臥洛陽秋。", "微月有時隱，長河到曉流。", "起來還囑雁，鄉信在吳洲。"]'),
('32898701-8d9c-4b4d-b192-510564f63b2f','途中口號','郭向','唐','唐诗','tang','','[]','抱玉三朝楚，懷書十上秦。',24,'全唐诗/poet.tang.10000.json','["抱玉三朝楚，懷書十上秦。", "年年洛陽陌，花鳥弄歸人。"]'),
('ee36aa5a-c3d0-4875-8ff8-e1807a7ce622','題李將軍山亭','郭良','唐','唐诗','tang','','[]','鳳轄將軍位，龍門司隸家。',48,'全唐诗/poet.tang.10000.json','["鳳轄將軍位，龍門司隸家。", "衣冠爲隱逸，山水作繁華。", "徑出重林草，池搖兩岸花。", "誰知貴公第，亭院有煙霞。"]'),
('736323fa-2b48-48cc-9d86-16f2c914eedb','早行','郭良','唐','唐诗','tang','','[]','早行星尚在，數里未天明。',48,'全唐诗/poet.tang.10000.json','["早行星尚在，數里未天明。", "不辨雲林色，空聞風水聲。", "月從山上落，河入斗間橫。", "漸至重門外，依稀見洛城。"]'),
('40dbb564-d86b-4616-882c-4dbbd9ac9335','過故人舊宅','王喬','唐','唐诗','tang','','[]','故人軒騎罷歸來，舊宅園林閑不開。',32,'全唐诗/poet.tang.10000.json','["故人軒騎罷歸來，舊宅園林閑不開。", "唯餘挾瑟樓中婦，哭向平生歌舞臺。"]'),
('c5a4ede4-70dc-4bb3-95ab-e113f83a0a85','關山月','徐九臯','唐','唐诗','tang','','[]','玉塞抵長城，金徽暎高闕。',48,'全唐诗/poet.tang.10000.json','["玉塞抵長城，金徽暎高闕。", "遙心萬餘里，直望三邊月。", "霜靜影逾懸，露晞光漸沒。", "思君不可見，空歎將焉歇。"]'),
('2f37ab92-d8ed-43f3-ba85-eff243e94cc9','戰城南','徐九臯','唐','唐诗','tang','','[]','塞北狂胡旅，城南敵漢圍。',48,'全唐诗/poet.tang.10000.json','["塞北狂胡旅，城南敵漢圍。", "巉巖一鼓氣，拔利五兵威。", "虜騎瞻山哭，王師拓地飛。", "不應須寵戰，當遂勒金徽。"]'),
('1ab1c514-5415-4e59-9139-bf6b53c4ae54','詠史','徐九臯','唐','唐诗','tang','','[]','亡國秦韓代，榮身劉項年。',48,'全唐诗/poet.tang.10000.json','["亡國秦韓代，榮身劉項年。", "金槌擊政後，玉斗碎增前。", "聖主稱三傑，明離保四賢。", "已申黃石祭，方慕赤松仙。"]'),
('f8c23174-925f-4a29-8972-f182a6cfc7e6','途中覽鏡','徐九臯','唐','唐诗','tang','','[]','四海遊長倦，百年愁半侵。',24,'全唐诗/poet.tang.10000.json','["四海遊長倦，百年愁半侵。", "賴窺明鏡裏，時見丈夫心。"]'),
('618f5d33-d89f-4ada-9ed0-46e0ae1f0045','送部四鎮人往單于別知故','徐九臯','唐','唐诗','tang','','[]','天下今無事，雲中獨未寧。',48,'全唐诗/poet.tang.10000.json','["天下今無事，雲中獨未寧。", "忝驅更戍卒，方遠送邊庭。", "馬飲長城水，軍占太白星。", "國恩行可報，何必守經營。"]'),
('b15a6f1f-1730-49e2-8f50-a0a5f7e51e26','松滋江北阻風','閻寬','唐','唐诗','tang','','[]','江風久未歇，山雨復相仍。',48,'全唐诗/poet.tang.10000.json','["江風久未歇，山雨復相仍。", "巨浪天涯起，餘寒川上凝。", "憂人勞夕惕，鄉事憊晨興。", "遠聽知音駭，誠哉不可陵。"]'),
('9a1d375c-cd38-43f0-beb5-2e5312d155e7','曉入宜都渚','閻寬','唐','唐诗','tang','','[]','問俗周楚甸，川行眇江潯。',48,'全唐诗/poet.tang.10000.json','["問俗周楚甸，川行眇江潯。", "興隨曉光發，道會春言深。", "回眺佳氣象，遠懷得山林。", "佇應舟楫用，曷務歸閑心。"]'),
('745f033f-4e88-4bd1-beba-ad28de1e2e47','古意','閻寬','唐','唐诗','tang','','[]','庭樹發華滋，瑤草復葳蕤。',60,'全唐诗/poet.tang.10000.json','["庭樹發華滋，瑤草復葳蕤。", "好鳥飛相從，愁人深此時。", "天中有靈匹，日夕嚬蛾眉。", "願逐飄風花，千里入遙帷。", "心逝愛不見，空歌悲莫悲。"]'),
('24c9a5d0-71a0-4a42-98d5-7dab45839b1f','春宵覽月','閻寬','唐','唐诗','tang','','[]','月生東荒外，天雲收夕陰。',48,'全唐诗/poet.tang.10000.json','["月生東荒外，天雲收夕陰。", "愛見澄清景，象吾虛白心。", "耳目靜無譁，神超道性深。", "乘興得至樂，寓言因永吟。"]'),
('8d2083db-5ccc-416b-be4c-375ef271acc0','秋懷','閻寬','唐','唐诗','tang','','[]','下帷長日盡，虛館早涼生。',48,'全唐诗/poet.tang.10000.json','["下帷長日盡，虛館早涼生。", "芳草猶未薦，如何蜻蛚鳴。", "秋風已振衣，客去何時歸。", "爲問當途者，寧知心有違。"]'),
('5eb98284-b6e8-4232-acf1-47cc896293d1','和中書侍郎院壁畫雲','李收','唐','唐诗','tang','','[]','粉壁畫雲成，如能上太清。',48,'全唐诗/poet.tang.10000.json','["粉壁畫雲成，如能上太清。", "影從霄漢發，光照掖垣明。", "暎篠多幽趣，臨軒得野情。", "獨思作霖雨，流潤及生靈。"]'),
('d2badd5e-3ef1-45e1-a80c-7a520b185952','幽情','李收','唐','唐诗','tang','','[]','幽人惜春暮，潭上折芳草。',24,'全唐诗/poet.tang.10000.json','["幽人惜春暮，潭上折芳草。", "佳期何時還，欲寄千里道。"]'),
('2c6094fa-74b2-4226-b42d-d06cc51fb646','懷魯','程彌綸','唐','唐诗','tang','','[]','曲阜國，尼丘山。',56,'全唐诗/poet.tang.10000.json','["曲阜國，尼丘山。", "周公邈難問，夫子猶啓關。", "履風雩兮若見，游夏興兮魯顏。", "天孫天孫，何爲今兮學且難，負星明而東遊閑閑。"]'),
('7715e2f7-4e7e-4794-942e-bfbad57f953d','燕歌行','屈同仙','唐','唐诗','tang','','[]','君不見漁陽八月塞草腓，征人相對併思歸。',163,'全唐诗/poet.tang.10000.json','["君不見漁陽八月塞草腓，征人相對併思歸。", "雲和朔氣連天黑，蓬雜驚沙散野飛。", "是時天地陰埃遍，瀚海龍城皆習戰。", "兩軍鼓角暗相聞，四面旌旗看不見。", "昭君遠嫁已年多，戎狄無厭不復和。", "漢兵候月秋防塞，胡騎乘冰夜渡河。", "河塞東西萬餘里，地與京華不相似。", "燕支山下少春暉，黃沙磧裏無流水。", "金戈玉劍十年征，紅粉青樓多怨情。", "厭向殊鄉久離別，秋來愁聽擣衣聲。"]'),
('8551389a-8251-4516-80e0-9247893493ca','烏江女','屈同仙','唐','唐诗','tang','','[]','越豔誰家女，朝遊江岸傍。',48,'全唐诗/poet.tang.10000.json','["越豔誰家女，朝遊江岸傍。", "青春猶未嫁，紅粉舊來娼。", "錦袖盛朱橘，銀鉤摘紫房。", "見人羞不語，回艇入溪藏。"]'),
('c2b3aeca-a140-477f-bd2f-54a71f4353cd','昌年宮之作','豆盧復','唐','唐诗','tang','','[]','但有離宮處，君王每不居。',48,'全唐诗/poet.tang.10000.json','["但有離宮處，君王每不居。", "旗門芳草合，輦路小槐疎。", "殿閉山煙滿，窗凝野靄虛。", "豐年多望幸，春色待鑾輿。"]'),
('215caa5f-74fc-4e81-af61-b8ba6c9a9ff0','落第歸鄉留別長安主人','豆盧復','唐','唐诗','tang','','[]','客裏愁多不記春，聞鶯始歎柳條新。',32,'全唐诗/poet.tang.10000.json','["客裏愁多不記春，聞鶯始歎柳條新。", "年年下第東歸去，羞見長安舊主人。"]'),
('f558fbb7-b8d7-413b-bc61-fbafc0b99404','奉試詠青','荆冬倩','唐','唐诗','tang','','[]','路闢天光遠，春還月道臨。',48,'全唐诗/poet.tang.10000.json','["路闢天光遠，春還月道臨。", "草濃河畔色，槐結路邊陰。", "未映君王史，先標胄子襟。", "經明如可拾，自有致雲心。"]'),
('b22bb0c9-e21c-40d4-8aaf-24d3bf78fc49','觀漢水','梁洽','唐','唐诗','tang','','[]','發源自嶓冢，東注經襄陽。',48,'全唐诗/poet.tang.10000.json','["發源自嶓冢，東注經襄陽。", "一道入溟渤，別流爲滄浪。", "求思詠游女，投弔悲昭王。", "水濱不可問，日暮空湯湯。"]'),
('2237386f-91db-4f62-9103-fec2c5791d81','遊越溪','鄭紹','唐','唐诗','tang','','[]','溪水碧悠悠，猨聲斷客愁。',48,'全唐诗/poet.tang.10000.json','["溪水碧悠悠，猨聲斷客愁。", "漁潭逢釣楫，月浦值孤舟。", "訪泊隨煙火，迷途視斗牛。", "今宵越鄉意，還取醉忘憂。"]'),
('19340af6-e25d-41c8-90fc-b465d9be1134','登樓','朱斌','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9ec4\u6cb3", "\u5c71\u6c34", "\u52b1\u5fd7", "\u767b\u697c", "\u5199\u666f"]','白日依山盡，黃河入海流。',24,'全唐诗/poet.tang.10000.json','["白日依山盡，黃河入海流。", "欲窮千里目，更上一層樓。"]'),
('12ae270e-cab4-4a34-b9a1-0aaa66c16f98','感寓二首 一','梁德裕','唐','唐诗','tang','','[]','彩雲呈瑞質，五色發人寰。',48,'全唐诗/poet.tang.10000.json','["彩雲呈瑞質，五色發人寰。", "獨作龍虎狀，孤飛天地間。", "隱隱臨北極，峨峨象南山。", "恨在帝鄉外，不逢枝葉攀。"]'),
('19d9cc0a-3c1b-4697-871d-f53f26660013','感寓二首 二','梁德裕','唐','唐诗','tang','','[]','幽澗生蕙若，幽渚老江蘺。',72,'全唐诗/poet.tang.10000.json','["幽澗生蕙若，幽渚老江蘺。", "榮落人不見，芳香徒爾爲。", "不及綠萍草，生君紅蓮池。", "左右美人弄，朝夕春風吹。", "葉洗玉泉水，珠清湛露滋。", "心亦願如此，託君君不知。"]'),
('1c5837c9-6ef1-4c77-b669-77663144d23d','詠談容娘','常非月','唐','唐诗','tang','','[]','舉手整花鈿，翻身舞錦筵。',48,'全唐诗/poet.tang.10000.json','["舉手整花鈿，翻身舞錦筵。", "馬圍行處匝，人壓看場圓。", "歌要齊聲和，情教細語傳。", "不知心大小，容得許多憐。"]'),
('82a5b213-a081-4aa3-9f2d-2f36a9313063','覽史','張良璞','唐','唐诗','tang','','[]','享年八十已，歷數窮蒼生。',96,'全唐诗/poet.tang.10000.json','["享年八十已，歷數窮蒼生。", "七虎門源上，咆哮關內鳴。", "建都用鶉宿，設險因金城。", "舜曲煙火起，汾河珠翠明。", "海雲引天仗，朔雪留邊兵。", "作孽人怨久，其亡鬼信盈。", "素靈感劉季，白馬從子嬰。", "昏虐不務德，百代無芳聲。"]'),
('994e03a6-82ba-4093-a8f0-e13f2e784c19','奉試冷井詩','孫欣','唐','唐诗','tang','','[]','仙闈井初鑿，靈液沁成泉。',48,'全唐诗/poet.tang.10000.json','["仙闈井初鑿，靈液沁成泉。", "色湛青苔裏，寒凝紫綆邊。", "銅瓶向影落，玉甃抱虛圓。", "永願調神鼎，堯時泰萬年。"]'),
('b8bc4775-9f20-4ede-b873-0c0138d9bdd0','都中閑居','王羨門','唐','唐诗','tang','','[]','君王巡海內，北闕下明臺。',48,'全唐诗/poet.tang.10000.json','["君王巡海內，北闕下明臺。", "雲物天中少，煙花歲後來。", "河從御苑出，山向國門開。", "寂寞東京裏，空留賈誼才。"]'),
('6bfd22e0-4623-4efc-9678-a4d436cde303','江南弄','芮挺章','唐','唐诗','tang','','[]','春江可憐事，最在美人家。',48,'全唐诗/poet.tang.10000.json','["春江可憐事，最在美人家。", "鸚鵡能言鳥，芙蓉巧笑花。", "地銜金作埒，水抱玉爲沙。", "薄晚青絲騎，長鞭赴狹斜。"]'),
('c312e177-7bc0-4c6e-b9a6-ea31ebc32c39','少年行','芮挺章','唐','唐诗','tang','','[]','任氣稱張放，銜恩在少年。',48,'全唐诗/poet.tang.10000.json','["任氣稱張放，銜恩在少年。", "玉階朝就日，金屋夜升天。", "軒騎青雲際，笙歌綠水邊。", "建章明月好，留醉伴風煙。"]'),
('17e77a5c-a215-4d63-9f3a-c75c4c48187c','伊水門','樓頴','唐','唐诗','tang','','[]','朝涉伊水門，伊水入門流。',72,'全唐诗/poet.tang.10000.json','["朝涉伊水門，伊水入門流。", "愜心乃成興，澹然汎孤舟。", "霏微傍青靄，容與隨白鷗。", "竹陰交前浦，柳花媚中洲。", "日落陰雲生，彌覺茲路幽。", "聊以恣所適，此外知何求。"]'),
('b4d5874c-4eaf-4eec-ae81-15e1130e6fd4','東郊納涼憶左威衛李錄事收昆季太原崔參軍三首 一','樓頴','唐','唐诗','tang','','[]','水竹誰家宅，幽庭向苑門。',48,'全唐诗/poet.tang.10000.json','["水竹誰家宅，幽庭向苑門。", "今知季倫沼，舊是辟疆園。", "飢鷺窺魚靜，鳴鴉帶子喧。", "興成秪自適，欲白返忘言。"]'),
('2d69a74c-1dad-46c4-a6d8-78d56d12145d','東郊納涼憶左威衛李錄事收昆季太原崔參軍三首 二','樓頴','唐','唐诗','tang','','[]','納涼每選地，近得青門東。',48,'全唐诗/poet.tang.10000.json','["納涼每選地，近得青門東。", "林與繚垣接，池將沁水通。", "枝交帝女樹，橋映美人虹。", "想是忘機者，悠悠在興中。"]'),
('43033c59-1b27-4769-9fee-3d2c3185ce1a','東郊納涼憶左威衛李錄事收昆季太原崔參軍三首 三','樓頴','唐','唐诗','tang','','[]','林間求適意，池上得清飆。',48,'全唐诗/poet.tang.10000.json','["林間求適意，池上得清飆。", "稍稍斜回檝，時時一度橋。", "水光壁際動，山影浪中搖。", "不見李元禮，神仙何處要。"]'),
('79882b3c-9e56-4a56-a59e-96ee3cd33301','西施石','樓頴','唐','唐诗','tang','','[]','西施昔日浣紗津，石上青苔思殺人。',32,'全唐诗/poet.tang.10000.json','["西施昔日浣紗津，石上青苔思殺人。", "一去姑蘇不復返，岸旁桃李爲誰春。"]'),
('f0c0473c-b66b-47d3-aec2-8033fe7e2cce','江南行','李康成','唐','唐诗','tang','','[]','楊柳青青鶯欲啼，風光搖蕩綠蘋齊，金陰城頭日色低。',40,'全唐诗/poet.tang.10000.json','["楊柳青青鶯欲啼，風光搖蕩綠蘋齊，金陰城頭日色低。", "日色低，情難極，水中鳧鷖雙比翼。"]'),
('935306d8-d08d-41f7-b8f0-cad379229322','采蓮曲','李康成','唐','唐诗','tang','','[]','采蓮去，月沒春江曙。',50,'全唐诗/poet.tang.10000.json','["采蓮去，月沒春江曙。", "翠鈿紅袖水中央，青荷蓮子雜衣香，雲起風生歸路長。", "歸路長，那得久。", "各迴船，兩搖手。"]'),
('76d53cae-3896-4d5a-a8ee-5594289c037a','玉華仙子歌','李康成','唐','唐诗','tang','','[]','紫陽仙子名玉華，珠盤承露餌丹砂。',236,'全唐诗/poet.tang.10000.json','["紫陽仙子名玉華，珠盤承露餌丹砂。", "轉態凝情五雲裏，嬌顏千歲芙蓉花。", "紫陽綵女矜無數，遙見玉華皆掩嫭。", "高堂初日不成妍，洛渚流風徒自憐。", "璇階霓綺閣，碧題霜羅幕。", "仙娥桂樹長自春，王母桃花未嘗落。", "上元夫人賓上清，深宮寂歷厭層城。", "解佩空憐鄭交甫，吹簫不逐許飛瓊。", "溶溶紫庭步，渺渺瀛臺路。", "蘭陵貴士謝相逢，濟北風生尚迴顧。", "滄洲傲吏愛金丹，清心迴望雲之端。", "羽蓋霓裳一相識，傳情寫念長無極。", "長無極，永相隨。", "攀霄歷金闕，弄影下瑤池。", "夕宿紫府雲母帳，朝餐玄圃崑崙芝。", "不學蘭香中道絕，却教青鳥報相思。"]'),
('157dde0c-9fb0-4ca2-8c33-6f412582c028','自君之出矣','李康成','唐','唐诗','tang','','[]','自君之出矣，弦吹絕無聲。',24,'全唐诗/poet.tang.10000.json','["自君之出矣，弦吹絕無聲。", "思君如百草，撩亂逐春生。"]'),
('32e82de4-254a-41e6-a92f-2b2c676e9a1f','句','李康成','唐','唐诗','tang','','[]','因緣苟會合，萬里猶同鄉。',24,'全唐诗/poet.tang.10000.json','["因緣苟會合，萬里猶同鄉。", "運命尚不諧，隔壁無津梁。"]'),
('c05348b3-0526-4cf9-b443-eb0aecf607b5','時興','楊賁','唐','唐诗','tang','','[]','貴人昔未貴，咸願顧寒微。',48,'全唐诗/poet.tang.10000.json','["貴人昔未貴，咸願顧寒微。", "及自登樞要，何曾問布衣。", "平明登紫閣，日晏下彤闈。", "擾擾路傍子，無勞歌是非。"]'),
('612abeca-9d61-4454-8ba4-6e0b3e393cc9','詠石季倫','李清','唐','唐诗','tang','','[]','金谷繁華石季倫，只能謀富不謀身。',32,'全唐诗/poet.tang.10000.json','["金谷繁華石季倫，只能謀富不謀身。", "當時縱與綠珠去，猶有無窮歌舞人。"]'),
('82664df2-6554-44d5-ad5c-fceffb3c45bc','鶴警露','陳季','唐','唐诗','tang','','[]','南國商飆動，東臯野鶴鳴。',72,'全唐诗/poet.tang.10000.json','["南國商飆動，東臯野鶴鳴。", "溪松寒暫宿，露草滴還驚。", "欲有高飛意，空聞召侶情。", "風間傳藻質，月下引清聲。", "未假摶扶勢，焉知羽翼輕。", "吾君開太液，願得應皇明。"]'),
('df64caa8-cae5-4863-b8ce-d499357b1dab','湘靈鼓瑟','陳季','唐','唐诗','tang','','[]','神女泛瑤瑟，古祠嚴野亭。',72,'全唐诗/poet.tang.10000.json','["神女泛瑤瑟，古祠嚴野亭。", "楚雲來泱漭，湘水助清泠。", "妙指微幽契，繁聲入杳冥。", "一彈新月白，數曲暮山青。", "調苦荆人怨，時遙帝子靈。", "遺音如可賞，試奏爲君聽。"]'),
('abf04401-d182-49d3-8f95-1731010abba7','湘靈鼓瑟','王邕','唐','唐诗','tang','','[]','寶瑟和琴韻，靈妃應樂章。',72,'全唐诗/poet.tang.10000.json','["寶瑟和琴韻，靈妃應樂章。", "依稀聞促柱，髣髴夢新妝。", "波外聲初發，風前曲正長。", "淒清和萬籟，斷續繞三湘。", "轉覺雲山迥，空懷杜若芳。", "誠能傳此意，雅奏在宮商。"]'),
('6fcd37d1-dd53-4dd6-a562-45cd6b346dd6','嵩山望幸','王邕','唐','唐诗','tang','','[]','峻極位何崇，方知造化功。',72,'全唐诗/poet.tang.10000.json','["峻極位何崇，方知造化功。", "降靈逢聖主，望幸表維嵩。", "隱映連青壁，嵯峨向碧空。", "象車因叶瑞，龍駕願升中。", "萬歲聲長在，千巖氣轉雄。", "東都歌盛事，西笑佇皇風。"]'),
('6bd56fd4-dab6-4485-b48f-0333a6f4e4bc','湘靈鼓瑟','莊若訥','唐','唐诗','tang','','[]','帝子鳴金瑟，餘聲自抑揚。',72,'全唐诗/poet.tang.10000.json','["帝子鳴金瑟，餘聲自抑揚。", "悲風絲上斷，流水曲中長。", "出沒遊魚聽，逶迤彩鳳翔。", "微音時扣徵，雅韻乍含商。", "神理誠難測，幽情詎可量。", "至今聞古調，應恨滯三湘。"]'),
('799e398b-266a-474f-a861-cdcacae127a2','湘靈鼓瑟','魏璀','唐','唐诗','tang','','[]','瑤瑟多哀怨，朱弦且莫聽。',72,'全唐诗/poet.tang.10000.json','["瑤瑟多哀怨，朱弦且莫聽。", "扁舟三楚客，藂竹二妃靈。", "淅瀝聞餘響，依稀欲辨形。", "柱間寒水碧，曲裏暮山青。", "良馬悲銜草，遊魚思繞萍。", "知音若相遇，終不滯南溟。"]'),
('4d17d86c-b052-4a60-be76-3015ea8d1e8b','懷素上人草書歌','王𩔪','唐','唐诗','tang','','[]','衡陽雙峽插天峻，青壁巉巉萬餘仞。',226,'全唐诗/poet.tang.10000.json','["衡陽雙峽插天峻，青壁巉巉萬餘仞。", "此中靈秀衆所知，草書獨有懷素奇。", "懷素身長五尺四，嚼湯誦呪吁可畏。", "銅瓶錫杖倚閑庭，斑管秋毫多逸意。", "或粉壁，或綵牋，蒲葵絹素何相鮮。", "忽作風馳如電掣，更點飛花兼散雪。", "寒猨飲水撼枯藤，壯士拔山伸勁鐵。", "君不見張芝昔日稱獨賢，君不見近日張旭爲老顛。", "二公絕藝人所惜，懷素傳之得真跡。", "崢嶸蹙出海上山，突兀狀成湖畔石。", "一縱又一橫，一欹又一傾。", "臨江不羨飛帆勢，下筆長爲驟雨聲。", "我牧此州喜相識，又見草書多慧力。", "懷素懷素不可得，開卷臨池轉相憶。"]'),
('c269dec4-e6e7-40b3-b1c5-b371d0450eb0','懷素上人草書歌','竇冀','唐','唐诗','tang','','[]','狂僧揮翰狂且逸，獨任天機摧格律。',256,'全唐诗/poet.tang.10000.json','["狂僧揮翰狂且逸，獨任天機摧格律。", "龍虎慚因點畫生，雷霆却避鋒鋩疾。", "魚牋娟素豈不貴，只嫌局促兒童戲。", "粉壁長廊數十間，興來小豁胸襟氣。", "長幼集，賢豪至，枕糟藉麴猶半醉。", "忽然絕叫三五聲，滿壁縱橫千萬字。", "吳興張老爾莫顛，葉縣公孫我何謂。", "如熊如羆不足比，如虺如蛇不足擬。", "涵物爲動鬼神泣，狂風入林花亂起。", "殊形怪狀不易說，就中驚燥尤枯絕。", "邊風殺氣同慘烈，崩槎臥木爭摧折。", "塞草遙飛大漠霜，胡天亂下陰山雪。", "偏看能事轉新奇，郡守王公同賦詩。", "枯藤勁鐵媿三舍，驟雨寒猨驚一時。", "此生絕藝人莫測，假此常爲護持力。", "連城之璧不可量，五百年知草聖當。"]'),
('39bc54b3-62f5-49f3-8629-bcd6fe2026ff','懷素上人草書歌','魯收','唐','唐诗','tang','','[]','吾觀文士多利用，筆精墨妙誠堪重。',192,'全唐诗/poet.tang.10000.json','["吾觀文士多利用，筆精墨妙誠堪重。", "身上藝能無不通，就中草聖最天縱。", "有時興酣發神機，抽毫點墨縱橫揮。", "風聲吼烈隨手起，龍蛇迸落空壁飛。", "連拂數行勢不絕，藤懸查蹙生奇節。", "劃然放縱驚雲濤，或時頓挫縈豪髮。", "自言轉腕無所拘，大笑羲之用陣圖。", "狂來紙盡勢不盡，投筆抗聲連叫呼。", "信知鬼神助此道，墨池未盡書已好。", "行路談君口不容，滿堂觀者空絕倒。", "所恨時人多笑聲，唯知賤實翻貴名。", "觀爾向來三五字，顛奇何謝張先生。"]'),
('2365ddee-8124-44e2-ac84-53e8c677b8a9','懷素上人草書歌','朱逵','唐','唐诗','tang','','[]','幾年出家通宿命，一朝却憶臨池聖。',160,'全唐诗/poet.tang.10000.json','["幾年出家通宿命，一朝却憶臨池聖。", "轉腕摧鋒增崛崎，秋毫繭紙常相隨。", "衡陽客舍來相訪，連飲百杯神轉王。", "忽聞風裏度飛泉，紙落紛紛如跕鳶。", "形容脫略真如助，心思周游在何處。", "筆下惟看激電流，字成只畏盤龍去。", "怪狀崩騰若轉蓬，飛絲歷亂如迴風。", "長松老死倚雲壁，蹙浪相翻驚海鴻。", "于今年少尚如此，歷覩遠代無倫比。", "妙絕當動鬼神泣，崔蔡幽魂更心死。"]'),
('0b63bb31-0c8a-4643-af5a-b393c1c9c4d4','題懷素上人草書','許瑤','唐','唐诗','tang','','[]','志在新奇無定則，古瘦灕纚半無墨。',32,'全唐诗/poet.tang.10000.json','["志在新奇無定則，古瘦灕纚半無墨。", "醉來信手兩三行，醒後却書書不得。"]'),
('28b2515e-49c3-49f9-8702-d7b63a8136f4','祀風師樂章 迎神','包佶','唐','唐诗','tang','','[]','太皞御氣，句芒肇功。',40,'全唐诗/poet.tang.10000.json','["太皞御氣，句芒肇功。", "蒼龍青旗，爰候祥風。", "律以和應，神以感通。", "鼎俎脩蠁，時惟禮崇。"]'),
('fb26e2fd-fd49-4ebe-a774-2c01ad17fa90','祀風師樂章 奠幣登歌','包佶','唐','唐诗','tang','','[]','旨酒告潔，青蘋應候。',40,'全唐诗/poet.tang.10000.json','["旨酒告潔，青蘋應候。", "禮陳瑤幣，樂獻金奏。", "彈弦自昔，解凍惟舊。", "仰瞻肸蠁，羣祥來湊。"]'),
('d6a27558-dde1-4b22-b245-664a2bf49a29','祀風師樂章 迎俎酌獻','包佶','唐','唐诗','tang','','[]','德盛昭臨，迎拜巽方。',40,'全唐诗/poet.tang.10000.json','["德盛昭臨，迎拜巽方。", "爰候發生，式薦馨香。", "酌醴具舉，工歌再揚。", "神歆入律，恩降百祥。"]'),
('28e9732b-57cd-451d-b6f1-80004f369685','祀風師樂章 亞獻終獻','包佶','唐','唐诗','tang','','[]','膋薌備，玉帛陳。',32,'全唐诗/poet.tang.10000.json','["膋薌備，玉帛陳。", "風動物，樂感神。", "三獻終，百神臻。", "草木榮，天下春。"]'),
('43745683-136f-47c7-9e3c-0bdba015e213','祀風師樂章 送神','包佶','唐','唐诗','tang','','[]','微穆敷華能應節，飄揚發彩宜行慶。',64,'全唐诗/poet.tang.10000.json','["微穆敷華能應節，飄揚發彩宜行慶。", "送迎靈駕神心饗，跪拜靈壇禮容盛。", "氣和草木發萌芽，德暢禽魚遂翔泳。", "永望翠蓋逐流雲，自茲率土調春令。"]'),
('100d48d7-777e-48a5-8a24-437bbb9aad06','祀雨師樂章 迎神','包佶','唐','唐诗','tang','','[]','陟降左右，誠達幽圓。',40,'全唐诗/poet.tang.10000.json','["陟降左右，誠達幽圓。", "作解之功，樂惟有年。", "雲軿戾止，灑霧飄煙。", "惟馨展禮，爰列豆籩。"]'),
('dfe6bbaa-2b5f-4aed-94a1-b23a41960a48','祀雨師樂章 奠幣登歌','包佶','唐','唐诗','tang','','[]','歲正朱明，禮布玄制。',40,'全唐诗/poet.tang.10000.json','["歲正朱明，禮布玄制。", "惟樂能感，與神合契。", "陰霧離披，靈馭搖裔。", "膏澤之慶，期於稔歲。"]'),
('a97b3c58-cbd4-419d-a959-8b4c3beeb3ad','祀雨師樂章 迎俎酌獻','包佶','唐','唐诗','tang','','[]','陽開幽蟄，躬奉鬱鬯。',40,'全唐诗/poet.tang.10000.json','["陽開幽蟄，躬奉鬱鬯。", "禮備節應，震來靈降。", "動植求聲，飛沈允望。", "時康氣茂，惟神之貺。"]'),
('d09d1609-8bf2-4982-82e3-83cce2ef2a91','祀雨師樂章 亞獻終獻','包佶','唐','唐诗','tang','','[]','奠既備，獻將終。',32,'全唐诗/poet.tang.10000.json','["奠既備，獻將終。", "神行令，瑞飛空。", "迎乾德，祈歲功。", "乘煙燎，儼從風。"]'),
('44e3940f-60cb-4554-a34f-44c4e20939b5','祀雨師樂章 送神','包佶','唐','唐诗','tang','','[]','整駕升車望寥廓，垂陰薦祉蕩昏氛。',64,'全唐诗/poet.tang.10000.json','["整駕升車望寥廓，垂陰薦祉蕩昏氛。", "饗時靈貺僾如在，樂罷餘聲遙可聞。", "飲福陳誠禮容備，撤俎終獻曙光分。", "跪拜臨壇結空想，年年應節候油雲。"]'),
('3701a25a-98c8-4ff3-bfa5-1118d77f8800','答竇援遺臥病見寄','包佶','唐','唐诗','tang','','[]','今春扶病移滄海，幾度承恩對白花。',64,'全唐诗/poet.tang.10000.json','["今春扶病移滄海，幾度承恩對白花。", "送客屢聞簾外鵲，銷愁已辨酒中虵。", "瓶開枸杞懸泉水，鼎鍊芙蓉伏火砂。", "誤入塵埃牽吏役，羞將簿領到君家。"]'),
('28880f73-8de2-43d1-8e5d-648dee798338','對酒贈故人','包佶','唐','唐诗','tang','','[]','扶起離披菊，霜輕喜重開。',48,'全唐诗/poet.tang.10000.json','["扶起離披菊，霜輕喜重開。", "醉中驚老去，笑裏覺愁來。", "月送人無盡，風吹浪不回。", "感時將有寄，詩思澀難裁。"]'),
('a2f6d5f6-85d3-4363-ae06-f7c437690049','同李吏部伏日口號呈元庶子路中丞','包佶','唐','唐诗','tang','','[]','火炎逢六月，金伏過三庚。',48,'全唐诗/poet.tang.10000.json','["火炎逢六月，金伏過三庚。", "幾度衣裳汗，誰家枕簟清。", "頒冰無下位，裁扇有高名。", "吏部還開甕，殷勤二客情。"]'),
('fa21adbe-1de4-40d0-888d-38ebbe473d3a','嶺下臥疾寄劉長卿員外','包佶','唐','唐诗','tang','','[]','唯有貧兼病，能令親愛疎。',72,'全唐诗/poet.tang.10000.json','["唯有貧兼病，能令親愛疎。", "歲時供放逐，身世付空虛。", "脛弱秋添絮，頭風曉廢梳。", "波瀾喧衆口，藜藿靜吾廬。", "喪馬思開卦，占鴞嬾發書。", "十年江海隔，離恨子知予。"]'),
('9b7c07da-1c88-4ce4-8576-fd922f78d183','戲題諸判官廳壁','包佶','唐','唐诗','tang','','[]','六十老翁無所取，二三君子不相遺。',32,'全唐诗/poet.tang.10000.json','["六十老翁無所取，二三君子不相遺。", "願留今日交歡意，直到隳官謝病時。"]'),
('cd892edd-f7b3-4d5c-bacc-8b1a02a0564a','酬兵部李侍郎晚過東廳之作','包佶','唐','唐诗','tang','','[]','酒禮慙先祭，刑書已曠官。',48,'全唐诗/poet.tang.10000.json','["酒禮慙先祭，刑書已曠官。", "詔馳黃紙速，身在絳紗安。", "聖位登堂靜，生徒跪席寒。", "庭槐暫搖落，幸爲入春看。"]'),
('7bfe6521-bb53-46ae-af7c-2339309f0605','昭德皇后挽歌詞','包佶','唐','唐诗','tang','','[]','西汜馳暉過，東園別路長。',48,'全唐诗/poet.tang.10000.json','["西汜馳暉過，東園別路長。", "歲華唯隴柏，春事罷公桑。", "龜兆開泉戶，禽巢閉畫梁。", "更聞哀禮過，明詔制心喪。"]'),
('3dff0f52-aa3a-4933-ad04-39145433b715','秋日過徐氏園林','包佶','唐','唐诗','tang','','[]','回塘分越水，古樹積吳煙。',48,'全唐诗/poet.tang.10000.json','["回塘分越水，古樹積吳煙。", "掃竹催鋪席，垂蘿待繫船。", "鳥窺新罅栗，龜上半攲蓮。", "屢入忘歸地，長嗟俗事牽。"]'),
('4e1e3697-9fad-4ec7-9c4e-4bc4b8bb90f3','雙山過信公所居','包佶','唐','唐诗','tang','','[]','遙禮前朝塔，微聞後夜鐘。',48,'全唐诗/poet.tang.10000.json','["遙禮前朝塔，微聞後夜鐘。", "人間第四祖，雲裏一雙峰。", "積雨封苔徑，多年亞石松。", "傳心不傳法，誰可繼高蹤。"]'),
('c46b6815-891b-4b37-8fd1-533c6b1c31a2','尚書宗兄使過詩以奉獻','包佶','唐','唐诗','tang','','[]','洛下交親滿，歸閑意有餘。',72,'全唐诗/poet.tang.10000.json','["洛下交親滿，歸閑意有餘。", "翻嫌舊坐宅，却駕所懸車。", "腹飽山僧供，頭輕侍婢梳。", "上官唯揖讓，半祿代耕鉏。", "雨散三秋別，風傳一字書。", "勝遊如可繼，還欲並園廬。"]'),
('0879b3a8-9a54-4a34-9746-c2490ef2497e','抱疾謝李吏部贈訶黎勒葉','包佶','唐','唐诗','tang','','[]','一葉生西徼，齎來上海查。',72,'全唐诗/poet.tang.10000.json','["一葉生西徼，齎來上海查。", "歲時經水府，根本別天涯。", "方士真難見，商胡輒自誇。", "此香同異域，看色勝仙家。", "茗飲暫調氣，梧丸喜伐邪。", "幸蒙祛老疾，深願駐韶華。"]'),
('23ecc4c8-9ab8-4d67-a68c-1d2f0e57f0ff','奉和柳相公中書言懷','包佶','唐','唐诗','tang','','[]','運籌時所貴，前席禮偏深。',48,'全唐诗/poet.tang.10000.json','["運籌時所貴，前席禮偏深。", "羸駕歸貧宅，攲冠出禁林。", "鳳巢方得地，牛喘最關心。", "雅望期三入，東山未可尋。"]'),
('3b39dc82-798d-44db-8452-bf8e17e7d343','客自江南話過亡友朱司議故宅','包佶','唐','唐诗','tang','','[]','交臂多相共，風流憶此人。',48,'全唐诗/poet.tang.10000.json','["交臂多相共，風流憶此人。", "海翻移里巷，書蠹積埃塵。", "奉佛棲禪久，辭官上疏頻。", "故來分半宅，惟是舊交親。"]'),
('a2250742-d493-44e6-9035-33a91c1b5162','酬于侍郎湖南見寄十四韻','包佶','唐','唐诗','tang','','[]','桂嶺千崖斷，湘流一派通。',168,'全唐诗/poet.tang.10000.json','["桂嶺千崖斷，湘流一派通。", "長沙今賈傅，東海舊于公。", "章甫經殊俗，離騷繼雅風。", "金閨文作字，玉匣氣成虹。", "翰墨時招侶，丹青夙在公。", "主恩留左掖，人望積南宮。", "巧拙循名異，浮沈顧位同。", "九遷歸上略，三已契愚衷。", "責謝庭中吏，悲寬塞上翁。", "楚材欣有適，燕石愧無功。", "山曉重嵐外，林春苦霧中。", "雪花翻海鶴，波影倒江楓。", "去札頻逢信，回帆早挂空。", "避賢方有日，非敢愛微躬。"]'),
('f9bf081f-19e0-4276-bfae-1331b732a6d3','朝拜元陵','包佶','唐','唐诗','tang','','[]','宮前石馬對中峰，雲裏金鋪閉幾重。',32,'全唐诗/poet.tang.10000.json','["宮前石馬對中峰，雲裏金鋪閉幾重。", "不見露盤迎曉日，唯聞木斧扣寒松。"]'),
('b0e238eb-b1b5-4edb-820b-e5cc8b6481e1','發襄陽後却寄公安人','包佶','唐','唐诗','tang','','[]','揮淚送迴人，將書報所親。',48,'全唐诗/poet.tang.10000.json','["揮淚送迴人，將書報所親。", "晚年多疾病，中路有風塵。", "王粲頻徵楚，君恩許入秦。", "還同星火去，馬上別江春。"]'),
('12cabe5b-f212-401c-bcd7-fc940a5870b6','立春後休沐','包佶','唐','唐诗','tang','','[]','心與青春背，新年亦掩扉。',48,'全唐诗/poet.tang.10000.json','["心與青春背，新年亦掩扉。", "漸窮無相學，惟避不材譏。", "積病攻難愈，銜恩報轉微。", "定知書課日，優詔許辭歸。"]'),
('feb085bc-e461-4a18-b787-e831e3ef1885','宿廬山贈白鶴觀劉尊師','包佶','唐','唐诗','tang','','["\u5e90\u5c71"]','蒼蒼五老霧中壇，杳杳三山洞裏官。',64,'全唐诗/poet.tang.10000.json','["蒼蒼五老霧中壇，杳杳三山洞裏官。", "手護崑崙象牙簡，心推霹靂棗枝盤。", "春飛雪粉如毫潤，曉漱瓊膏冰齒寒。", "漸恨流年筋力少，惟思露冕事星冠。"]'),
('5b59b031-7cee-4c88-8023-1b0b04a9da60','觀壁盧九想圖','包佶','唐','唐诗','tang','','[]','一世榮枯無異同，百年哀樂又歸空。',32,'全唐诗/poet.tang.10000.json','["一世榮枯無異同，百年哀樂又歸空。", "夜闌鳥鵲相爭處，林下真僧在定中。"]'),
('6d7b4fc4-62ae-48e7-a486-a8ff73caaf7d','送日本國聘賀使晁巨卿東歸','包佶','唐','唐诗','tang','','[]','上才生下國，東海是西鄰。',72,'全唐诗/poet.tang.10000.json','["上才生下國，東海是西鄰。", "九譯蕃君使，千年聖主臣。", "野情偏得禮，木性本含真。", "錦帆乘風轉，金裝照地新。", "孤城開蜃閣，曉日上朱輪。", "早識來朝歲，塗山玉帛均。"]'),
('7da2608c-26ec-44e8-a87b-2ba1aa566724','顧著作宅賦詩','包佶','唐','唐诗','tang','','[]','幾年江海煙霞，乘醉一到京華。',56,'全唐诗/poet.tang.10000.json','["幾年江海煙霞，乘醉一到京華。", "已覺不嫌羊酪，誰能長守兔罝。", "脫巾偏招相國，逢竹便認吾家。", "各在芸臺閣裏，煩君日日登車。"]'),
('6360ff09-9f22-4d4e-87bf-301394732d34','近獲風痺之疾題寄所懷','包佶','唐','唐诗','tang','','[]','病夫將已矣，無可答君恩。',96,'全唐诗/poet.tang.10000.json','["病夫將已矣，無可答君恩。", "衾枕同羇客，圖書委外孫。", "久來從吏道，常欲奉空門。", "疾走機先息，攲行力漸煩。", "無醫能却老，有變是游魂。", "鳥宿還依伴，蓬飄莫問根。", "寓形齊指馬，觀境制心猨。", "唯借南榮地，清晨暫負喧。"]'),
('42864ab0-426d-435d-b6e9-81a45a5f225d','奉和常閣老晚秋集賢院即事寄贈徐薛二侍郎','包佶','唐','唐诗','tang','','[]','祕殿掖垣西，書樓苑樹齊。',144,'全唐诗/poet.tang.10000.json','["祕殿掖垣西，書樓苑樹齊。", "秋煙凝縹帙，曉色上璇題。", "門接承明近，池連太液低。", "疎鐘文馬駐，繁葉綵禽栖。", "職美綸江綍，榮深組及珪。", "九霄偏眷顧，三事早提攜。", "對案臨青玉，窺書捧紫泥。", "始歡新遇重，還惜舊遊暌。", "左宦登吳岫，分家渡越溪。", "賦中頻歎鵩，卜處幾聽雞。", "望闕應多戀，臨津不用迷。", "柏梁思和曲，朝夕候金閨。"]'),
('c55e35df-d9e5-49a2-a088-4595d03dd2f0','酬顧況見寄','包佶','唐','唐诗','tang','','[]','于越城邊楓葉高，楚人書裏寄離騷。',32,'全唐诗/poet.tang.10000.json','["于越城邊楓葉高，楚人書裏寄離騷。", "寒江鸂鶒思儔侶，歲歲臨流刷羽毛。"]'),
('e27839b5-a0d2-41ff-aa5b-a2a0355afc68','歲日作','包佶','唐','唐诗','tang','','[]','更勞今日春風至，枯樹無枝可寄花。',32,'全唐诗/poet.tang.10000.json','["更勞今日春風至，枯樹無枝可寄花。", "覽鏡唯看飄亂髮，臨風誰爲駐浮槎。"]'),
('002801a4-8a5f-4931-83cd-49a1f94b0e51','元日觀百僚朝會','包佶','唐','唐诗','tang','','[]','萬國賀唐堯，清晨會百僚。',72,'全唐诗/poet.tang.10000.json','["萬國賀唐堯，清晨會百僚。", "花冠蕭相府，繡服霍嫖姚。", "壽色凝丹檻，歡聲徹九霄。", "御鑪分獸炭，仙管弄雲韶。", "日照金觴動，風吹玉佩搖。", "都城獻賦者，不得共趨朝。"]'),
('99e68734-394d-4679-93a3-e60c4e1ad4b4','再過金陵','包佶','唐','唐诗','tang','','[]','玉樹歌終王氣收，鴈行高送石城秋。',32,'全唐诗/poet.tang.10000.json','["玉樹歌終王氣收，鴈行高送石城秋。", "江山不管興亡事，一任斜陽伴客愁。"]'),
('485b1bb2-22ad-445c-980e-219abd32e4f0','寄楊侍御','包佶','唐','唐诗','tang','','[]','一官何幸得同時，十載無媒獨見遺。',32,'全唐诗/poet.tang.10000.json','["一官何幸得同時，十載無媒獨見遺。", "今日不論腰下組，請君看取鬢邊絲。"]'),
('a9c84c93-6f83-4456-80d8-8b7fe5e427a2','江上曲','李嘉祐','唐','唐诗','tang','','[]','江心澹澹芙蓉花，江口蛾眉獨浣紗。',80,'全唐诗/poet.tang.10000.json','["江心澹澹芙蓉花，江口蛾眉獨浣紗。", "可憐應是陽臺女，對坐鷺鷥嬌不語。", "掩面羞看北地人，回身忽作空山語。", "蒼梧秋色不堪論，千載依依帝子魂。", "君看峰上斑斑竹，盡是湘妃泣淚痕。"]'),
('28a07ece-270c-4194-ad97-8b944d5d4293','傷吳中','李嘉祐','唐','唐诗','tang','','[]','館娃宮中春已歸，闔閭城頭鶯已飛。',96,'全唐诗/poet.tang.10000.json','["館娃宮中春已歸，闔閭城頭鶯已飛。", "復見花開人又老，橫塘寂寂柳依依。", "憶昔吳王在宮闕，館娃滿眼看花發。", "舞袖朝欺陌上春，歌聲夜怨江邊月。", "古來人事亦猶今，莫厭清觴與綠琴。", "獨向西山聊一笑，白雲芳草自知心。"]'),
('7e30c468-9d80-4b8c-9a87-1276b583687a','夜聞江南人家賽神因題即事','李嘉祐','唐','唐诗','tang','','[]','南方淫祀古風俗，楚嫗解唱迎神曲。',128,'全唐诗/poet.tang.10000.json','["南方淫祀古風俗，楚嫗解唱迎神曲。", "鎗鎗銅鼓蘆葉深，寂寂瓊筵江水綠。", "雨過風清洲渚閑，椒漿醉盡迎神還。", "帝女凌空下湘岸，番君隔浦向堯山。", "月隱回塘猶自舞，一門依倚神之祜。", "韓康靈藥不復求，扁鵲醫方曾莫覩。", "逐客臨江空自悲，月明流水無已時。", "聽此迎神送神曲，攜觴欲弔屈原祠。"]'),
('6474e381-8e86-4d81-859b-c164f2155a19','古興','李嘉祐','唐','唐诗','tang','','[]','十五小家女，雙鬟人不如。',88,'全唐诗/poet.tang.10000.json','["十五小家女，雙鬟人不如。", "蛾眉暫一見，可直千金餘。", "自從得向蓬萊裏，出入金輿乘玉趾。", "梧桐樹上春鴉鳴，曉伴君王猶未起。", "莫道君恩長不休，婕妤團扇苦悲秋。", "君看魏帝鄴都裏，惟有銅臺漳水流。"]'),
('9fb7edee-7723-4b43-b0d1-9266be92085a','雜興','李嘉祐','唐','唐诗','tang','','[]','花間昔日黃鸝囀，妾向青樓已生怨。',60,'全唐诗/poet.tang.10000.json','["花間昔日黃鸝囀，妾向青樓已生怨。", "花落黃鸝不復來，妾老君心亦應變。", "君心比妾心，妾意舊來深。", "一別十年無尺素，歸時莫贈路傍金。"]'),
('02fdb3e2-f9dc-42c6-86cc-7d25e26b7411','送韋邕少府歸鍾山','李嘉祐','唐','唐诗','tang','','[]','祈門官罷後，負笈向桃源。',48,'全唐诗/poet.tang.10000.json','["祈門官罷後，負笈向桃源。", "萬卷長開帙，千峰不閉門。", "綠楊垂野渡，黃鳥傍山村。", "念爾能高枕，丹墀會一論。"]'),
('533548fe-7dd5-4443-9374-5d91c7be7eea','送盧員外往饒州','李嘉祐','唐','唐诗','tang','','[]','爲郎復典郡，錦帳映朱輪。',48,'全唐诗/poet.tang.10000.json','["爲郎復典郡，錦帳映朱輪。", "露冕隨龍節，停橈得水人。", "早霜蘆葉變，寒雨石榴新。", "莫怪諳風土，三年作逐臣。"]'),
('5fc627fa-6569-4d61-9498-2b3b770ae02c','送裴五歸京口','李嘉祐','唐','唐诗','tang','','[]','君罷江西日，家貧爲一官。',48,'全唐诗/poet.tang.10000.json','["君罷江西日，家貧爲一官。", "還歸五陵去，只向遠峰看。", "暮色催人別，秋風待雨寒。", "遙知到三徑，唯有菊花殘。"]'),
('6ddf2b76-d1de-4a26-adaa-48c0cd3203d2','送嚴維歸越州','李嘉祐','唐','唐诗','tang','','[]','艱難只用武，歸向淛河東。',48,'全唐诗/poet.tang.10000.json','["艱難只用武，歸向淛河東。", "松雪千山暮，林泉一水通。", "鄉心緣綠草，野思看青楓。", "春日偏相憶，裁書寄剡中。"]'),
('4173ec91-e1df-4acd-ab7c-697ff97e31b8','送杜士瞻楚州覲省','李嘉祐','唐','唐诗','tang','','[]','風流與才思，俱似晉時人。',48,'全唐诗/poet.tang.10000.json','["風流與才思，俱似晉時人。", "淮月歸心促，江花入興新。", "雲深滄海暮，柳暗白田春。", "共道官猶小，憐君孝養親。"]'),
('c8a0aa65-3552-4460-9a5a-08eecec348a7','送裴宣城上元所居','李嘉祐','唐','唐诗','tang','','[]','水流過海稀，爾去換春衣。',48,'全唐诗/poet.tang.10000.json','["水流過海稀，爾去換春衣。", "淚向檳榔盡，身隨鴻雁歸。", "草思晴後發，花怨雨中飛。", "想到金陵渚，酣歌對落暉。"]'),
('dde40866-706c-4105-8845-b9babd63a926','留別毘陵諸公','李嘉祐','唐','唐诗','tang','','[]','久作涔陽令，丹墀忽再還。',48,'全唐诗/poet.tang.10000.json','["久作涔陽令，丹墀忽再還。", "淒涼辭澤國，離亂到鄉山。", "北固灘聲滿，南徐草色閑。", "知心從此別，相憶鬢毛斑。"]'),
('71435a7a-6541-45dd-a0f3-de97ca80c620','送獨孤拾遺先輩先赴上都','李嘉祐','唐','唐诗','tang','','[]','行春日已曉，桂檝逐寒煙。',48,'全唐诗/poet.tang.10000.json','["行春日已曉，桂檝逐寒煙。", "轉曲遙峰出，看濤極浦連。", "入京當獻賦，封事更聞天。", "日日趨黃閣，應忘雲海邊。"]'),
('6a1dfe28-4e40-488a-844d-5dbf5f3023e8','常州韋郎中汎舟見餞','李嘉祐','唐','唐诗','tang','','[]','主人馮軾貴，送客汎舟稀。',48,'全唐诗/poet.tang.10000.json','["主人馮軾貴，送客汎舟稀。", "逼岸隨芳草，回橈背落暉。", "映花雙節駐，臨水伯勞飛。", "醉與羣公狎，春塘露冕歸。"]'),
('c1ebbb06-55b7-40d1-8f23-63491faa6fa7','送崔侍御入朝','李嘉祐','唐','唐诗','tang','','[]','十年猶執憲，萬里獨歸春。',48,'全唐诗/poet.tang.10000.json','["十年猶執憲，萬里獨歸春。", "舊國逢芳草，青雲見故人。", "潘郎今髮白，陶令本家貧。", "相送臨京口，停橈淚滿巾。"]'),
('ccd8a969-3713-4066-b890-ead4d4fb7b6e','送岳州司馬弟之任','李嘉祐','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','岳陽天水外，念爾一帆過。',48,'全唐诗/poet.tang.10000.json','["岳陽天水外，念爾一帆過。", "野墅人煙逈，山城雁影多。", "有時巫峽色，終日洞庭波。", "丞相今爲郡，應無勞者歌。"]'),
('41181679-c303-4d56-a0a2-f454236cfa0b','裴侍御見贈斑竹杖','李嘉祐','唐','唐诗','tang','','[]','騷人誇竹杖，贈我意何深。',48,'全唐诗/poet.tang.10000.json','["騷人誇竹杖，贈我意何深。", "萬點湘妃淚，三年賈誼心。", "願持終白首，誰道貴黃金。", "他日歸愚谷，偏宜綠綺琴。"]'),
('3e04861a-4123-4038-8fb3-b7089068eada','送張觀歸袁州','李嘉祐','唐','唐诗','tang','','[]','羨爾湘東去，煙花尚可親。',48,'全唐诗/poet.tang.10000.json','["羨爾湘東去，煙花尚可親。", "綠芳深映鳥，遠岫遞迎人。", "飢狖啼初日，殘鶯惜暮春。", "遙憐謝客興，佳句又應新。"]'),
('a7994f02-d08b-4d5b-9ffa-1aab1ca621a1','冬夜饒州使堂餞相公五叔赴歙州','李嘉祐','唐','唐诗','tang','','[]','丞相過邦牧，清絃送羽觴。',48,'全唐诗/poet.tang.10000.json','["丞相過邦牧，清絃送羽觴。", "高情同客醉，子夜爲人長。", "斜漢這過斗，寒雲正護霜。", "新安江自綠，明主待惟良。"]'),
('2b67d634-5c78-4b60-a552-b2a4c1c0f570','蔣山開善寺','李嘉祐','唐','唐诗','tang','','[]','山殿秋雲裏，香煙出翠微。',48,'全唐诗/poet.tang.10000.json','["山殿秋雲裏，香煙出翠微。", "客尋朝磬至，僧背夕陽歸。", "下界千門在，前朝萬事非。", "看心兼送目，葭菼自依依。"]'),
('64ce1225-6e8b-46b5-b1df-50a4cba1f0f3','晚發江寧道中呈嚴維','李嘉祐','唐','唐诗','tang','','[]','惆悵遙江路，蕭條落日過。',48,'全唐诗/poet.tang.10000.json','["惆悵遙江路，蕭條落日過。", "蟬鳴獨樹急，鴉向古城多。", "轉曲隨青嶂，因高見白波。", "潘生秋徑草，嚴子意如何。"]'),
('020842e9-f0d8-42ab-b484-44909b2da611','句容縣東青陽館作','李嘉祐','唐','唐诗','tang','','[]','句曲千峰暮，歸人向遠煙。',48,'全唐诗/poet.tang.10000.json','["句曲千峰暮，歸人向遠煙。", "風搖近水葉，雲護欲晴天。", "夕照留山館，秋光落草田。", "征途傍斜日，一騎獨翩翩。"]'),
('74dba239-9f0b-4c10-b35c-a4a3440c1844','晚春宴無錫蔡明府西亭','李嘉祐','唐','唐诗','tang','','[]','茅簷閑寂寂，無事覺人和。',48,'全唐诗/poet.tang.10000.json','["茅簷閑寂寂，無事覺人和。", "井近時澆圃，城低下見河。", "興緣芳草積，情向遠峰多。", "別日歸吳地，停橈更一過。"]'),
('d93b38b6-87b1-4440-9a3e-ef787ece0177','送王端赴朝','李嘉祐','唐','唐诗','tang','','[]','君承明主意，日日上丹墀。',48,'全唐诗/poet.tang.10000.json','["君承明主意，日日上丹墀。", "東閣論兵後，南宮草奏期。", "人稀傍河處，槐暗入關時。", "獨遣吳州客，平陵結夢思。"]'),
('9deee86d-3d16-40f1-aff9-f8805c75d827','送王正字山寺讀書','李嘉祐','唐','唐诗','tang','','[]','欲究先儒教，還過支遁居。',48,'全唐诗/poet.tang.10000.json','["欲究先儒教，還過支遁居。", "山堦閑聽法，竹逕獨看書。", "向日荷新卷，迎秋柳半疎。", "風流有佳句，不似帶經鋤。"]'),
('d4964360-04be-4cde-a26a-df00ee1f498c','送房明府罷長寧令湖州客舍','李嘉祐','唐','唐诗','tang','','[]','君爲萬里宰，恩及五湖人。',48,'全唐诗/poet.tang.10000.json','["君爲萬里宰，恩及五湖人。", "未滿先求退，歸閑不厭貧。", "遠峰晴更近，殘柳雨還新。", "要自趨丹陛，明年雞樹親。"]'),
('5c23312e-3048-4c55-9912-4d83d982cf18','詠螢','李嘉祐','唐','唐诗','tang','','[]','映水光難定，凌虛體自輕。',48,'全唐诗/poet.tang.10000.json','["映水光難定，凌虛體自輕。", "夜風吹不滅，秋露洗還明。", "向燭仍分焰，投書更有情。", "猶將流亂影，來此傍簷楹。"]'),
('50b98014-0f20-4554-b959-8c8929b28582','送李中丞楊判官','李嘉祐','唐','唐诗','tang','','[]','射策名先著，論兵氣自雄。',48,'全唐诗/poet.tang.10000.json','["射策名先著，論兵氣自雄。", "能全季布諾，不道魯連功。", "流水蒹葭外，諸山睥睨中。", "別君秋日晚，回首夕陽空。"]'),
('90852836-e7f5-4e1f-87d7-5961625496ad','至七里灘作','李嘉祐','唐','唐诗','tang','','[]','遷客投於越，臨江淚滿衣。',48,'全唐诗/poet.tang.10000.json','["遷客投於越，臨江淚滿衣。", "獨隨流水遠，轉覺故人稀。", "萬木迎秋序，千峰駐晚暉。", "行舟猶未已，惆悵暮潮歸。"]'),
('4da1836b-da70-4a43-9e51-a9bc390a0fe9','南浦渡口','李嘉祐','唐','唐诗','tang','','[]','寂寞橫塘路，新篁覆水低。',48,'全唐诗/poet.tang.10000.json','["寂寞橫塘路，新篁覆水低。", "東風潮信滿，時雨稻秔齊。", "寡婦共租稅，漁人逐鼓鼙。", "慙無卓魯術，解印謝黔黎。"]'),
('0167aaca-d4f5-4e4b-9fb8-bd29260f31b7','暮秋遷客增思寄京華','李嘉祐','唐','唐诗','tang','','[]','宋玉怨三秋，張衡復四愁。',48,'全唐诗/poet.tang.10000.json','["宋玉怨三秋，張衡復四愁。", "思鄉雁北至，欲別水東流。", "倚樹看黃葉，逢人訴白頭。", "佳期不可失，落日自登樓。"]'),
('d09e9302-9cad-4c5d-9a81-9333926e16c5','送蘇修往上饒','李嘉祐','唐','唐诗','tang','','[]','愛爾無羈束，雲山恣意過。',48,'全唐诗/poet.tang.10000.json','["愛爾無羈束，雲山恣意過。", "一身隨遠岫，孤櫂任輕波。", "世事關心少，漁家寄宿多。", "蘆花泊舟處，江月奈人何。"]'),
('e5e8730f-33d8-4f24-9e84-c5736559a754','題王十九茆堂','李嘉祐','唐','唐诗','tang','','[]','滿庭多種藥，入里作山家。',48,'全唐诗/poet.tang.10000.json','["滿庭多種藥，入里作山家。", "終日能留客，凌寒亦對花。", "海鷗過竹嶼，門柳拂江沙。", "知爾卑棲意，題詩美白華。"]'),
('4058b815-c70e-4e63-8101-481838451b80','送弘志上人歸湖州','李嘉祐','唐','唐诗','tang','','[]','山林唯幽靜，行住不妨禪。',48,'全唐诗/poet.tang.10000.json','["山林唯幽靜，行住不妨禪。", "高月穿松逕，殘陽過水田。", "詩從宿世悟，法爲本師傳。", "能使南人敬，修持香火緣。"]'),
('a8af9dc6-1cb8-481a-99f5-a5b541a7211c','送陸士倫宰義興','李嘉祐','唐','唐诗','tang','','[]','陽羨蘭陵近，高城帶水閑。',48,'全唐诗/poet.tang.10000.json','["陽羨蘭陵近，高城帶水閑。", "淺流通野寺，綠茗蓋春山。", "長吏多愁罷，遊人詎肯還。", "知君日清淨，無事掩重關。"]'),
('57a69cfd-64bb-45a4-a77f-acd1e0ccd4f2','和張舍人中書宿直','李嘉祐','唐','唐诗','tang','','[]','漢主留才子，春城直紫微。',48,'全唐诗/poet.tang.10000.json','["漢主留才子，春城直紫微。", "對花閶闔靜，過竹吏人稀。", "裁詔催添燭，將朝欲更衣。", "玉堂宜歲久，且莫厭彤闈。"]'),
('906f5bf6-edeb-4e57-ad55-b555632ed3f2','司勳王郎中宅送韋九郎中往濠州','李嘉祐','唐','唐诗','tang','','[]','憐爾因同舍，看書似外家。',48,'全唐诗/poet.tang.10000.json','["憐爾因同舍，看書似外家。", "出關逢落葉，傍水見寒花。", "送遠添秋思，將衰戀歲華。", "清淮倍相憶，回首莫令賒。"]'),
('cffe3dda-3661-44a4-82b5-a6e797d90996','晚春送吉校書歸楚州','李嘉祐','唐','唐诗','tang','','[]','詩人饒楚思，淮上及春歸。',48,'全唐诗/poet.tang.10000.json','["詩人饒楚思，淮上及春歸。", "舊浦菱花發，閑門柳絮飛。", "高名鄉曲重，少事道流稀。", "定向漁家醉，殘陽臥釣磯。"]'),
('3b2c8e43-f10d-45f0-a287-b9a9a7f7d90d','送嚴二擢第東歸','李嘉祐','唐','唐诗','tang','','[]','隳官就賓薦，時輩詎爭先。',48,'全唐诗/poet.tang.10000.json','["隳官就賓薦，時輩詎爭先。", "盛業推儒行，高科獨少年。", "迎秋見衰葉，餘照逐鳴蟬。", "舊里三峰下，開門古縣前。"]'),
('6b91be50-04b7-4afd-a8cd-fd519f6913e2','送冷朝陽及第東歸江寧','李嘉祐','唐','唐诗','tang','','[]','高第由佳句，諸生似者稀。',48,'全唐诗/poet.tang.10000.json','["高第由佳句，諸生似者稀。", "長安帶酒別，建業候潮歸。", "稚子歡迎櫂，隣人爲掃扉。", "含情過舊浦，鷗鳥亦依依。"]'),
('8c08bd7f-4428-47f3-b4c8-dfb6c845732e','送越州辛法曹之任','李嘉祐','唐','唐诗','tang','','[]','但能一官適，莫羨五侯尊。',48,'全唐诗/poet.tang.10000.json','["但能一官適，莫羨五侯尊。", "山色垂趨府，潮聲自到門。", "緣塘剡溪路，映竹五湖村。", "王謝登臨處，依依今尚存。"]'),
('4f14e7e2-6703-487c-acde-03fcb5af2dda','送樊兵曹潭州謁韋大夫','李嘉祐','唐','唐诗','tang','','[]','塞鴻歸欲盡，北客始辭春。',48,'全唐诗/poet.tang.10000.json','["塞鴻歸欲盡，北客始辭春。", "零桂雖逢竹，湘川少見人。", "江花鋪淺水，山木暗殘春。", "修刺轅門裏，多憐爾爲親。"]'),
('7001236e-1245-48ce-af89-43614dce03bd','送杜御史還廣陵','李嘉祐','唐','唐诗','tang','','[]','慙君從弱歲，顧我比諸昆。',48,'全唐诗/poet.tang.10000.json','["慙君從弱歲，顧我比諸昆。", "同事元戎久，俱承國士恩。", "隨鶯過淮水，看柳向轅門。", "草色金陵岸，思心那可論。"]'),
('04eb81bc-564c-434c-89a8-bb2920ae3ac1','送兗州杜別駕之任','李嘉祐','唐','唐诗','tang','','[]','停車邀別乘，促軫奏胡笳。',48,'全唐诗/poet.tang.10000.json','["停車邀別乘，促軫奏胡笳。", "若見楚山暮，因愁浙水賒。", "河堤經淺草，村徑歷繁花。", "更有堪悲處，梁城春日斜。"]'),
('42bff76a-a87d-4701-966c-ac367bf4d4d0','題裴十六少卿東亭','李嘉祐','唐','唐诗','tang','','[]','平津舊東閣，深巷見南山。',48,'全唐诗/poet.tang.10000.json','["平津舊東閣，深巷見南山。", "卷箔嵐煙潤，遮牕竹影閑。", "傾茶兼落帽，戀客不開關。", "斜照窺簾外，川禽時往還。"]'),
('8788cd3e-5458-47a4-86b0-9ca39798283e','同皇甫侍御題薦福寺一公房','李嘉祐','唐','唐诗','tang','','[]','虛室獨焚香，林空靜磬長。',48,'全唐诗/poet.tang.10000.json','["虛室獨焚香，林空靜磬長。", "閑窺數竿竹，老在一繩牀。", "啜茗翻真偈，然燈繼夕陽。", "人歸遠相送，步履出回廊。"]'),
('ace98560-95a8-432b-9f52-eb9538c9b4a5','送從姪端之東都','李嘉祐','唐','唐诗','tang','','[]','虜近人行少，憐君獨出城。',48,'全唐诗/poet.tang.10000.json','["虜近人行少，憐君獨出城。", "故關逢落葉，寒日逐徂征。", "聞笛添歸思，看山愜野情。", "皇華今絕少，龍頟也相迎。"]'),
('a06822a8-066a-4eaf-96e9-b074349ac01d','送王諫議充東都留守判官','李嘉祐','唐','唐诗','tang','','[]','時稱謝康樂，別事漢平津。',48,'全唐诗/poet.tang.10000.json','["時稱謝康樂，別事漢平津。", "衰柳寒關道，高車左掖臣。", "背河見北雁，到洛問東人。", "憶昔遊金谷，相看華髮新。"]'),
('9cf2d943-e52c-4406-bd53-03f686f4abb7','和都官苗員外秋夜省直對雨簡諸知己','李嘉祐','唐','唐诗','tang','','[]','多雨南宮夜，仙郎寓直時。',48,'全唐诗/poet.tang.10000.json','["多雨南宮夜，仙郎寓直時。", "漏長丹鳳闕，秋冷白雲司。", "螢影侵堦亂，鴻聲出苑遲。", "蕭條人吏散，小謝有新詩。"]'),
('f83410d6-cd74-4482-812f-2e7b1d126333','送從弟歸河朔','李嘉祐','唐','唐诗','tang','','[]','故鄉那可到，令弟獨能歸。',48,'全唐诗/poet.tang.10000.json','["故鄉那可到，令弟獨能歸。", "諸將矜旄節，何人重布衣。", "空城流水在，荒澤舊村稀。", "秋日平原路，蟲鳴桑葉飛。"]'),
('0117d122-eb63-4b9c-9b0d-764719baccc1','送崔夷甫員外和蕃','李嘉祐','唐','唐诗','tang','','[]','君過湟中去，尋源未是賒。',48,'全唐诗/poet.tang.10000.json','["君過湟中去，尋源未是賒。", "經春逢白草，盡日度黃沙。", "雙節行爲伴，孤烽到似家。", "和戎非用武，不學李輕車。"]'),
('c4f82821-1cd6-41ed-a7fb-8ce1470eea9b','春日長安送從弟尉吳縣','李嘉祐','唐','唐诗','tang','','[]','春愁能浩蕩，送別又如何。',48,'全唐诗/poet.tang.10000.json','["春愁能浩蕩，送別又如何。", "人向吳臺遠，鶯飛漢苑多。", "見花羞白髮，因爾憶滄波。", "好是神仙尉，前賢亦未過。"]'),
('fbbc6828-0b3a-4640-a1c9-04223b560134','元日無衣冠入朝寄皇甫拾遺冉從弟補闕紓','李嘉祐','唐','唐诗','tang','','[]','伏奏隨廉使，周行外冗員。',48,'全唐诗/poet.tang.10000.json','["伏奏隨廉使，周行外冗員。", "白髭空受歲，丹陛不朝天。", "秉燭千官去，垂簾一室眠。", "羨君青瑣裏，並冕入爐煙。"]'),
('a72f115d-7bd1-4549-a495-dc1043f2a8a6','和韓郎中揚子津翫雪寄嚴維','李嘉祐','唐','唐诗','tang','','[]','雪深揚子岸，看柳盡成梅。',48,'全唐诗/poet.tang.10000.json','["雪深揚子岸，看柳盡成梅。", "山色潛知近，潮聲只聽來。", "夜禽驚曉散，春物受寒催。", "粉署生新興，瑤華寄上才。"]'),
('c03ba182-6545-4ebb-8758-ecb1989b981b','送王牧往吉州謁王使君叔','李嘉祐','唐','唐诗','tang','','["\u9001\u522b", "\u6625\u5929", "\u60dc\u522b"]','細草綠汀洲，王孫耐薄遊。',48,'全唐诗/poet.tang.10000.json','["細草綠汀洲，王孫耐薄遊。", "年華初冠帶，文體舊弓裘。", "野渡花爭發，春塘水亂流。", "使君憐小阮，應念倚門愁。"]'),
('72b4526a-3179-4df1-a534-6ed85a50a07e','廣陵送林宰','李嘉祐','唐','唐诗','tang','','[]','清政過前哲，香名達至尊。',48,'全唐诗/poet.tang.10000.json','["清政過前哲，香名達至尊。", "明通漢家籍，重識府公恩。", "春景生雲物，風潮歛雪痕。", "長吟策羸馬，青楚入關門。"]'),
('3fb130fc-fd7a-4f7a-9128-120886ff520b','贈衛南長官赴任','李嘉祐','唐','唐诗','tang','','[]','吏曹難茂宰，主意念疲人。',48,'全唐诗/poet.tang.10000.json','["吏曹難茂宰，主意念疲人。", "更事文犀節，還過白馬津。", "雲間辭北闕，樹裏出西秦。", "爲報陶明府，裁書莫厭貧。"]'),
('90f7a912-549f-444d-9b12-99c89f224b94','自常州還江陰途中作','李嘉祐','唐','唐诗','tang','','[]','處處空籬落，江村不忍看。',48,'全唐诗/poet.tang.10000.json','["處處空籬落，江村不忍看。", "無人花色慘，多雨鳥聲寒。", "黃霸初臨郡，陶潛未罷官。", "乘春務征伐，誰肯問凋殘。"]'),
('2ff09cfa-7e73-42d6-a0b9-26ae6d4f85f8','潤州楊別駕宅送蔣九侍御收兵歸揚州','李嘉祐','唐','唐诗','tang','','[]','沴氣清金虎，兵威壯鐵冠。',48,'全唐诗/poet.tang.10000.json','["沴氣清金虎，兵威壯鐵冠。", "揚旌川色暗，吹角水風寒。", "人對輜軿醉，花垂睥睨殘。", "羨歸丞相閣，空望舊門欄。"]'),
('889929d5-2846-4b0b-a3ad-1572ec48dfa4','仲夏江陰官舍寄裴明府','李嘉祐','唐','唐诗','tang','','[]','萬室邊江次，孤城對海安。',48,'全唐诗/poet.tang.10000.json','["萬室邊江次，孤城對海安。", "朝霞晴作雨，濕氣晚生寒。", "苔色侵衣桁，潮痕上井欄。", "題詩招茂宰，思爾欲辭官。"]'),
('9c56b83a-34f3-4a30-a7fe-c0f7bb2fcac1','送夏侯審參軍遊江東','李嘉祐','唐','唐诗','tang','','[]','袖中多麗句，未遣世人聞。',48,'全唐诗/poet.tang.10000.json','["袖中多麗句，未遣世人聞。", "醉夜眠江月，閑時逐海雲。", "荻花寒漫漫，鷗鳥暮羣羣。", "若到長沙苑，漁家更待君。"]'),
('2bd840b4-d47c-467f-a3f5-98ed69b0a1a4','送袁員外宣慰勸農畢赴洪州使院','李嘉祐','唐','唐诗','tang','','[]','聖主臨前殿，殷憂遣使臣。',48,'全唐诗/poet.tang.10000.json','["聖主臨前殿，殷憂遣使臣。", "氣迎天詔喜，恩發土膏春。", "草色催歸櫂，鶯聲爲送人。", "龍沙多道里，流水自相親。"]'),
('3377290f-6a0b-403b-8e2b-66980e476240','送侍御史四叔歸朝','李嘉祐','唐','唐诗','tang','','[]','淮南頻送別，臨水惜殘春。',48,'全唐诗/poet.tang.10000.json','["淮南頻送別，臨水惜殘春。", "攀折隋宮柳，淹留秦地人。", "含情歸上國，論舊見平津。", "更接天津近，餘花映綬新。"]'),
('a44cd68d-3b13-4e10-bbf4-035abc5948a4','登楚州城望驛路十餘里山村竹林相次交映','李嘉祐','唐','唐诗','tang','','[]','十里山村道，千峰櫟樹林。',48,'全唐诗/poet.tang.10000.json','["十里山村道，千峰櫟樹林。", "霜濃竹枝亞，歲晚荻花深。", "草市多樵客，漁家足水禽。", "幽居雖可羨，無那子牟心。"]'),
('ed9d64a1-e731-4851-92fa-05556336ef56','奉陪韋潤州遊鶴林寺','李嘉祐','唐','唐诗','tang','','[]','野寺江城近，雙旌五馬過。',48,'全唐诗/poet.tang.10000.json','["野寺江城近，雙旌五馬過。", "禪心超忍辱，梵語問多羅。", "松林閑僧老，雲煙晚日和。", "寒塘歸路轉，清磬隔微波。"]'),
('659a929c-5811-471d-a322-9d3aa5b6d9b8','奉酬路五郎中院長新除工部員外見簡','李嘉祐','唐','唐诗','tang','','[]','一門同祕省，萬里作長城。',48,'全唐诗/poet.tang.10000.json','["一門同祕省，萬里作長城。", "問絹蓮花府，揚旗細柳營。", "詞鋒偏却敵，草奏直論兵。", "何幸新詩贈，真輸小謝名。"]'),
('f8b5abae-eba0-409b-8690-9bcb9655ab1e','送韋司直西行','李嘉祐','唐','唐诗','tang','','[]','不恥青袍故，尤宜白髮新。',48,'全唐诗/poet.tang.10000.json','["不恥青袍故，尤宜白髮新。", "心朝玉皇帝，貌似紫陽人。", "湘浦眠銷日，桃源醉度春。", "能文兼證道，莊叟是前身。"]'),
('436fc561-fab5-49ce-8506-59c5945fb2b5','送上官侍御赴黔中','李嘉祐','唐','唐诗','tang','','[]','莫向黔中路，令人到欲迷。',48,'全唐诗/poet.tang.10000.json','["莫向黔中路，令人到欲迷。", "水聲巫峽裏，山色夜郎西。", "樹隔朝雲合，猨窺曉月啼。", "南方饒翠羽，知爾飲清溪。"]'),
('c1a00c30-798a-4085-a3c8-bb6dd38b2e61','送元侍御還荆南幕府','李嘉祐','唐','唐诗','tang','','[]','迢遞荆州路，山多水又分。',48,'全唐诗/poet.tang.10000.json','["迢遞荆州路，山多水又分。", "霜林澹寒日，朔鴈蔽南雲。", "八座由持節，三湘亦置軍。", "自當行直指，應不爲功勳。"]'),
('cb65a8de-23eb-4aa0-a490-61fb8e57f42a','登湓城浦望廬山初晴直省齎敕催赴江陰','李嘉祐','唐','唐诗','tang','','["\u5e90\u5c71"]','西望香爐雪，千峰晚色新。',48,'全唐诗/poet.tang.10000.json','["西望香爐雪，千峰晚色新。", "白頭悲作吏，黃紙苦催人。", "多負登山屐，深藏漉酒巾。", "傷心公府內，手板日相親。"]'),
('545ae0c5-171e-4e69-9c4c-b9a4300f6f95','九日','李嘉祐','唐','唐诗','tang','','[]','惆悵重陽日，空山野菊新。',48,'全唐诗/poet.tang.10000.json','["惆悵重陽日，空山野菊新。", "蒹葭百戰地，江海十年人。", "歎老堪衰柳，傷秋對白蘋。", "孤樓聞夕磬，塘路向城闉。"]'),
('11df3b79-9086-4902-840b-c9e9adf9fc25','九日送人','李嘉祐','唐','唐诗','tang','','[]','晴景應重陽，高臺愴遠鄉。',48,'全唐诗/poet.tang.10000.json','["晴景應重陽，高臺愴遠鄉。", "水澄千室倒，霧卷四山長。", "受節人逾老，驚寒菊半黃。", "席前愁此別，未別已沾裳。"]'),
('f523cd08-69d6-45c1-bc6a-633f43223f59','春日淇上作','李嘉祐','唐','唐诗','tang','','[]','淇上春風漲，鴛鴦逐浪飛。',48,'全唐诗/poet.tang.10000.json','["淇上春風漲，鴛鴦逐浪飛。", "清明桑葉小，度雨杏花稀。", "衛女紅粧薄，王孫白馬肥。", "相將踏青去，不解惜羅衣。"]'),
('528dac78-a720-4031-8164-12f0f165c2e1','送從叔陽冰祇召赴都','李嘉祐','唐','唐诗','tang','','[]','自小從遊慣，多由戲笑偏。',48,'全唐诗/poet.tang.10000.json','["自小從遊慣，多由戲笑偏。", "常時矜禮數，漸老荷優憐。", "見主承休命，爲郎貴晚年。", "伯喈文與篆，虛作漢家賢。"]'),
('de9b1a7e-ae47-460e-9d7d-6798210877ff','送友人入湘','李嘉祐','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','聞說湘川路，年年苦雨多。',48,'全唐诗/poet.tang.10000.json','["聞說湘川路，年年苦雨多。", "猨啼巫峽雨，月照洞庭波。", "窮海人還去，孤城雁共過。", "青山不可極，來往自蹉跎。"]'),
('1baae898-b280-4e24-aa44-1c7b92850846','送裴員外往江南','李嘉祐','唐','唐诗','tang','','[]','公務江南遠，留驩幕下榮。',48,'全唐诗/poet.tang.10000.json','["公務江南遠，留驩幕下榮。", "楓林緣楚塞，水驛到湓城。", "岸草知春晚，沙禽好夜驚。", "風帆幾度泊，處處暮潮聲。"]'),
('953fb239-9773-4cb6-922b-505de607ecac','登秦嶺','李嘉祐','唐','唐诗','tang','','[]','南登秦嶺頭，回望始堪愁。',48,'全唐诗/poet.tang.10000.json','["南登秦嶺頭，回望始堪愁。", "漢闕青門遠，高山藍水流。", "三湘遷客去，九陌故人遊。", "從此辭鄉淚，雙垂不復收。"]'),
('c16afdba-9694-47d9-b108-51b6dca140bc','送張惟儉秀才入舉','李嘉祐','唐','唐诗','tang','','[]','清秀過終童，攜書訪老翁。',48,'全唐诗/poet.tang.10000.json','["清秀過終童，攜書訪老翁。", "以吾爲世舊，憐爾繼家風。", "淮岸經霜柳，關城帶月鴻。", "春歸定得意，花送到東中。"]'),
('f24485df-2c1c-4633-8220-d7e60cdb3aa4','送韋侍御湖南幕府','李嘉祐','唐','唐诗','tang','','["\u8861\u5c71"]','執憲隨征虜，逢秋出故關。',48,'全唐诗/poet.tang.10000.json','["執憲隨征虜，逢秋出故關。", "雨多愁郢路，葉下識衡山。", "地遠從軍樂，兵強分野閑。", "皇家不易將，此去未應還。"]'),
('7f92251f-8521-4f44-ac7f-2cb17365e348','同皇甫冉赴官留別靈一上人','李嘉祐','唐','唐诗','tang','','["\u5e90\u5c71"]','法許廬山遠，詩傳休上人。',48,'全唐诗/poet.tang.10000.json','["法許廬山遠，詩傳休上人。", "獨歸雙樹宿，靜與百花親。", "對物雖留興，觀空已悟身。", "能令折腰客，遙賞竹房春。"]'),
('1a3d9214-9963-48a6-bb04-ce3cb73e07b3','送客遊荆州','李嘉祐','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u9001\u522b"]','草色隨驄馬，悠悠共出秦。',48,'全唐诗/poet.tang.10000.json','["草色隨驄馬，悠悠共出秦。", "水傳雲夢曉，山接洞庭春。", "帆影連三峽，猨聲在四隣。", "青門一分首，難見杜陵人。"]'),
('5b9c6487-5561-4147-8a86-32b4e5956147','與鄭錫遊春','李嘉祐','唐','唐诗','tang','','[]','東門垂柳長，回首獨心傷。',48,'全唐诗/poet.tang.10000.json','["東門垂柳長，回首獨心傷。", "日暖臨芳草，天晴憶故鄉。", "映花鶯上下，過水蝶悠颺。", "借問同行客，今朝淚幾行。"]'),
('f19370d8-5bc7-42c7-a16b-740337f9e5d8','故燕國相公輓歌二首 一','李嘉祐','唐','唐诗','tang','','[]','文若爲全德，留侯是重名。',48,'全唐诗/poet.tang.10000.json','["文若爲全德，留侯是重名。", "論公長不宰，因病得無生。", "大夢依禪定，高墳共化城。", "自應憐寂滅，人世但傷情。"]'),
('5a5dcd73-11dd-46df-9eb3-e345148ad909','故燕國相公輓歌二首 二','李嘉祐','唐','唐诗','tang','','[]','共美持衡日，皆言折檻時。',48,'全唐诗/poet.tang.10000.json','["共美持衡日，皆言折檻時。", "蜀侯供廟略，漢主缺台司。", "車馬行仍止，笳簫咽又悲。", "今年杜陵陌，殄瘁百花遲。"]'),
('e84d461b-df53-426b-ba6a-848c87223cab','故吏部郎中贈給事中韋公挽歌二首 一','李嘉祐','唐','唐诗','tang','','[]','神理今何在，斯人竟若斯。',48,'全唐诗/poet.tang.10000.json','["神理今何在，斯人竟若斯。", "顏淵徒有德，伯道且無兒。", "白髮今非老，青雲數有奇。", "誰言夕郎拜，翻向夜臺悲。"]'),
('e70522e6-cb7f-4624-94e7-96ce81db4c6c','故吏部郎中贈給事中韋公挽歌二首 二','李嘉祐','唐','唐诗','tang','','[]','社里東城接，松阡北地開。',48,'全唐诗/poet.tang.10000.json','["社里東城接，松阡北地開。", "聞笳春色慘，執紼故人哀。", "終日南山對，何時渭水回。", "仁兄與恩舊，相望泣泉臺。"]'),
('2d233eb4-3770-4ebd-abaf-7e54728db062','和袁郎中破賊後經剡縣山水上太尉','李嘉祐','唐','唐诗','tang','','[]','受律仙郎貴，長驅下會稽。',72,'全唐诗/poet.tang.10000.json','["受律仙郎貴，長驅下會稽。", "鳴笳山月曉，搖斾野雲低。", "翦寇人皆賀，迴軍馬自嘶。", "地閑春草綠，城靜夜烏啼。", "破竹清閩嶺，看花入剡溪。", "元戎催獻捷，莫道事攀躋。"]'),
('f6b89b6c-ce08-47a5-b56c-4d3c26dd52fd','送評事十九叔入秦','李嘉祐','唐','唐诗','tang','','[]','白露沾蕙草，王孫轉憶歸。',72,'全唐诗/poet.tang.10000.json','["白露沾蕙草，王孫轉憶歸。", "蔡州新戰罷，郢路去人稀。", "謁帝不辭遠，懷親空有違。", "孤舟看落葉，平楚逐斜暉。", "北闕見端冕，南臺當繡衣。", "唯余播遷客，只伴鷓鴣飛。"]'),
('1f888b69-cfce-4eb1-bee2-109b63caf609','贈王八衢','李嘉祐','唐','唐诗','tang','','[]','丹地偏相逐，清江若有期。',72,'全唐诗/poet.tang.10000.json','["丹地偏相逐，清江若有期。", "腰金才子貴，剖竹老人遲。", "桂楫閑迎客，茶甌對說詩。", "渚田分邑里，山桂樹罘罳。", "心靜無華髮，人和似古時。", "別君遠山去，幽獨更應悲。"]'),
('a31da724-61fb-4082-a5e3-ba1d3b7f2d9c','入睦州分水路憶劉長卿','李嘉祐','唐','唐诗','tang','','[]','北闕忤明主，南方隨白雲。',72,'全唐诗/poet.tang.10000.json','["北闕忤明主，南方隨白雲。", "沿洄灘草色，應接海鷗羣。", "建德潮已盡，新安江又分。", "回看嚴子瀨，朗詠謝安文。", "雨過暮山碧，猨吟秋日曛。", "吳洲不可到，刷鬢爲思君。"]'),
('fb420b79-5f9d-405b-9bd3-37fece652d2f','奉和杜相公長興新宅即事呈元相公','李嘉祐','唐','唐诗','tang','','[]','意有空門樂，居無甲第奢。',96,'全唐诗/poet.tang.10000.json','["意有空門樂，居無甲第奢。", "經過容法侶，雕飾讓侯家。", "隱樹重簷肅，開園一逕斜。", "據梧聽好鳥，行藥寄名花。", "夢蝶留清簟，垂貂坐絳紗。", "當山不掩戶，映日自傾茶。", "雅望歸安石，深知在叔牙。", "還成吉甫頌，贈荅比瑤華。"]'),
('3007f5f4-1d3c-4960-9e74-d75729d8fe3a','江湖秋思','李嘉祐','唐','唐诗','tang','','[]','趨陪禁掖鴈行隨，遷向江潭鶴髮垂。',64,'全唐诗/poet.tang.10000.json','["趨陪禁掖鴈行隨，遷向江潭鶴髮垂。", "素浪遙疑八谿水，清楓忽似萬年枝。", "嵩南春徧傷魂夢，壺口雲深隔路岐。", "共望漢朝多霈澤，蒼蠅早晚得先知。"]'),
('d7c38125-f18c-453a-beaf-e2aea15560a4','送朱中舍游江東','李嘉祐','唐','唐诗','tang','','[]','孤城郭外送王孫，越水吳洲共爾論。',64,'全唐诗/poet.tang.10000.json','["孤城郭外送王孫，越水吳洲共爾論。", "野寺山邊斜有逕，漁家竹裏半開門。", "青楓獨映搖前浦，白鷺閑飛過遠村。", "若到西陵征戰處，不堪秋草自傷魂。"]'),
('2ce226b7-ea64-4eff-8070-de1fefab65b3','送竇拾遺赴朝因寄中書十七弟','李嘉祐','唐','唐诗','tang','','[]','自歎未霑黃紙詔，那堪遠送赤墀人。',64,'全唐诗/poet.tang.10000.json','["自歎未霑黃紙詔，那堪遠送赤墀人。", "老爲僑客偏相戀，素是詩家倍益親。", "妻兒共載無羈思，鴛鷺同行不負身。", "憑爾將書通令弟，唯論華髮愧頭巾。"]'),
('39623e50-e397-46d0-8715-f405674194cf','自蘇臺至望亭驛人家盡空春物增思悵然有作因寄從弟紓','李嘉祐','唐','唐诗','tang','','[]','南浦菰蔣覆白蘋，東吳黎庶逐黃巾。',64,'全唐诗/poet.tang.10000.json','["南浦菰蔣覆白蘋，東吳黎庶逐黃巾。", "野棠自發空臨水，江燕初歸不見人。", "遠岫依依如送客，平田渺渺獨傷春。", "那堪回首長洲苑，烽火年年報虜塵。"]'),
('f38be33d-7a3b-4a47-a06d-1c87deffd4ef','承恩量移宰江邑臨鄱江悵然之作','李嘉祐','唐','唐诗','tang','','[]','四年謫宦滯江城，未厭門前鄱水清。',64,'全唐诗/poet.tang.10000.json','["四年謫宦滯江城，未厭門前鄱水清。", "誰言宰邑化黎庶，欲別雲山如弟兄。", "雙鷗爲底無心狎，白髮從他遶鬢生。", "惆悵閑眠臨極浦，夕陽秋草不勝情。"]'),
('c1b6399b-c2e2-4a61-8d15-b3362da6d6b0','題靈臺縣東山村主人','李嘉祐','唐','唐诗','tang','','["\u9ec4\u6cb3"]','處處征胡人漸稀，山村寥落暮煙微。',64,'全唐诗/poet.tang.10000.json','["處處征胡人漸稀，山村寥落暮煙微。", "門臨莽蒼經年閉，身逐嫖姚幾日歸。", "貧妻白髮輸殘稅，餘寇黃河未解圍。", "天子如今能用武，祗應歲晚息兵機。"]'),
('defb1a3b-499d-47da-b4ed-e397a921753e','同皇甫冉登重玄閣','李嘉祐','唐','唐诗','tang','','[]','高閣朱欄不厭遊，蒹葭白水遶長洲。',64,'全唐诗/poet.tang.10000.json','["高閣朱欄不厭遊，蒹葭白水遶長洲。", "孤雲獨鳥川光暮，萬井千山海色秋。", "清梵林中人轉靜，夕陽城上角偏愁。", "誰憐遠作秦吳別，離恨歸心雙淚流。"]'),
('930a9bfb-ee77-4806-b03c-7bf63a9b070e','宋州東登望題武陵驛','李嘉祐','唐','唐诗','tang','','[]','梁宋人稀鳥自啼，登艫一望倍含悽。',64,'全唐诗/poet.tang.10000.json','["梁宋人稀鳥自啼，登艫一望倍含悽。", "白骨半隨河水去，黃雲猶傍郡城低。", "平陂戰地花空落，舊苑春田草未齊。", "明主頻移虎符守，幾時行縣向黔黎。"]'),
('e0561406-6676-4987-8d23-f7aba74b1273','晚登江樓有懷','李嘉祐','唐','唐诗','tang','','[]','獨坐南樓佳興新，青山綠水共爲隣。',64,'全唐诗/poet.tang.10000.json','["獨坐南樓佳興新，青山綠水共爲隣。", "爽氣遙分隔浦岫，斜光偏照渡江人。", "心閑鷗鳥時相近，事簡魚竿私自親。", "只憶帝京不可到，秋琴一弄欲沾巾。"]'),
('36128fe1-a9f6-4841-99a6-9b7995ac94d3','遊徐城河忽見清淮因寄趙八','李嘉祐','唐','唐诗','tang','','[]','自緣遲暮憶滄洲，翻愛南河濁水流。',64,'全唐诗/poet.tang.10000.json','["自緣遲暮憶滄洲，翻愛南河濁水流。", "初過重陽惜殘菊，行看舊浦識羣鷗。", "朝霞映日同歸處，暝柳搖風欲別秋。", "長恨相逢即分首，含情掩淚獨回頭。"]'),
('a742e3a3-3988-418b-9cab-d8f72c78f439','題遊仙閣白公廟','李嘉祐','唐','唐诗','tang','','[]','仙冠輕舉竟何之，薜荔緣堦竹映祠。',64,'全唐诗/poet.tang.10000.json','["仙冠輕舉竟何之，薜荔緣堦竹映祠。", "甲子不知風馭日，朝昏唯見雨來時。", "霓旌翠蓋終難遇，流水青山空所思。", "逐客自憐雙鬢改，梵香多負白雲期。"]'),
('9259cb41-d39c-4d4d-b7b4-a231bc70e4d2','送鄭正則漢陽迎婦','李嘉祐','唐','唐诗','tang','','[]','錦字相催鳥急飛，郎君暫脫老萊衣。',64,'全唐诗/poet.tang.10000.json','["錦字相催鳥急飛，郎君暫脫老萊衣。", "遙想雙眉待人畫，行看五馬送潮歸。", "望夫山上花猶發，新婦江邊鶯未稀。", "令秩和鳴真可羨，此行誰道負春輝。"]'),
('f6dae641-c374-41d8-9195-525ac6869f79','送皇甫冉往安宜','李嘉祐','唐','唐诗','tang','','[]','江臯盡日唯煙水，君向白田何日歸。',64,'全唐诗/poet.tang.10000.json','["江臯盡日唯煙水，君向白田何日歸。", "楚地蒹葭連海逈，隋朝楊柳映堤稀。", "津樓故市無行客，山館荒城閉落暉。", "若問行人與征戰，使君雙淚定霑衣。"]'),
('f250e306-a578-4bb0-bdef-066a2be420fb','晚發咸陽寄同院遺補','李嘉祐','唐','唐诗','tang','','[]','征戰初休草又衰，咸陽晚眺淚堪垂。',64,'全唐诗/poet.tang.10000.json','["征戰初休草又衰，咸陽晚眺淚堪垂。", "去路全無千里客，秋田不見五陵兒。", "秦家故事隨流水，漢代高墳對石碑。", "回首青山獨不語，羨君談笑萬年枝。"]'),
('27acb13b-76e1-46ee-a681-148fc96b24b6','早秋京口旅泊章侍御寄書相問因以贈之時七夕','李嘉祐','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282"]','移家避寇逐行舟，厭見南徐江水流。',64,'全唐诗/poet.tang.10000.json','["移家避寇逐行舟，厭見南徐江水流。", "吳越征徭非舊日，秣陵凋弊不宜秋。", "千家閉戶無砧杵，七夕何人望斗牛。", "祗有同時驄馬客，偏宜尺牘問窮愁。"]'),
('fad0b1d2-0982-4e21-a0f7-9fbde68bd3e3','秋曉招隱寺東峰茶宴送內弟閻伯均歸江州','李嘉祐','唐','唐诗','tang','','[]','萬畦新稻傍山村，數里深松到寺門。',64,'全唐诗/poet.tang.10000.json','["萬畦新稻傍山村，數里深松到寺門。", "幸有香茶留穉子，不堪秋草送王孫。", "煙塵怨別唯愁隔，井邑蕭條誰忍論。", "莫怪臨歧獨垂淚，魏舒偏念外家恩。"]'),
('1a3d6317-14e6-4974-85bf-696d58458a5e','送嚴員外','李嘉祐','唐','唐诗','tang','','["\u5199\u96e8", "\u9001\u522b", "\u6000\u624d\u4e0d\u9047", "\u96e8"]','春風倚櫂闔閭城，水國春寒陰復晴。',64,'全唐诗/poet.tang.10000.json','["春風倚櫂闔閭城，水國春寒陰復晴。", "細雨濕衣看不見，閑花落地聽無聲。", "日斜江上孤帆影，草綠湖南萬里情。", "君去若逢相識問，青袍今已誤儒生。"]'),
('a8b615ec-00f5-4b3c-bcb7-8435e10014aa','赴南中留別褚七少府湖上林亭','李嘉祐','唐','唐诗','tang','','[]','種田東郭傍春陂，萬事無情把釣絲。',64,'全唐诗/poet.tang.10000.json','["種田東郭傍春陂，萬事無情把釣絲。", "綠竹放侵行逕裏，青山常對卷簾時。", "紛紛花發門空閉，寂寂鶯啼日更遲。", "從此別君千萬里，白雲流水憶佳期。"]'),
('47037677-642e-4c75-a11d-36d3e89d9c8d','與從弟正字從兄兵曹宴集林園','李嘉祐','唐','唐诗','tang','','[]','竹窓松戶有佳期，美酒香茶慰所思。',64,'全唐诗/poet.tang.10000.json','["竹窓松戶有佳期，美酒香茶慰所思。", "輔嗣外生還解易，惠連羣從總能詩。", "簷前花落春深後，谷裏鶯啼日暮時。", "去路歸程仍待月，垂韁不控馬行遲。"]'),
('fee12dd9-a381-4288-903b-129416897f9b','酬皇甫十六侍御曾見寄','李嘉祐','唐','唐诗','tang','','[]','自顧衰容累玉除，忽承優詔赴銅魚。',64,'全唐诗/poet.tang.10000.json','["自顧衰容累玉除，忽承優詔赴銅魚。", "江頭鳥避青旄節，城裏人迎露網車。", "長沙地近悲才子，古郡山多憶舊廬。", "更枉新詩思何苦，離騷愁處亦無如。"]'),
('d3092fea-a23f-44ab-a0da-65be3e4e1fae','暮春宜陽郡齋愁坐忽枉劉七侍御新詩因以酬答','李嘉祐','唐','唐诗','tang','','[]','子規夜夜[啼]櫧葉，遠道逢春半是愁。',66,'全唐诗/poet.tang.10000.json','["子規夜夜[啼]櫧葉，遠道逢春半是愁。", "芳草伴人還易老，落花隨水亦東流。", "山臨睥睨恆多雨，地接瀟湘畏及秋。", "唯羨君爲周柱史，手持黃紙到滄洲。"]'),
('df2faabf-b5ef-4c87-8091-da1a91285122','送舍弟','李嘉祐','唐','唐诗','tang','','[]','諸謝偏推永嘉守，三何獨許水曹郎。',64,'全唐诗/poet.tang.10000.json','["諸謝偏推永嘉守，三何獨許水曹郎。", "老兄鄙思難儔匹，令弟清詞堪比量。", "疊嶂入雲藏古寺，高秋背月轉南湘。", "定知馬上多新句，早寄袁溪當八行。"]'),
('beee5922-6237-4c9a-af25-43a4cb4274e6','送從弟永任饒州錄事參軍','李嘉祐','唐','唐诗','tang','','[]','一官萬里向千溪，水宿山行魚浦西。',64,'全唐诗/poet.tang.10000.json','["一官萬里向千溪，水宿山行魚浦西。", "日晚長煙高岸近，天寒積雪遠峰低。", "蘆花渚裏鴻相呌，苦竹叢邊猨暗啼。", "聞道慈親倚門待，到時蘭葉正萋萋。"]'),
('c611bf84-57f9-44ee-ac22-d7a270a21190','送馬將軍奏事畢歸滑州使幕','李嘉祐','唐','唐诗','tang','','["\u9ec4\u6cb3"]','吳門別後蹈滄州，帝里相逢俱白頭。',64,'全唐诗/poet.tang.10000.json','["吳門別後蹈滄州，帝里相逢俱白頭。", "自歎馬卿常帶病，還嗟李廣未封侯。", "棠梨宮裏瞻龍衮，細柳營前著豹裘。", "想到滑臺桑葉落，黃河東注荻花秋。"]'),
('25e0e52b-b822-44f8-9cc5-4ffa1a63948e','聞逝者自驚','李嘉祐','唐','唐诗','tang','','[]','亦知死是人間事，年老聞之心自疑。',64,'全唐诗/poet.tang.10000.json','["亦知死是人間事，年老聞之心自疑。", "黃卷清琴總爲累，落花流水共添悲。", "願將從藥看真訣，又欲休官就本師。", "兒女眼前難喜捨，彌憐雙鬢漸如絲。"]'),
('6038ff33-cb0f-4ab7-82bd-c603b030c1bb','傷歙州陳二使君','李嘉祐','唐','唐诗','tang','','[]','憐君辭滿臥滄洲，一旦云亡萬事休。',64,'全唐诗/poet.tang.10000.json','["憐君辭滿臥滄洲，一旦云亡萬事休。", "慈母斷腸妻獨泣，寒雲慘色水空流。", "江村故老長懷惠，山路孤猨亦共愁。", "寂寞荒墳近漁浦，野松孤月即千秋。"]'),
('cb4f4170-b86e-44bf-813e-516858bef701','白田西憶楚州使君弟','李嘉祐','唐','唐诗','tang','','[]','山陽郭裏無潮，野水自向新橋。',56,'全唐诗/poet.tang.10000.json','["山陽郭裏無潮，野水自向新橋。", "魚網平鋪荷葉，鷺鷥閑步稻苗。", "秣陵歸人惆悵，楚地連山寂寥。", "却憶士龍賓閣，清琴綠竹蕭蕭。"]'),
('2ae993ab-d22e-4fd2-ab42-db08325f8452','送陸澧還吳中','李嘉祐','唐','唐诗','tang','','[]','瓜步寒潮送客，楊花暮雨霑衣。',28,'全唐诗/poet.tang.10000.json','["瓜步寒潮送客，楊花暮雨霑衣。", "故鄉南望何處，春水連天獨歸。"]'),
('098ed74c-c5fa-4944-9078-b76bd958fbba','春日憶家','李嘉祐','唐','唐诗','tang','','[]','自覺勞鄉夢，無人見客心。',24,'全唐诗/poet.tang.10000.json','["自覺勞鄉夢，無人見客心。", "空餘庭草色，日日伴愁襟。"]'),
('adc558c2-6360-4480-be16-abc304c00cb4','遠寺鐘','李嘉祐','唐','唐诗','tang','','[]','疎鐘何處來，度竹兼拂水。',24,'全唐诗/poet.tang.10000.json','["疎鐘何處來，度竹兼拂水。", "漸逐微風聲，依依猶在耳。"]'),
('5cdca6e7-551e-4198-a27f-f392fafb9d63','白鷺','李嘉祐','唐','唐诗','tang','','[]','江南淥水多，顧影逗輕波。',24,'全唐诗/poet.tang.10000.json','["江南淥水多，顧影逗輕波。", "落日秦雲裏，山高奈若何。"]'),
('97808292-ac16-4d5e-bee4-a18466d6f570','夜宴南陵留別','李嘉祐','唐','唐诗','tang','','["\u79bb\u522b", "\u6708\u591c", "\u51ac\u5929"]','雪滿前庭月色閑，主人留客未能還。',32,'全唐诗/poet.tang.10000.json','["雪滿前庭月色閑，主人留客未能還。", "預愁明日相思處，匹馬千山與萬山。"]'),
('00b580c8-f454-4c84-bd31-82181647e0f8','題前溪館','李嘉祐','唐','唐诗','tang','','[]','兩年謫宦在江西，舉目雲山要自迷。',32,'全唐诗/poet.tang.10000.json','["兩年謫宦在江西，舉目雲山要自迷。", "今日始知風土異，潯陽南去鷓鴣啼。"]'),
('bc772e4d-25ce-4aa6-8efb-7c1624eec584','過烏公山寄錢起員外','李嘉祐','唐','唐诗','tang','','[]','雨過青山猨呌時，愁人淚點石榴枝。',32,'全唐诗/poet.tang.10000.json','["雨過青山猨呌時，愁人淚點石榴枝。", "無端王事還相繫，腸斷蒹葭君不知。"]'),
('861ef4ac-6a0f-4307-a083-e0175c488c75','寄王舍人竹樓','李嘉祐','唐','唐诗','tang','','["\u5199\u7269", "\u6292\u60c5", "\u95f2\u9002", "\u8d5e\u7f8e", "\u9690\u5c45"]','傲吏身閑笑五侯，西江取竹起高樓。',32,'全唐诗/poet.tang.10000.json','["傲吏身閑笑五侯，西江取竹起高樓。", "南風不用蒲葵扇，紗帽閑眠對水鷗。"]'),
('7f6e313b-5dbb-49b5-b3f9-5df77fff1cbf','韋潤州後亭海榴','李嘉祐','唐','唐诗','tang','','[]','江上年年小雪遲，年光獨報海榴知。',32,'全唐诗/poet.tang.10000.json','["江上年年小雪遲，年光獨報海榴知。", "寂寂山城風日暖，謝公含笑向南枝。"]'),
('3a030fce-75ee-45a4-aa0c-a08f08411c58','送崔十一弟歸北京','李嘉祐','唐','唐诗','tang','','[]','潘郎美貌謝公詩，銀印花驄年少時。',32,'全唐诗/poet.tang.10000.json','["潘郎美貌謝公詩，銀印花驄年少時。", "楚地江臯一爲別，晉山沙水獨相思。"]'),
('b5b34377-94f1-4b05-9a2c-88743f3c5507','訪韓司空不遇','李嘉祐','唐','唐诗','tang','','[]','圖畫風流似長康，文詞體格效陳王。',32,'全唐诗/poet.tang.10000.json','["圖畫風流似長康，文詞體格效陳王。", "蓬萊對去歸常晚，叢竹閑飛滿夕陽。"]'),
('c5953a86-c1c2-432a-8e73-cfb2ab364071','題道虔上人竹房','李嘉祐','唐','唐诗','tang','','[]','詩思禪心共竹閑，任他流水向人間。',32,'全唐诗/poet.tang.10000.json','["詩思禪心共竹閑，任他流水向人間。", "手持如意高窓裏，斜日沿江千萬山。"]'),
('b51c9f56-c13f-487f-846f-90ec85b1b7ac','秋朝木芙蓉','李嘉祐','唐','唐诗','tang','','[]','水面芙蓉秋已衰，繁條到是著花時。',32,'全唐诗/poet.tang.10000.json','["水面芙蓉秋已衰，繁條到是著花時。", "平明露滴垂紅臉，似有朝愁暮落悲。"]'),
('6f26ba25-f4d8-4154-ad57-55c52c23dbf2','袁江口憶王司勳王吏部二郎中起居十七弟','李嘉祐','唐','唐诗','tang','','[]','京華不啻三千里，客淚如今一萬雙。',32,'全唐诗/poet.tang.10000.json','["京華不啻三千里，客淚如今一萬雙。", "若個最爲相憶處，青楓黃竹入袁江。"]'),
('7506cd12-8989-487c-8fcd-ba8bdfabf91b','答泉州薛播使君重陽日贈酒','李嘉祐','唐','唐诗','tang','','[]','欲強登高無力去，籬邊黃菊爲誰開。',32,'全唐诗/poet.tang.10000.json','["欲強登高無力去，籬邊黃菊爲誰開。", "共知不是潯陽郡，那得王弘送酒來。"]'),
('717fa41a-9749-4852-9fde-9062bd2cf900','題張公洞','李嘉祐','唐','唐诗','tang','','[]','空山杳杳鸞鳳飛，神仙門戶開翠微。',32,'全唐诗/poet.tang.10000.json','["空山杳杳鸞鳳飛，神仙門戶開翠微。", "主人白髮雪霞衣，松間留我談玄機。"]'),
('18b46e80-2f5a-46a6-90c7-04489f737d04','句','李嘉祐','唐','唐诗','tang','','[]','水田飛白鷺，夏木囀黃鸝。',42,'全唐诗/poet.tang.10000.json','["水田飛白鷺，夏木囀黃鸝。", "白馬撼金珂，紛紛侍從多。", "身居驃騎幕，家住滹沱河。", "溪北映初星。"]'),
('339220a8-d5ec-402c-a634-61b8cfbcbff1','送泉州李使君之任','包何','唐','唐诗','tang','','[]','傍海皆荒服，分符重漢臣。',48,'全唐诗/poet.tang.10000.json','["傍海皆荒服，分符重漢臣。", "雲山百越路，市井十洲人。", "執玉來朝遠，還珠入貢頻。", "連年不見雪，到處即行春。"]'),
('6a323547-6881-41da-b642-fed14eca69de','和孟虔州閑齋即事','包何','唐','唐诗','tang','','[]','古郡鄰江嶺，公庭半薜蘿。',48,'全唐诗/poet.tang.10000.json','["古郡鄰江嶺，公庭半薜蘿。", "府僚閑不入，山鳥靜偏過。", "睥睨臨花柳，欄干枕芰荷。", "麥秋今欲至，君聽兩岐歌。"]'),
('a493fa7e-84de-40f6-b655-46677ab9ff46','同李郎中淨律院梡子樹','包何','唐','唐诗','tang','','[]','本梡稀難識，沙門種則生。',48,'全唐诗/poet.tang.10000.json','["本梡稀難識，沙門種則生。", "葉殊經寫字，子爲佛稱名。", "濾水澆新長，燃燈暖更榮。", "亭亭無別意，只是勸修行。"]'),
('969d645c-9a62-4480-97a2-10621a949360','同閻伯均宿道士觀有述','包何','唐','唐诗','tang','','[]','南國佳人去不迴，洛陽才子更須媒。',64,'全唐诗/poet.tang.10000.json','["南國佳人去不迴，洛陽才子更須媒。", "綺琴白雪無心弄，羅幌清風到曉開。", "冉冉修篁依戶牖，迢迢列宿映樓臺。", "縱令奔月成仙去，且作行雲入夢來。"]'),
('67060c60-5264-4524-99a9-aa12ae3c641a','送烏程王明府貶巴江','包何','唐','唐诗','tang','','[]','一片孤帆無四鄰，北風吹過五湖濱。',32,'全唐诗/poet.tang.10000.json','["一片孤帆無四鄰，北風吹過五湖濱。", "相看盡是江南客，獨有君爲嶺外人。"]'),
('c2897a95-99ad-4753-a6f2-2136d02d696e','同舍弟佶班韋二員外秋苔對之成詠','包何','唐','唐诗','tang','','[]','每看苔蘚色，如向簿書閑。',48,'全唐诗/poet.tang.10000.json','["每看苔蘚色，如向簿書閑。", "幽思纏芳樹，高情寄遠山。", "雨痕連地綠，日色出林斑。", "却笑興公賦，臨危滑石間。"]'),
('f8f5187e-4b1c-4be1-9abe-8fa0c2275009','送王汶宰江陰','包何','唐','唐诗','tang','','[]','郡北乘流去，花間竟日行。',48,'全唐诗/poet.tang.10000.json','["郡北乘流去，花間竟日行。", "海魚朝滿市，江鳥夜喧城。", "止酒非關病，援琴不在聲。", "應緣五斗米，數日滯淵明。"]'),
('50cada64-f5ae-4538-a363-474c0ab3a296','和苗員外寓直中書','包何','唐','唐诗','tang','','[]','朝列稱多士，君家有二難。',48,'全唐诗/poet.tang.10000.json','["朝列稱多士，君家有二難。", "貞爲臺裏柏，芳作省中蘭。", "夜宿分曹闊，晨趨接武歡。", "每憐雙闕下，鴈序入鴛鸞。"]'),
('f1f7c92e-a574-4324-9c60-8b87a2f2a94f','闕下芙蓉','包何','唐','唐诗','tang','','[]','一人理國致昇平，萬物呈祥助聖明。',64,'全唐诗/poet.tang.10000.json','["一人理國致昇平，萬物呈祥助聖明。", "天上河從闕下過，江南花向殿前生。", "慶雲垂蔭開難落，湛露爲珠滿不傾。", "更對樂懸張宴處，歌工欲奏採蓮聲。"]'),
('601b5495-9683-460a-9ef7-f27c3965cef1','江上田家','包何','唐','唐诗','tang','','[]','近海川原薄，人家本自稀。',48,'全唐诗/poet.tang.10000.json','["近海川原薄，人家本自稀。", "黍苗期臘酒，霜葉是寒衣。", "市井誰相識，漁樵夜始歸。", "不須騎馬問，恐畏狎鷗飛。"]'),
('c5f9b99b-fe97-4eef-8fea-30b45125aa97','送韋侍御奉使江嶺諸道催青苗錢','包何','唐','唐诗','tang','','[]','近遠從王事，南行處處經。',48,'全唐诗/poet.tang.10000.json','["近遠從王事，南行處處經。", "手持霜簡白，心在夏苗青。", "迴鴈書應報，愁猨夜屢聽。", "因君使絕域，方物盡來庭。"]'),
('6dbed00f-b5d4-4276-8de1-d65054b3d4a7','和程員外春日東郊即事','包何','唐','唐诗','tang','','[]','郎官休浣憐遲日，野老歡娛爲有年。',64,'全唐诗/poet.tang.10000.json','["郎官休浣憐遲日，野老歡娛爲有年。", "幾處折花驚蝶夢，數家留葉待蠶眠。", "藤垂宛地縈珠履，泉迸侵堦浸綠錢。", "直到閉關朝謁去，鶯聲不散柳含煙。"]'),
('1fc07309-faba-489d-924d-9c46e950a35c','裴端公使院賦得隔簾見春雨','包何','唐','唐诗','tang','','[]','細雨未成霖，垂簾但覺陰。',48,'全唐诗/poet.tang.10000.json','["細雨未成霖，垂簾但覺陰。", "唯看上砌濕，不遣入簷深。", "度隟霑霜簡，因風潤綺琴。", "須移戶外屨，簷溜夜相侵。"]'),
('b48efd98-7757-45e7-88d9-f9bbcadadc51','相里使君第七男生日','包何','唐','唐诗','tang','','[]','取妻生子復生男，獨有君家衆所談。',64,'全唐诗/poet.tang.10000.json','["取妻生子復生男，獨有君家衆所談。", "荀氏八龍唯欠一，桓山四鳳已過三。", "他時幹蠱聲名著，今日懸弧宴樂酣。", "誰道衆賢能繼體，須知箇箇出於藍。"]'),
('13603ba0-f3e4-43a0-adb6-eb8f9dc839ca','同諸公尋李方直不遇','包何','唐','唐诗','tang','','[]','聞說到揚州，吹簫憶舊遊。',24,'全唐诗/poet.tang.10000.json','["聞說到揚州，吹簫憶舊遊。", "人來多不見，莫是上迷樓。"]'),
('6e3a1fc2-0e5b-4e24-818e-d91c7f84c403','婺州留別鄧使君','包何','唐','唐诗','tang','','[]','西掖馳名久，東陽出守時。',48,'全唐诗/poet.tang.10000.json','["西掖馳名久，東陽出守時。", "江山婺女分，風月隱侯詩。", "別恨雙溪急，留歡五馬遲。", "迴舟映沙嶼，未遠剩相思。"]'),
('2a8dc382-dabc-4d44-933a-a9cd5d1d198f','寄楊侍御','包何','唐','唐诗','tang','','[]','一官何幸得同時，十載無媒獨見遺。',32,'全唐诗/poet.tang.10000.json','["一官何幸得同時，十載無媒獨見遺。", "今日不論腰下組，請君看取鬢邊絲。"]'),
('1ab01ce4-3218-4299-9a70-5eec67eb1501','賦得秤送孟孺卿','包何','唐','唐诗','tang','','[]','願以金秤鎚，因君贈別離。',48,'全唐诗/poet.tang.10000.json','["願以金秤鎚，因君贈別離。", "鉤懸新月吐，衡舉衆星隨。", "掌握須平執，錙銖必盡知。", "由來投分審，莫放弄權移。"]'),
('f5a1b0dc-92fd-41ad-aa63-3bb3b4c772f7','長安曉望寄崔補闕','包何','唐','唐诗','tang','','[]','迢遞山河擁帝京，參差宮殿接雲平。',64,'全唐诗/poet.tang.10000.json','["迢遞山河擁帝京，參差宮殿接雲平。", "風吹曉漏經長樂，柳帶晴煙出禁城。", "天淨笙歌臨路發，日高車馬隔塵行。", "自憐久滯諸生列，未得金閨籍姓名。"]'),
('1df593c6-0623-4de8-b8a5-af33274f0bb6','送蕭穎士赴東府得路字','賈邕','唐','唐诗','tang','','[]','子欲適東周，門人盈岐路。',48,'全唐诗/poet.tang.10000.json','["子欲適東周，門人盈岐路。", "高標信難仰，薄官非始務。", "綿邈千里途，裴回四郊暮。", "征車日云遠，撫己慙深顧。"]'),
('f7482274-6498-487b-bec5-1847f108176b','送蕭穎士赴東府得適字','劉舟','唐','唐诗','tang','','[]','大名掩諸古，獨斷無不適。',48,'全唐诗/poet.tang.10000.json','["大名掩諸古，獨斷無不適。", "德遂天下宗，官爲幕中客。", "驪山浮雲散，灞岸零雨夕。", "請業非遠期，圓光再生魄。"]'),
('34d2f706-800b-4608-8ea2-2588e9c32644','送蕭穎士赴東府得離字','長孫鑄','唐','唐诗','tang','','[]','大德詎可擬，高梧有長離。',48,'全唐诗/poet.tang.10000.json','["大德詎可擬，高梧有長離。", "素懷經綸具，昭世猶安卑。", "落日去關外，悠悠隔山陂。", "我心如浮雲，千里相追隨。"]'),
('70847d6a-a1e9-4b6f-a904-25924ca4c875','送蕭穎士赴東府得還字','房白','唐','唐诗','tang','','[]','夫子高世蹟，時人不可攀。',48,'全唐诗/poet.tang.10000.json','["夫子高世蹟，時人不可攀。", "今予亦云幸，謬得承溫顏。", "良策資入幕，遂行從近關。", "青春灞亭別，此去何時還。"]'),
('8f272b01-b1f7-44cd-8a4f-866e6efaf0ff','送蕭穎士赴東府得引字','元晟','唐','唐诗','tang','','[]','吾見夫子德，誰云習相近。',48,'全唐诗/poet.tang.10000.json','["吾見夫子德，誰云習相近。", "數仞不可窺，言味終難盡。", "處喧慮常澹，作吏心亦隱。", "更有嵩少峰，東南爲勝引。"]'),
('6cc8c077-d931-4eb2-85fd-4fe1bfdb5810','送蕭穎士赴東府得淺字','劉太沖','唐','唐诗','tang','','[]','吾師繼微言，贊述在墳典。',48,'全唐诗/poet.tang.10000.json','["吾師繼微言，贊述在墳典。", "寸祿聊自資，平生宦情鮮。", "逶遲東州路，春草深復淺。", "日遠夫子門，中心曷由展。"]'),
('ed0a8f5b-76c8-4fc8-aa9d-4b45fe3a18eb','送蕭穎士赴東府得草字','姚發','唐','唐诗','tang','','[]','天生良史筆，浪跡擅文藻。',48,'全唐诗/poet.tang.10000.json','["天生良史筆，浪跡擅文藻。", "中夏授參謀，東夷願聞道。", "行軒翫春日，餞席藉芳草。", "幸得師季良，欣留篋笥寶。"]'),
('aba90e40-6a95-49eb-9432-5ef7e17a3ee8','送蕭穎士赴東府得往字','鄭愕','唐','唐诗','tang','','[]','斤溪數畝田，素心擬長往。',48,'全唐诗/poet.tang.10000.json','["斤溪數畝田，素心擬長往。", "繄君曲得引，使我纓俗網。", "風塵豈不勞，道義成心賞。", "春郊桃李月，忍此戒征兩。"]'),
('2dad9262-faad-45d2-a3d8-69c51f97ddad','送蕭穎士赴東府得散字','殷少野','唐','唐诗','tang','','[]','官閑幕府下，聊以任縱誕。',48,'全唐诗/poet.tang.10000.json','["官閑幕府下，聊以任縱誕。", "文學魯仲尼，高標嵇中散。", "出門時雨潤，對酒春風暖。", "感激知己恩，別離魂欲斷。"]'),
('c7f47dc5-2dbd-43bd-a851-74c76735992e','送蕭穎士赴東府得君字','鄔載','唐','唐诗','tang','','[]','策名十二載，獨立先斯文。',120,'全唐诗/poet.tang.10000.json','["策名十二載，獨立先斯文。", "邇來及門者，半已昇青雲。", "青雲豈無姿，黃鵠素不羣。", "一辭芸香吏，幾歲滄江濆。", "散職既不羈，天聽亦昭聞。", "雖承急賢詔，未謁陶唐君。", "薄俸還自急，此言那足云。", "和風媚東郊，時物滋南薰。", "蕙草正可摘，豫章猶未分。", "宗師忽千里，使我心氛氳。"]'),
('d5082efe-beda-482e-8f57-f88241cdda54','奉陪韋中丞使君遊鶴林寺','皇甫曾','唐','唐诗','tang','','[]','古寺傳燈久，層城閉閣閑。',48,'全唐诗/poet.tang.10000.json','["古寺傳燈久，層城閉閣閑。", "香花同法侶，旌斾入深山。", "寒磬虛空裏，孤雲起滅間。", "謝公憶高臥，徒御欲東還。"]'),
('432d77a0-08de-44b9-a3c4-06db88347496','奉送杜侍御還京','皇甫曾','唐','唐诗','tang','','[]','罷戰回龍節，朝天上鳳池。',48,'全唐诗/poet.tang.10000.json','["罷戰回龍節，朝天上鳳池。", "寒生五湖道，春入萬年枝。", "召化多遺愛，胡清已畏知。", "懷恩偏感別，墮淚向旌麾。"]'),
('9c4d514a-2b2c-4a60-bdfd-8ad970a85e8a','酬鄭侍御秋夜見寄','皇甫曾','唐','唐诗','tang','','[]','搖落空林夜，河陽興已生。',48,'全唐诗/poet.tang.10000.json','["搖落空林夜，河陽興已生。", "未辭公府步，知結遠山情。", "高柳風難定，寒泉月助明。", "袁公方臥雪，尺素及柴荆。"]'),
('b2d89260-e3b7-4077-aaaa-0a67db01d5b6','酬竇拾遺秋日見呈','皇甫曾','唐','唐诗','tang','','[]','孤城永巷時相見，衰柳閑門日半斜。',32,'全唐诗/poet.tang.10000.json','["孤城永巷時相見，衰柳閑門日半斜。", "欲送近臣朝魏闕，猶憐殘菊在陶家。"]'),
('84fccfc1-60e4-4e70-a963-bcd0224c80c9','韋使君宅海榴詠','皇甫曾','唐','唐诗','tang','','[]','淮陽臥理有清風，臘月榴花帶雪紅。',32,'全唐诗/poet.tang.10000.json','["淮陽臥理有清風，臘月榴花帶雪紅。", "閉閣寂寥常對此，江湖心在數枝中。"]'),
('c3aa3e06-2bfd-435e-ada7-fbd1a0b015ec','送普上人還陽羨','皇甫曾','唐','唐诗','tang','','[]','花宮難久別，道者憶千燈。',48,'全唐诗/poet.tang.10000.json','["花宮難久別，道者憶千燈。", "殘雪入林路，暮山歸寺僧。", "日光依嫩草，泉響滴春冰。", "何用求方便，看心是一乘。"]'),
('ae5bb0aa-b924-4c04-8363-53ee18269524','送李中丞歸本道','皇甫曾','唐','唐诗','tang','','[]','上將還專席，雙旌復出秦。',36,'全唐诗/poet.tang.10000.json','["上將還專席，雙旌復出秦。", "關河三晉路，賓從五原人。", "孤戍雲連海，平沙雪度春。"]'),
('9149aa7c-b352-4a0f-aaeb-85ab10403744','和謝舍人雪夜寓直','皇甫曾','唐','唐诗','tang','','[]','禁省夜沈沈，春風雪滿林。',48,'全唐诗/poet.tang.10000.json','["禁省夜沈沈，春風雪滿林。", "滄洲歸客夢，青瑣近臣心。", "揮翰宣鳴玉，承恩在賜金。", "建章寒漏起，更助掖垣深。"]'),
('803b76e6-7aed-4569-88a8-7cd6c5b74c6a','尋劉處士','皇甫曾','唐','唐诗','tang','','[]','幾年人不見，林下掩柴關。',48,'全唐诗/poet.tang.10000.json','["幾年人不見，林下掩柴關。", "留客當清夜，逢君話舊山。", "隔城寒杵急，帶月早鴻還。", "南陌雖相近，其如隱者閑。"]'),
('e8cc31e9-6b51-4a37-818b-7891dfb9677c','哭陸處士','皇甫曾','唐','唐诗','tang','','[]','從此無期見，柴門對雪開。',48,'全唐诗/poet.tang.10000.json','["從此無期見，柴門對雪開。", "二毛逢世難，萬恨掩泉臺。", "返照空堂夕，孤城弔客迴。", "漢家偏訪道，猶畏鶴書來。"]'),
('189ab60e-c415-4aa2-b883-e6a899426407','烏程水樓留別','皇甫曾','唐','唐诗','tang','','[]','悠悠千里去，惜此一尊同。',48,'全唐诗/poet.tang.10000.json','["悠悠千里去，惜此一尊同。", "客散高樓上，帆飛細雨中。", "山程隨遠水，楚思在青楓。", "共說前期易，滄波處處同。"]'),
('7a31f052-4673-4acb-b344-3f421bb6980d','題贈吳門邕上人','皇甫曾','唐','唐诗','tang','','[]','春山唯一室，獨坐草萋萋。',48,'全唐诗/poet.tang.10000.json','["春山唯一室，獨坐草萋萋。", "身寂心成道，花閑鳥自啼。", "細泉松徑裏，返景竹林西。", "晚與門人別，依依出虎溪。"]'),
('2bdc3e83-80ca-4977-bbc1-cc1e37918e14','送陸鴻漸山人採茶回','皇甫曾','唐','唐诗','tang','','[]','千峯待逋客，香茗復叢生。',48,'全唐诗/poet.tang.10000.json','["千峯待逋客，香茗復叢生。", "採摘知深處，烟霞羨獨行。", "幽期山寺遠，野飯石泉清。", "寂寂燃燈夜，相思一磬聲。"]'),
('997fc4da-ca67-42e2-99c4-7bd68a155c8a','寄劉員外長卿','皇甫曾','唐','唐诗','tang','','[]','南憶新安郡，千山帶夕陽。',48,'全唐诗/poet.tang.10000.json','["南憶新安郡，千山帶夕陽。", "斷猨知夜久，秋草助江長。", "疎髮應成素，青松獨耐霜。", "愛才稱漢主，題柱待回鄉。"]'),
('ee1af307-1e4b-4b18-a2d9-1194784cae0a','寄張仲甫','皇甫曾','唐','唐诗','tang','','[]','悲風生舊浦，雲嶺隔東田。',48,'全唐诗/poet.tang.10000.json','["悲風生舊浦，雲嶺隔東田。", "伏臘同雞黍，柴門閉雪天。", "孤村明夜火，稚子候歸船。", "靜者心相憶，離居畏度年。"]'),
('155165e4-9098-48e4-8965-5484a4983d54','送元侍御充使湖南','皇甫曾','唐','唐诗','tang','','[]','雲夢南行盡，三湘萬里流。',48,'全唐诗/poet.tang.10000.json','["雲夢南行盡，三湘萬里流。", "山川重分手，徒御亦悲秋。", "白簡勞王事，清猨助客愁。", "離羣復多病，歲晚憶滄洲。"]'),
('48703e8c-71bb-4c72-b21f-9dbde75ee5af','晚至華陰','皇甫曾','唐','唐诗','tang','','[]','臘盡促歸心，行人及華陰。',48,'全唐诗/poet.tang.10000.json','["臘盡促歸心，行人及華陰。", "雲霞仙掌出，松柏古祠深。", "野渡冰生岸，寒川燒隔林。", "溫泉看漸近，宮樹晚沈沈。"]'),
('5bb0cf37-0685-4b52-b9b5-45e959d05e12','送孔徵士','皇甫曾','唐','唐诗','tang','','[]','谷口山多處，君歸不可尋。',48,'全唐诗/poet.tang.10000.json','["谷口山多處，君歸不可尋。", "家貧青史在，身老白雲深。", "掃雪開松徑，疏泉過竹林。", "餘生負丘壑，相送亦何心。"]'),
('1a821e55-d4ca-44ff-a15d-a5c15ce0df81','秋興','皇甫曾','唐','唐诗','tang','','[]','流螢與落葉，秋晚共紛紛。',48,'全唐诗/poet.tang.10000.json','["流螢與落葉，秋晚共紛紛。", "返照城中盡，寒砧雨外聞。", "離人見衰鬢，獨鶴暮何羣。", "楚客在千里，相思看碧雲。"]'),
('32c87342-3c08-4cff-952c-67eda7fb9d46','送歸中丞使新羅','皇甫曾','唐','唐诗','tang','','[]','南幰銜恩去，東夷泛海行。',48,'全唐诗/poet.tang.10000.json','["南幰銜恩去，東夷泛海行。", "天遙辭上國，水盡到孤城。", "已變炎涼氣，仍愁浩淼程。", "雲濤不可極，來往見雙旌。"]'),
('ebb316eb-28f4-4a18-9eb2-07ccf943a7eb','送少微上人東南遊','皇甫曾','唐','唐诗','tang','','[]','石梁人不到，獨往更迢迢。',48,'全唐诗/poet.tang.10000.json','["石梁人不到，獨往更迢迢。", "乞食山家少，尋鐘野寺遙。", "松門風自掃，瀑布雪難消。", "秋夜聞清梵，餘音逐海潮。"]'),
('ffe2114c-a56d-4f43-bae4-49a13ec043e3','送韋判官赴閩中','皇甫曾','唐','唐诗','tang','','[]','孤棹閩中客，雙旌海上軍。',48,'全唐诗/poet.tang.10000.json','["孤棹閩中客，雙旌海上軍。", "路人從北少，海水向南分。", "野鶴傷秋別，林猨忌夜聞。", "漢家崇亞相，知子遠邀勳。"]'),
('ebb507f6-cdf8-4ab1-bd60-180f62f78338','送人還荆州','皇甫曾','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u9001\u522b"]','草色隨驄馬，悠悠同出秦。',48,'全唐诗/poet.tang.10000.json','["草色隨驄馬，悠悠同出秦。", "水傳雲夢曉，山接洞庭春。", "帆影連三峽，猨聲近四隣。", "青門一分手，難見杜陵人。"]'),
('b5cbb21b-6545-4746-995f-b084fca74d5e','寄淨虛上人初至雲門','皇甫曾','唐','唐诗','tang','','[]','寒蹤白雲裏，法侶自提攜。',48,'全唐诗/poet.tang.10000.json','["寒蹤白雲裏，法侶自提攜。", "竹徑通城下，松門隔水西。", "方同沃洲去，不似武陵迷。", "彷彿方知處，高峯是會稽。"]'),
('b47c9575-fe60-44e4-92f7-94386b4d512f','春和杜相公移入長興宅奉呈諸宰執','皇甫曾','唐','唐诗','tang','','[]','欲向幽偏適，還從絕地移。',96,'全唐诗/poet.tang.10000.json','["欲向幽偏適，還從絕地移。", "秦官鼎食貴，堯世土階卑。", "戟戶槐陰滿，書窗竹葉垂。", "才分午夜漏，遙隔萬年枝。", "北闕深恩在，東林遠夢知。", "日斜門掩暎，山遠樹參差。", "論道齊鴛翼，題詩憶鳳池。", "從公亦何幸，長與珮聲隨。"]'),
('aad0a00e-1871-44e1-ae2a-1a92eab081b4','路中口號','皇甫曾','唐','唐诗','tang','','[]','還鄉不見家，年老眼多淚。',24,'全唐诗/poet.tang.10000.json','["還鄉不見家，年老眼多淚。", "車馬上河橋，城中好天氣。"]'),
('144c623f-415c-4d5f-8474-dcd38e5ae34b','山下泉','皇甫曾','唐','唐诗','tang','','[]','漾漾帶山光，澄澄倒林影。',24,'全唐诗/poet.tang.10000.json','["漾漾帶山光，澄澄倒林影。", "那知石上喧，却憶山中靜。"]'),
('4e492d9a-f739-4962-84ec-d377838a6ada','早朝日寄所知','皇甫曾','唐','唐诗','tang','','[]','長安雪夜見歸鴻，紫禁朝天拜舞同。',64,'全唐诗/poet.tang.10000.json','["長安雪夜見歸鴻，紫禁朝天拜舞同。", "曙色漸分雙闕下，漏聲遙在百花中。", "爐煙乍起開仙仗，玉佩纔成引上公。", "共荷發生同雨露，不應黃葉久隨風。"]'),
('98ff9839-2561-494c-a2ad-ed70217d0790','秋夕寄懷契上人','皇甫曾','唐','唐诗','tang','','[]','已見槿花朝委露，獨悲孤鶴在人羣。',64,'全唐诗/poet.tang.10000.json','["已見槿花朝委露，獨悲孤鶴在人羣。", "真僧出世心無事，靜夜名香手自焚。", "窗臨絕澗聞流水，客至孤峯掃白雲。", "更想清晨誦經處，獨看松上雪紛紛。"]'),
('707975d7-671c-4727-9168-3c6103cbdb20','張芬見訪郊居作','皇甫曾','唐','唐诗','tang','','[]','林中雨散早涼生，已有迎秋促織聲。',64,'全唐诗/poet.tang.10000.json','["林中雨散早涼生，已有迎秋促織聲。", "三徑荒蕪羞對客，十年衰老愧稱兄。", "愁心自惜江蘺晚，世事方看木槿榮。", "君若罷官攜手日，尋山莫算白雲程。"]'),
('39e6e1d3-5d9e-4b3b-90f6-762839b3b8ed','贈鑒上人','皇甫曾','唐','唐诗','tang','','[]','律儀傳教誘，僧臘老煙霄。',72,'全唐诗/poet.tang.10000.json','["律儀傳教誘，僧臘老煙霄。", "樹色依禪誦，泉聲入寂寥。", "寶龕經末劫，畫壁見南朝。", "深竹風開合，寒潭月動搖。", "息心歸靜理，愛道坐中宵。", "更欲尋真去，乘船過海潮。"]'),
('b27b13fb-d8e2-4231-a109-65068e60437d','奉寄中書王舍人','皇甫曾','唐','唐诗','tang','','[]','腰金載筆謁承明，至道安禪得此生。',64,'全唐诗/poet.tang.10000.json','["腰金載筆謁承明，至道安禪得此生。", "西掖幾年綸綍貴，東山遙夜薜蘿情。", "風傳刻漏星河曙，月上梧桐雨露清。", "聖主好文誰爲薦，閉門空賦子虛成。"]'),
('5ceea715-909e-454c-ad89-5cda63cc119d','送湯中丞和蕃','皇甫曾','唐','唐诗','tang','','[]','繼好中司出，天心外國知。',72,'全唐诗/poet.tang.10000.json','["繼好中司出，天心外國知。", "已傳堯雨露，更說漢威儀。", "隴上應回首，河源復載馳。", "孤峯問徒御，空磧見旌麾。", "春草鄉愁起，邊城旅夢移。", "莫嗟行遠地，此去荅恩私。"]'),
('7677c346-7aca-42c9-9bcd-63de4115339d','送和西蕃使','皇甫曾','唐','唐诗','tang','','[]','白簡初分命，黃金已在腰。',72,'全唐诗/poet.tang.10000.json','["白簡初分命，黃金已在腰。", "恩華通外國，徒御發中朝。", "雨雪從邊起，旌旗上隴遙。", "暮天沙漠漠，空磧馬蕭蕭。", "寒路隨河水，關城見柳條。", "和戎先罷戰，知勝霍嫖姚。"]'),
('f9f6dd33-84b8-4c24-b692-75bfef1237ea','送王相公赴幽州','皇甫曾','唐','唐诗','tang','','[]','台衮兼戎律，勤憂秉化元。',72,'全唐诗/poet.tang.10000.json','["台衮兼戎律，勤憂秉化元。", "鳳池東掖寵，龍節北方尊。", "長路山河轉，前驅鼓角喧。", "人安布時令，地遠荅君恩。", "暮日平沙迥，秋風大斾翻。", "漁陽在天末，戀別信陵門。"]'),
('7a9710da-e7ef-4cce-aad2-f7e3c28558d1','送徐大夫赴南海','皇甫曾','唐','唐诗','tang','','[]','舊國當分閫，天涯荅聖私。',72,'全唐诗/poet.tang.10000.json','["舊國當分閫，天涯荅聖私。", "大軍傳羽檄，老將拜旌旗。", "位重登壇後，恩深弄印時。", "何年諫獵賦，今日飲泉詩。", "海內求民瘼，城隅見島夷。", "由來黃霸去，自有上台期。"]'),
('4572699f-cc98-457f-8880-7258b363532a','贈沛禪師','皇甫曾','唐','唐诗','tang','','["\u8861\u5c71"]','南嶽滿湘沅，吾師經利涉。',72,'全唐诗/poet.tang.10000.json','["南嶽滿湘沅，吾師經利涉。", "身歸沃洲老，名與支公接。", "淨教傳荆吳，道緣止漁獵。", "觀空色不染，對境心自愜。", "室中人寂寞，門外山重疊。", "天台積幽夢，早晚當負笈。"]'),
('5d00aa80-4a3e-4909-a123-cfdacd14f390','萼嶺四望','皇甫曾','唐','唐诗','tang','','[]','漢家仙仗在咸陽，洛水東流出建章。',32,'全唐诗/poet.tang.10000.json','["漢家仙仗在咸陽，洛水東流出建章。", "野老至今猶望幸，離宮秋樹獨蒼蒼。"]'),
('048ac046-9aad-43f4-ad68-bf6e68032857','過劉員外長卿別墅','皇甫曾','唐','唐诗','tang','','[]','謝客開山後，郊扉積水通。',48,'全唐诗/poet.tang.10000.json','["謝客開山後，郊扉積水通。", "江湖千里別，衰老一尊同。", "返照寒川滿，平田暮雪空。", "滄洲自有趣，不便哭途窮。"]'),
('58205c60-2b77-46dd-adb0-2c98a17b1f60','遇風雨作','皇甫曾','唐','唐诗','tang','','[]','草草理夜裝，涉江又登陸。',168,'全唐诗/poet.tang.10000.json','["草草理夜裝，涉江又登陸。", "望路殊未窮，指期今已促。", "傳呼戒徒馭，振轡轉林麓。", "陰雲擁巖端，霑雨當山腹。", "震雷如在耳，飛電來照目。", "獸跡不敢窺，馬蹄惟務速。", "虔心若齋禱，濡體如沐浴。", "萬竅相怒號，百泉暗奔瀑。", "危梁慮足跌，峻坂憂車覆。", "問我何以然，前日愛微祿。", "轉知人代事，纓組乃徽束。", "向若家居時，安枕春夢熟。", "遵途稍已近，候吏來相續。", "曉霽心始安，林端見初旭。"]'),
('02e93ea0-09d8-40da-9d83-10e2549dc21b','送商州杜中丞赴任','皇甫曾','唐','唐诗','tang','','[]','安康地理接商於，帝命專城總賦輿。',64,'全唐诗/poet.tang.10000.json','["安康地理接商於，帝命專城總賦輿。", "夕拜忽辭青瑣闥，晨裝獨捧紫泥書。", "深山古驛分騶騎，芳草閑雲逐隼旟。", "綺皓清風千古在，因君一爲謝巖居。"]'),
('258e8498-75f6-4ec4-968f-9043297c7e68','送著公歸越','皇甫曾','唐','唐诗','tang','','[]','誰能愁此別，到越會相逢。',48,'全唐诗/poet.tang.10000.json','["誰能愁此別，到越會相逢。", "長憶雲門寺，門前千萬峯。", "石牀埋積雪，山路倒枯松。", "莫學白居士，無人知去蹤。"]'),
('71448655-65bb-48ff-95e6-e5ccfbb55b12','送鄭秀才貢舉','皇甫曾','唐','唐诗','tang','','[]','西去意如何，知隨貢士科。',48,'全唐诗/poet.tang.10000.json','["西去意如何，知隨貢士科。", "吟詩向月路，驅馬出煙蘿。", "晚色寒蕪遠，秋聲候雁多。", "自憐歸未得，相送一勞歌。"]'),
('e0b22e4e-6160-4470-9a8e-1f03f9bd354f','錫杖歌送明楚上人歸佛川','皇甫曾','唐','唐诗','tang','','[]','上人遠自西天至，頭陀行遍南朝寺。',112,'全唐诗/poet.tang.10000.json','["上人遠自西天至，頭陀行遍南朝寺。", "口翻貝葉古字經，手持金策聲泠泠。", "護法護身惟振錫，石瀨雲溪深寂寂。", "乍來松徑風露寒，遙暎霜天月成魄。", "後夜空山禪誦時，寥寥挂在枯樹枝。", "真法嘗傳心不住，東西南北隨緣路。", "佛川此去何時迴，應真莫便遊天台。"]'),
('c1c10c13-909a-48d0-af29-f2cf67732f9c','玉山嶺上作','皇甫曾','唐','唐诗','tang','','[]','悠悠驅匹馬，征路上連岡。',48,'全唐诗/poet.tang.10000.json','["悠悠驅匹馬，征路上連岡。", "晚翠深雲竇，寒臺淨石梁。", "秋花偏似雪，楓葉不禁霜。", "愁見前程遠，空郊下夕陽。"]'),
('82c60214-4e01-4141-9673-b131fa6978b2','國子柳博士兼領太常博士輙申賀贈','皇甫曾','唐','唐诗','tang','','[]','博士本秦官，求才帖職難。',48,'全唐诗/poet.tang.10000.json','["博士本秦官，求才帖職難。", "臨風曲臺淨，對月碧池寒。", "講學分陰重，齋祠曉漏殘。", "朝衣辨色處，雙綬更宜看。"]'),
('898de8fd-d231-41f0-9607-5ebceb7fbad0','送裴秀才貢舉','皇甫曾','唐','唐诗','tang','','[]','儒衣羞此別，去抵漢公卿。',48,'全唐诗/poet.tang.10000.json','["儒衣羞此別，去抵漢公卿。", "賓貢年猶少，篇章藝已成。", "臨流惜暮景，話別起鄉情。", "離酌不辭醉，西江春草生。"]'),
('7eab571c-451d-4503-b79b-c2e3b26ec178','贈老將','皇甫曾','唐','唐诗','tang','','[]','白草黃雲塞上秋，曾隨驃騎出幷州。',32,'全唐诗/poet.tang.10000.json','["白草黃雲塞上秋，曾隨驃騎出幷州。", "轆轤劒折虯髯白，轉戰功多獨不侯。"]'),
('66fd0cb9-5f5b-4299-b7bd-a2d03ca5c89e','銅雀妓','高適','唐','唐诗','tang','','[]','日暮銅雀迥，秋深玉座清。',36,'全唐诗/poet.tang.10000.json','["日暮銅雀迥，秋深玉座清。", "蕭森松柏望，委鬱綺羅情。", "君恩不再得，妾舞爲誰輕。"]'),
('be7d571b-09e2-410f-af17-aab2fbc4c371','塞下曲','高適','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e", "\u58ee\u5fd7"]','結束浮雲駿，翩翩出從戎。',120,'全唐诗/poet.tang.10000.json','["結束浮雲駿，翩翩出從戎。", "且憑天子怒，復倚將軍雄。", "萬鼓雷殷地，千旗火生風。", "日輪駐霜戈，月魄懸琱弓。", "青海陣雲匝，黑山兵氣衡。", "戰酣太白高，戰罷旄頭空。", "萬里不惜死，一朝得成功。", "畫圖騏麟閣，入朝明光宮。", "大笑向文士，一經何足窮。", "古人昧此道，往往成老翁。"]'),
('0111fccd-210b-4e0d-b8f7-c4b09ed8476f','塞上','高適','唐','唐诗','tang','','[]','東出盧龍塞，浩然客思孤。',96,'全唐诗/poet.tang.10000.json','["東出盧龍塞，浩然客思孤。", "亭堠列萬里，漢兵猶備胡。", "邊塵漲北溟，虜騎正南驅。", "轉鬬豈長策，和親非遠圖。", "惟昔李將軍，按節出皇都。", "總戎掃大漠，一戰擒單于。", "常懷感激心，願效縱橫謨。", "倚劒欲誰語，關河空鬱紆。"]'),
('b44f7786-9795-41c3-b69e-cee35d6154b9','薊門行五首 一','高適','唐','唐诗','tang','','[]','薊門逢古老，獨立思氛氳。',36,'全唐诗/poet.tang.10000.json','["薊門逢古老，獨立思氛氳。", "一身既零丁，頭鬢白紛紛。", "勳庸今已矣，不識霍將軍。"]'),
('31796009-cfd9-4a91-8baa-85d8509fe93a','薊門行五首 二','高適','唐','唐诗','tang','','[]','漢家能用武，開拓窮異域。',36,'全唐诗/poet.tang.10000.json','["漢家能用武，開拓窮異域。", "戍卒厭糠覈，降胡飽衣食。", "關亭試一望，吾欲淚沾臆。"]'),
('ffe3d0db-accb-46d1-ab4c-ac215d65cc82','薊門行五首 三','高適','唐','唐诗','tang','','[]','邊城十一月，雨雪亂霏霏。',36,'全唐诗/poet.tang.10000.json','["邊城十一月，雨雪亂霏霏。", "元戎號令嚴，人馬亦輕肥。", "羌胡無盡日，征戰幾時歸。"]'),
('9788cd7e-a89d-4061-8f6e-fcb4d46f8e3a','薊門行五首 四','高適','唐','唐诗','tang','','[]','幽州多騎射，結髮重橫行。',36,'全唐诗/poet.tang.10000.json','["幽州多騎射，結髮重橫行。", "一朝事將軍，出入有聲名。", "紛紛獵秋草，相向角弓鳴。"]'),
('6145d02d-f6db-4a7e-be04-03535abd63c3','薊門行五首 五','高適','唐','唐诗','tang','','[]','黯黯長城外，日沒更煙塵。',36,'全唐诗/poet.tang.10000.json','["黯黯長城外，日沒更煙塵。", "胡騎雖憑陵，漢兵不顧身。", "古樹滿空塞，黃雲愁殺人。"]'),
('271fe949-a658-4f90-b142-866081137549','效古贈崔二','高適','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u8fb9\u585e", "\u8bbd\u523a", "\u6124\u61d1"]','十月河洲時，一看有歸思。',156,'全唐诗/poet.tang.10000.json','["十月河洲時，一看有歸思。", "風飆生慘烈，雨雪暗天地。", "我輩今胡爲，浩哉迷所至。", "緬懷當塗者，濟濟居聲位。", "邈然在雲霄，寧肯更淪躓。", "周旋多燕樂，門館列車騎。", "美人芙蓉姿，狹室蘭麝氣。", "金鑪陳獸炭，談笑正得意。", "豈論草澤中，有此枯槁士。", "我慙經濟策，久欲甘棄置。", "君負縱橫才，如何尚顦顇。", "長歌增鬱怏，對酒不能醉。", "窮達自有時，夫子莫下淚。"]'),
('f85038c4-be28-4117-afab-a023a2f18b59','鉅鹿贈李少府','高適','唐','唐诗','tang','','[]','李侯雖薄宦，時譽何籍籍。',48,'全唐诗/poet.tang.10000.json','["李侯雖薄宦，時譽何籍籍。", "駿馬常借人，黃金每留客。", "投壺華館靜，縱酒涼風夕。", "即此遇神仙，吾欣知損益。"]'),
('451fc40e-4dad-47ec-88e7-bb54fbc6bb60','東平留贈狄司馬','高適','唐','唐诗','tang','','[]','古人無宿諾，茲道以爲難。',156,'全唐诗/poet.tang.10000.json','["古人無宿諾，茲道以爲難。", "萬里赴知己，一言誠可歎。", "馬蹄經月窟，劒術指樓蘭。", "地出北庭盡，城臨西海寒。", "森然瞻武庫，則是弄儒翰。", "入幕綰銀綬，乘軺兼鐵冠。", "練兵日精銳，殺敵無遺殘。", "獻捷見天子，論功俘可汗。", "激昂丹墀下，顧盼青雲端。", "誰謂縱橫策，翻爲權勢干。", "將軍既坎壈，使者亦辛酸。", "耿介挹三事，羇離從一官。", "知君不得意，他日會鵬摶。"]'),
('0b4a2ac4-56be-43c9-83e4-753081c0caf0','過盧明府有贈','高適','唐','唐诗','tang','','[]','良吏不易得，古人今可傳。',156,'全唐诗/poet.tang.10000.json','["良吏不易得，古人今可傳。", "靜然本諸已，以此知其賢。", "我行挹高風，羨爾兼少年。", "胸懷豁清夜，史漢如流泉。", "明日復行春，逶迤出郊壇。", "登高見百里，桑野鬱芊芊。", "時平俯鵲巢，歲熟多人烟。", "奸猾唯閉戶，逃亡歸種田。", "廻軒自郭南，老幼滿馬前。", "皆賀蠶農至，而無徭役牽。", "君觀黎庶心，撫之誠萬全。", "何幸逢大道，願言烹小鮮。", "能奏明廷主，一試武城弦。"]'),
('cfec06fe-678e-45b9-8da3-93ed36cb9f9e','單父逢鄧司倉覆倉庫因而有贈','高適','唐','唐诗','tang','','[]','邦牧今坐嘯，羣賢趨紀綱。',132,'全唐诗/poet.tang.10000.json','["邦牧今坐嘯，羣賢趨紀綱。", "四人忽不擾，耕者遙相望。", "粲粲府中妙，授詞如履霜。", "炎炎伏熱時，草木無晶光。", "匹馬度睢水，清風何激揚。", "校緡閱帑藏，發廩欣斯箱。", "邂逅得相逢，歡言至夕陽。", "開襟自公餘，載酒登琴堂。", "舉桮挹山川，寓目窮毫芒。", "白鳥向田盡，青蟬歸路長。", "醉中不惜別，況乃正遊梁。"]'),
('a0256412-ab0a-4c8c-a3e1-09e8434506c1','薊門不遇王之[渙]郭密之因以留贈','高適','唐','唐诗','tang','','[]','適遠登薊丘，茲晨獨搔屑。',84,'全唐诗/poet.tang.10000.json','["適遠登薊丘，茲晨獨搔屑。", "賢交不可見，吾願終難說。", "迢遞千里遊，羇離十年別。", "才華仰清興，功業嗟芳節。", "曠蕩阻雲海，蕭條帶風雪。", "逢時事多謬，失路心彌折。", "行矣勿重陳，懷君但愁絕。"]'),
('4a3ab918-5792-4cc1-b05d-bcf0acd26e54','寄孟五少府','高適','唐','唐诗','tang','','[]','秋氣落窮巷，離憂兼暮蟬。',60,'全唐诗/poet.tang.10000.json','["秋氣落窮巷，離憂兼暮蟬。", "後時已如此，高興亦徒然。", "知君念淹泊，憶我屢周旋。", "征路見來雁，歸人悲遠天。", "平生感千里，相望在貞堅。"]'),
('20aa930c-017e-4a7d-8909-0782047d574d','苦雨寄房四昆季','高適','唐','唐诗','tang','','[]','獨坐見多雨，況茲兼索居。',228,'全唐诗/poet.tang.10000.json','["獨坐見多雨，況茲兼索居。", "茫茫十月交，窮陰千里餘。", "彌望無端倪，北風擊林箊。", "白日渺難覩，黃雲爭卷舒。", "安得造化功，曠然一掃除。", "滴瀝簷宇愁，寥寥談笑疎。", "泥塗擁城郭，水潦盤丘墟。", "惆悵憫田農，裴回傷里閭。", "曾是力井稅，曷爲無斗儲。", "萬事切中懷，十年思上書。", "君門嗟緬邈，身計念居諸。", "沈吟顧草茅，鬱怏任盈虛。", "黃鵠不可羨，雞鳴時起予。", "故人平臺側，高館臨通衢。", "兄弟方荀陳，才華冠應徐。", "彈棊自多暇，飲酒更何如。", "知人想林宗，直道慙史魚。", "攜手風流在，開襟鄙吝祛。", "寧能訪窮巷，相與對園蔬。"]'),
('ec8e6f54-f69f-43a9-ab8b-155ff46ce8f2','和賀蘭判官望北海作','高適','唐','唐诗','tang','','[]','聖代務平典，輶軒推上才。',168,'全唐诗/poet.tang.10000.json','["聖代務平典，輶軒推上才。", "迢遙溟海際，曠望滄波開。", "四牡未遑息，三山安在哉。", "巨鼇不可釣，高浪何崔嵬。", "湛湛朝百谷，茫茫連九垓。", "挹流納廣大，觀異增遲廻。", "日出見魚目，月圓知蚌胎。", "跡非想像到，心以精靈猜。", "遠色帶孤嶼，虛聲涵殷雷。", "風行越裳貢，水遏天吳災。", "攬轡隼將擊，忘機鷗復來。", "緣情韻騷雅，獨立遺塵埃。", "吏道竟殊用，翰林仍忝陪。", "長鳴謝知己，所媿非龍媒。"]'),
('d5653ac5-0da7-42d7-b638-9b818b3567ed','和崔二少府登楚丘城作','高適','唐','唐诗','tang','','[]','故人亦不遇，異縣久棲託。',120,'全唐诗/poet.tang.10000.json','["故人亦不遇，異縣久棲託。", "辛勤失路意，感歎登樓作。", "清晨眺原野，獨立窮寥廓。", "雲散芒碭山，水還睢陽郭。", "繞梁即襟帶，封衛多漂泊。", "事古悲城池，年豐愛墟落。", "相逢俱未展，攜手空蕭索。", "何意千里心，仍求百金諾。", "公侯皆我輩，動用在謀略。", "聖心思賢才，朅來刈葵藿。"]'),
('c7eb94c0-2bf9-4da6-ba0a-7af47801b062','酬司空璲少府','高適','唐','唐诗','tang','','[]','飄颻未得意，感激與誰論。',84,'全唐诗/poet.tang.10000.json','["飄颻未得意，感激與誰論。", "昨日遇夫子，仍欣吾道存。", "江山滿詞賦，札翰起涼溫。", "吾見風雅作，人知德業尊。", "驚飆蕩萬木，秋氣屯高原。", "燕趙何蒼茫，鴻雁來翩翻。", "此時與君別，握手欲無言。"]'),
('5561dd82-ac19-4c72-ba0c-a941cec526c8','酬李少府','高適','唐','唐诗','tang','','[]','出塞魂屢驚，懷賢意難說。',108,'全唐诗/poet.tang.10000.json','["出塞魂屢驚，懷賢意難說。", "誰知吾道間，乃在客中別。", "日夕捧瓊瑤，相思無休歇。", "伊人雖薄宦，舉代推高節。", "述作凌江山，聲華滿冰雪。", "一登薊丘上，四顧何慘烈。", "來雁無盡時，邊風正騷屑。", "將從崖谷遁，且與沈浮絕。", "君若登青雲，余當投魏闕。"]'),
('ea341c3a-1c84-49ef-9458-64f84f5e7eac','酬裴秀才','高適','唐','唐诗','tang','','[]','男兒貴得意，何必相知早。',48,'全唐诗/poet.tang.10000.json','["男兒貴得意，何必相知早。", "飄蕩與物永，躊跎覺年老。", "長卿無產業，季子慙妻嫂。", "此事難重陳，未於衆人道。"]'),
('cb1ed1bb-9a23-42f5-94b7-fb065fa6d411','酬陸少府','高適','唐','唐诗','tang','','[]','朝臨淇水岸，還望衛人邑。',72,'全唐诗/poet.tang.10000.json','["朝臨淇水岸，還望衛人邑。", "別意在山阿，征途背原隰。", "蕭蕭前村口，唯見轉蓬入。", "水渚人去遲，霜天雁飛急。", "固應不遠別，所與路未及。", "欲濟川上舟，相思空佇立。"]'),
('bb4a1d16-2a2e-4a68-9732-77e2bfafde5e','奉酬北海李太守丈人夏日平陰亭','高適','唐','唐诗','tang','','[]','天子股肱守，丈人山嶽靈。',180,'全唐诗/poet.tang.10000.json','["天子股肱守，丈人山嶽靈。", "出身侍丹墀，舉翮凌青冥。", "當昔皇運否，人神俱未寧。", "諫官莫敢議，酷吏方專刑。", "谷永獨言事，匡衡多引經。", "兩朝納深衷，萬乘無不聽。", "盛烈播南史，雄詞豁東溟。", "誰謂整隼旟，翻然憶柴扃。", "寄書汶陽客，廻首平陰亭。", "開封見千里，結念存百齡。", "隱軫江山麗，氛氳蘭茝馨。", "自憐遇時休，漂泊隨流萍。", "春野變木德，夏天臨火星。", "一生徒羨魚，四十猶聚螢。", "從此日閑放，焉能懷拾青。"]'),
('ff7aca6e-232d-464f-91cf-75f019591e69','酬馬八效古見贈','高適','唐','唐诗','tang','','[]','深崖無綠竹，秀色徒氛氳。',48,'全唐诗/poet.tang.10000.json','["深崖無綠竹，秀色徒氛氳。", "時代種桃李，無人顧此君。", "奈何冰雪操，尚與蒿萊羣。", "願託靈仙子，一聲吹入雲。"]'),
('4bb52f17-5109-4d2a-93b9-7e1074dbb45b','酬鴻臚裴主簿雨後睢陽北樓見贈之作','高適','唐','唐诗','tang','','[]','暮霞照新晴，歸雲猶相逐。',120,'全唐诗/poet.tang.10000.json','["暮霞照新晴，歸雲猶相逐。", "有懷晨昏暇，相見登眺目。", "問禮侍彤襜，題詩訪茅屋。", "高樓多古今，陳事滿陵谷。", "地久微子封，臺餘孝王築。", "裴回顧霄漢，豁達俯川陸。", "遠水對秋城，長天向喬木。", "公門何清淨，列戟森已肅。", "不歎攜手稀，恆思着鞭速。", "終當拂羽翰，輕舉隨鴻鵠。"]'),
('9ca5eb72-69e6-47f0-a27d-06034645217d','酬裴員外以詩代書','高適','唐','唐诗','tang','','[]','少時方浩蕩，遇物猶塵埃。',288,'全唐诗/poet.tang.10000.json','["少時方浩蕩，遇物猶塵埃。", "脫略身外事，交遊天下才。", "單車入燕趙，獨立心悠哉。", "寧知戎馬間，忽展平生懷。", "且欣清論高，豈顧夕陽頹。", "題詩碣石館，縱酒燕王臺。", "北望沙漠垂，漫天雪皚皚。", "臨邊無策略，覽古空裴回。", "樂毅吾所憐，拔齊翻見猜。", "荆卿吾所悲，適秦不復廻。", "然諾多死地，公忠成禍胎。", "與君從此辭，每恐流年催。", "如何俱老大，始復忘形骸。", "兄弟真二陸，聲名連八裴。", "乙未將星變，賊臣候天災。", "胡騎犯龍山，乘輿經馬嵬。", "千官無倚着，萬姓徒悲哀。", "誅呂鬼神動，安劉天地開。", "奔波走風塵，倏忽值雲雷。", "擁旄出淮甸，入幕徵楚材。", "誓當剪鯨鯢，永以竭駑駘。", "小人胡不仁，讒我成死灰。", "賴得日月明，照耀無不該。", "留司洛陽宮，詹府唯蒿萊。"]'),
('a6a2e130-f45f-49a4-a7da-e0441d1578cd','酬龐十兵曹','高適','唐','唐诗','tang','','[]','憶昔遊京華，自言生羽翼。',156,'全唐诗/poet.tang.10000.json','["憶昔遊京華，自言生羽翼。", "懷書訪知己，末路空相識。", "許國不成名，還家有慙色。", "託身從𤱶畝，浪跡初自得。", "雨澤感天時，耕耘忘帝力。", "同人洛陽至，問我睢水北。", "遂爾款津涯，淨然見胸臆。", "高談懸物象，逸韻投翰墨。", "別岸迥無垠，海鶴鳴不息。", "梁城多古意，攜手共悽惻。", "懷賢想鄒枚，登高思荆棘。", "世情惡疵賤，之子憐孤直。", "酬贈感幷深，離憂豈終極。"]'),
('a8133806-1aeb-44d9-8b5e-6309fe6bd8cb','同呂員外酬田著作幕門軍西宿盤山秋夜作','高適','唐','唐诗','tang','','[]','磧路天早秋，邊城夜應永。',132,'全唐诗/poet.tang.10000.json','["磧路天早秋，邊城夜應永。", "遙傳戎旅作，已報關山冷。", "上將頓盤阪，諸軍徧泉井。", "綢繆閫外書，慷慨幕中請。", "能使勳業高，動令氛霧屏。", "遠途能自致，短步終難騁。", "羽翮時一看，窮愁始三省。", "人生感然諾，何啻若形影。", "白髮知苦心，陽春見佳境。", "星河連塞絡，刁斗兼山靜。", "憶君霜露時，使我空引領。"]'),
('276d7c1f-d89d-48fd-a8f5-777b9efd9d23','酬祕書弟兼寄幕下諸公','高適','唐','唐诗','tang','','[]','亞相膺時傑，羣才遇良工。',288,'全唐诗/poet.tang.10000.json','["亞相膺時傑，羣才遇良工。", "翩翩幕下來，拜賜甘泉宮。", "信知命世奇，適會非常功。", "侍御執邦憲，清詞煥春叢。", "末路望繡衣，他時常發蒙。", "孰云三軍壯，懼我彈射雄。", "誰謂萬里遙，在我樽俎中。", "光祿經濟器，精微自深衷。", "前席屢榮問，長城兼在躬。", "高縱激頹波，逸翮馳蒼穹。", "將副節制籌，欲令沙漠空。", "司業志應徐，雅度思沖融。", "相思三十年，憶昨猶兒童。", "今來抱青紫，忽若披鵷鴻。", "說劒增慷慨，論交持始終。", "祕書即吾門，虛白無不通。", "多才陸平原，碩學鄭司農。", "獻封到關西，獨步歸山東。", "永意久知處，嘉言能亢宗。", "客從梁宋來，行役隨轉蓬。", "酬贈欣元弟，憶賢瞻數公。", "游鱗戲滄浪，鳴鳳棲梧桐。", "並負垂天翼，俱乘破浪風。", "眈眈天府間，偃仰誰敢同。"]'),
('13619ace-57d2-4444-ac03-15481045fff6','淇上酬薛三據兼寄郭少府微','高適','唐','唐诗','tang','','[]','自從別京華，我心乃蕭索。',240,'全唐诗/poet.tang.10000.json','["自從別京華，我心乃蕭索。", "十年守章句，萬事空寥落。", "北上登薊門，茫茫見沙漠。", "倚劒對風塵，慨然思衛霍。", "拂衣去燕趙，驅馬悵不樂。", "天長滄洲路，日暮邯鄲郭。", "酒肆或淹留，漁潭屢棲泊。", "獨行備艱險，所見窮善惡。", "永願拯芻蕘，孰云干鼎鑊。", "皇情念淳古，時俗何浮薄。", "理道資任賢，安人在求瘼。", "故交負靈奇，逸氣抱謇諤。", "隱軫經濟具，縱橫建安作。", "才望忽先鳴，風期無宿諾。", "飄颻勞州縣，迢遞限言謔。", "東馳眇貝丘，西顧彌虢略。", "淇水徒自流，浮雲不堪託。", "吾謀適可用，天路豈寥廓。", "不然買山田，一身與耕鑿。", "且欲同鷦鷯，焉能志鴻鵠。"]'),
('cf44f6f5-acdc-449d-b10e-3096bfde8eed','酬岑二十主簿秋夜見贈之作','高適','唐','唐诗','tang','','[]','舍下蛩亂鳴，居然自蕭索。',96,'全唐诗/poet.tang.10000.json','["舍下蛩亂鳴，居然自蕭索。", "緬懷高秋興，忽枉清夜作。", "感物我心勞，涼風驚二毛。", "池枯菡萏死，月出梧桐高。", "如何異鄉縣，復得交才彥。", "汨沒嗟後時，蹉跎耻相見。", "箕山別來久，魏闕誰不戀。", "獨有江海心，悠悠未嘗倦。"]'),
('5a76b6ea-07ee-44b6-ac20-a87d18203810','答侯少府','高適','唐','唐诗','tang','','[]','常日好讀書，晚年學垂綸。',288,'全唐诗/poet.tang.10000.json','["常日好讀書，晚年學垂綸。", "漆園多喬木，睢水清粼粼。", "詔書下柴門，天命敢逡巡。", "赫赫三伏時，十日到咸秦。", "褐衣不得見，黃綬翻在身。", "吏道頓羈束，生涯難重陳。", "北使經大寒，關山饒苦辛。", "邊兵若芻狗，戰骨成埃塵。", "行矣勿復言，歸歟傷我神。", "如何燕趙陲，忽遇平生親。", "開館納征騎，彈絃娛遠賓。", "飄颻天地間，一別方茲晨。", "東道有佳作，南朝無此人。", "性靈出萬象，風骨超常倫。", "吾黨謝王粲，羣賢推郄詵。", "明時取秀才，落日過蒲津。", "節苦名已富，祿微家轉貧。", "相逢愧薄遊，撫己荷陶鈞。", "心事正堪盡，離居寧太頻。", "兩河歸路遙，二月芳草新。", "柳接滹沱暗，鶯連渤海春。", "誰謂行路難，猥當希代珍。", "提握每終日，相思猶比鄰。", "江海有扁舟，丘園有角巾。"]'),
('efc46322-baf5-49cd-9988-7c7333a99a2b','宋中別周梁李三子','高適','唐','唐诗','tang','','[]','曾是不得意，適來兼別離。',156,'全唐诗/poet.tang.10000.json','["曾是不得意，適來兼別離。", "如何一尊酒，翻作滿堂悲。", "周子負高價，梁生多逸詞。", "周旋梁宋間，感激建安時。", "白雪正如此，青雲無自疑。", "李侯懷英雄，骯髒乃天資。", "方寸且無間，衣冠當在斯。", "俱爲千里遊，忽念兩鄉辭。", "且見壯心在，莫嗟攜手遲。", "涼風吹北原，落日滿西陂。", "露下草初白，天長雲屢滋。", "我心不可問，君去定何之。", "京洛多知己，誰能憶左思。"]'),
('c12a5688-d65f-4e18-a9c6-6f5be6510e1c','宋中別李八','高適','唐','唐诗','tang','','[]','歲晏誰不歸，君歸意可說。',84,'全唐诗/poet.tang.10000.json','["歲晏誰不歸，君歸意可說。", "將趨倚門望，還念同人別。", "駐馬臨長亭，飄然事明發。", "蒼茫眺千里，正值苦寒節。", "舊國多轉蓬，平臺下明月。", "世情薄疵賤，夫子懷賢哲。", "行矣各勉旃，吾當挹餘烈。"]'),
('944aa163-f965-4396-9cea-d4fd8746eaf7','別王徹','高適','唐','唐诗','tang','','[]','歸客自南楚，悵然思北林。',96,'全唐诗/poet.tang.10000.json','["歸客自南楚，悵然思北林。", "蕭條秋風暮，廻首江淮深。", "留君終日歡，或爲梁父吟。", "時輩想鵬舉，他人嗟陸沈。", "載酒登平臺，贈君千里心。", "浮雲暗長路，落日有歸禽。", "離別未足悲，辛勤當自任。", "吾知十年後，季子多黃金。"]'),
('c64926d8-1757-4e1f-8096-dd24190f1ba1','送蕭十八與房侍御廻還','高適','唐','唐诗','tang','','[]','常苦古人遠，今見斯人古。',96,'全唐诗/poet.tang.10000.json','["常苦古人遠，今見斯人古。", "澹泊遺聲華，周旋必鄒魯。", "故交在梁宋，遊方出庭戶。", "匹馬鳴朔風，一身濟河滸。", "辛勤采蘭詠，款曲翰林主。", "歲月催別離，庭圍遠風土。", "寥寥寒煙靜，莽莽夕陰吐。", "明發不在茲，青天眇難覩。"]'),
('a9b7af05-49db-4fac-8c70-6f300183e59f','宋中送族姪式顏','高適','唐','唐诗','tang','','["\u9001\u522b", "\u8d5e\u7f8e"]','大夫擊東胡，胡塵不敢起。',204,'全唐诗/poet.tang.10000.json','["大夫擊東胡，胡塵不敢起。", "胡人山下哭，胡馬海邊死。", "部曲盡公侯，輿臺亦朱紫。", "當時有勳業，末路遭讒毀。", "轉斾燕趙間，剖符括蒼裏。", "弟兄莫相見，親族遠枌梓。", "不改青雲心，仍招布衣士。", "平生懷感激，本欲候知己。", "去矣難重陳，飄然自茲始。", "遊梁且未遇，適越今何以。", "鄉山西北愁，竹箭東南美。", "崢嶸縉雲外，蒼莽幾千里。", "旅雁悲啾啾，朝昏孰云已。", "登臨多瘴癘，動息在風水。", "雖有賢主人，終爲客行子。", "我攜一尊酒，滿酌聊勸爾。", "勸爾惟一言，家聲勿淪滓。"]'),
('0e108405-df95-4dca-abfe-9357e312eae6','又送族姪式顏','高適','唐','唐诗','tang','','[]','惜君才未遇，愛君才若此。',48,'全唐诗/poet.tang.10000.json','["惜君才未遇，愛君才若此。", "世上五百年，吾家一千里。", "俱遊帝城下，忽在梁園裏。", "我今行山東，離憂不能已。"]'),
('7bb37684-e982-4765-bce8-fbfe3b87dc15','贈別王十七管記','高適','唐','唐诗','tang','','["\u9001\u522b", "\u6292\u6000", "\u6000\u624d\u4e0d\u9047"]','故交吾未測，薄宦空年歲。',288,'全唐诗/poet.tang.10000.json','["故交吾未測，薄宦空年歲。", "晚節蹤曩賢，雄詞冠當世。", "堂中皆食客，門外多酒債。", "產業曾未言，衣裘與人敝。", "飄颻戎幕下，出入關山際。", "轉戰輕壯心，立談有邊計。", "雲沙自廻合，天海空迢遞。", "星高漢將驕，月盛胡兵銳。", "沙深冷陘斷，雪暗遼陽閉。", "亦謂掃欃槍，旋驚陷蜂蠆。", "歸旌告東捷，鬬騎傳西敗。", "遙飛絕漢書，已築長安第。", "畫龍俱在葉，寵鶴先居衛。", "勿辭部曲勳，不藉將軍勢。", "相逢季冬月，倀望窮海裔。", "折劒留贈人，嚴裝遂云邁。", "我行將悠𥾝，及此還羈滯。", "曾非濟代謀，且有臨深誡。", "隨波混清濁，與物同醜麗。", "眇憶青巖棲，寧忘褐衣拜。", "自言愛水石，本欲親蘭蕙。", "何意薄松筠，翻然重菅蒯。", "恆深取與分，孰慢平生契。", "欵曲雞黍期，酸辛別離袂。"]'),
('18c3e26e-8080-4a15-abf7-5b92cc862711','漣上別王秀才','高適','唐','唐诗','tang','','[]','飄颻經遠道，客思滿窮秋。',108,'全唐诗/poet.tang.10000.json','["飄颻經遠道，客思滿窮秋。", "浩蕩對長漣，君行殊未休。", "崎嶇山海側，想像無前儔。", "何意照乘珠，忽然欲暗投。", "東路方蕭條，楚歌復悲愁。", "暮帆使人感，去鳥兼離憂。", "行矣當自愛，壯年莫悠悠。", "余亦從此辭，異鄉難久留。", "贈言豈終極，慎勿滯滄洲。"]'),
('27246964-80bd-4b60-ae59-0921b0832948','贈別沈四逸人','高適','唐','唐诗','tang','','[]','沈侯未可測，其況信浮沈。',108,'全唐诗/poet.tang.10000.json','["沈侯未可測，其況信浮沈。", "十載常獨坐，幾人知此心。", "乘舟蹈滄海，買劒投黃金。", "世務不足煩，有田西山岑。", "我來遇知己，遂得開清襟。", "何意閫閾間，沛然江海深。", "疾風掃秋樹，濮上多鳴砧。", "耿耿尊酒前，聯雁飛愁音。", "平生重離別，感激對孤琴。"]'),
('6956d17b-9f62-4b03-876f-07ff4e278c15','送韓九','高適','唐','唐诗','tang','','[]','惆悵別離日，裴回岐路前。',48,'全唐诗/poet.tang.10000.json','["惆悵別離日，裴回岐路前。", "歸人望獨樹，匹馬隨秋蟬。", "常與天下士，許君兄弟賢。", "良時正可用，行矣莫徒然。"]'),
('5a966ed0-e64c-4cd4-9361-c79dbe37c05f','送崔錄事赴宣城','高適','唐','唐诗','tang','','[]','大國非不理，小官皆用才。',60,'全唐诗/poet.tang.10000.json','["大國非不理，小官皆用才。", "欲行宣城印，住飲洛陽桮。", "晚景爲人別，長天無鳥廻。", "舉帆風波渺，倚櫂江山來。", "羨爾兼乘興，蕪湖千里開。"]'),
('c5e21ddd-ceac-4c68-84c6-1de487ea4216','別張少府','高適','唐','唐诗','tang','','[]','歸客留不住，朝雲縱復橫。',48,'全唐诗/poet.tang.10000.json','["歸客留不住，朝雲縱復橫。", "馬頭向春草，斗柄臨高城。", "嗟我久離別，羨君看弟兄。", "歸心更難道，回首一傷情。"]'),
('d43c8384-8c19-4dd5-814a-14e14e0f7803','淇上別劉少府子英','高適','唐','唐诗','tang','','[]','近來住淇上，蕭條惟空林。',120,'全唐诗/poet.tang.10000.json','["近來住淇上，蕭條惟空林。", "又非耕種時，閑散多自任。", "伊君獨知我，驅馬欲招尋。", "千里忽攜手，十年同苦心。", "求仁見交態，於道喜甘臨。", "逸思乃天縱，微才應陸沈。", "飄然歸故鄉，不復問離襟。", "南登黎陽渡，莽蒼寒雲陰。", "桑葉原上起，河淩山下深。", "途窮更遠別，相對益悲吟。"]'),
('c6491c82-16cc-417f-bc8d-4cf938aa4ed4','別耿都尉','高適','唐','唐诗','tang','','[]','四十能學劒，時人無此心。',48,'全唐诗/poet.tang.10000.json','["四十能學劒，時人無此心。", "如何耿夫子，感激投知音。", "翩翩白馬來，二月青草深。", "別易小千里，興酣傾百金。"]'),
('83de3747-2242-4ae3-be3e-56a7b040aae2','宋中遇林盧楊十七山人因而有別','高適','唐','唐诗','tang','','[]','昔余涉漳水，驅車行鄴西。',180,'全唐诗/poet.tang.10000.json','["昔余涉漳水，驅車行鄴西。", "遙見林慮山，蒼蒼戛天倪。", "邂逅逢爾曹，說君彼巖棲。", "蘿徑垂野蔓，石房倚雲梯。", "秋韭何青青，藥苗數百畦。", "栗林隘谷口，栝樹森廻谿。", "耕耘有山田，紡績有山妻。", "人生苟如此，何必組與珪。", "誰謂遠相訪，曩情殊不迷。", "簷前舉醇醪，竈下烹雙雞。", "朔風忽振蕩，昨夜寒螿啼。", "遊子益思歸，罷琴傷解攜。", "出門盡原野，白日黯已低。", "始驚道路難，終念言笑暌。", "因聲謝岑壑，歲暮一攀躋。"]'),
('b458468f-a5c3-44a5-aa38-29e8ab8f3533','酬別薛三蔡大留簡韓十四主簿','高適','唐','唐诗','tang','','[]','迢遞辭京華，辛勤異鄉縣。',156,'全唐诗/poet.tang.10000.json','["迢遞辭京華，辛勤異鄉縣。", "登高俯滄海，廻首淚如霰。", "同人久離別，失路還相見。", "薛侯懷直道，德業應時選。", "蔡子負清才，當年擢賓薦。", "韓公有奇節，詞賦凌羣彥。", "讀書嵩岑間，作吏滄海甸。", "伊余寡棲託，感激多慍見。", "縱誕非爾情，飄淪任疵賤。", "忽枉瓊瑤作，乃深平生眷。", "始謂吾道存，終嗟客遊倦。", "歸心無晝夜，別事除言宴。", "復值涼風時，蒼茫夏雲變。"]'),
('01f00674-7790-44fb-86fb-40ba014c2bd2','送虞城劉明府謁魏郡苗太守','高適','唐','唐诗','tang','','[]','天官蒼生望，出入承明廬。',132,'全唐诗/poet.tang.10000.json','["天官蒼生望，出入承明廬。", "肅肅領舊藩，皇皇降璽書。", "茂宰多感激，良將復吹噓。", "永懷一言合，誰謂千里疎。", "對酒忽命駕，茲情何起予。", "炎天晝如火，極目無行車。", "長路出雷澤，浮雲歸孟諸。", "魏郡十萬家，歌鐘喧里閭。", "傳道賢君至，閉關常晏如。", "君將挹高論，定是問樵漁。", "今日逢明聖，吾爲陶隱居。"]'),
('108dcb9b-73b4-4157-9269-32514cd5dc3e','途中酬李少府贈別之作','高適','唐','唐诗','tang','','[]','西上逢節換，東征私自憐。',252,'全唐诗/poet.tang.10000.json','["西上逢節換，東征私自憐。", "故人今臥疾，欲別還留連。", "舉酒臨南軒，夕陽滿中筵。", "寧知江上興，乃在河梁偏。", "行李多光輝，札翰忽相鮮。", "誰謂歲月晚，交情尚貞堅。", "終嗟州縣勞，官謗復迍邅。", "雖負忠信美，其如方寸懸。", "連帥扇清風，千里猶眼前。", "曾是趨藻鏡，不應翻棄捐。", "日來知自強，風氣殊未痊。", "可以加藥物，胡爲輙憂煎。", "驅馬出大梁，原野一悠然。", "柳色感行客，雲陰愁遠天。", "皇明燭幽遐，德澤普照宣。", "鵷鴻列霄漢，燕雀何翩翩。", "余亦愜所從，漁樵十二年。", "種瓜漆園裏，鑿井盧門邊。", "去去勿重陳，生涯難勉旃。", "或期遇春事，與爾復周旋。", "投報空回首，狂歌謝比肩。"]'),
('8fc37ad3-7f3b-466e-aad1-e00a080fdf1d','睢陽酬別暢大判官','高適','唐','唐诗','tang','','[]','吾友遇知己，策名逢聖朝。',216,'全唐诗/poet.tang.10000.json','["吾友遇知己，策名逢聖朝。", "高才擅白雪，逸翰懷青霄。", "承詔選嘉賓，慨然即馳軺。", "清晝下公館，尺書忽相邀。", "留歡惜別離，畢景駐行鑣。", "言及沙漠事，益令胡馬驕。", "丈夫拔東蕃，聲冠霍嫖姚。", "兜鍪衝矢石，鐵甲生風飆。", "諸將出冷陘，連營濟石橋。", "酋豪盡俘馘，子弟輸征徭。", "邊庭絕刁斗，戰地成漁樵。", "榆關夜不扃，塞口長蕭蕭。", "降胡滿薊門，一一能射鵰。", "軍中多宴樂，馬上何輕趫。", "戎狄本無厭，羇縻非一朝。", "飢附誠足用，飽飛安可招。", "李牧制儋藍，遺風豈寂寥。", "君還謝幕府，慎勿輕芻蕘。"]'),
('482ab10e-32bb-455b-8208-204f55f6d37f','宴韋司戶山亭院','高適','唐','唐诗','tang','','[]','人幽想靈山，意愜憐遠水。',84,'全唐诗/poet.tang.10000.json','["人幽想靈山，意愜憐遠水。", "習靜務爲適，所居還復爾。", "汲流漲華池，開酌宴君子。", "苔逕試窺踐，石屏可攀倚。", "入門見中峰，攜手如萬里。", "橫琴了無事，垂釣應有以。", "高館何沈沈，颯然涼風起。"]'),
('a491ab1b-43b6-4757-b3bb-9e984de2b5d9','同諸公登慈恩寺浮圖','高適','唐','唐诗','tang','','[]','香界泯羣有，浮圖豈諸相。',108,'全唐诗/poet.tang.10000.json','["香界泯羣有，浮圖豈諸相。", "登臨駭孤高，披拂欣大壯。", "言是羽翼生，迥出虛空上。", "頓疑身世別，乃覺形神王。", "宮闕皆戶前，山河盡簷向。", "秋風昨夜至，秦塞多清曠。", "千里何蒼蒼，五陵鬱相望。", "盛時慙阮步，末宦知周防。", "輸效獨無因，斯焉可遊放。"]'),
('8c75cce0-2e86-4277-bef4-dd0fe6b1c1aa','同薛司直諸公秋霽曲江俯見南山作','高適','唐','唐诗','tang','','[]','南山鬱初霽，曲江湛不流。',120,'全唐诗/poet.tang.10000.json','["南山鬱初霽，曲江湛不流。", "若臨瑤池前，想望崑崙丘。", "廻首見黛色，眇然波上秋。", "深沈俯崢嶸，清淺延阻修。", "連潭萬木影，插岸千巖幽。", "杳靄信難測，淵淪無暗投。", "片雲對漁父，獨鳥隨虛舟。", "我心寄青霞，世事慙白鷗。", "得意在乘興，忘懷非外求。", "良辰自多暇，欣與數子遊。"]'),
('98c02d61-b06c-46b4-b775-bf43c1362cde','登廣陵棲靈寺塔','高適','唐','唐诗','tang','','[]','淮南富登臨，茲塔信奇最。',108,'全唐诗/poet.tang.10000.json','["淮南富登臨，茲塔信奇最。", "直上造雲族，憑虛納天籟。", "迥然碧海西，獨立飛鳥外。", "始知高興盡，適與賞心會。", "連山黯吳門，喬木吞楚塞。", "城池滿窗下，物象歸掌內。", "遠思駐江帆，暮時結春靄。", "軒車疑蠢動，造化資大塊。", "何必了無身，然後知所退。"]'),
('d42cb59a-2f8d-4fe9-9db7-1e973995ef42','登百丈峰二首 一','高適','唐','唐诗','tang','','[]','朝登百丈峰，遙望燕支道。',60,'全唐诗/poet.tang.10000.json','["朝登百丈峰，遙望燕支道。", "漢壘青冥間，胡天白如掃。", "憶昔霍將軍，連年此征討。", "匈奴終不滅，寒山徒草草。", "唯見鴻雁飛，令人傷懷抱。"]'),
('b2163cf8-fdf0-4c2b-a57e-feee532938a4','登百丈峰二首 二','高適','唐','唐诗','tang','','[]','晉武輕後事，惠皇終已昏。',60,'全唐诗/poet.tang.10000.json','["晉武輕後事，惠皇終已昏。", "豺狼塞瀍洛，胡羯爭乾坤。", "四海如鼎沸，五原徒自尊。", "而今白庭路，猶對青陽門。", "朝市不足問，君臣隨草根。"]'),
('b86dfe06-639c-446e-ac96-298a1403d16e','同羣公秋登琴臺','高適','唐','唐诗','tang','','[]','古跡使人感，琴臺空寂寥。',120,'全唐诗/poet.tang.10000.json','["古跡使人感，琴臺空寂寥。", "靜然顧遺塵，千載如昨朝。", "臨眺自茲始，羣賢久相邀。", "德與形神高，孰知天地遙。", "四時何倏忽，六月鳴秋蜩。", "萬象歸白帝，平川橫赤霄。", "猶是對夏伏，幾時有涼飆。", "燕雀滿簷楹，鴻鵠摶扶搖。", "物性各自得，我心在漁樵。", "兀然還復醉，尚握尊中瓢。"]'),
('e6078251-050b-4d8b-b77c-f416392eecf8','同羣公出獵海上','高適','唐','唐诗','tang','','[]','畋獵自古昔，況伊心賞俱。',120,'全唐诗/poet.tang.10000.json','["畋獵自古昔，況伊心賞俱。", "偶與羣公遊，曠然出平蕪。", "層陰漲溟海，殺氣窮幽都。", "鷹隼何翩翩，馳驟相傳呼。", "豺狼竄榛莽，麋鹿罹艱虞。", "高鳥下騂弓，困獸鬬匹夫。", "塵驚大澤晦，火燎深林枯。", "失之有餘恨，獲者無全軀。", "咄彼工拙間，恨非指蹤徒。", "猶懷老氏訓，感歎此歡娛。"]'),
('1b0eb975-d6fd-4b70-b6e6-a8ee5bbd6563','同羣公題鄭少府田家','高適','唐','唐诗','tang','','[]','鄭侯應悽惶，五十頭盡白。',84,'全唐诗/poet.tang.10000.json','["鄭侯應悽惶，五十頭盡白。", "昔爲南昌尉，今作東郡客。", "與語多遠情，論心知所益。", "秋林既清曠，窮巷空淅瀝。", "蝶舞園更閑，雞鳴日云夕。", "男兒未稱意，其道固無適。", "勸君且杜門，勿歎人事隔。"]'),
('36dc18a5-470c-48eb-adb5-3c3c151851fb','同羣公題中山寺','高適','唐','唐诗','tang','','[]','平原十里外，稍稍雲巖深。',72,'全唐诗/poet.tang.10000.json','["平原十里外，稍稍雲巖深。", "遂及清淨所，都無人世心。", "名僧既禮謁，高閣復登臨。", "石壁倚松徑，山田多栗林。", "超遙盡巘崿，逼側仍嶇嶔。", "吾欲休世事，於焉聊自任。"]'),
('8d968574-77fb-46e2-9594-d31f60408227','同羣公宿開善寺贈陳十六所居','高適','唐','唐诗','tang','','[]','駕車出人境，避暑投僧家。',72,'全唐诗/poet.tang.10000.json','["駕車出人境，避暑投僧家。", "裴回龍象側，始見香林花。", "讀書不及經，飲酒不勝茶。", "知君悟此道，所未搜袈裟。", "談空忘外物，持誡破諸邪。", "則是無心地，相看唯月華。"]'),
('b9c7a087-4ff1-4367-a310-79116ad7f9bd','同韓四薛三東亭翫月','高適','唐','唐诗','tang','','[]','遠遊悵不樂，茲賞吾道存。',96,'全唐诗/poet.tang.10000.json','["遠遊悵不樂，茲賞吾道存。", "款曲故人意，辛勤清夜言。", "東亭何寥寥，佳境無朝昏。", "堦墀近洲渚，戶牖當郊原。", "矧乃窮周旋，游時怡討論。", "樹陰蕩瑤瑟，月氣延清尊。", "明河帶飛雁，野火連荒村。", "對此更愁予，悠哉懷故園。"]'),
('e7fe9e63-321b-4afd-8a47-3dc37dbf7ba6','同敬八盧五汎河間清河','高適','唐','唐诗','tang','','[]','清川在城下，沿汎多所宜。',96,'全唐诗/poet.tang.10000.json','["清川在城下，沿汎多所宜。", "同濟愜數公，翫物欣良時。", "飄颻波上興，燕婉舟中詞。", "昔陟乃平原，今來忽漣漪。", "東流達滄海，西流延滹池。", "雲樹共晦明，井邑相逶迤。", "稍隨歸月帆，若與沙鷗期。", "漁父更留我，前潭水未滋。"]'),
('f38c1894-0609-4b47-b3d9-48e1b6543efe','同房侍御山園新亭與邢判官同遊','高適','唐','唐诗','tang','','[]','隱隱春城外，朦朧陳跡深。',120,'全唐诗/poet.tang.10000.json','["隱隱春城外，朦朧陳跡深。", "君子顧榛莽，興言傷古今。", "決河導新流，疏逕蹤舊林。", "開亭俯川陸，時景宜招尋。", "肅穆逢使軒，夤緣事登臨。", "忝遊芝蘭室，還對桃李陰。", "岸遠白波來，氣喧黃鳥吟。", "因睹歌頌作，始知經濟心。", "灌壇有遺風，單父多鳴琴。", "誰爲久州縣，蒼生懷德音。"]'),
('b39ad3db-8f27-43c9-a11d-9b16e5259431','同馬太守聽九思法師講金剛經','高適','唐','唐诗','tang','','[]','吾師晉陽寶，傑出山河最。',120,'全唐诗/poet.tang.10000.json','["吾師晉陽寶，傑出山河最。", "途經世諦間，心到空王外。", "鳴鐘山虎伏，說法天龍會。", "了義同建瓴，梵法若吹籟。", "深知億劫苦，善喻恆沙大。", "捨施割肌膚，攀緣去親愛。", "招提何清淨，良牧駐輕蓋。", "露冕衆香中，臨人覺苑內。", "心持佛印久，標割魔軍退。", "願開初地因，永奉彌天對。"]'),
('50d852c5-4091-413a-a002-bb048d74dcc7','漣上題樊氏水亭','高適','唐','唐诗','tang','','[]','漣上非所趣，偶爲世務牽。',132,'全唐诗/poet.tang.10000.json','["漣上非所趣，偶爲世務牽。", "經時駐歸棹，日夕對平川。", "莫論行子愁，且得主人賢。", "亭上酒初熟，廚中魚每鮮。", "自說宦遊來，因之居住偏。", "煮鹽滄海曲，種稻長淮邊。", "四時常晏如，百口無飢年。", "菱芋藩籬下，漁樵耳目前。", "異縣少朋從，我行復迍邅。", "向不逢此君，孤舟已言旋。", "明日又分首，風濤還眇然。"]'),
('e07c9276-01df-4b93-9d66-6d0f5d3904e6','同呂判官從哥舒大夫破洪濟城廻登積石軍多福七級浮圖','高適','唐','唐诗','tang','','[]','塞口連濁河，轅門對山寺。',120,'全唐诗/poet.tang.10000.json','["塞口連濁河，轅門對山寺。", "寧知鞍馬上，獨有登臨事。", "七級凌太清，千崖列蒼翠。", "飄飄方寓目，想像見深意。", "高興殊未平，涼風颯然至。", "拔城陣雲合，轉斾胡星墜。", "大將何英靈，官軍動天地。", "君懷生羽翼，本欲附騏驥。", "款段苦不前，清冥信難致。", "一歌陽春後，三歎終自愧。"]'),
('1ae7f676-2137-47e6-ae10-7cc96deddd94','三君詠 魏鄭公','高適','唐','唐诗','tang','','[]','鄭公經綸日，隋氏風塵昏。',48,'全唐诗/poet.tang.10000.json','["鄭公經綸日，隋氏風塵昏。", "濟代取高位，逢時敢直言。", "道光先帝業，義激舊君恩。", "寂寞臥龍處，英靈千載魂。"]'),
('0c521179-7dd9-49a9-8b29-c7331d8870d0','三君詠 郭代公','高適','唐','唐诗','tang','','[]','代公實英邁，津涯浩難識。',48,'全唐诗/poet.tang.10000.json','["代公實英邁，津涯浩難識。", "擁兵抗矯徵，仗節歸有德。", "縱橫負才智，顧盻安社稷。", "流落勿重陳，懷哉爲悽惻。"]'),
('1f069771-1d5d-48e9-abb5-3ecbb9167700','三君詠 狄梁公','高適','唐','唐诗','tang','','[]','梁公乃貞固，勳烈垂竹帛。',48,'全唐诗/poet.tang.10000.json','["梁公乃貞固，勳烈垂竹帛。", "昌言太后朝，潛運儲君策。", "待賢開相府，共理登方伯。", "至今青雲人，猶是門下客。"]'),
('caeb5c1f-6a0e-4701-9158-9f403db9c47e','宓公琴臺詩三首 一','高適','唐','唐诗','tang','','[]','宓子昔爲政，鳴琴登此臺。',48,'全唐诗/poet.tang.10000.json','["宓子昔爲政，鳴琴登此臺。", "琴和人亦閑，千載稱其才。", "臨眺忽悽愴，人琴安在哉？", "悠悠此天壤，唯有頌聲來。"]'),
('320af109-788d-45f4-8792-1e014aeda653','宓公琴臺詩三首 二','高適','唐','唐诗','tang','','[]','邦伯感遺事，慨然建琴堂。',48,'全唐诗/poet.tang.10000.json','["邦伯感遺事，慨然建琴堂。", "乃知靜者心，千載猶相望。", "入室想其人，出門何茫茫。", "唯見白雲合，東臨鄒魯鄉。"]'),
('8793edad-baed-4834-9411-199ca140b5c7','宓公琴臺詩三首 三','高適','唐','唐诗','tang','','[]','皤皤邑中老，自誇邑中理。',48,'全唐诗/poet.tang.10000.json','["皤皤邑中老，自誇邑中理。", "何必升君堂，然後知君美。", "開門無犬吠，早臥常晏起。", "昔人不忍欺，今我還復爾。"]'),
('9d8d3ee1-81f4-4938-8797-5dcd5be1f720','李雲南征蠻詩','高適','唐','唐诗','tang','','["\u6218\u4e89", "\u6b4c\u9882", "\u5c06\u58eb"]','聖人赫斯怒，詔伐西南戎。',228,'全唐诗/poet.tang.10000.json','["聖人赫斯怒，詔伐西南戎。", "肅穆廟堂上，深沈節制雄。", "遂令感激士，得建非常功。", "料死不料敵，顧恩寧顧終。", "鼓行天海外，轉戰蠻夷中。", "梯巘近高鳥，穿林經毒蟲。", "鬼門無歸客，北戶多南風。", "蜂蠆隔萬里，雲雷隨九攻。", "長驅大浪破，急擊羣山空。", "餉道忽已遠，懸軍垂欲窮。", "精誠動白日，憤薄連蒼穹。", "野食掘田鼠，晡餐兼僰僮。", "收兵列亭堠，拓地彌西東。", "臨事耻苟免，履危能飭躬。", "將星獨照耀，邊色何溟濛。", "瀘水夜可涉，交州今始通。", "歸來長安道，召見甘泉宮。", "廉藺若未死，孫吳知暗同。", "相逢論意氣，慷慨謝深衷。"]'),
('d44f2dfd-d7d4-4bab-80eb-de60e198953f','題尉遲將軍新廟','高適','唐','唐诗','tang','','[]','周室既板蕩，賊臣立嬰兒。',132,'全唐诗/poet.tang.10000.json','["周室既板蕩，賊臣立嬰兒。", "將軍獨激昂，誓欲酬恩私。", "孤城日無援，高節終可悲。", "家國共淪亡，精魂空在斯。", "沈沈積冤氣，寂寂無人知。", "良牧懷深仁，與君建明祠。", "父子俱血食，軒車每逶迤。", "我來薦蘋蘩，感歎興此詞。", "晨光上階闥，殺氣翻旌旗。", "明明幽冥理，至誠信莫欺。", "唯夫二千石，多慶方自茲。"]'),
('326cb4cd-2658-4a7a-a51d-d99ef1fc58f3','觀李九少府翥樹宓子賤神祠碑','高適','唐','唐诗','tang','','[]','吾友吏茲邑，亦嘗懷宓公。',132,'全唐诗/poet.tang.10000.json','["吾友吏茲邑，亦嘗懷宓公。", "安知夢寐間，忽與精靈通。", "一見興永歎，再來激深衷。", "賓從何逶迤，二十四老翁。", "於焉建層碑，突兀長林東。", "作者無愧色，行人感遺風。", "坐令高岸盡，獨對秋山空。", "片石勿謂輕，斯言固難窮。", "龍盤色絲外，鵲顧偃波中。", "形勝駐羣目，堅貞指蒼穹。", "我非王仲宣，去矣徒發蒙。"]'),
('2409c579-a1d8-4ea2-8fa5-790b0b45247e','同觀陳十六史興碑','高適','唐','唐诗','tang','','[]','荆衡氣偏秀，江漢流不歇。',144,'全唐诗/poet.tang.10000.json','["荆衡氣偏秀，江漢流不歇。", "此地多精靈，有時生才傑。", "伊人今獨步，逸思能間發。", "永懷掩風騷，千載常矻矻。", "新碑亦崔嵬，佳句懸日月。", "則是刊石經，終然繼檮杌。", "我來觀雅製，慷慨變毛髮。", "季主盡荒淫，前王徒貽厥。", "東周既削弱，兩漢更淪沒。", "西晉何披猖，五胡相唐突。", "作歌乃彰善，比物仍惡訐。", "感歎將謂誰，對之空咄咄。"]'),
('f1cb1f76-9344-4712-a551-eac9457e519c','宋中十首 一','高適','唐','唐诗','tang','','[]','梁王昔全盛，賓客復多才。',36,'全唐诗/poet.tang.10000.json','["梁王昔全盛，賓客復多才。", "悠悠一千年，陳跡唯高臺。", "寂寞向秋草，悲風千里來。"]'),
('1082dfa9-28dd-4dfe-9e5e-e8baa0bea8ad','宋中十首 二','高適','唐','唐诗','tang','','[]','朝臨孟諸上，忽見芒碭間。',36,'全唐诗/poet.tang.10000.json','["朝臨孟諸上，忽見芒碭間。", "赤帝終已矣，白雲長不還。", "時清更何有，禾黍徧空山。"]'),
('8edbfa08-16c6-4b38-9958-40c4cefa520a','宋中十首 三','高適','唐','唐诗','tang','','[]','景公德何廣，臨變莫能欺。',36,'全唐诗/poet.tang.10000.json','["景公德何廣，臨變莫能欺。", "三請皆不忍，妖星終自移。", "君心本如此，天道豈無知。"]'),
('89a6c133-8b77-4365-960f-79e7c3991f49','宋中十首 四','高適','唐','唐诗','tang','','[]','梁苑白日暮，梁山秋草時。',36,'全唐诗/poet.tang.10000.json','["梁苑白日暮，梁山秋草時。", "君王不可見，脩竹令人悲。", "九月桑葉盡，寒風鳴樹枝。"]'),
('3530235e-e711-41d8-b30a-4a238a3d9ed4','宋中十首 五','高適','唐','唐诗','tang','','[]','登高臨舊國，懷古對窮秋。',36,'全唐诗/poet.tang.10000.json','["登高臨舊國，懷古對窮秋。", "落日鴻雁度，寒城砧杵愁。", "昔賢不復有，行矣莫淹留。"]'),
('2f57d743-cd54-4c89-bcd1-79192dc2d495','宋中十首 六','高適','唐','唐诗','tang','','[]','出門望終古，獨立悲且歌。',36,'全唐诗/poet.tang.10000.json','["出門望終古，獨立悲且歌。", "憶昔魯仲尼，悽悽此經過。", "衆人不可向，伐樹將如何。"]'),
('d9ac2959-1f77-492f-9079-30c25f8af521','宋中十首 七','高適','唐','唐诗','tang','','[]','逍遙漆園吏，冥沒不知年。',36,'全唐诗/poet.tang.10000.json','["逍遙漆園吏，冥沒不知年。", "世事浮雲外，閑居大道邊。", "古來同一馬，今我亦忘筌。"]'),
('88b7713b-419a-4972-9174-3418204f1e09','宋中十首 八','高適','唐','唐诗','tang','','[]','五霸遞征伐，宋人無戰功。',36,'全唐诗/poet.tang.10000.json','["五霸遞征伐，宋人無戰功。", "解圍幸奇說，易子傷吾衷。", "唯見盧門外，蕭條多轉蓬。"]'),
('c6675460-3613-4c43-a435-5bd2f44c5e5f','宋中十首 九','高適','唐','唐诗','tang','','[]','常愛宓子賤，鳴琴能自親。',36,'全唐诗/poet.tang.10000.json','["常愛宓子賤，鳴琴能自親。", "邑中靜無事，豈不由其身。", "何意千年後，寂寞無此人。"]'),
('d3d18a80-f7b2-42d8-a910-ab4e51270e3a','宋中十首 十','高適','唐','唐诗','tang','','[]','閼伯去已久，高丘臨道傍。',36,'全唐诗/poet.tang.10000.json','["閼伯去已久，高丘臨道傍。", "人皆有兄弟，爾獨爲參商。", "終古猶如此，而今安可量。"]'),
('8fb95f8c-bd7b-45d7-a0f9-c61746b7cbb7','薊中作','高適','唐','唐诗','tang','','["\u53d9\u4e8b", "\u58ee\u5fd7\u96be\u916c", "\u8fb9\u585e", "\u6124\u61d1"]','策馬自沙漠，長驅登塞垣。',60,'全唐诗/poet.tang.10000.json','["策馬自沙漠，長驅登塞垣。", "邊城何蕭條，白日黃雲昏。", "一到征戰處，每愁胡虜翻。", "豈無安邊書，諸將已承恩。", "惆悵孫吳事，歸來獨閉門。"]'),
('02feeee3-8ca8-43eb-9e53-507cd7b9a960','自淇涉黃河途中作十三首 一','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','川上常極目，世情今已閑。',48,'全唐诗/poet.tang.10000.json','["川上常極目，世情今已閑。", "去帆帶落日，征路隨長山。", "親友若雲霄，可望不可攀。", "於茲任所愜，浩蕩風波間。"]'),
('6ec03821-1ece-4cdc-97cb-c7b976ac47b1','自淇涉黃河途中作十三首 二','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','清晨泛中流，羽族滿汀渚。',48,'全唐诗/poet.tang.10000.json','["清晨泛中流，羽族滿汀渚。", "黃鵠何處來，昂藏寡儔侶。", "飛鳴無人見，飲啄豈得所。", "雲漢爾固知，胡爲不輕舉。"]'),
('6dceb62b-832f-40d9-8055-2d12282d781c','自淇涉黃河途中作十三首 三','高適','唐','唐诗','tang','','["\u9ec4\u6cb3"]','野人頭盡白，與我忽相訪。',48,'全唐诗/poet.tang.10000.json','["野人頭盡白，與我忽相訪。", "手持青竹竿，日暮淇水上。", "雖老美容色，雖貧亦閑放。", "釣魚三十年，中心無所向。"]');
